DROP TABLE IF EXISTS "public"."okved_2";
CREATE TABLE "public"."okved_2" (
  "code" text COLLATE "pg_catalog"."default" NOT NULL DEFAULT ''::text,
  "parent_code" text COLLATE "pg_catalog"."default" NOT NULL DEFAULT ''::text,
  "section" text COLLATE "pg_catalog"."default" NOT NULL DEFAULT ''::text,
  "name" text COLLATE "pg_catalog"."default" NOT NULL DEFAULT ''::text,
  "comment" text COLLATE "pg_catalog"."default" NOT NULL DEFAULT ''::text
)
;

-- ----------------------------
-- Records of okved_2
