INSERT INTO "public"."okved_2" VALUES ('A', '', 'A', 'СЕЛЬСКОЕ, ЛЕСНОЕ ХОЗЯЙСТВО, ОХОТА, РЫБОЛОВСТВО И РЫБОВОДСТВО', 'Этот раздел включает:
- использование растительных и животных природных ресурсов, включая выращивание зерновых, содержание и разведение животных;
- получение древесины и других растений, животных или продуктов животного происхождения на ферме или в естественной среде обитания');
INSERT INTO "public"."okved_2" VALUES ('01', 'A', 'A', 'Растениеводство и животноводство, охота и предоставление соответствующих услуг в этих областях', 'Эта группировка включает:
- два основных вида деятельности, а именно: производство продукции растениеводства и производство продукции животноводства, охватывая также формы органического сельского хозяйства, выращивание и разведение генетически-модифицированных культур и животных

Эта группировка также включает:
- деятельность, второстепенную по отношению к сельскому хозяйству, а также охоту, ловлю животных и предоставление услуг в этих областях');
INSERT INTO "public"."okved_2" VALUES ('01.1', '01', 'A', 'Выращивание однолетних культур', 'Эта группировка включает:
- выращивание однолетних культур, т. е. растений, вегетативный период которых состоит не более чем из двух сезонов
Выращивание данных культур включено также для целей семеноводства');
INSERT INTO "public"."okved_2" VALUES ('01.11', '01.1', 'A', 'Выращивание зерновых (кроме риса), зернобобовых культур и семян масличных культур', 'Эта группировка включает:
- все формы выращивания зерновых, зернобобовых культур и семян масличных культур в открытом грунте
Выращивание этих культур часто комбинируется в тех или иных сельскохозяйственных подразделениях.

Эта группировка также включает:
- выращивание зерновых культур, таких как: пшеница, кукуруза, сорго, ячмень, рожь, овес, просо, гречиха и прочие зерновые культуры, не включенные в другие группировки;
- выращивание зернобобовых культур, таких как: горох, люпин, чечевица, бобы, конские бобы, нут (бараний горох), вигна, вика и прочие зернобобовые культуры;
- выращивание семян масличных культур, таких как: подсолнечник, соевые бобы, рапс, лен масличный, арахис (земляной орех), клещевина обыкновенная, горчица, масличная нуга, сафлор, кунжут и прочих масличных культур

Эта группировка не включает:
- выращивание сахарной кукурузы, см. 01.13;
- выращивание кормовой кукурузы, см. 01.19;
- выращивание плодов масличных культур, см. 01.26');
