INSERT INTO "public"."okved_2" VALUES ('01.15', '01.1', 'A', 'Выращивание табака и махорки', 'Эта группировка включает:
- выращивание табака;
- выращивание махорки

Эта группировка не включает:
- производство табачных изделий, см. 12.00');
INSERT INTO "public"."okved_2" VALUES ('01.16', '01.1', 'A', 'Выращивание волокнистых прядильных культур', 'Эта группировка включает:
- выращивание джута, кенафа и других текстильных лубяных волокон;
- выращивание льна-долгунца, конопли обыкновенной, хлопчатника и др.;
- выращивание сизаля и другого текстильного волокна семейства агавы;
- выращивание абаки, рами и других растительных текстильных волокон;
- выращивание прочих текстильных культур');
INSERT INTO "public"."okved_2" VALUES ('01.16.1', '01.16', 'A', 'Выращивание хлопчатника', '');
INSERT INTO "public"."okved_2" VALUES ('01.16.2', '01.16', 'A', 'Выращивание льна', '');
INSERT INTO "public"."okved_2" VALUES ('01.16.3', '01.16', 'A', 'Выращивание обыкновенной конопли', '');
INSERT INTO "public"."okved_2" VALUES ('01.16.9', '01.16', 'A', 'Выращивание прочих текстильных культур', '');
INSERT INTO "public"."okved_2" VALUES ('01.19', '01.1', 'A', 'Выращивание прочих однолетних культур', 'Эта группировка включает:
- выращивание всех прочих однолетних культур: брюквы, кормовой свеклы, кормовых корнеплодов, клевера, люцерны, эспарцета, кормовой кукурузы и прочих кормовых трав, кормовой капусты и подобных кормовых культур;
- выращиваниесемян свеклы (кроме семян сахарной свеклы) и семян кормовых культур;
- выращивание цветов;
- производство цветов на срез и цветочных бутонов;
- выращивание семян цветов

Эта группировка не включает:
- выращивание однолетних специй, см. 01.28;
- выращивание пряно-ароматических культур, см. 01.28;
- выращивание эфирномасличных культур, см. 01.28;
- выращивание лекарственных культур, см. 01.28');
INSERT INTO "public"."okved_2" VALUES ('01.19.1', '01.19', 'A', 'Выращивание однолетних кормовых культур', '');
INSERT INTO "public"."okved_2" VALUES ('01.19.2', '01.19', 'A', 'Цветоводство', '');
INSERT INTO "public"."okved_2" VALUES ('01.19.21', '01.19.2', 'A', 'Выращивание цветов в открытом и защищенном грунте', '');
INSERT INTO "public"."okved_2" VALUES ('01.19.22', '01.19.2', 'A', 'Выращивание семян цветов', '');
INSERT INTO "public"."okved_2" VALUES ('01.19.3', '01.19', 'A', 'Выращивание семян свеклы (кроме семян сахарной свеклы) и семян кормовых культур', '');
INSERT INTO "public"."okved_2" VALUES ('01.19.9', '01.19', 'A', 'Выращивание прочих однолетних культур, не включенных в другие группировки', '');
INSERT INTO "public"."okved_2" VALUES ('01.2', '01', 'A', 'Выращивание многолетних культур', 'Эта группировка включает:
- выращивание многолетних культур, т. е. растений, вегетативный период которых длится более двух сезонов

Эта группировка также включает:
- выращивание и подготовку семян');
INSERT INTO "public"."okved_2" VALUES ('01.21', '01.2', 'A', 'Выращивание винограда', 'Эта группировка включает:
- выращивание винных и столовых сортов винограда на виноградниках

Эта группировка не включает:
- производство вина, см. 11.02');
INSERT INTO "public"."okved_2" VALUES ('01.22', '01.2', 'A', 'Выращивание тропических и субтропических культур', 'Эта группировка включает:
- выращивание тропических и субтропических культур, таких как авокадо, бананы и овощные бананы, финики, фиги (инжир), манго, папайя, ананасы, прочие тропические и субтропические фрукты');
INSERT INTO "public"."okved_2" VALUES ('01.23', '01.2', 'A', 'Выращивание цитрусовых культур', 'Эта группировка включает:
- выращивание цитрусовых культур, таких как: грейпфруты и помело, лимоны и лаймы, апельсины, мандарины всех видов, прочие цитрусовые культуры');
INSERT INTO "public"."okved_2" VALUES ('01.24', '01.2', 'A', 'Выращивание семечковых и косточковых культур', 'Эта группировка включает:
- выращивание таких семечковых и косточковых плодов, как: яблоки, абрикосы, вишня и черешня, персики и нектарины, груши и айва, сливы и терн, прочие семечковые и косточковые плоды');
INSERT INTO "public"."okved_2" VALUES ('01.25', '01.2', 'A', 'Выращивание прочих плодовых деревьев, кустарников и орехов', '');
INSERT INTO "public"."okved_2" VALUES ('01.25.1', '01.25', 'A', 'Выращивание прочих плодовых и ягодных культур', '');
INSERT INTO "public"."okved_2" VALUES ('01.25.2', '01.25', 'A', 'Выращивание семян плодовых и ягодных культур', '');
INSERT INTO "public"."okved_2" VALUES ('01.25.3', '01.25', 'A', 'Выращивание орехоплодных культур', '');
INSERT INTO "public"."okved_2" VALUES ('01.26', '01.2', 'A', 'Выращивание плодов масличных культур', 'Эта группировка включает:
- выращивание плодов масличных культур, таких как: кокосовые орехи, оливки (маслины), плоды масличной пальмы, плоды прочих масличных культур

Эта группировка не включает:
- выращивание соевых бобов, арахиса (земляного ореха)и прочих семян масличных культур, см. 01.11');
INSERT INTO "public"."okved_2" VALUES ('01.27', '01.2', 'A', 'Выращивание культур для производства напитков', 'Эта группировка включает:
- выращивание культур для производства напитков, таких как: кофе, чай, мате, какао, прочие культуры для производства напитков');
INSERT INTO "public"."okved_2" VALUES ('01.27.1', '01.27', 'A', 'Выращивание чая', '');
INSERT INTO "public"."okved_2" VALUES ('01.49.31', '01.49.3', 'A', 'Производство грен шелкопряда', '');
INSERT INTO "public"."okved_2" VALUES ('01.27.9', '01.27', 'A', 'Выращивание прочих культур для производства напитков', '');
INSERT INTO "public"."okved_2" VALUES ('01.28', '01.2', 'A', 'Выращивание специй, пряно-ароматических, эфиромасличных и лекарственных культур', 'Эта группировка включает:
- выращивание многолетних и однолетних специй и эфиромасличных культур, таких как: черный горошковый перец, красный и черный стручковый перец, мускатный орех, женьшень, виды ароматных специй, изготовленных из сушеной шелухимускатного ореха и кардамона, анис, бадьян и фенхель, корица, гвоздика, имбирь, ваниль, прочие специи и эфиромасличные культуры;
- выращивание культур, содержащих лекарственные и наркотические вещества');
INSERT INTO "public"."okved_2" VALUES ('01.28.1', '01.28', 'A', 'Выращивание пряностей', '');
INSERT INTO "public"."okved_2" VALUES ('01.28.2', '01.28', 'A', 'Выращивание хмеля', '');
INSERT INTO "public"."okved_2" VALUES ('01.28.3', '01.28', 'A', 'Выращивание растений, используемых в основном в парфюмерии, фармации или в качестве инсектицидов, фунгицидов и для аналогичных целей', '');
INSERT INTO "public"."okved_2" VALUES ('01.29', '01.2', 'A', 'Выращивание прочих многолетних культур', 'Эта группировка включает:
- выращивание каучуковых деревьев для сбора латекса;
- выращивание новогодних елок;
- выращивание деревьев для извлечения сока;
- выращивание растительных материалов, используемых для плетения

Эта группировка не включает:
-выращивание цветов, производство цветов на срез и цветочных бутонов и выращивание семян цветов, см. 01.19;
- сбор древесного сока или каучукоподобных смол эвкалиптов, см. 02.30');
INSERT INTO "public"."okved_2" VALUES ('01.3', '01', 'A', 'Выращивание рассады', '');
INSERT INTO "public"."okved_2" VALUES ('01.30', '01.3', 'A', 'Выращивание рассады', 'Эта группировка включает:
- производство всех растительных посадочных материалов, включая черенки, побеги и сеянцы для непосредственного выращивания растений или для создания запаса растительного пересадочного материала

Эта группировка также включает:
- выращивание растений для посадки;
- выращивание рассады растений для декоративных целей, включая выращивание дерна для пересадки;
- выращивание растений для получения луковиц, клубней и корней, отростков и саженцев;
- уход и обработку деревьев, за исключением ухода за лесными насаждениями

Эта группировка не включает:
- выращивание растений для получения семян, см. 01.1, 01.2;
- деятельность лесопитомников, см. 02.10');
INSERT INTO "public"."okved_2" VALUES ('01.4', '01', 'A', 'Животноводство', 'Эта группировка включает:
- выращивание и разведение всех видов животных, кроме водных

Эта группировка не включает:
- содержание сельскохозяйственных животных и уход за ними, см. 01.62;
- обработку кож и шкур на бойнях, см. 10.11');
INSERT INTO "public"."okved_2" VALUES ('01.41', '01.4', 'A', 'Разведение молочного крупного рогатого скота, производство сырого молока', 'Эта группировка включает:
- выращивание и разведение молочного крупного рогатого скота;
- разведение племенного молочного крупного рогатого скота;
- производство сырого коровьего и сырого молока прочего крупного рогатого скота (буйволов, яков, зебу)

Эта группировка не включает:
- переработку молока, см. 10.51');
INSERT INTO "public"."okved_2" VALUES ('01.41.1', '01.41', 'A', 'Разведение молочного крупного рогатого скота', '');
