INSERT INTO "public"."okved_2" VALUES ('01.41.2', '01.41', 'A', 'Производство сырого коровьего молока и сырого молока прочего крупного рогатого скота (буйволов, яков и др.)', '');
INSERT INTO "public"."okved_2" VALUES ('01.41.21', '01.41.2', 'A', 'Производство сырого коровьего молока', '');
INSERT INTO "public"."okved_2" VALUES ('01.41.29', '01.41.2', 'A', 'Производство сырого молока прочего крупного рогатого скота (буйволов, яков и др.)', '');
INSERT INTO "public"."okved_2" VALUES ('01.42', '01.4', 'A', 'Разведение прочих пород крупного рогатого скота и буйволов, производство спермы', 'Эта группировка включает:
- выращивание и разведение крупного рогатого скота (кроме молочного), буйволов, яков и др.;
- разведение племенного крупного рогатого скота (кроме молочного);
- производство бычьей спермы, а также спермы буйволов, яков и т.д.');
INSERT INTO "public"."okved_2" VALUES ('01.42.1', '01.42', 'A', 'Разведение мясного и прочего крупного рогатого скота, включая буйволов, яков и др.', '');
INSERT INTO "public"."okved_2" VALUES ('01.42.11', '01.42.1', 'A', 'Разведение мясного и прочего крупного рогатого скота, включая буйволов, яков и др., на мясо', '');
INSERT INTO "public"."okved_2" VALUES ('01.42.12', '01.42.1', 'A', 'Разведение племенного мясного и прочего крупного рогатого скота, включая буйволов, яков и др.', '');
INSERT INTO "public"."okved_2" VALUES ('01.42.2', '01.42', 'A', 'Производство бычьей спермы, а также спермы буйволов, яков и др.', '');
INSERT INTO "public"."okved_2" VALUES ('01.49.21', '01.49.2', 'A', 'Разведение кроликов, производство тонкого волоса кроликов на фермах', '');
INSERT INTO "public"."okved_2" VALUES ('01.49.22', '01.49.2', 'A', 'Разведение прочих пушных зверей на фермах', '');
INSERT INTO "public"."okved_2" VALUES ('01.49.3', '01.49', 'A', 'Разведение шелкопряда', '');
INSERT INTO "public"."okved_2" VALUES ('01.43', '01.4', 'A', 'Разведение лошадей и прочих животных семейства лошадиных отряда непарнокопытных', 'Эта группировка включает:
- выращивание и разведение лошадей, ослов, мулов, лошаков;
- производство сырого кобыльего молока;
- производство спермы жеребцов и ослов

Эта группировка не включает:
- содержание скаковых и беговых лошадей в конюшнях, школах верховой езды, см. 93.19');
INSERT INTO "public"."okved_2" VALUES ('01.43.1', '01.43', 'A', 'Разведение лошадей, ослов, мулов, лошаков', '');
INSERT INTO "public"."okved_2" VALUES ('01.43.2', '01.43', 'A', 'Производство сырого кобыльего молока', '');
INSERT INTO "public"."okved_2" VALUES ('01.43.3', '01.43', 'A', 'Производство спермы жеребцов и ослов', '');
INSERT INTO "public"."okved_2" VALUES ('01.44', '01.4', 'A', 'Разведение верблюдов и прочих животных семейства верблюжьих', 'Эта группировка включает:
- выращивание и разведение верблюдов (одногорбых верблюдов) и прочих животных семейства верблюжьих;
- производство сырого верблюжьего молока');
INSERT INTO "public"."okved_2" VALUES ('01.45', '01.4', 'A', 'Разведение овец и коз', 'Эта группировка включает:
- выращивание и разведение овец и коз;
- производство сырого овечьего и козьего молока;
- производство сырой (немытой) шерсти и волоса козы;
- производство спермы баранов и козлов

Эта группировка не включает:
- предоставление услуг по стрижке овец за отдельную плату или на договорной основе, см. 01.62;
- производство щипаной шерсти, см. 10.11;
- переработку молока, см. 10.51');
INSERT INTO "public"."okved_2" VALUES ('01.45.1', '01.45', 'A', 'Разведение овец и коз', '');
INSERT INTO "public"."okved_2" VALUES ('01.45.2', '01.45', 'A', 'Производство сырого овечьего и козьего молока', '');
INSERT INTO "public"."okved_2" VALUES ('01.45.3', '01.45', 'A', 'Производство сырой (немытой) шерсти и волоса козы', '');
INSERT INTO "public"."okved_2" VALUES ('01.45.4', '01.45', 'A', 'Разведение племенных овец и коз', '');
INSERT INTO "public"."okved_2" VALUES ('01.46', '01.4', 'A', 'Разведение свиней', '');
INSERT INTO "public"."okved_2" VALUES ('01.46.1', '01.46', 'A', 'Выращивание и разведение свиней', '');
INSERT INTO "public"."okved_2" VALUES ('01.46.11', '01.46.1', 'A', 'Выращивание свиней на мясо', '');
INSERT INTO "public"."okved_2" VALUES ('01.46.12', '01.46.1', 'A', 'Разведение племенного поголовья свиней', '');
INSERT INTO "public"."okved_2" VALUES ('01.46.2', '01.46', 'A', 'Производство спермы хряков', '');
INSERT INTO "public"."okved_2" VALUES ('01.47', '01.4', 'A', 'Разведение сельскохозяйственной птицы', 'Эта группировка включает:
- выращивание и разведение сельскохозяйственной птицы: кур, индеек, уток, гусей и цесарок;
- производство яиц сельскохозяйственной птицы;
- деятельность инкубаторов для птицеводства

Эта группировка не включает:
- производство пера и пуха, см. 10.12');
INSERT INTO "public"."okved_2" VALUES ('01.47.1', '01.47', 'A', 'Выращивание и разведение сельскохозяйственной птицы: кур, индеек, уток, гусей и цесарок', '');
INSERT INTO "public"."okved_2" VALUES ('01.47.11', '01.47.1', 'A', 'Выращивание сельскохозяйственной птицы на мясо', '');
INSERT INTO "public"."okved_2" VALUES ('01.47.12', '01.47.1', 'A', 'Разведение племенной сельскохозяйственной птицы', '');
INSERT INTO "public"."okved_2" VALUES ('01.47.2', '01.47', 'A', 'Производство яиц сельскохозяйственной птицы', '');
INSERT INTO "public"."okved_2" VALUES ('01.47.3', '01.47', 'A', 'Деятельность инкубаторов для птицеводства', '');
INSERT INTO "public"."okved_2" VALUES ('01.49', '01.4', 'A', 'Разведение прочих животных', 'Эта группировка включает:
- выращивание и разведение полуодомашненных и прочих животных, таких как: страусы, прочая птица (кроме сельскохозяйственной), насекомые, кролики и прочие пушные звери на фермах;
- производство пушнины, производство тонкого волоса кроликов, кожи пресмыкающихся и птиц на ферме;
- разведение дождевых червей, земляных моллюсков, улиток и т. д. на фермах;
- разведение шелковичных червей, производство коконов шелковичного червя;
- пчеловодство и производство меда и воска;
- выращивание и разведение домашних животных (кроме рыбы), таких как: кошки и собаки, птицы, такие как длиннохвостые попугаи и т. д., хомяки и т. д.;
- разведение прочих животных

Эта группировка не включает:
- производство шкур и кож, получаемых в результате охоты или отлова и отстрела животных, см. 01.70;
- разведение лягушек, крокодилов, морских червей на фермах, см. 03.21, 03.22;
- разведение рыбы на фермах, см. 03.21, 03.22;
- содержание и дрессировку домашних животных, см. 96.09;
- выращиваниеи разведение сельскохозяйственной птицы, см. 01.47');
INSERT INTO "public"."okved_2" VALUES ('01.49.1', '01.49', 'A', 'Пчеловодство', 'Эта группировка включает:
- разведение, содержание медоносных пчел, их использование для опыления сельскохозяйственных энтомофильных растений, получения продуктов пчеловодства');
INSERT INTO "public"."okved_2" VALUES ('01.49.11', '01.49.1', 'A', 'Пчеловодство медового направления', 'Эта группировка включает:
- пчеловодство, специализированное на производстве меда');
INSERT INTO "public"."okved_2" VALUES ('01.49.12', '01.49.1', 'A', 'Пчеловодство опылительного направления', 'Эта группировка включает:
- пчеловодство, специализированное на опылении энтомофильных сельскохозяйственных культур');
INSERT INTO "public"."okved_2" VALUES ('01.49.13', '01.49.1', 'A', 'Пчеловодство разведенческого направления', 'Эта группировка включает:
- пчеловодство, специализированное на производстве пчелиных маток и пчелиных семей');
INSERT INTO "public"."okved_2" VALUES ('01.49.2', '01.49', 'A', 'Разведение кроликов и прочих пушных зверей на фермах', '');
INSERT INTO "public"."okved_2" VALUES ('01.49.32', '01.49.3', 'A', 'Производство коконов шелкопряда', '');
INSERT INTO "public"."okved_2" VALUES ('01.49.4', '01.49', 'A', 'Разведение оленей', 'Эта группировка включает:
- выращивание и разведение оленей;
- производство сырых и консервированных пантов на фермах');
INSERT INTO "public"."okved_2" VALUES ('01.49.41', '01.49.4', 'A', 'Разведение домашних северных оленей', '');
INSERT INTO "public"."okved_2" VALUES ('01.49.42', '01.49.4', 'A', 'Разведение пятнистых оленей, ланей', '');
INSERT INTO "public"."okved_2" VALUES ('01.49.43', '01.49.4', 'A', 'Разведение благородных оленей (европейских, кавказских, маралов, изюбрей)', '');
INSERT INTO "public"."okved_2" VALUES ('01.49.44', '01.49.4', 'A', 'Производство пантов северных оленей, пятнистых оленей, благородных оленей (европейских, кавказских, маралов, изюбрей), ланей', '');
INSERT INTO "public"."okved_2" VALUES ('01.49.5', '01.49', 'A', 'Разведение домашних животных', '');
INSERT INTO "public"."okved_2" VALUES ('01.49.6', '01.49', 'A', 'Разведение лабораторных животных', '');
INSERT INTO "public"."okved_2" VALUES ('01.49.7', '01.49', 'A', 'Разведение дождевых червей', '');
INSERT INTO "public"."okved_2" VALUES ('01.49.9', '01.49', 'A', 'Разведение прочих животных, не включенных в другие группировки', '');
INSERT INTO "public"."okved_2" VALUES ('01.5', '01', 'A', 'Смешанное сельское хозяйство', '');
INSERT INTO "public"."okved_2" VALUES ('01.50', '01.5', 'A', 'Смешанное сельское хозяйство', 'Эта группировка включает:
- растениеводство в сочетании с животноводством без специализированного производства культур или животных
Размер сельскохозяйственной деятельности не является определяющим фактором. Если валовая прибыль от растениеводства или животноводства составляет 66% и более от стандартной валовой прибыли, смешанная сельскохозяйственная деятельность должна быть включена в растениеводство или животноводство

Эта группировка не включает:
- смешанное растениеводство, см. 01.1 и 01.2;
-смешанное животноводство, см. 01.4');
INSERT INTO "public"."okved_2" VALUES ('01.6', '01', 'A', 'Деятельность вспомогательная в области производства сельскохозяйственных культур и послеуборочной обработки сельхозпродукции', 'Эта группировка включает:
- вспомогательные виды деятельности для сельскохозяйственного производства, а также, близкие сельскому хозяйству, не используемые в целях производства, произведенные за вознаграждение или на договорной основе
Эта группировкатакже включает:
- деятельность, осуществляемую после сбора урожая, направленную на подготовку сельскохозяйственной продукции к сбыту на рынке');
INSERT INTO "public"."okved_2" VALUES ('01.61', '01.6', 'A', 'Предоставление услуг в области растениеводства', 'Эта группировка включает:
- деятельность в области растениеводства за вознаграждение или на договорной основе, такую как подготовка полей, посев сельскохозяйственных культур, возделывание и выращивание сельскохозяйственных культур, опрыскивание сельскохозяйственных культур, в том числе с воздуха;
- обрезку фруктовых деревьев и виноградной лозы;
- пересаживание риса, рассаживание свеклы;
- уборку урожая;
- защиту растений от сельскохозяйственных вредителей (включая кроликов);
защиту садов, огородов и зеленых насаждений от вредителей и болезней по индивидуальному заказу населения;
- поддержание сельскохозяйственных угодий в хорошем состоянии с аграрной и экологической сторон;
- эксплуатацию мелиоративных систем

Эта группировка также включает:
- предоставление сельскохозяйственных машин вместе с операторами и бригадой

Эта группировка не включает:
- деятельность, следующую за сбором урожая, см. 01.63;
- дренаж сельскохозяйственного угодья, см. 43.12;
- предоставление услуг в области садово-парковой архитектуры, см. 71.11;
- деятельность агрономов и экономистов в области сельского хозяйства, см. 74.90;
- предоставление услуг в области декоративного садоводства, озеленения, см. 81.30;
- организацию сельскохозяйственных выставок и ярмарок, см. 82.30');
INSERT INTO "public"."okved_2" VALUES ('01.62', '01.6', 'A', 'Предоставление услуг в области животноводства', 'Эта группировка включает:
- деятельность в области животноводства за вознаграждение или на договорной основе: разведение, увеличение численности и продуктивности животных, обследование состояния стада, перегонка скота, выпас скота, выбраковка сельскохозяйственной птицы, чистка курятников и т. п., искусственное осеменение животных, услуги конюшен, стрижка овец, сортировка яиц, содержание сельскохозяйственных животных и уход за ними

Эта группировка также включает:
- подковывание лошадей

Эта группировка не включает:
- предоставление места только для содержания животных, см. 68.20;
- предоставление ветеринарных услуг, см. 75.00;
- вакцинацию животных, см. 75.00;
- аренду животных (например, стада), см. 77.39;
- содержание домашних животных, см.96.09');
INSERT INTO "public"."okved_2" VALUES ('01.63', '01.6', 'A', 'Деятельность сельскохозяйственная после сбора урожая', 'Эта группировка включает:
- подготовку сельскохозяйственных культур для хранения и сбыта на рынке, т. е. очистку, обрезку, сушку, сортировку, обеззараживание;
- очистку хлопка;
- подготовку листьев табака, например сушку;
- подготовку бобов какао, например очистку;
- обработку плодов воском;
- хранение картофеля, овощей, фруктов и ягод

Эта группировка не включает:
- подготовку сельскохозяйственных продуктов производителем, см. 01.1, 01.2 или 01.3;
- улучшение качества семян после сбора урожая, см. 01.64;
- очистку и повторную сушку табака, см. 12.00;
- маркетинговую деятельность комиссионеров и кооперативных организаций, см. 46;
- оптовую торговлю сельскохозяйственным сырьем, см. 46.2');
INSERT INTO "public"."okved_2" VALUES ('07.29.21', '07.29.2', 'B', 'Добыча и обогащение никелевой руды', '');
INSERT INTO "public"."okved_2" VALUES ('07.29.22', '07.29.2', 'B', 'Добыча и обогащение кобальтовой руды', '');
INSERT INTO "public"."okved_2" VALUES ('07.29.5', '07.29', 'B', 'Добыча и обогащение свинцово-цинковой руды', '');
INSERT INTO "public"."okved_2" VALUES ('01.64', '01.6', 'A', 'Обработка семян для посадки', 'Эта группировка включает:
- всю деятельность, следующую за сбором урожая, которая нацелена на улучшение качества посадки семян при помощи удаления неурожайных материалов, неправильного размера, поврежденных механически или насекомыми, незрелых семян,вместе с уменьшением влажности семян до допустимого уровня для безопасного хранения
Эти виды деятельности включают:
- сушку, чистку, сортировку и обработку семян до сбыта

Эта группировка также включает:
- обработку генетически модифицированных семян

Эта группировка не включает:
- выращивание семян, см. 01.1 и 01.2;
- обработку семян для получения масла, см. 10.41;
- исследования, направленные на развитие и модификацию форм сельскохозяйственных культур, см. 72.11');
INSERT INTO "public"."okved_2" VALUES ('01.7', '01', 'A', 'Охота, отлов и отстрел диких животных, включая предоставление услуг в этих областях', '');
INSERT INTO "public"."okved_2" VALUES ('01.70', '01.7', 'A', 'Охота, отлов и отстрел диких животных, включая предоставление услуг в этих областях', 'Эта группировка включает:
- охоту, отлов и отстрел в коммерческих целях;
- отлов и отстрел животных для получения продуктов питания, шкур, кож или для использования в исследовательских целях, в зоопарках или в качестве домашних животных;
- производство пушнины, кожи пресмыкающихся, птиц в результате охоты или отлова животных

Эта группировка также включает:
- наземную ловлю морских млекопитающих, таких как морж и тюлень

Эта группировка не включает:
- производство пушнины, кожи пресмыкающихся, птиц в результате разведения животных на фермах, см. 01.49;
- разведение диких животных на фермах, см. 01.4;
- отлов и отстрел китов, см. 03.11;
- обработку шкур и кож на бойнях, см 10.11;
- спортивную и любительскую охоту и предоставление услуг в этихобластях, см. 93.19;
- предоставление услуг в целях популяризации охоты, отлова и отстрела диких животных, см. 94.99');
INSERT INTO "public"."okved_2" VALUES ('02', 'A', 'A', 'Лесоводство и лесозаготовки', 'Эта группировка включает:
- производство круглых лесоматериалов, а также добычу и сбор дикорастущих и не древесных лесопродуктов
Помимо производства древесины, в результате деятельности лесоводства производятся продукты, которые подвергаются небольшой обработке, такие как дрова, древесный уголь и круглые лесоматериалы, используемые в необработанной форме (например, рудничные стойки, балансы и т. п.). Такая деятельность может быть реализована в естественных или искусственно посаженных лесах

Эта группировка не включает:
- дальнейшую обработку лесоматериалов, начиная от распиловки и технологической подготовки лесоматериалов, см. 16');
INSERT INTO "public"."okved_2" VALUES ('02.1', '02', 'A', 'Лесоводство и прочая лесохозяйственная деятельность', '');
INSERT INTO "public"."okved_2" VALUES ('02.10', '02.1', 'A', 'Лесоводство и прочая лесохозяйственная деятельность', 'Эта группировка включает:
- выращивание леса: посадку, повторную посадку, пересадку саженцев, прореживание и охрану лесов и лесосек;
- выращивание поросли, балансовой древесины и леса на дрова;
- функционирование лесных питомников
Эта деятельность может быть реализована в естественных или искусственно посаженных лесах

Эта группировка не включает:
- выращивание новогодних елок, см. 01.29;
- функционирование лесных питомников, за исключением лесных деревьев, см. 01.30;
- заготовку и сбор пищевых лесных ресурсов, недревесных лесных ресурсов и лекарственных растений, см. 02.30;
- производство древесной щепы и ДСП, см. 16.10');
INSERT INTO "public"."okved_2" VALUES ('02.10.1', '02.10', 'A', 'Деятельность лесопитомников', '');
INSERT INTO "public"."okved_2" VALUES ('02.10.11', '02.10.1', 'A', 'Выращивание посадочного материала лесных растений (саженцев, сеянцев)', '');
INSERT INTO "public"."okved_2" VALUES ('02.10.19', '02.10.1', 'A', 'Выращивание прочей продукции лесопитомниками', '');
INSERT INTO "public"."okved_2" VALUES ('02.10.2', '02.10', 'A', 'Деятельность лесохозяйственная прочая', '');
INSERT INTO "public"."okved_2" VALUES ('02.2', '02', 'A', 'Лесозаготовки', '');
INSERT INTO "public"."okved_2" VALUES ('03.21.1', '03.21', 'A', 'Рыбоводство морское индустриальное', 'Индустриальная аквакультура осуществляется без использования рыбоводных участков в бассейнах, на установках с замкнутой системой водоснабжения, а также на рыбоводных участках с использованием садков и (или) других технических средств, предназначенныхдля выращивания объектов аквакультуры в искусственно созданной среде обитания');
INSERT INTO "public"."okved_2" VALUES ('03.21.2', '03.21', 'A', 'Рыбоводство морское пастбищное', 'Пастбищная аквакультура осуществляется на рыбоводных участках в отношении объектов аквакультуры, которые в ходе соответствующих работ выпускаются в водные объекты, где они обитают в состоянии естественной свободы');
INSERT INTO "public"."okved_2" VALUES ('07.29.3', '07.29', 'B', 'Добыча и обогащение алюминийсодержащего сырья (бокситов и нефелин-апатитовых руд)', '');
INSERT INTO "public"."okved_2" VALUES ('02.20', '02.2', 'A', 'Лесозаготовки', 'Эта группировка включает:
- производство круглых лесоматериалов для лесообрабатывающей промышленности;
- производство круглых лесоматериалов, используемых в необработанной форме, типа рудничных стоек, ограждений и вспомогательных столбов;
- сбор и производство лесоматериалов для энергетической промышленности;
- производство древесного угля в лесу с использованием традиционных методов Продукция, получаемая в результате этой деятельности, может иметь вид бревен или дров

Эта группировка не включает:
- выращивание новогодних елок, см. 01.29;
- выращивание леса: посадку, повторную посадку, пересадку саженцев, прореживание и охрану лесов и лесосек, см. 02.10;
- заготовку и сбор пищевых лесных ресурсов, недревесных лесных ресурсов и лекарственныхрастений, см. 02.30;
- производство древесной щепы и ДСП, см. 16.10;
- производство древесного угля с помощью дистилляции древесины, см. 20.14');
INSERT INTO "public"."okved_2" VALUES ('02.3', '02', 'A', 'Сбор и заготовка пищевых лесных ресурсов, недревесных лесных ресурсов и лекарственных растений', '');
INSERT INTO "public"."okved_2" VALUES ('02.30', '02.3', 'A', 'Сбор и заготовка пищевых лесных ресурсов, недревесных лесных ресурсов и лекарственных растений', 'Эта группировка включает:
- сбор дикорастущих материалов: грибов, трюфелей, ягод, орехов, балаты и прочих каучукообразных смол, коры пробкового дерева, шеллака (природного лака) и смол, бальзамов, растительного красителя, морской травы, желудей, конского каштана, мхов и лишайников

Эта группировка не включает:
- управление производством любого из этих продуктов (кроме выращивания пробковых деревьев), см. 01;
- выращивание грибов или трюфелей, см. 01.13;
- выращивание ягод или орехов, см. 01.25;
-сбор дров, см. 02.20;
- производство древесной щепы, см. 16.10');
INSERT INTO "public"."okved_2" VALUES ('02.30.1', '02.30', 'A', 'Сбор и заготовка пищевых лесных ресурсов', '');
INSERT INTO "public"."okved_2" VALUES ('02.30.11', '02.30.1', 'A', 'Сбор и заготовка дикорастущих грибов', '');
INSERT INTO "public"."okved_2" VALUES ('02.30.12', '02.30.1', 'A', 'Сбор и заготовка дикорастущих плодов, ягод', '');
INSERT INTO "public"."okved_2" VALUES ('02.30.13', '02.30.1', 'A', 'Сбор и заготовка дикорастущих орехов', '');
INSERT INTO "public"."okved_2" VALUES ('02.30.14', '02.30.1', 'A', 'Сбор лекарственных растений', '');
INSERT INTO "public"."okved_2" VALUES ('02.30.2', '02.30', 'A', 'Сбор и заготовка недревесных лесных ресурсов', '');
INSERT INTO "public"."okved_2" VALUES ('02.4', '02', 'A', 'Предоставление услуг в области лесоводства и лесозаготовок', '');
INSERT INTO "public"."okved_2" VALUES ('02.40', '02.4', 'A', 'Предоставление услуг в области лесоводства и лесозаготовок', 'Эта группировка включает:
- выполнение доли деятельности лесоводства за вознаграждение или на договорной основе

Эта группировка также включает:
- предоставление услуг в области лесоводства, таких как: инвентаризация лесоводства, предоставление консультационных услуг по ведению лесного хозяйства, оценка лесоматериала, реализация мер пожарной безопасности в лесах, тушение пожаров в лесах и защита лесов от вредных организмов;
- перевозку бревен в пределах леса

Эта группировка не включает:
- работулесных питомников, см. 02.10;
- осушение лесных земель, см. 43.12;
- расчистку участков под строительство, см. 43.12');
INSERT INTO "public"."okved_2" VALUES ('02.40.1', '02.40', 'A', 'Предоставление услуг в области лесоводства', '');
INSERT INTO "public"."okved_2" VALUES ('02.40.2', '02.40', 'A', 'Предоставление услуг в области лесозаготовок', '');
INSERT INTO "public"."okved_2" VALUES ('03', 'A', 'A', 'Рыболовство и рыбоводство', 'Эта группировка включает:
- рыболовство и рыбоводство, включая использование ресурсов рыболовства в морских, минерализованных или пресных водах, с целью добычи (вылова) или сбора рыбы, ракообразных, моллюсков и прочих морских организмов и продуктов (например, водорослей, жемчуга, губок и т. д.)

Эта группировка также включает:
- деятельность, которая чаще всего является частью производства за собственный счет (например, осеменение устриц для производства жемчуга)
Вспомогательные производственныеуслуги рыболовства в морской или пресной воде или рыбоводстве включены в соответствующую деятельность в сфере рыболовства или рыбоводства

Эта группировка не включает:
- строительство и восстановление судов и лодок, см. 30.1, 33.15;
- спортивно-любительскую рыбалку, см. 93.19;
- обработку рыбы, ракообразных или моллюсков на заводах, расположенных на берегу или на производственных судах, см.10.20');
INSERT INTO "public"."okved_2" VALUES ('07.21.11', '07.21.1', 'B', 'Добыча урановых руд подземным способом, включая способы подземного и кучного выщелачивания', '');
INSERT INTO "public"."okved_2" VALUES ('07.21.12', '07.21.1', 'B', 'Добыча урановых руд открытым способом, включая способ кучного выщелачивания', '');
INSERT INTO "public"."okved_2" VALUES ('07.21.2', '07.21', 'B', 'Добыча и первичное обогащение ториевых руд', '');
INSERT INTO "public"."okved_2" VALUES ('07.29.31', '07.29.3', 'B', 'Добыча алюминийсодержащего сырья подземным способом', '');
INSERT INTO "public"."okved_2" VALUES ('07.29.32', '07.29.3', 'B', 'Добыча алюминийсодержащего сырья открытым способом', '');
INSERT INTO "public"."okved_2" VALUES ('03.1', '03', 'A', 'Рыболовство', 'Эта группировка включает:
- рыболовство в открытых районах Мирового океана, т. е. деятельность в сфере добычи (вылова) и сбора водных биологических ресурсов (преобладающие - рыба, моллюски и ракообразные), включая растения океанских, прибрежных или внутренних вод для потребления человеком и для других целей, вручную или чаще различными типами устройств для добычи (вылова) и сбора водных биологических ресурсов, включая растения океанских, прибрежных или внутренних вод для потребления человеком идля других целей с помощью закидных и ставных неводов, самодельных или промышленных плавсредств
Также такие действия могут быть проведены на береговой линии приливной зоны (например, сбор моллюсков, таких как мидии и устрицы) или прибрежных сетей, сприменением или без применения специализированных орудий добычи (вылова) в прибрежных водах или водах материковой отмели

Эта группировка также включает:
- добычу (вылов) рыбы в обновляемых водоемах;
- добычу (вылов) морских млекопитающих');
INSERT INTO "public"."okved_2" VALUES ('03.11', '03.1', 'A', 'Рыболовство морское', 'Эта группировка включает:
- добычу (вылов) рыбы в коммерческих целях в открытом водном пространстве и внутренних водах, внутренних морских водах;
- добычу (вылов) морских ракообразных и моллюсков;
- добычу (вылов) китов;
- добычу (вылов) морских животных: черепах, асцидий, оболочников, морских ежей и т. п.

Эта группировка также включает:
- деятельность судов, задействованных как в морской добыче (вылове) рыбы, так и в переработке и консервировании рыбы;
- сбор прочих морских организмов и материалов: природного жемчуга, губок, кораллов и морских водорослей

Эта группировка не включает:
- добычу морских млекопитающих, кроме китов, например, моржей, тюленей, см. 01.70;
- переработку китов на производственных суднах, см. 10.11;
- переработку рыбы, ракообразных и моллюсков на производственных судах или на рыбозаводах, расположенных на берегу, см. 10.20;
- аренду туристических морских или прибрежных транспортных средств с экипажем (например, для рыболовных круизов), см. 50.10;
- рыболовный надзор, защиту и службу патрулирования, см. 84.24;
- спортивно-любительское рыболовство и предоставление услуг в этой области, см. 93.19;
- работу заповедников спортивного рыболовства, см. 93.19');
INSERT INTO "public"."okved_2" VALUES ('03.11.1', '03.11', 'A', 'Рыболовство морское промышленное', '');
INSERT INTO "public"."okved_2" VALUES ('03.11.2', '03.11', 'A', 'Рыболовство морское прибрежное', '');
INSERT INTO "public"."okved_2" VALUES ('03.11.3', '03.11', 'A', 'Рыболовство в научно-исследовательских и контрольных целях', '');
INSERT INTO "public"."okved_2" VALUES ('03.11.4', '03.11', 'A', 'Рыболовство в учебных и культурно-просветительских целях', '');
INSERT INTO "public"."okved_2" VALUES ('03.11.5', '03.11', 'A', 'Рыболовство морское в целях аквакультуры (рыбоводства)', '');
INSERT INTO "public"."okved_2" VALUES ('03.12', '03.1', 'A', 'Рыболовство пресноводное', 'Эта группировка включает:
- рыболовство на коммерческой основе на внутренних водах;
- добычу (вылов) пресноводных ракообразных и моллюсков;
- добычу (вылов) пресноводных животных

Эта группировка также включает:
- добычу (вылов) пресноводных материалов');
INSERT INTO "public"."okved_2" VALUES ('03.12.1', '03.12', 'A', 'Рыболовство пресноводное промышленное', '');
INSERT INTO "public"."okved_2" VALUES ('03.12.2', '03.12', 'A', 'Рыболовство пресноводное в целях аквакультуры (рыбоводства)', '');
INSERT INTO "public"."okved_2" VALUES ('03.12.3', '03.12', 'A', 'Рыболовство любительское и спортивное', '');
INSERT INTO "public"."okved_2" VALUES ('03.12.4', '03.12', 'A', 'Рыболовство в целях обеспечения ведения традиционного образа жизни и осуществления традиционной хозяйственной деятельности коренных малочисленных народов Севера, Сибири и Дальнего Востока Российской Федерации', '');
INSERT INTO "public"."okved_2" VALUES ('03.2', '03', 'A', 'Рыбоводство', 'Эта группировка включает:
- рыбоводство, т. е. производственный процесс, включающий выращивание или разведение водных организмов (рыб, моллюсков, ракообразных, растений, крокодилов, аллигаторов и амфибий), используя методы, нацеленные на увеличение количества особей вне естественной окружающей среды (например, поддержание, кормление и защита от хищников)
Выращивание и разведение направлено на увеличение численности молодняка и взрослых особей

Эта группировка также включает:
- индивидуальное, кооперативное или государственное владение отдельными особями с целью увеличения их численности, включая их потомство');
INSERT INTO "public"."okved_2" VALUES ('03.21', '03.2', 'A', 'Рыбоводство морское', 'Эта группировка включает:
- разведение рыбы в морской воде, включая декоративные виды морских рыб;
- производство двустворчатого моллюска (устриц, мидии и т. п.), лобстера, личинок креветок, молоди рыб и мальков;
- выращивание красной водоросли и прочих съедобных морских водорослей;
- выращивание ракообразных, двустворчатых моллюсков, прочих моллюсков и прочих водных животных в морской воде

Эта группировка также включает:
- деятельность рыбоводства в минерализованных водах;
- деятельность рыбоводства в заполненных соленой водой емкостях и резервуарах;
- работу морских рыбопитомников;
- работу ферм по разведению морских червей

Эта группировка не включает:
- выращивание лягушек, см. 03.22;
- работа заповедников для спортивно-любительского рыболовства, см. 93.19');
INSERT INTO "public"."okved_2" VALUES ('07.29.33', '07.29.3', 'B', 'Обогащение нефелин-апатитовых руд', '');
INSERT INTO "public"."okved_2" VALUES ('07.29.4', '07.29', 'B', 'Добыча руд и песков драгоценных металлов и руд редких металлов', '');
INSERT INTO "public"."okved_2" VALUES ('07.29.6', '07.29', 'B', 'Добыча и обогащение оловянной руды', '');
INSERT INTO "public"."okved_2" VALUES ('03.21.3', '03.21', 'A', 'Мелиорация рыбохозяйственная морских и минерализированных водных объектов', 'Эта группировка включает:
- мероприятия по улучшению показателей гидрологического, гидрогеохимического, экологического состояния водных объектов в целях создания условий для сохранения и рационального использования водных биоресурсов, а также обеспечения производства продукции аквакультуры в целях создания условий для сохранения и рационального использования водных биоресурсов');
INSERT INTO "public"."okved_2" VALUES ('03.21.4', '03.21', 'A', 'Воспроизводство морских биоресурсов искусственное', 'Эта группировка включает:
- добычу (вылов) водных биоресурсов в целях получения от них икры, молоки (спермы) и формирования ремонтно-маточных стад;
- выращивание с последующим выпуском молоди (личинок) водных биоресурсов в водные объекты рыбохозяйственного значения;
- отлов хищных и малоценных видов водных биоресурсов в целях предотвращения выедания молоди водных биоресурсов в местах ее выпуска');
INSERT INTO "public"."okved_2" VALUES ('03.21.5', '03.21', 'A', 'Акклиматизация морских биоресурсов', 'Эта группировка включает:
- деятельность по вселению водных биоресурсов ценных видов в водные объекты рыбохозяйственного значения и созданию их устойчивых популяций в водных объектах рыбохозяйственного значения, в которых водные биоресурсы данных видов не обитали ранее или утратили свое значение');
INSERT INTO "public"."okved_2" VALUES ('03.21.9', '03.21', 'A', 'Деятельность по морскому рыбоводству прочая', '');
INSERT INTO "public"."okved_2" VALUES ('03.22', '03.2', 'A', 'Рыбоводство пресноводное', 'Эта группировка включает:
- рыбоводство в пресной воде, включая выращивание пресноводной декоративной рыбы;
- выращивание пресноводных ракообразных, двустворчатых моллюсков, прочих моллюсков и прочих водных животных;
- работу пресноводных рыбопитомников;
- выращивание лягушек

Эта группировка не включает:
- рыбоводство в заполненных соленой водой емкостях и резервуарах, см. 03.21;
- работу заповедников для спортивно-любительского рыболовства, см. 93.19');
INSERT INTO "public"."okved_2" VALUES ('03.22.1', '03.22', 'A', 'Рыбоводство пресноводное индустриальное', 'Индустриальная аквакультура осуществляется без использования рыбоводных участков в бассейнах, на установках с замкнутой системой водоснабжения, а также на рыбоводных участках с использованием садков и (или) других технических средств, предназначенныхдля выращивания объектов аквакультуры в искусственно созданной среде обитания');
INSERT INTO "public"."okved_2" VALUES ('03.22.2', '03.22', 'A', 'Рыбоводство пресноводное пастбищное', 'Пастбищная аквакультура осуществляется на рыбоводных участках в отношении объектов аквакультуры, которые в ходе соответствующих работ выпускаются в водные объекты, где они обитают в состоянии естественной свободы');
INSERT INTO "public"."okved_2" VALUES ('03.22.3', '03.22', 'A', 'Рыбоводство прудовое', 'Прудовая аквакультура предусматривает разведение и (или) содержание, выращивание объектов аквакультуры в прудах, обводненных карьерах, а также на водных объектах, используемых в процессе функционирования мелиоративных систем, включая ирригационные системы');
INSERT INTO "public"."okved_2" VALUES ('03.22.4', '03.22', 'A', 'Мелиорация рыбохозяйственная пресноводных объектов', 'Эта группировка включает:
- мероприятия по улучшению показателей гидрологического, гидрогеохимического, экологического состояния водных объектов в целях создания условий для сохранения и рационального использования водных биоресурсов.');
INSERT INTO "public"."okved_2" VALUES ('03.22.5', '03.22', 'A', 'Воспроизводство пресноводных биоресурсов искусственное', 'Эта группировка включает:
- добычу (вылов) водных биоресурсов в целях получения от них икры, молоки (спермы) и формирования ремонтно-маточных стад;
- выращивание с последующим выпуском молоди (личинок) водных биоресурсов в водные объекты рыбохозяйственного значения;
- отлов хищных и малоценных видов водных биоресурсов в целях предотвращения выедания молоди водных биоресурсов в местах ее выпуска');
INSERT INTO "public"."okved_2" VALUES ('03.22.6', '03.22', 'A', 'Акклиматизация пресноводных биоресурсов', 'Эта группировка включает:
- деятельность по вселению водных биоресурсов ценных видов в водные объекты рыбохозяйственного значения и созданию их устойчивых популяций в водных объектах рыбохозяйственного значения, в которых водные биоресурсы данных видов не обитали ранее или утратили свое значение');
INSERT INTO "public"."okved_2" VALUES ('03.22.9', '03.22', 'A', 'Деятельность по пресноводному рыбоводству прочая', '');
INSERT INTO "public"."okved_2" VALUES ('07.29.41', '07.29.4', 'B', 'Добыча руд и песков драгоценных металлов (золота, серебра и металлов платиновой группы)', '');
INSERT INTO "public"."okved_2" VALUES ('07.29.42', '07.29.4', 'B', 'Добыча и обогащение руд редких металлов (циркония, тантала, ниобия и т. п.)', '');
INSERT INTO "public"."okved_2" VALUES ('B', '', 'B', 'ДОБЫЧА ПОЛЕЗНЫХ ИСКОПАЕМЫХ', 'Данный раздел включает:
- добычу полезных ископаемых, встречающихся в природе в виде твердых пород (уголь и руда), в жидком состоянии (нефть) или в газообразном состоянии (природный газ)
Добыча может осуществляться различными методами, такими как подземная или открытая разработка месторождений, бурение скважин, разработка морского дна и т. д.
Данный раздел также включает:
- дополнительные виды деятельности с целью подготовки сырья к реализации: дробление, измельчение, очистка, просушка, сортировка, обогащение руды, обогащение угля, сжижение природного газа и агломерация твердого топлива
Перечисленные виды работ обычно выполняются хозяйствующими субъектами, которые сами занимаются добычей полезных ископаемых и/или расположены в районе добычиполезных ископаемых. Добыча полезных ископаемых классифицируется в группировках по виду основного добываемого минерального сырья
Группировки 05 и 06 включают:
- добычу топливно-энергетических полезных ископаемых (каменного угля, бурого угля
(лигнита), нефти, газа);
Группировки 07 и 08 включают:
- добычу металлических руд, различных минералов и нерудных полезных ископаемых
Некоторые технологические процессы, относящиеся к данному разделу, в частности процессы, связанные с добычей углеводородов,могут также осуществляться специализированными предприятиями по заказу третьих сторон в качестве производственных услуг, описанных в группировке 09
Этот раздел не включает:
- переработку извлеченных/добытых полезных ископаемых, см. раздел C (Обрабатывающие производства);
- использование извлеченных материалов без дальнейшей обработки в строительных целях, см. раздел F (Строительство);
- розлив в бутылки ключевой и минеральной воды из источников и скважин, см. 11.07;
- дробление, измельчение и другие виды обработки некоторых грунтов, горных пород и минералов, не связанные с операциями по добыче полезных ископаемых, см. 23.9');
INSERT INTO "public"."okved_2" VALUES ('05', 'B', 'B', 'Добыча угля', 'Эта группировка включает:
- добычу твердого минерального топлива подземным или открытым способом и виды работ (например, гранулирование, очистку, прессовку и прочие операции, необходимые для перевозки добываемого сырья и т. д.) для получения продукции, пригодной для сбыта

Эта группировка не включает:
- коксование, см. 19.10;
- услуги, сопутствующие добыче угля или бурого угля (лигнита), см. 09.90');
INSERT INTO "public"."okved_2" VALUES ('05.1', '05', 'B', 'Добыча и обогащение угля и антрацита', '');
INSERT INTO "public"."okved_2" VALUES ('05.10', '05.1', 'B', 'Добыча и обогащение угля и антрацита', 'Эта группировка включает:
- добычу угля: добычу подземным или открытым способом;
- обогащение, классификацию, грохочение, измельчение, прессование и т. д. угля для улучшения его качества, облегчения перевозки или хранения

Эта группировка также включает:
- извлечение каменного угля из отвалов

Эта группировка не включает:
- добычу бурого угля, см. 05.20;
- торфоразработки, см. 08.92;
- вспомогательную деятельность по добыче антрацита, см. 09.90;
- пробное бурение для добычи угля, см. 09.90;
- работу коксовых печей, производящих твердое топливо, см. 19.10;
- работу, направленную на развитие угольной промышленности, см. 43.12');
