INSERT INTO "public"."okved_2" VALUES ('05.2', '05', 'B', 'Добыча и обогащение бурого угля (лигнита)', '');
INSERT INTO "public"."okved_2" VALUES ('05.20', '05.2', 'B', 'Добыча и обогащение бурого угля (лигнита)', 'Эта группировка включает:
- добычу бурого угля (лигнита) подземным или открытым способом, включая добычу путем плавления;
- промывку, просушку, дробление, прессовку бурого угля (лигнита) для улучшения качества, облегчения перевозки или хранения

Эта группировка не включает:
- добычу угля, см. 05.10;
- разработку месторождений торфа, см. 08.92;
- осуществление вспомогательной деятельности, связанной с добычей бурого угля (лигнита), см. 09.90;
- пробное бурение при добыче угля, см. 09.90;
- осуществление работ, направленных на развитие или улучшение условий подготовки для добычи угля, см. 43.12');
INSERT INTO "public"."okved_2" VALUES ('05.20.1', '05.20', 'B', 'Добыча бурого угля (лигнита)', '');
INSERT INTO "public"."okved_2" VALUES ('05.20.11', '05.20.1', 'B', 'Добыча бурого угля (лигнита) открытым способом', '');
INSERT INTO "public"."okved_2" VALUES ('05.20.12', '05.20.1', 'B', 'Добыча бурого угля (лигнита) подземным способом', '');
INSERT INTO "public"."okved_2" VALUES ('05.20.2', '05.20', 'B', 'Обогащение бурого угля (лигнита)', '');
INSERT INTO "public"."okved_2" VALUES ('07.29', '07.2', 'B', 'Добыча руд прочих цветных металлов', 'Эта группировка включает:
- добычу и подготовку руд цветных металлов, не содержащих железа: алюминия (боксита), меди, свинца, цинка, олова, марганца, хрома, никеля, кобальта, молибдена, тантала, ванадия, а также руд драгоценных металлов (золота, серебра, платины)

Эта группировка не включает:
- добычу и обработку урановой и ториевой руды, см. 07.21;
- производство оксида алюминия, см. 24.42;
- производство никелевого и медного штейна, см. 24.44, 24.45');
INSERT INTO "public"."okved_2" VALUES ('07.29.1', '07.29', 'B', 'Добыча и обогащение медной руды', '');
INSERT INTO "public"."okved_2" VALUES ('07.29.2', '07.29', 'B', 'Добыча и обогащение никелевой и кобальтовой руд', '');
INSERT INTO "public"."okved_2" VALUES ('06', 'B', 'B', 'Добыча нефти и природного газа', 'Эта группировка включает: - добычу нефти; - добычу нефтяного (попутного) газа; - добычу горючих (битуминозных) сланцев и битуминозных песков и извлечение из них нефти; - добычу природного газа и жидких углеводородов (конденсата) 
Эта группировка включ ает также: - деятельность по эксплуатации и/или разработке нефтяных и газовых месторождений Подобная деятельность может включать оснащение и оборудование скважин, эксплуатацию промысловых сепараторов, деэмульгаторов, илоотделителей, нефтепромысловых трубопроводов и все прочие виды деятельности по подготовке нефти или газа, для перевозки от места их добычи до пункта отгрузки (поставки) 
Эта группировка не включает: - услуги по добыче нефти и газа за вознаграждение или на контрактной основе, см. 09 .10; - поисково-разведочные работы на нефтяных и газовых скважинах, см. 09.10; - разведочное бурение, см. 09.10; - очистку нефтепродуктов, см. 19.20; - разведку нефтяных месторождений и другие геофизические, геологические и сейсмические исследования, см. 71.12');
INSERT INTO "public"."okved_2" VALUES ('06.1', '06', 'B', 'Добыча нефти и нефтяного (попутного) газа', 'Добыча нефти и нефтяного (попутного) газа');
INSERT INTO "public"."okved_2" VALUES ('06.10', '06.1', 'B', 'Добыча нефти и нефтяного (попутного) газа', 'Эта группировка включает: - добычу нефти 
Эта группировка также включает: - добычу нефтяного (попутного) газа; - добычу горючих (битуминозных) или нефтяных сланцев и битуминозного песка; - производство нефти из горючих (битуминозных) сланцев и песка; - процессы получения нефти: декантацию, опреснение, дегидрацию, стабилизацию и т.п. 
Эта группировка не включает: - предоставление услуг по добыче нефти и природного газа, см. 09.10; - разведку нефтяных и газовых месторождений, см. 09.10; - производст во очищенных нефтепродуктов, см. 19.20; - получение сжиженных газов при очистке нефти, см. 19.20; - эксплуатацию нефтепроводов, см. 49.50');
INSERT INTO "public"."okved_2" VALUES ('06.10.1', '06.10', 'B', 'Добыча нефти', 'Добыча нефти');
INSERT INTO "public"."okved_2" VALUES ('06.10.2', '06.10', 'B', 'Добыча горючих (битуминозных) сланцев, песка и озокерита', '');
INSERT INTO "public"."okved_2" VALUES ('06.10.3', '06.10', 'B', 'Добыча нефтяного (попутного) газа', '');
INSERT INTO "public"."okved_2" VALUES ('06.2', '06', 'B', 'Добыча природного газа и газового конденсата', '');
INSERT INTO "public"."okved_2" VALUES ('06.20', '06.2', 'B', 'Добыча природного газа и газового конденсата', 'Эта группировка включает:
- добычу, обезвоживание и сепарацию фракций жидких углеводородов;
- извлечение метана, этана, бутана и пропана на месте добычи;
- извлечение гелия и сероводорода;
- производство сырого газообразного углеводорода (природногогаза);
- добычу конденсатов;
- дренаж и выделение жидких фракций углеводорода;
- десульфурацию газа

Эта группировка также включает:
- добычу жидкого углеводорода путем сжижения или пиролиза');
INSERT INTO "public"."okved_2" VALUES ('06.20.1', '06.20', 'B', 'Добыча природного газа', '');
INSERT INTO "public"."okved_2" VALUES ('06.20.2', '06.20', 'B', 'Добыча газового конденсата', '');
INSERT INTO "public"."okved_2" VALUES ('07', 'B', 'B', 'Добыча металлических руд', 'Эта группировка включает:
- добычу металлических полезных ископаемых (руды) подземным и открытым способом и с морского дна

Эта группировка также включает:
- обогащение и очистку руды, например, дробление, измельчение, промывка, просушка, спекание, прокаливание или выщелачивание, операции гравитационного разделения или флотации

Эта группировка не включает:
- обжиг железного колчедана, см. 20.13;
- производство оксида алюминия, см. 24.42;
- обеспечение работы доменных печей, см. 24');
INSERT INTO "public"."okved_2" VALUES ('07.1', '07', 'B', 'Добыча и обогащение железных руд', '');
INSERT INTO "public"."okved_2" VALUES ('07.10', '07.1', 'B', 'Добыча и обогащение железных руд', 'Эта группировка включает:
- добычу руд преимущественно с содержанием в них железа;
- обогащение и агломерацию железных руд

Эта группировка не включает:
- добычу и обогащение серного и магнитного колчедана (кроме обжига), см. 08.91');
INSERT INTO "public"."okved_2" VALUES ('07.10.1', '07.10', 'B', 'Добыча железных руд подземным способом', '');
INSERT INTO "public"."okved_2" VALUES ('07.10.2', '07.10', 'B', 'Добыча железных руд открытым способом', '');
INSERT INTO "public"."okved_2" VALUES ('07.10.3', '07.10', 'B', 'Обогащение и агломерация железных руд', '');
INSERT INTO "public"."okved_2" VALUES ('07.2', '07', 'B', 'Добыча руд цветных металлов', 'Эта группировка включает:
- добычу руд цветных металлов');
INSERT INTO "public"."okved_2" VALUES ('07.21', '07.2', 'B', 'Добыча урановой и ториевой руд', 'Эта группировка включает:
- добычу урановой и ториевой руд, преимущественно, с содержанием в них урана и тория:
уранинита и т. п.;
- первичное обогащение таких руд;
- производство желтого кека (концентрата урана)

Эта группировка не включает:
- обогащение урановой и ториевой руд, см. 20.13;
- производство металлического урана из уранинита или прочих руд, см. 24.46;
- плавку и рафинирование урана, см. 24.46');
INSERT INTO "public"."okved_2" VALUES ('07.21.1', '07.21', 'B', 'Добыча и первичное обогащение урановых руд', '');
