INSERT INTO "public"."okved_2" VALUES ('07.29.99', '07.29.9', 'B', 'Добыча и обогащение руд прочих цветных металлов, не включенных в другие группировки', '');
INSERT INTO "public"."okved_2" VALUES ('08', 'B', 'B', 'Добыча прочих полезных ископаемых', 'Эта группировка включает:
- добычу ископаемых из карьеров, а также разработку аллювиальных отложений, скальных пород, соляных месторождений
Получаемые продукты используются главным образом в строительстве (например, песок, камень и т. п.), в производстве строительных материалов (например, глины, гипса и т. п.), в производстве химикатов и т. п.

Эта группировка не включает:
- процессы обработки (кроме дробления, измельчения, обогащения, сушки, сортировки и смешивания) добываемых полезных ископаемых, см. раздел С');
INSERT INTO "public"."okved_2" VALUES ('08.1', '08', 'B', 'Добыча камня, песка и глины', '');
INSERT INTO "public"."okved_2" VALUES ('08.11', '08.1', 'B', 'Добыча декоративного и строительного камня, известняка, гипса, мела и сланцев', 'Эта группировка включает:
- добычу, первичную обработку, распиловку камня для строительства и изготовления памятников, такого как мрамор, гранит, песчаник и т. д.;
- дробление и измельчение декоративного и строительного камня;
- добычу, дробление и измельчение известняка;
- добычу гипса и ангидрита;
- добычу мела и некальцинированного доломита

Эта группировка не включает:
- добычу минерального сырья для химических производств и производства удобрений, см. 08.91;
- производство обожженного (кальцинированного) доломита, см. 23.52;
- резку, обработку и отделку камня за пределами карьеров, см. 23.70');
