INSERT INTO "public"."okved_2" VALUES ('09', 'B', 'B', 'Предоставление услуг в области добычи полезных ископаемых', 'Эта группировка включает:
- специализированные вспомогательные услуги при разработке месторождений за вознаграждение или на договорной основе
В эту группировку входят:
- поисково-изыскательские работы с использованием традиционных методов разведки, например взятие образцов руды и проведение геологических наблюдений, а также бурение (пробное или повторное);
- бурение для нефтяных скважин, металлических и неметаллических полезных ископаемых
- прочие услуги по бурению нефтяных и газовых скважин и их обустройству: установка нефтяных и газовых скважин, цементирование корпуса газовой скважины, очистка, тартание и свабирование нефтяных и газовых скважин, установка систем вентиляции и откачки и услуги по промышленному строительству объектов обустройства месторождений, включая строительство нефтесборных сетей, водоводов, объектов энергетического хозяйства, площадочных объектов и т. д.');
INSERT INTO "public"."okved_2" VALUES ('09.1', '09', 'B', 'Предоставление услуг в области добычи нефти и природного газа', '');
INSERT INTO "public"."okved_2" VALUES ('09.10', '09.1', 'B', 'Предоставление услуг в области добычи нефти и природного газа', 'Эта группировка включает: - предоставление услуг в части добычи нефти и газа за вознаграждение или на договорной основе, в том числе: - проведение наземных маршрутов геологического содержания при геологической съемке, геологическом доизучении ранее заснятых площадей, комплексной съемке, гидрогеологическом доизучении ранее заснятых площадей, поисках и поисково-оценочных работах, работах общего назначения; - отбор и обработка проб горных пород и полезных ископаемых; - проведение геохимических раб от; - проведение гидрогеологических работ; - проведение геоэкологических работ; - проведение полевых сейсморазведочных работ; - проведение работ с применением методов электроразведки; - проведение работ с применением методов гравиразведки и магнитора зведки; - проведение аэрогеофизических работ; - проведение геофизических исследований скважин на нефть и газ; - проведение работ по бурению глубоких скважин различных категорий, включая опорные, параметрические, поисково-оценочные и разведочные, на у глеводородное сырье; - проходка поверхностных и подземных горных выработок; - проведение морских геолого-геофизических работ; - проведение инженерно-геологических работ; - проведение лабораторных работ; -проведение топогеодезических работ; - направл енное бурение и повторное бурение, ударное бурение, монтаж буровой установки на месте, ремонт и демонтаж, цементирование обсадных труб нефтяных и газовых скважин, откачка скважин, заглушка и консервация скважин и т.д.; - сжижение и обогащение природн ого газа на месте добычи для последующей перевозки; - услуги по дренажу и откачке воды за вознаграждение или на договорной основе, пробное бурение на месте предполагаемой добычи нефти или газа 
Эта группировка также включает: - противопожарные услуги на месторождениях нефти и газа');
