INSERT INTO "public"."okved_2" VALUES ('13.20.43', '13.20.4', 'C', 'Производство прочих махровых полотенечных и аналогичных махровых тканей', '');
INSERT INTO "public"."okved_2" VALUES ('13.20.44', '13.20.4', 'C', 'Производство марли', '');
INSERT INTO "public"."okved_2" VALUES ('13.20.45', '13.20.4', 'C', 'Производство ворсовых тканей', '');
INSERT INTO "public"."okved_2" VALUES ('13.20.46', '13.20.4', 'C', 'Производство тканей из стекловолокна', '');
INSERT INTO "public"."okved_2" VALUES ('13.20.5', '13.20', 'C', 'Производство искусственного меха ткацким способом', '');
INSERT INTO "public"."okved_2" VALUES ('13.20.6', '13.20', 'C', 'Производство арамидных нитей и волокна', '');
INSERT INTO "public"."okved_2" VALUES ('13.3', '13', 'C', 'Отделка тканей и текстильных изделий', '');
INSERT INTO "public"."okved_2" VALUES ('13.30', '13.3', 'C', 'Отделка тканей и текстильных изделий', 'Эта группировка включает:
- конечную обработку текстиля и одежды, т. е. отбеливание, окрашивание, отделку и прочие действия;
- отбеливание и окрашивание текстиля, волокон, тканей и текстильных изделий, включая готовую одежду;
- аппретирование, сушку,обработку паром, декатировку, противоусадочную отделку, смягчение тканей и текстильных изделий, включая готовую одежду

Эта группировка также включает:
- отбеливание джинсов;
- плиссировочные и подобные работы на текстильных материалах;
- нанесение водозащитного слоя, специальных покрытий, прорезинивание, пропитку приобретенной одежды;
- нанесение рисунка на текстильные изделия и готовую одежду');
INSERT INTO "public"."okved_2" VALUES ('13.30.2', '13.30', 'C', 'Аппретирование, сушка, обработка паром, декатировка, противоусадочная отделка, смягчение тканей и текстильных изделий, включая готовую одежду', '');
INSERT INTO "public"."okved_2" VALUES ('13.30.3', '13.30', 'C', 'Плиссировка и подобные работы на текстильных материалах', '');
INSERT INTO "public"."okved_2" VALUES ('13.30.4', '13.30', 'C', 'Нанесение водозащитного слоя, специальных покрытий, прорезинивание, пропитка приобретенной одежды', '');
INSERT INTO "public"."okved_2" VALUES ('13.30.5', '13.30', 'C', 'Нанесение рисунка на текстильные изделия и готовую одежду', '');
INSERT INTO "public"."okved_2" VALUES ('13.9', '13', 'C', 'Производство прочих текстильных изделий', 'Эта группировка включает:
- производство текстильных изделий, за исключением готовой одежды, таких как искусственные текстильные изделия, ковры и коврики, веревки, узкие ткани, отделка и т. п.');
INSERT INTO "public"."okved_2" VALUES ('13.91', '13.9', 'C', 'Производство трикотажного и вязаного полотна', 'Эта группировка включает:
- производство и обработку трикотажного или вязаного полотна: ворсового и махрового полотна; сетчатого и гардинно-тюлевого полотна, изготовленного на рашель-машинах и подобных машинах; прочего трикотажного или вязаного полотна

Эта группировка также включает:
- производство искусственного меха методом вязания');
INSERT INTO "public"."okved_2" VALUES ('13.91.1', '13.91', 'C', 'Производство и обработка трикотажного или вязаного полотна', '');
INSERT INTO "public"."okved_2" VALUES ('13.91.2', '13.91', 'C', 'Производство искусственного меха методом вязания', '');
INSERT INTO "public"."okved_2" VALUES ('13.92', '13.9', 'C', 'Производство готовых текстильных изделий, кроме одежды', 'Эта группировка включает:
- производство готовых изделий из любого текстильного материала, в том числе из трикотажного полотна: одеял, в том числе дорожных пледов; белья для кухонь, ванной, постельного и столового белья; ватных и пуховых стеганых одеял, подушек, в том числе диванных подушек, пуфов, спальных мешков и т.п.;
- производство готовых изделий хозяйственно- бытового и другого назначения, кроме специального назначения: гардин, портьер, штор, постельных покрывал, чехлов для мебели и машини т.п.;
- производство брезентов, палаток, снаряжения для кемпингов, парусов, солнцезащитных жалюзи, чехлов для автомобилей и т.п., флагов, знамен, вымпелов;
- производство тряпок для удаления пыли, мочалок и подобных изделий;
- производство бронежилетов, спасательных жилетов, парашютов и т.п.;
- пошив готовых текстильных изделий, кроме одежды по индивидуальному заказу населения

Эта группировка также включает:
- производство текстильных частей электроодеял;
- производство гобеленов ручной работы;
- производство изделий из искусственного меха

Эта группировка не включает:
- производство кружевного сетчатого и гардинно- тюлевого полотна, изготовленного на рашель- машинах и подобных машинах, см. 13.99;
- производство вязаной и трикотажной одежды, см. 14.39');
INSERT INTO "public"."okved_2" VALUES ('13.93', '13.9', 'C', 'Производство ковров и ковровых изделий', 'Эта группировка включает:
- производство текстильных изделий, в том числе напольных покрытий из тканого войлока: ковров, ковровых изделий, матов, ковриков, в том числе ручной работы

Эта группировка также включает:
- производство войлочных половых покрытий на рапирном лентоткацком станке');
INSERT INTO "public"."okved_2" VALUES ('13.94', '13.9', 'C', 'Производство канатов, веревок, шпагата и сетей', 'Эта группировка включает:
- производство шпагата, канатов, веревок и тросов из текстильных волокон и лент, с пропиткой и без пропитки, с покрытием, защищенных или не защищенных оболочкой из резины или пластмассы;
- производство сетей из шпагата, канатов и веревки;
- производство изделий из веревки и сетного полотна: рыболовных сетей, предохранительных сеток на судах, защитных средств, используемых при погрузочно-разгрузочных работах, стропов, веревок или тросов с металлическими кольцами и т. п.

Эта группировка не включает:
- производство сеток для волос, см. 14.19;
- производство проволочных канатов, см. 25.93;
- производство сетей для спортивной рыбалки, см. 32.30');
INSERT INTO "public"."okved_2" VALUES ('13.94.1', '13.94', 'C', 'Производство шпагата, канатов, веревок и тросов из текстильных волокон и лент, с пропиткой и без пропитки, с покрытием, защищенных или не защищенных оболочкой из резины или пластмассы', '');
INSERT INTO "public"."okved_2" VALUES ('13.94.2', '13.94', 'C', 'Производство изделий из веревки и сетного полотна: рыболовных сетей, предохранительных сеток на судах, защитных средств, используемых при погрузочно-разгрузочных работах, стропов, веревок или тросов с металлическими кольцами', '');
INSERT INTO "public"."okved_2" VALUES ('13.95', '13.9', 'C', 'Производство нетканых текстильных материалов и изделий из них, кроме одежды', 'Эта группировка включает:
- все виды работ, связанных с производством текстиля и текстильной продукции, не включенные в группировки 13 или 14, которые описывают большое количество процессов обработки и большой ассортимент продукции, в том числе производство нетканых материалов и нетканых ватинов');
INSERT INTO "public"."okved_2" VALUES ('14.12', '14.1', 'C', 'Производство спецодежды', 'Эта группировка включает:
- производство рабочей и специальной одежды, в том числе комплектов, курток, блейзеров, брюк, комбинезонов, фартуков, жилетов, халатов;
- пошив производственной одежды по индивидуальному заказу населения

Эта группировка не включает:
- производство обуви, см. 15.20;
- производство огнеустойчивой и защитной одежды, см. 32.99;
- ремонт одежды, см. 95.29');
INSERT INTO "public"."okved_2" VALUES ('14.19.13', '14.19.1', 'C', 'Производство трикотажных или вязаных перчаток, рукавиц (варежек) и митенок', '');
INSERT INTO "public"."okved_2" VALUES ('13.96', '13.9', 'C', 'Производство прочих технических и промышленных текстильных изделий', 'Эта группировка включает:
- производство узких тканей, в том числе состоящих из основы безуточного переплетения и соединяемых клеящим веществом;
- производство этикеток, эмблем и т. п.;
- производство декоративных аксессуаров: шнуров, тесьмы, кистей,помпонов и т. д.;
- производство пропитанных, окрашенных, прорезиненных и покрытых пластиком тканей;
- производство металлизированной пряжи, резиновых нитей и текстильных веревок, текстильной пряжи или пропитанных, окрашенных, прорезиненных и покрытых пластиком шнуров;
- производство резиновой ткани из высокопрочного искусственного материала;
- производство прочих обработанных и пропитанных тканей: кальки, канвы готовой для использования художниками, холстов и подобных грубых текстильных тканей, тканей, покрытых клеем или эмульсией;
- производство разнотипных текстильных изделий: фитилей, кожухов для газовых труб;
- производство плащевой ткани, ткани для пожарных рукавов/шлангов, трансмиссионных и конвейерных ремней (усиленных и неусиленных металлическими или прочими материалами), сетчатой ткани, эластичной одежды;
- производство предметов декоративной отделки автомобиля;
- производство холстов для рисования и кальки

Эта группировка не включает:
- производство конвейерных и приводныхремней, текстильных волокон, канатов покрытых, заламинированных, прорезиненных, если резина является основным компонентом, см. 22.19;
- производство прорезиненных и пластиковых плит и листов в сочетании с текстилем для арматурных целей, см. 22.19, 22.21;
- производство тканей из металлической проволоки, см. 25.93');
INSERT INTO "public"."okved_2" VALUES ('13.96.1', '13.96', 'C', 'Производство металлизированной пряжи или металлизированной позументной тесьмы', '');
INSERT INTO "public"."okved_2" VALUES ('13.96.2', '13.96', 'C', 'Производство ткани из металлической нити и ткани из металлизированной пряжи', '');
INSERT INTO "public"."okved_2" VALUES ('13.96.3', '13.96', 'C', 'Производство резиновых нитей и шнуров с текстильным покрытием; производство текстильных нитей и лент, пропитанных или с пластмассовым или резиновым покрытием', '');
INSERT INTO "public"."okved_2" VALUES ('13.96.4', '13.96', 'C', 'Производство текстильных материалов, пропитанных или с покрытием', '');
INSERT INTO "public"."okved_2" VALUES ('13.96.5', '13.96', 'C', 'Производство кордных тканей', '');
INSERT INTO "public"."okved_2" VALUES ('13.96.6', '13.96', 'C', 'Производство текстильных материалов и изделий технического назначения (включая фитили, калильные сетки газовых фонарей, текстильные шланги, конвейерные ленты и приводные ремни, ситовые ткани и фильтровальные ткани)', '');
INSERT INTO "public"."okved_2" VALUES ('13.96.7', '13.96', 'C', 'Производство узких текстильных тканей, в том числе состоящих из основы безуточного переплетения и соединяемых клеящим веществом', '');
INSERT INTO "public"."okved_2" VALUES ('13.99', '13.9', 'C', 'Производство прочих текстильных изделий, не включенных в другие группировки', 'Эта группировка включает:
- производство фетра и войлока;
- производство кружевного сетчатого и гардинно- тюлевого полотна, а также кружев и вышитых изделий, в кусках, в форме полос или отдельных вышивок;
- производство тканей, в том числе соединяемых клеящим веществом;
- производство тканевых шнурков для обуви;
- производство набивных пуховок и перчаток;
- изготовление прочих текстильных изделий, не включенных в другие группировки по индивидуальному заказу населения

Эта группировка не включает:
- производство ворсяного покрытия на рапирном лентоткацком станке, см. 13.93;
- производство текстильного упаковочного материала и изделий из ваты, таких как: гигиенические полотенца, тампоны и т.д., см. 17.22');
INSERT INTO "public"."okved_2" VALUES ('13.99.1', '13.99', 'C', 'Производство кружевного сетчатого и гардинно-тюлевого полотна, а также кружев и вышитых изделий, в кусках, в форме полос или отдельных вышивок', '');
INSERT INTO "public"."okved_2" VALUES ('13.99.2', '13.99', 'C', 'Производство фетра и войлока', '');
INSERT INTO "public"."okved_2" VALUES ('13.99.3', '13.99', 'C', 'Производство ваты из текстильных материалов', '');
INSERT INTO "public"."okved_2" VALUES ('13.99.9', '13.99', 'C', 'Производство текстильных изделий различного назначения, не включенных в другие группировки', '');
INSERT INTO "public"."okved_2" VALUES ('14', 'C', 'C', 'Производство одежды', 'Эта группировка включает:
- все швейные изделия (готовые или сделанные по индивидуальному заказу) из всех материалов (например, из кожи, текстильных тканей, вязаных и трикотажных тканей и т. д.), все виды одежды (например, верхняя одежда, нижнее белье для мужчин, женщин или детей; рабочая, офисная или повседневная одежда и т. д.) и аксессуары
Не существует каких-либо разграничений между одеждой для взрослых и для детей или между современной и традиционной одеждой

Эта группировка также включает:
- производство кожаной одежды (меховых изделий)');
INSERT INTO "public"."okved_2" VALUES ('14.1', '14', 'C', 'Производство одежды, кроме одежды из меха', 'Эта группировка включает:
- производство готовой одежды;
- пошив одежды по индивидуальному заказу населения
Используемый материал может быть любого типа: покрыт специальными составами, пропитан или прорезинен');
INSERT INTO "public"."okved_2" VALUES ('14.11', '14.1', 'C', 'Производство одежды из кожи', 'Эта группировка включает:
- производство одежды, сделанной из кожи или имеющую кожу в составе, включая отдельные виды спецодежды, такие как кожаные фартуки для сварщиков;
- пошив одежды из натуральной и искусственной кожи, замши по индивидуальному заказу населения

Эта группировка не включает:
- производство одежды из меха, см. 14.20;
- производство спортивных кожаных перчаток и спортивных головных уборов, см. 32.30;
- производство огнеустойчивой и защитной одежды, см. 32.99');
INSERT INTO "public"."okved_2" VALUES ('14.19.12', '14.19.1', 'C', 'Производство спортивных костюмов, лыжных костюмов, купальных костюмов и прочей трикотажной или вязаной одежды', '');
INSERT INTO "public"."okved_2" VALUES ('14.13', '14.1', 'C', 'Производство прочей верхней одежды', 'Эта группировка включает:
- производство верхней одежды, изготовленной из тканей, трикотажного полотна, нетканых материалов и т. п., для мужчин, женщин и детей: пальто, костюмов, полупальто, курток, плащей, пиджаков, юбок и т. п.

Эта группировка также включает:
- индивидуальный пошив;
- производство деталей перечисленных изделий;
- производство форменной (ведомственной) одежды, униформы, одежды для церковнослужителей

Эта группировка не включает:
- производство верхней одежды из меха (кроме головных уборов), см. 14.20;
- производство одежды из резины или пластмасс не сшитой, а склеенной, см. 22.19, 22.29;
- производство огнеустойчивой и защитной одежды, см. 32.99;
- ремонт верхней одежды, см. 95.29');
INSERT INTO "public"."okved_2" VALUES ('14.13.1', '14.13', 'C', 'Производство верхней трикотажной или вязаной одежды', '');
INSERT INTO "public"."okved_2" VALUES ('14.13.11', '14.13.1', 'C', 'Производство верхней трикотажной или вязаной одежды для мужчин или мальчиков', '');
INSERT INTO "public"."okved_2" VALUES ('14.13.12', '14.13.1', 'C', 'Производство верхней трикотажной или вязаной одежды для женщин или девочек', '');
INSERT INTO "public"."okved_2" VALUES ('14.13.2', '14.13', 'C', 'Производство верхней одежды из текстильных материалов, кроме трикотажных или вязаных', '');
INSERT INTO "public"."okved_2" VALUES ('14.13.21', '14.13.2', 'C', 'Производство верхней одежды из текстильных материалов, кроме трикотажных или вязаных, для мужчин или мальчиков', '');
INSERT INTO "public"."okved_2" VALUES ('14.13.22', '14.13.2', 'C', 'Производство верхней одежды из текстильных материалов, кроме трикотажных или вязаных, для женщин или девочек', '');
INSERT INTO "public"."okved_2" VALUES ('14.14', '14.1', 'C', 'Производство нательного белья', 'Эта группировка включает:
- производство трикотажного нательного белья и белья для сна из тканых, вязаных крючком и спицами тканей, кружев и т.д. для мужчин, женщин, детей: рубашек, футболок, трусов, шорт, пижам, ночных рубашек, халатов, блузок, плавок, бюстгальтеров, корсетов и т.п.;
- пошив нательного белья, легкой одежды, корсетных изделий по индивидуальному заказу населения

Эта группировка не включает:
- ремонт одежды, см. 95.29');
INSERT INTO "public"."okved_2" VALUES ('14.14.1', '14.14', 'C', 'Производство трикотажного и вязаного нательного белья', '');
INSERT INTO "public"."okved_2" VALUES ('14.14.11', '14.14.1', 'C', 'Производство трикотажных или вязаных рубашек для мужчин или для мальчиков', '');
INSERT INTO "public"."okved_2" VALUES ('14.14.12', '14.14.1', 'C', 'Производство маек и прочего трикотажного или вязаного нательного белья для мужчин или мальчиков', '');
INSERT INTO "public"."okved_2" VALUES ('14.14.13', '14.14.1', 'C', 'Производство трикотажных или вязаных блузок, рубашек и батников для женщин или для девочек', '');
INSERT INTO "public"."okved_2" VALUES ('14.14.14', '14.14.1', 'C', 'Производство маек и прочего трикотажного или вязаного нательного белья для женщин или для девочек', '');
INSERT INTO "public"."okved_2" VALUES ('14.14.2', '14.14', 'C', 'Производство нательного белья из тканей', '');
INSERT INTO "public"."okved_2" VALUES ('14.14.21', '14.14.2', 'C', 'Производство рубашек из текстильных материалов, кроме трикотажных или вязаных, для мужчин или для мальчиков', '');
INSERT INTO "public"."okved_2" VALUES ('14.14.22', '14.14.2', 'C', 'Производство маек и прочего нательного белья из текстильных материалов, кроме трикотажных или вязаных, для мужчин или для мальчиков', '');
INSERT INTO "public"."okved_2" VALUES ('14.14.23', '14.14.2', 'C', 'Производство блузок, рубашек и батников из текстильных материалов, кроме трикотажных или вязаных, для женщин или для девочек', '');
INSERT INTO "public"."okved_2" VALUES ('14.14.24', '14.14.2', 'C', 'Производство маек и прочего нательного белья из текстильных материалов, кроме трикотажных или вязаных, для женщин или для девочек', '');
INSERT INTO "public"."okved_2" VALUES ('14.14.25', '14.14.2', 'C', 'Производство бюстгальтеров, поясов, корсетов и аналогичных изделий, и их частей из любого текстильного материала, включая трикотажные или вязаные', '');
INSERT INTO "public"."okved_2" VALUES ('14.14.3', '14.14', 'C', 'Производство трикотажных или вязаных футболок, маек и прочих нижних рубашек', '');
INSERT INTO "public"."okved_2" VALUES ('14.19', '14.1', 'C', 'Производство прочей одежды и аксессуаров одежды', 'Эта группировка включает:
- производство предметов одежды для детей младшего возраста, тренировочных костюмов, лыжных костюмов, купальных костюмов и т.п.;
- производство шляп и кепок;
- изготовление аксессуаров: перчаток, поясов, платков, ремней, шейных платков, галстуков, шарфов, сеток для волос и т.п.

Эта группировка также включает:
- производство меховых головных уборов;
- производство обуви из текстильных материалов без подошвы;
- производство деталей перечисленных изделий;
- пошив и вязаниепо индивидуальному заказу населения перечисленных изделий');
INSERT INTO "public"."okved_2" VALUES ('14.19.1', '14.19', 'C', 'Производство трикотажной или вязаной одежды для детей младшего возраста, спортивной или прочей одежды, аксессуаров и деталей одежды', '');
INSERT INTO "public"."okved_2" VALUES ('14.19.11', '14.19.1', 'C', 'Производство трикотажных или вязаных одежды и аксессуаров одежды для детей младшего возраста', '');
INSERT INTO "public"."okved_2" VALUES ('16.29.23', '16.29.2', 'C', 'Производство корзиночных и плетеных изделий', '');
INSERT INTO "public"."okved_2" VALUES ('14.19.19', '14.19.1', 'C', 'Производство прочих трикотажных или вязаных аксессуаров одежды, в том числе платков, шарфов, галстуков и прочих аналогичных изделий', '');
INSERT INTO "public"."okved_2" VALUES ('14.19.2', '14.19', 'C', 'Производство одежды для детей младшего возраста, спортивной или прочей одежды и аксессуаров одежды из текстильных материалов, кроме трикотажных или вязаных', '');
INSERT INTO "public"."okved_2" VALUES ('14.19.21', '14.19.2', 'C', 'Производство одежды и аксессуаров одежды для детей младшего возраста из текстильных материалов, кроме трикотажных или вязаных', '');
INSERT INTO "public"."okved_2" VALUES ('14.19.22', '14.19.2', 'C', 'Производство спортивных костюмов, лыжных костюмов, купальных костюмов и прочей одежды из текстильных материалов, кроме трикотажных или вязаных', '');
INSERT INTO "public"."okved_2" VALUES ('14.19.23', '14.19.2', 'C', 'Производство аксессуаров одежды, в том числе платков, шарфов, галстуков, перчаток и прочих аналогичных изделий из текстильных материалов, кроме трикотажных или вязаных', '');
INSERT INTO "public"."okved_2" VALUES ('14.19.3', '14.19', 'C', 'Производство аксессуаров одежды из кожи; производство одежды из фетра или нетканых материалов; производство одежды из текстильных материалов с покрытием', '');
INSERT INTO "public"."okved_2" VALUES ('14.19.31', '14.19.3', 'C', 'Производство аксессуаров одежды из натуральной или композиционной кожи', '');
INSERT INTO "public"."okved_2" VALUES ('14.19.32', '14.19.3', 'C', 'Производство одежды из фетра, нетканых материалов, из текстильных материалов с пропиткой или покрытием', '');
INSERT INTO "public"."okved_2" VALUES ('14.19.4', '14.19', 'C', 'Производство головных уборов', '');
INSERT INTO "public"."okved_2" VALUES ('14.2', '14', 'C', 'Производство меховых изделий', '');
INSERT INTO "public"."okved_2" VALUES ('14.20', '14.2', 'C', 'Производство меховых изделий', 'Эта группировка включает:
- производство изделий из меха: одежды из меха и ее аксессуаров, наборов из меха (например, отдельные куски меха, пластины, коврики, полосы и т.д.), различных изделий из меха: ковриков, ненабивных пуфов, промышленных тряпокдля полировки;
- пошив одежды из меха по индивидуальному заказу населения;
- пошив пристегивающихся воротников, капюшонов, манжет из натурального и искусственного меха по индивидуальному заказу населения

Эта группировка не включает:
- производство сырых меховых шкур, см. 01.4, 01.70;
- обработку сырых шкур и кож, см. 10.11;
- производство тканых и трикотажных длинноворсовых материалов, имитирующих мех, см. 13.20, 13.91;
- производство меховых головных уборов, см. 14.19;
- производство одежды с мехом, см. 14.19;
- выделку и окрашивание меха, см. 15.11;
- производство ботинок, сапог и туфель с меховыми деталями, см. 15.20');
INSERT INTO "public"."okved_2" VALUES ('14.3', '14', 'C', 'Производство вязаных и трикотажных изделий одежды', '');
INSERT INTO "public"."okved_2" VALUES ('14.31', '14.3', 'C', 'Производство вязаных и трикотажных чулочно-носочных изделий', 'Эта группировка включает:
- производство чулочно-носочных изделий, включая носки, трико и колготки;
- изготовление вязаных и трикотажных чулочно-носочных изделий по индивидуальному заказу населения');
INSERT INTO "public"."okved_2" VALUES ('14.39', '14.3', 'C', 'Производство прочих вязаных и трикотажных изделий', 'Эта группировка включает:
- производство вязаной одежды и иных изделий, которым форма придается непосредственно в процессе изготовления: джемперов, жакетов, жилетов, кардиганов, пуловеров и подобных изделий;
- изготовление прочих вязаных и трикотажных изделий

Эта группировка не включает:
- производство вязаных и трикотажных тканей, см. 13.91;
- производство чулочно- носочных изделий, см. 14.31');
INSERT INTO "public"."okved_2" VALUES ('15', 'C', 'C', 'Производство кожи и изделий из кожи', 'Эта группировка включает:
- отделку и окрашивание меха;
- переработку сырых шкур в кожу путем дубления и создание изделий из кожи, готовых к конечному потреблению

Эта группировка также включает:
- производство подобных изделий из других материалов (искусственных кож или заменителей кожи), таких как резиновая обувь, чемоданы из ткани и т. д.;
- производство изделий, изготовленных из остатков кожаного производства по таким же технологиям и нередко на том же оборудовании, как и все перечисленные изделия из кожи');
INSERT INTO "public"."okved_2" VALUES ('15.1', '15', 'C', 'Дубление и отделка кожи, производство чемоданов, сумок, шорно-седельных изделий из кожи; выделка и крашение меха', 'Эта группировка включает:
- производство кожи, меха и изделий из них');
INSERT INTO "public"."okved_2" VALUES ('20', 'C', 'C', 'Производство химических веществ и химических продуктов', 'Эта группировка включает:
- преобразование органического и неорганического сырья посредством химических процессов в химические продукты. Различается производство основных химических веществ, составляющих первую подгруппу, и производство промежуточныхи конечных продуктов, получаемых при переработке основных химических продуктов, которое составляет остальные подгруппы');
INSERT INTO "public"."okved_2" VALUES ('43.34.2', '43.34', 'F', 'Производство стекольных работ', '');
INSERT INTO "public"."okved_2" VALUES ('15.11', '15.1', 'C', 'Дубление и выделка кожи, выделка и крашение меха', 'Эта группировка включает:
- дубление, крашение, выделку шкур и кожи;
- производство замши, пергаментной кожи, лакированной кожи и металлизированной кожи;
- производство композиционной кожи;
- выскабливание, стрижку, выщипывание, отделку, дубление, осветление, крашение меховых шкур и шкур с волосяным покровом

Эта группировка не включает:
- производство сырых шкур и кож, см. 01.70;
- обработку сырых шкур и кож, см. 10.11;
- производство одежды из кожи, см. 14.11;
- производство имитации кожи из полимеров, резины, см. 22.19, 22.29');
INSERT INTO "public"."okved_2" VALUES ('15.11.1', '15.11', 'C', 'Выделка и крашение меха', '');
INSERT INTO "public"."okved_2" VALUES ('15.11.2', '15.11', 'C', 'Производство замши, пергаментной кожи, лакированной и металлизированной кожи', '');
INSERT INTO "public"."okved_2" VALUES ('15.11.3', '15.11', 'C', 'Дубление, выделка и крашение кожи из шкур крупного рогатого скота или животных семейства лошадиных', '');
INSERT INTO "public"."okved_2" VALUES ('15.11.4', '15.11', 'C', 'Дубление, выделка и крашение кожи из шкур овец, коз и свиней', '');
INSERT INTO "public"."okved_2" VALUES ('15.11.5', '15.11', 'C', 'Дубление, выделка и крашение кожи из шкур прочих животных, производство композиционной кожи', '');
INSERT INTO "public"."okved_2" VALUES ('15.11.51', '15.11.5', 'C', 'Дубление, выделка и крашение кожи из шкур прочих животных', '');
INSERT INTO "public"."okved_2" VALUES ('15.11.52', '15.11.5', 'C', 'Производство композиционной кожи', '');
INSERT INTO "public"."okved_2" VALUES ('15.12', '15.1', 'C', 'Производство чемоданов, дамских сумок и аналогичных изделий из кожи и других материалов; производство шорно-седельных и других изделий из кожи', 'Эта группировка включает:
- производство чемоданов, сумок и аналогичных изделий из натуральной или композиционной кожи и других материалов (пластмасс, текстильных материалов, фибры или картона) с применением той же технологии, что и для кожи;
- производство шорно-седельных изделий;
- производство неметаллических ремешков для часов (например, из ткани, кожи, пластика);
- производство различных изделий технического назначения из натуральной или композиционной кожи, включая производство приводных ремней, прокладок и т. п.;
- производство кожаных шнурков для обуви;
- производство кнутов и снаряжения для верховой езды

Эта группировка не включает:
- производство одежды из кожи, см. 14.11;
- производство перчаток и головных уборов из кожи, см. 14.19;
- производство обуви, см. 15.20;
- производство сидений для велосипедов, см. 30.92;
- производство ремешков и браслетов для часов из драгоценных металлов, см. 32.12;
- производство металлических ремешков и браслетов для часов из недрагоценных металлов, см. 32.13;
- производство ремней безопасности и прочих ремней для производственных целей, см. 32.99');
INSERT INTO "public"."okved_2" VALUES ('15.2', '15', 'C', 'Производство обуви', '');
INSERT INTO "public"."okved_2" VALUES ('15.20', '15.2', 'C', 'Производство обуви', 'Эта группировка включает:
- производство обуви разного назначения, из широкого круга материала с использованием различных технологий, в том числе литьевого метода формования, включая резиновую обувь (см. указанные ниже исключения);
- производство деталей обуви: верха и деталей верха, подошв, стелек, каблуков и т.п.;
- производство гетр, гамашей и подобных изделий;
- пошив обуви по индивидуальному заказу населения

Эта группировка не включает:
- производство обуви из текстильных материалов без подошвы, см. 14.19;
- производство деревянных деталей обуви (например, каблуков и колодок), см. 16.29;
- производство резиновых каблуков, подошв и прочих резиновых деталей обуви, см. 22.19;
- производство пластиковых частей обуви, см. 22.29;
- производство лыжных ботинок, см. 32.30;
- производство ортопедической обуви, см. 32.50');
INSERT INTO "public"."okved_2" VALUES ('15.20.1', '15.20', 'C', 'Производство обуви, кроме спортивной, защитной и ортопедической', '');
INSERT INTO "public"."okved_2" VALUES ('15.20.11', '15.20.1', 'C', 'Производство водонепроницаемой обуви с верхом из резины или пластмассы', '');
INSERT INTO "public"."okved_2" VALUES ('15.20.12', '15.20.1', 'C', 'Производство обуви с верхом из резины и пластмассы, кроме водопроницаемой', '');
INSERT INTO "public"."okved_2" VALUES ('15.20.13', '15.20.1', 'C', 'Производство обуви с верхом из кожи, кроме спортивной обуви, обуви с защитным металлическим подноском и различной специальной обуви', '');
INSERT INTO "public"."okved_2" VALUES ('15.20.14', '15.20.1', 'C', 'Производство обуви с верхом из текстильных материалов, кроме спортивной обуви', '');
INSERT INTO "public"."okved_2" VALUES ('15.20.2', '15.20', 'C', 'Производство спортивной обуви', '');
INSERT INTO "public"."okved_2" VALUES ('15.20.3', '15.20', 'C', 'Производство защитной обуви', '');
INSERT INTO "public"."okved_2" VALUES ('15.20.31', '15.20.3', 'C', 'Производство обуви с защитным металлическим подноском', '');
INSERT INTO "public"."okved_2" VALUES ('15.20.32', '15.20.3', 'C', 'Производство деревянной и различной специальной обуви', '');
INSERT INTO "public"."okved_2" VALUES ('15.20.4', '15.20', 'C', 'Производство деталей обуви из кожи; вкладных стелек, подпяточников и аналогичных изделий; производство гетр, гамашей и аналогичных изделий', '');
INSERT INTO "public"."okved_2" VALUES ('15.20.41', '15.20.4', 'C', 'Производство деталей обуви из кожи; вкладных стелек, подпяточников и аналогичных изделий', '');
INSERT INTO "public"."okved_2" VALUES ('15.20.42', '15.20.4', 'C', 'Производство гетр, гамашей и аналогичных изделий', '');
INSERT INTO "public"."okved_2" VALUES ('20.1', '20', 'C', 'Производство основных химических веществ, удобрений и азотных соединений, пластмасс и синтетического каучука в первичных формах', 'Эта группировка включает:
- производство основных химических веществ, удобрений и азотных соединений, а также пластмасс и синтетического каучука в первичных формах');
INSERT INTO "public"."okved_2" VALUES ('23.11.2', '23.11', 'C', 'Производство листового узорчатого, прокатного (но не обработанного другим способом): неармированного стекла', '');
INSERT INTO "public"."okved_2" VALUES ('16', 'C', 'C', 'Обработка древесины и производство изделий из дерева и пробки, кроме мебели, производство изделий из соломки и материалов для плетения', 'Эта группировка включает:
- производство изделий из дерева, таких как пиломатериалы, фанера, шпон, деревянные контейнеры, настилы, деревянные связки и сборные деревянные строения
Производственные процессы включают распиловку, обработку на строгальномстанке, формовку, ламинирование и сборку изделий из дерева, начиная с распилки необработанного лесоматериала на короткие бревна или на пиломатериалы, которые затем могут быть обрезаны или обработаны на токарном станке или на других обрабатывающих станках. Пиломатериалы или прочие переработанные виды древесины также могут впоследствии быть подвергнуты строганию или полировке и собраны в готовые изделия, такие как деревянные контейнеры. За исключением распиловки эта группировка подразделяется, главным образом, по определенным видам производственных изделий

Эта группировка не включает:
- производство мебели, см. 31.0;
- установку деревянной фурнитуры и т. п., см. 43.32, 43.33, 43.39');
INSERT INTO "public"."okved_2" VALUES ('16.1', '16', 'C', 'Распиловка и строгание древесины', '');
INSERT INTO "public"."okved_2" VALUES ('16.10', '16.1', 'C', 'Распиловка и строгание древесины', 'Эта группировка включает:
- распиловку, строгание и другие виды механической обработки древесины, в том числе профилирование пиломатериалов по кромке;
- расщепление, очистку или рубку бревен;
- производство деревянных железнодорожных шпал;
- производство несобранного деревянного напольного покрытия;
- производство древесного волокна, древесной муки, щепы и стружек и т. п.

Эта группировка также включает:
- сушку древесины;
- пропитку или химическую обработку древесины защитными составами или другими веществами');
INSERT INTO "public"."okved_2" VALUES ('16.10.1', '16.10', 'C', 'Производство пиломатериалов, кроме профилированных, толщиной более 6 мм; производство непропитанных железнодорожных и трамвайных шпал из древесины', '');
INSERT INTO "public"."okved_2" VALUES ('16.10.2', '16.10', 'C', 'Производство пиломатериалов, профилированных по кромке; производство древесного полотна, древесной муки; производство технологической щепы или стружки', '');
INSERT INTO "public"."okved_2" VALUES ('16.10.3', '16.10', 'C', 'Производство древесины, пропитанной или обработанной защитными или другими веществами', '');
INSERT INTO "public"."okved_2" VALUES ('16.10.9', '16.10', 'C', 'Предоставление услуг по пропитке древесины', '');
INSERT INTO "public"."okved_2" VALUES ('16.2', '16', 'C', 'Производство изделий из дерева, пробки, соломки и материалов для плетения', 'Эта группировка включает:
- производство изделий из дерева, пробки, соломки и материалов для плетения, включая основные формы, а также собранные изделия');
INSERT INTO "public"."okved_2" VALUES ('16.21', '16.2', 'C', 'Производство шпона, фанеры, деревянных плит и панелей', 'Эта группировка включает:
- производство лущеного шпона, достаточно тонкого для использования в производстве оклеивания фанеры, и для прочих целей: полированного, окрашенного, облицованного, пропитанного, укрепленного (бумагой или тканевой подложкой); изготовленного в виде орнаментов;
- производство клееной фанеры, однослойной фанеры и подобных ламинированных листовых изделий;
- производство древесно-стружечных плит с ориентированным расположением стружки;
- производство древесно-волокнистых плит средней плотности и прочих древесноволокнистых материалов;
- производство уплотненной древесины;
- производство клееных деревянных изделий, ламинированных однослойной фанерой');
INSERT INTO "public"."okved_2" VALUES ('16.21.1', '16.21', 'C', 'Производство фанеры, деревянных фанерованных панелей и аналогичных слоистых материалов, древесных плит из древесины и других одревесневших материалов', '');
INSERT INTO "public"."okved_2" VALUES ('16.21.11', '16.21.1', 'C', 'Производство фанеры, деревянных фанерованных панелей и аналогичных слоистых материалов', '');
INSERT INTO "public"."okved_2" VALUES ('16.21.12', '16.21.1', 'C', 'Производство древесно-стружечных плит из древесины или других одревесневших материалов', '');
INSERT INTO "public"."okved_2" VALUES ('16.21.13', '16.21.1', 'C', 'Производство древесно-волокнистых плит из древесины или других одревесневших материалов', '');
INSERT INTO "public"."okved_2" VALUES ('16.21.2', '16.21', 'C', 'Производство листов для облицовки, шпона для фанеры, производство прессованной древесины', '');
INSERT INTO "public"."okved_2" VALUES ('16.21.21', '16.21.2', 'C', 'Производство листов для облицовки, шпона для фанеры', '');
INSERT INTO "public"."okved_2" VALUES ('16.21.22', '16.21.2', 'C', 'Производство прессованной древесины', '');
INSERT INTO "public"."okved_2" VALUES ('16.22', '16.2', 'C', 'Производство сборных паркетных покрытий', 'Эта группировка включает:
- производство паркетных досок, блоков для покрытия пола и т. п., собранных в панели (щитового паркета)

Эта группировка не включает:
- производство несобранных (отдельных) деревянных напольных покрытий, см. 16.10');
INSERT INTO "public"."okved_2" VALUES ('16.23', '16.2', 'C', 'Производство прочих деревянных строительных конструкций и столярных изделий', 'Эта группировка включает:
- производство деревянных изделий, предназначенных для использования в качестве составных частей в строительных конструкциях, таких как балки, стропила, несущие элементы покрытий; готовые клееные и соединенные металлом кровельные балки;
- производство дверей, окон, ставней и рам, которые могут содержать и не содержать металлических соединений, такие как петли, замки и т. п.;
- производство лестниц, перил, деревянных фигурных профилированных изделий, дранок и гонтов;
- производство сборных строений или их составных частей, преимущественно из древесины, например саун;
- производство передвижных домов;
- производство перегородок (за исключением свободностоящих)

Эта группировка не включает:
- производство кухонных, книжных, платяных шкафов и т. п., см. 31.01, 31.02, 31.09;
- производство деревянных свободностоящих перегородок, см. 31.01, 31.02, 31.09');
INSERT INTO "public"."okved_2" VALUES ('16.23.1', '16.23', 'C', 'Производство деревянных строительных конструкций и столярных изделий', 'Эта группировка включает:
- производство деревянных изделий, предназначенных для использования в основном в строительстве:
- балок, стропил, несущих элементов покрытий; дверей, окон, ставней и рам для них; лестниц, перил, деревянных фигурных профилированных изделий (плинтусов, наличников и т. п.);
- дранки и гонта; опалубки для бетонных строительных работ;
- паркетных досок, блоков для покрытия пола и т. п.;
- ячеистых деревянных панелей, используемых в основном для производства перегородок и дверей

Эта группировка не включает:
- производство ненаборных деревянных покрытий для пола и профилированных пиломатериалов, см. 16.10');
INSERT INTO "public"."okved_2" VALUES ('16.23.2', '16.23', 'C', 'Производство сборных деревянных строений', 'Эта группировка включает:
- производство сборных деревянных строений различного назначения: жилых домов, рабочих бытовок, хозблоков, бань, контор, гаражей, теплиц, навесов и т. п.');
INSERT INTO "public"."okved_2" VALUES ('16.24', '16.2', 'C', 'Производство деревянной тары', 'Эта группировка включает:
- производство деревянных упаковочных ящиков, коробок, решетчатой тары, барабанов и аналогичной деревянной тары;
- производство деревянных поддонов, стеллажей и прочих деревянных приспособлений для хранения и перевозки грузов;
- производство деревянных бочек, чанов, кадок и прочих бондарных изделий;
- изготовление и ремонт бондарной посуды по индивидуальному заказу населения;
- производство деревянных барабанов для намотки кабелей

Эта группировка не включает:
- производство багажных сумок, см. 15.12;
- производство корзин из материалов для плетения, см. 16.29');
INSERT INTO "public"."okved_2" VALUES ('16.29', '16.2', 'C', 'Производство прочих деревянных изделий; производство изделий из пробки, соломки и материалов для плетения', 'Эта группировка включает:
- производство различных изделий из дерева, таких как деревянные ручки и ящики для инструментов, щетки, кисти, деревянные колодки, вешалки для одежды, домашние аксессуары и кухонные принадлежности из дерева;
- производство деревянных статуэток и деревянных инкрустаций, деревянных ящиков для драгоценностей, столовых приборов и подобных изделий;
- производство деревянных катушек, шпулек, бобин для швейных ниток и подобных предметов из обточенного дерева;
- производство прочих предметов из дерева;
- изготовление изделий из дерева, пробки, соломки и материалов для плетения, корзиночных и плетеных изделий по индивидуальному заказу населения;
- изготовление и ремонт деревянных лодок по индивидуальному заказу населения;
-переработку натуральной пробки;
- производство агломерированной пробки;
- производство изделий из натуральной или агломерированной пробки, включая напольные покрытия;
- производство изделий из материалов для плетения, таких как: половики, циновки, ширмы, коробки и т.п.;
- производство бельевых корзин и прочих плетеных изделий;
- производство дров и брикетов, изготовленных из прессованной древесины;
- производство деревянных рам для зеркал и картин;
- производство рам для холстов художников;
- производство деревянных составных частей обуви (например, каблуков и деревянных колодок);
- производство ручек для зонтиков, тростей и т.п.;
- производство блоков для производства курительных трубок

Эта группировка не включает:
- производство матов или циновок и ковриков из текстильных материалов, см. 13.92;
- производство чемоданов, см. 15.12;
- производство деревянной обуви, см. 15.2;
- производство спичек, см. 20.51;
- производство деревянных корпусов для часов, см. 26.52;
- производство деревянных шпулек и катушек для текстильного оборудования, см. 28.94;
- производство мебели, см. 31.0;
- производство деревянных игрушек, см. 32.40;
- производство щеток и веников, см. 32.91;
- производство гробов, см. 32.99;
-производство пробковых спасат');
INSERT INTO "public"."okved_2" VALUES ('16.29.1', '16.29', 'C', 'Производство прочих деревянных изделий', '');
INSERT INTO "public"."okved_2" VALUES ('16.29.11', '16.29.1', 'C', 'Производство деревянных инструментов, корпусов и рукояток инструментов, рукояток щеток и метелок, обувных колодок и растяжек для обуви', '');
INSERT INTO "public"."okved_2" VALUES ('16.29.12', '16.29.1', 'C', 'Производство деревянных столовых и кухонных принадлежностей', '');
INSERT INTO "public"."okved_2" VALUES ('16.29.13', '16.29.1', 'C', 'Производство деревянных статуэток и украшений из дерева, мозаики и инкрустированного дерева, шкатулок, футляров для ювелирных изделий или ножей', '');
INSERT INTO "public"."okved_2" VALUES ('16.29.14', '16.29.1', 'C', 'Производство деревянных рам для картин, фотографий, зеркал или аналогичных предметов и прочих изделий из дерева', '');
INSERT INTO "public"."okved_2" VALUES ('16.29.15', '16.29.1', 'C', 'Производство топливных гранул и брикетов из отходов деревопереработки', '');
INSERT INTO "public"."okved_2" VALUES ('16.29.2', '16.29', 'C', 'Производство изделий из пробки, соломки и материалов для плетения; производство корзиночных и плетеных изделий', '');
INSERT INTO "public"."okved_2" VALUES ('16.29.21', '16.29.2', 'C', 'Производство изделий из пробки', '');
INSERT INTO "public"."okved_2" VALUES ('16.29.22', '16.29.2', 'C', 'Производство изделий из соломки, эспарто (альфы) и прочих материалов для плетения', '');
INSERT INTO "public"."okved_2" VALUES ('17', 'C', 'C', 'Производство бумаги и бумажных изделий', 'Эта группировка включает:
- производство бумажной массы, бумаги или изделий из дополнительно обработанной бумаги
При производстве этих товаров применяется вертикальная интеграция нескольких видов деятельности, так как различные операции осуществляются одним хозяйствующим субъектом последовательно. Выделяются три основных вида экономической деятельности. Производство бумажной массы состоит в отделении целлюлозных волокон от примесей, содержащихся в древесине, или растворении или очищении от чернил использованной бумаги и смешивании в небольшом количестве реагентов для усиления сплетения волокон. Производство бумаги, сопряженное с выливанием бумажной массы на движущуюся проволочную сетку, в результате чего формируется сплошной лист. Изделия из бумажной макулатуры производятся из бумаги и других материалов при помощи различных технологий. Печатание изделий из бумаги (например, обои, подарочная обвертка и т. п.) также включены в данную группировку при условии, что полиграфическая деятельность является вспомогательной. Производство древесной массы и целлюлозы, бумаги и картона без упаковки помещено в группировку 17.1, в то время как остальные группировки включают описание дальнейшего процесса производства бумаги и бумажной продукции');
INSERT INTO "public"."okved_2" VALUES ('17.1', '17', 'C', 'Производство целлюлозы, древесной массы, бумаги и картона', '');
INSERT INTO "public"."okved_2" VALUES ('17.11', '17.1', 'C', 'Производство целлюлозы и древесной массы', 'Эта группировка включает:
- производство отбеленной, не полностью отбеленной или неотбеленной бумажной древесной массы и целлюлозы механическим, химическим (растворение или неполное растворение), а также полухимическим методом переработки;
- производство целлюлозы из хлопкового пуха;
- очищение от чернил и типографской краски при производстве бумажной массы из макулатуры');
INSERT INTO "public"."okved_2" VALUES ('17.11.1', '17.11', 'C', 'Производство целлюлозы', '');
INSERT INTO "public"."okved_2" VALUES ('17.11.2', '17.11', 'C', 'Производство древесной массы', '');
INSERT INTO "public"."okved_2" VALUES ('17.11.9', '17.11', 'C', 'Производство прочих волокнистых полуфабрикатов', '');
INSERT INTO "public"."okved_2" VALUES ('17.12', '17.1', 'C', 'Производство бумаги и картона', 'Эта группировка включает:
- производство бумаги и картона, предназначенных для дальнейшей промышленной обработки: мелование, покрытие и пропитка бумаги и картона, включая производство крепированной бумаги;
- производство ламинированной фольгой бумаги;
- производство бумаги ручного отлива;
- производство газетной бумаги и прочей типографской и писчей бумаги;
- производство целлюлозного материала для набивки и ваты из целлюлозных волокон;
- производство копировальной или трафаретной бумаги в рулонах или больших листах

Эта группировка не включает:
- производство гофрированных бумаги и картона, см. 17.21;
- производство изделий из бумаги, картона или целлюлозы, см. 17.22, 17.23, 17.24, 17.29;
- производство бумаги с покрытием или пропитанной бумаги, где покрытие и пропитка являются основным компонентом, см. группировку, к которой относится покрытие и пропитка;
- производство наждачной бумаги, см. 23.91');
INSERT INTO "public"."okved_2" VALUES ('17.12.1', '17.12', 'C', 'Производство бумаги', '');
INSERT INTO "public"."okved_2" VALUES ('17.12.2', '17.12', 'C', 'Производство картона', '');
INSERT INTO "public"."okved_2" VALUES ('17.2', '17', 'C', 'Производство изделий из бумаги и картона', '');
INSERT INTO "public"."okved_2" VALUES ('17.21', '17.2', 'C', 'Производство гофрированной бумаги и картона, бумажной и картонной тары', 'Эта группировка включает:
- производство гофрированных бумаги и картона;
- производство тары из гофрированной бумаги и картона;
- производство складной тары из гофрированного картона;
- производство тары из твердого картона;
- производство прочей бумажной и картонной тары;
- производство бумажных мешков и сумок;
- производство офисных коробок для бумаг и подобных изделий

Эта группировка не включает:
- производство конвертов, см. 17.23;
- производство рельефных или прессованных изделий из древесной массы и целлюлозы (таких как коробки для упаковки яиц, рельефные тарелки из целлюлозы), см. 17.29');
INSERT INTO "public"."okved_2" VALUES ('17.22', '17.2', 'C', 'Производство бумажных изделий хозяйственно-бытового и санитарно-гигиенического назначения', 'Эта группировка включает:
- производство изделий хозяйственного назначения и для личной гигиены из бумаги и медицинского алигнина, включая: косметические салфетки, носовые платки, полотенца, салфетки для сервировки стола, туалетную бумагу, гигиенические полотенца и тампоны, детские пеленки и подгузники, стаканчики, тарелки и подносы;
- производство текстильного материала для набивки и изделий из нее для изготовления гигиенических полотенец, тампонов и т. п.

Эта группировка не включает:
- производство целлюлозных материалов для набивки, см. 17.12');
INSERT INTO "public"."okved_2" VALUES ('18.13', '18.1', 'C', 'Изготовление печатных форм и подготовительная деятельность', 'Эта группировка включает:
- составление, набор текста, фотонабор, подготовку данных, включая сканирование и оптическое распознавание символов/текста, электронный набор;
- подготовку данных для различных носителей информации (бумага, СD-RОМ, информационно-коммуникационная сеть Интернет, иные цифровые и электронные носители);
- изготовление печатных форм, включая обработку изображений (для машин высокой и офсетной печати);
- подготовку цилиндров, включая гравировку цилиндров для глубокой печати;
-обработку копии на печатной пластине: "с компьютера на пластину" (включая фотополимерные пластины);
- подготовку пластин и клише для рельефной штамповки или печати;
- подготовку к печати: художественных работ технического плана, таких как литографические стенды и деревянные блоки; средств для презентаций, например прозрачных слайдов и прочих форм демонстрации изображений; набросков, разметок, эскизов и т. п.;
- производство корректурных оттисков

Эта группировка не включает:
- специализированнуюдизайнерскую деятельность, см. 74.10');
INSERT INTO "public"."okved_2" VALUES ('17.23', '17.2', 'C', 'Производство бумажных канцелярских принадлежностей', 'Эта группировка включает:
- производство типографской и писчей бумаги, готовой для использования;
- производство бумаги для распечатки данных на компьютере, готовой для использования;
- производство самокопировальной бумаги, готовой для использования;
- производство трафаретной и копировальной бумаги, готовой для использования;
- производство самоклеящейся бумаги, готовой для использования;
- производство конвертов и почтовых карточек;
- производство школьных и офисных канцелярских товаров (блокнотов, тетрадей, журналов, бухгалтерских книг, деловых бланков и т. д.), если нанесение изображения на бумагу не является их главной характеристикой;
- производство коробок, сумок и пакетов и аналогичных изделий для хранения корреспонденции, а такжезаписных книжек, почтовых наборов, содержащих ассортимент писчебумажных принадлежностей и канцелярских товаров

Эта группировка не включает:
- печать на бумажной продукции, см. 18.1');
INSERT INTO "public"."okved_2" VALUES ('17.24', '17.2', 'C', 'Производство обоев', 'Эта группировка включает:
- производство обоев и подобных материалов для оклеивания стен, включая виниловые и текстильные обои

Эта группировка не включает:
- производство бумаги или картона без упаковки, см. 17.12;
- производство пластиковых обоев, см. 22.29');
INSERT INTO "public"."okved_2" VALUES ('17.29', '17.2', 'C', 'Производство прочих изделий из бумаги и картона', 'Эта группировка включает:
- производство этикеток;
- производство фильтровальной бумаги и картона, фильтровальных блоков, плит и пластин из бумажной массы;
- производство бумажных и картонных бобин, катушек, шпулек и т. п.;
- производство формованныхкартонных упаковок для яиц и прочих бумажных рельефных упаковочных изделий;
- производство бумажных сувениров;
- производство бумажных и картонных перфокарт для использования в жаккардовых текстильных станках;
- производство печатной упаковки из бумаги и картона

Эта группировка не включает:
- производство игральных карт, см. 32.40;
- производство игр и игрушек из бумаги и картона, см. 32.40');
INSERT INTO "public"."okved_2" VALUES ('18', 'C', 'C', 'Деятельность полиграфическая и копирование носителей информации', 'Эта группировка включает:
- печать газет, книг, периодических изданий, деловых бланков, поздравительных открыток и прочих материалов, а также вспомогательную деятельность, такую как переплетное дело, изготовление печатных форм и обработка изображений. Включенные в эту группировку вспомогательные виды деятельности являются неотъемлемой частью полиграфического производства, а продукты (формы для печати, книги в переплете, компьютерные диски или файлы) являются результатами этой деятельности. Процессы, используемые в печати, включают множество методов передачи изображения с формы для печати, растра или компьютера на носитель, такой как бумага, пластмасса, металл, текстильные изделия или деревянные изделия. Основной из этих методов состоит в передаче изображения с формы для печати или растра на носитель с помощью литографической, глубокой, растровой или флексографической печати. Часто компьютерный файл используется напрямую и для получения изображения бесконтактным способом с использованием средств отображения визуальной информации, в том числе принтеров. Хотя печать и издательские работы могут выполняться на том же самом оборудовании (например, газетная продукция), все реже бывает так, что эти отдельные виды деятельности осуществляются физически в одном месте

Эта группировка также включает:
- размножение носителей информации, таких как компакт-диски, видеозаписи, программное обеспечение на дисках и т. д.');
INSERT INTO "public"."okved_2" VALUES ('18.1', '18', 'C', 'Деятельность полиграфическая и предоставление услуг в этой области', 'Эта группировка включает:
- издание такой печатной продукции, как газеты, книги, периодические издания, деловые бланки, поздравительные открытки и прочие материалы;
- вспомогательную деятельность, такую как переплетное дело, изготовление печатных форм и обработка изображений. Печать может быть выполнена с использованием различных технологий и на различных материалах');
INSERT INTO "public"."okved_2" VALUES ('18.11', '18.1', 'C', 'Печатание газет', 'Эта группировка не включает:
- издание полиграфической продукции, см. 58.1;
- фотокопирование документов, см. 82.19');
INSERT INTO "public"."okved_2" VALUES ('18.12', '18.1', 'C', 'Прочие виды полиграфической деятельности', 'Эта группировка включает:
- печать журналов и прочих периодических изданий, выходящих реже четырех раз в неделю;
- печать книг и брошюр, нот и партитур, карт, атласов, плакатов, рекламных каталогов, проспектов и прочей печатной рекламы, почтовых марок, акцизных марок, товарораспорядительных документов, чеков и прочих ценных бумаг, смарт-карт, альбомов, дневников, календарей и прочей коммерческой печатной продукции, личных бланков и прочих печатных материалов, изготовленных высокой печатью, офсетной печатью, глубокой печатью, флексографической печатью, трафаретной печатью, а также с применением других методов, множительных машин, печатающих устройств компьютеров, машин для тиснения и т. п., включая срочное копирование;
- печать непосредственно на текстильные изделия, пластик, стекло, металл, дерево и керамику
Печатный материал, как правило, защищен Законом Российской Федерации "Об авторском праве и смежных правах"

Эта группировка также включает:
- печать этикеток или ярлыков (литография, гравюрная печать, флексография и т. п.);
- печать многокрасочной упаковки, с дополнительными оформительскими элементами, на листах бумаги и картона с последующим формированием конечного изделия');
INSERT INTO "public"."okved_2" VALUES ('19.34', '19.3', 'C', 'Производство термоуглей', '');
INSERT INTO "public"."okved_2" VALUES ('19.34.1', '19.34', 'C', 'Производство термоуглей из антрацита', '');
INSERT INTO "public"."okved_2" VALUES ('19.34.2', '19.34', 'C', 'Производство термоуглей из бурого угля (лигнита)', '');
INSERT INTO "public"."okved_2" VALUES ('19.34.3', '19.34', 'C', 'Производство теромуглей из угля за исключением антрацитов, лигнитов и угля каменного коксующегося', '');
INSERT INTO "public"."okved_2" VALUES ('22.29.9', '22.29', 'C', 'Предоставление услуг в области производства прочих пластмассовых изделий', '');
INSERT INTO "public"."okved_2" VALUES ('18.14', '18.1', 'C', 'Деятельность брошюровочно- переплетная и отделочная и сопутствующие услуги', 'Эта группировка включает:
- переплет издательской продукции, установку образцов и постпечатные услуги, например завершающую подготовку обложек, книг, брошюр, журналов, каталогов и т.п.;
- нанесение пленки, подрезание и выравнивание листов, сборку, стачивание отдельных частей;
- прошивание нитками, бесшовное клеевое скрепление блока, укладку, склеивание, упорядочение, наметывание, тиснение золотом, скрепление металлической и пластиковой спиралью;
- переплет и обработка печатной бумаги или печатного картона, сгибание, тиснение, пробивание отверстий, гравировка, склеивание, ламинирование;
- переплетные, брошюровочные, окантовочные, картонажные работы по индивидуальному заказу населения;
- завершающую подготовку для изготовления CD-ROM;
- завершающую подготовку почтовых отправлений, такую как изготовление конвертов по требованию заказчика, изготовление обложки;
- прочие завершающие виды деятельности, такие как штамповка, прессовка, тиснение, печать для незрячих');
INSERT INTO "public"."okved_2" VALUES ('18.2', '18', 'C', 'Копирование записанных носителей информации', '');
INSERT INTO "public"."okved_2" VALUES ('18.20', '18.2', 'C', 'Копирование записанных носителей информации', 'Эта группировка включает:
- копирование на грампластинки, компакт-диски и музыкальные или иные звукозаписи с оригинальной матрицы (мастер-копии);
- копирование на видеоленты, компакт-диски и кассеты фильмов и прочих видеозаписей с оригинальной матрицы;
- копирование на диски, магнитные ленты, запись на электронный носитель, запись в память ЭВМ компьютерных программ и данных с оригинального носителя

Эта группировка не включает:
- размножение печатной продукции, см. 18.11, 18.12;
- выпуск программного обеспечения, см. 58.2;
- производство и распространение кинофильмов, видеозаписей и фильмов на DVD и подобных носителях, см. 59.11, 59.12, 59.13;
- тиражирование кинофильмов для показа в кинотеатрах, см. 59.12;
- производство оригиналов с записями или звуковыми материалами, см. 59.20');
INSERT INTO "public"."okved_2" VALUES ('19', 'C', 'C', 'Производство кокса и нефтепродуктов', 'Эта группировка включает: - переработку нефти и угля в продукты, готовые к использованию Основной процесс - очистка нефти, которая влечет за собой разложение нефти на составные продукты методом крекинга и перегонки 
Эта группировка также включает: - производство таких газов, как этан, пропан и бутан в качестве продуктов нефтеочистительных заводов 
Эта группировка не включает: - производство газов, содержащих основные органические химические вещества, см. 20.14; - производственные газы, см. 20.11; - природные газы (метан, этан, бутан или пропан), см. 06.20; - производство топливного газа, отличного от нефтяного газа (например, каменноугольного газа, водяного газа, генераторного газа), см. 35.21; - производство нефтехимикатов из очищенной нефт и, см. 20');
INSERT INTO "public"."okved_2" VALUES ('19.1', '19', 'C', 'Производство кокса', '');
INSERT INTO "public"."okved_2" VALUES ('19.10', '19.1', 'C', 'Производство кокса', 'Эта группировка включает:
- обеспечение работы коксовых печей;
- производство кокса и полукокса;
- производство смолы, пека, асфальта и пекового кокса;
- производство коксового газа;
- производство каменноугольной и лингитовой смол;
- обогащение кокса');
INSERT INTO "public"."okved_2" VALUES ('19.2', '19', 'C', 'Производство нефтепродуктов', '');
INSERT INTO "public"."okved_2" VALUES ('19.20', '19.2', 'C', 'Производство нефтепродуктов', 'Эта группировка включает: - производство жидкого и газообразного топлива, а также прочих продуктов из нефти, битуминозных пород и продуктов собственного фракционирования Очистка нефти происходит в несколько этапов: фракционирование, прямая перегонка неочищенной нефти и разложение (крекинг-процесс) 
Эта группировка также включает: - производство дизельного топлива, бензина и керосина; - производство облегченного, среднего и тяжелого топлива, газов, таких как этан, пропан, бутан и т.д.; - производ ство смазочных масел или смазок из нефти, включая остатки ее перегонки, и из отработанного масла; - производство продуктов для нефтехимической промышленности, а также для производства дорожных покрытий; - производство нефтепродуктов: отбеливателей, в азелина, парафина, нефтяного кокса и т.д.; - производство нефтяных брикетов - смешивание биотоплива с нефтью (например, производство газохола) 
Эта группировка также включает: - получение сжиженных газов при очистке нефти');
INSERT INTO "public"."okved_2" VALUES ('19.3', '19', 'C', 'Агломерация угля, антрацита и бурого угля (лигнита) и производство термоуглей', '');
INSERT INTO "public"."okved_2" VALUES ('19.31', '19.3', 'C', 'Агломерация антрацита', '');
INSERT INTO "public"."okved_2" VALUES ('19.32', '19.3', 'C', 'Агломерация угля', '');
INSERT INTO "public"."okved_2" VALUES ('19.33', '19.3', 'C', 'Агломерация бурого угля (лигнита)', '');
INSERT INTO "public"."okved_2" VALUES ('20.11', '20.1', 'C', 'Производство промышленных газов', 'Эта группировка включает:
- производство сжиженных и сжатых неорганических газов для промышленных или медицинских целей: элементные газы, жидкий или сжатый воздух, холодильные агенты, смешанные промышленные газы, неорганические кислородные соединения, например, диоксид углерода, инертные газы

Эта группировка не включает:
- производство метана, этана, бутана или пропана, см. 06.20;
- производство топливных газов, таких как этан, бутан или пропан при переработке нефти, см. 19.20;
- производство искусственного горючего газа из угля и отходов и т. д., см. 35.21');
INSERT INTO "public"."okved_2" VALUES ('20.12', '20.1', 'C', 'Производство красителей и пигментов', 'Эта группировка включает:
- производство красителей и пигментов из исходного вещества в виде гранул или в виде концентрата

Эта группировка также включает:
- производство флуоресцентных веществ и люминофоров');
INSERT INTO "public"."okved_2" VALUES ('20.13', '20.1', 'C', 'Производство прочих основных неорганических химических веществ', 'Эта группировка включает:
- производство химических веществ с использованием основных процессов
Результатом этих процессов являются отдельные химические элементы или определенные химические соединения

Эта группировка также включает:
- производство хи мических элементов (кроме промышленных газов и основных сплавов);
- производство неорганических кислот (кроме азотной кислоты);
- производство щелочей, щелоков и прочих неорганических соединений (кроме аммиака);
- производство прочих неорганических с оединений;
- обжиг железного колчедана;
- производство дистиллированной воды

Эта группировка также включает:
- обогащение урановых и ториевых руд;
- производство урана, обогащенного U-235, и его соединений;
- производство плутония и его соединений;
- производство урана, обедненного U-235, и его соединений; 
- производство тория и его соединений;
- производство радиоактивных элементов и изотопов прочих;
- производство прочих ядерных материалов;
- производство прочих радиоактивных веществ');
INSERT INTO "public"."okved_2" VALUES ('20.14', '20.1', 'C', 'Производство прочих основных органических химических веществ', 'Эта группировка включает: - производство химических веществ при помощи основных процессов (таких как тепловой крекинг, дистилляция и низкотемпературное фракционирование) Результатом таких процессов обычно являются отдельные химические элементы или от');
