INSERT INTO "public"."okved_2" VALUES ('20.14.2', '20.14', 'C', 'Производство спиртов, фенолов, фенолоспиртов и их галогенированных, сульфированных, нитрованных или нитрозированных производных; производство жирных промышленных спиртов', '');
