INSERT INTO "public"."okved_2" VALUES ('23.42', '23.4', 'C', 'Производство керамических санитарно-технических изделий', 'Эта группировка включает:
- производство керамических санитарно-технических изделий, таких как раковины, ванны, биде, сливные бачки;
- производство прочих керамических изделий

