INSERT INTO "public"."okved_2" VALUES ('23.44.2', '23.44', 'C', 'Производство керамических и ферритовых магнитов', '');
INSERT INTO "public"."okved_2" VALUES ('23.49', '23.4', 'C', 'Производство прочих керамических изделий', 'Эта группировка включает:
- производство керамических горшков, банок, кувшинов и подобных изделий, используемых для транспортирования или упаковывания товаров;
- производство керамических изделий, не включенных в другие группировки

Эта группировка невключает:
- производство керамического гигиенического сантехнического оборудования, см. 23.42;
