INSERT INTO "public"."okved_2" VALUES ('23.61', '23.6', 'C', 'Производство изделий из бетона для использования в строительстве', 'Эта группировка включает:
- производство готовых строительных изделий из бетона, цемента и искусственного камня: плиток, плит, кирпича, щитов, листов, панелей, труб, столбов и т. п.;
- производство сборных строительных конструкций из цемента, бетонаи искусственного камня');
