INSERT INTO "public"."okved_2" VALUES ('26.40.3', '26.40', 'C', 'Производство аппаратуры для записи и воспроизведения звука и изображения', '');
INSERT INTO "public"."okved_2" VALUES ('26.40.4', '26.40', 'C', 'Производство электроакустической аппаратуры', '');
INSERT INTO "public"."okved_2" VALUES ('26.40.5', '26.40', 'C', 'Производство частей звукозаписывающей и звуковоспроизводящей аппаратуры и видеоаппаратуры', '');
INSERT INTO "public"."okved_2" VALUES ('26.5', '26', 'C', 'Производство контрольно-измерительных и навигационных приборов и аппаратов; производство часов', 'Эта группировка включает:
- производство средств измерений, испытаний и навигационного оборудования для различных промышленных и непромышленных целей, включая устройства измерения интервалов времени, такие как наручные или настенные часы и подобные им устройства');
INSERT INTO "public"."okved_2" VALUES ('26.51', '26.5', 'C', 'Производство инструментов и приборов для измерения, тестирования и навигации', 'Эта группировка включает:
- производство поисковых, навигационных и ориентационных, авиационных, космических и морских систем и инструментов, систем автоматического управления и регулирования для бытовых устройств, таких как отопительные приборы, кон диционеры, холодильные установки, инструменты и приборы для измерения, отображения, регистрации, записи, передачи и контроля температуры, влажности, давления, вакуума, потока, уровня, вязкости, плотности, кислотности, концентрации и других неэлектрич еских параметров, расходомеры и счетные устройства, инструменты и аппаратура для лабораторного анализа химического или физического состава веществ, концентрации жидких и газообразных веществ, инструменты для измерений и проведения испытаний, а также производство комплектующих изделий и составных частей для названных устройств;
- производство неэлектрического тестирующего и навигационного оборудования (за исключением простых механических инструментов)

Эта группировка также включает:
- производств о оборудования для авиационных и ракетных двигателей;
- производство контрольно-измерительной аппаратуры для разработки, изготовления, эксплуатации и ликвидации ядерной оружейной продукции;
- производство приборов контроля над выбросом автомобильных выхлопных газов;
- производство метеорологического оборудования;
- производство приборов для тестирования и проверки физических свойств;
- производство полиграфического оборудования;
- производство оборудования для выявления и мониторинга радиационно го излучения;
- производство метрологического оборудования');
INSERT INTO "public"."okved_2" VALUES ('27.2', '27', 'C', 'Производство электрических аккумуляторов и аккумуляторных батарей', '');
INSERT INTO "public"."okved_2" VALUES ('26.51.1', '26.51', 'C', 'Производство навигационных, метеорологических, геодезических, геофизических и аналогичного типа приборов, аппаратуры и инструментов', '');
INSERT INTO "public"."okved_2" VALUES ('26.51.2', '26.51', 'C', 'Производство радиолокационной, радионавигационной аппаратуры и радиоаппаратуры дистанционного управления', '');
INSERT INTO "public"."okved_2" VALUES ('26.51.3', '26.51', 'C', 'Производство точных весов; производство ручных инструментов для черчения, разметки и математических расчетов; производство ручных инструментов для измерения линейных размеров, не включенных в другие группировки', '');
INSERT INTO "public"."okved_2" VALUES ('26.51.4', '26.51', 'C', 'Производство приборов и аппаратуры для измерения электрических величин или ионизирующих излучений', 'Эта группировка также включает:
- производство ядерных аналитических приборов;
- производство радиоизотопных приборов;
- производство детекторов ионизирующего излучения');
INSERT INTO "public"."okved_2" VALUES ('26.51.5', '26.51', 'C', 'Производство приборов для контроля прочих физических величин', 'Эта группировка также включает:
- производство радиационных диагностических приборов и установок;
- производство устройств, блоков и узлов электронно-физических функциональных ядерных и радиоизотопных');
INSERT INTO "public"."okved_2" VALUES ('26.51.6', '26.51', 'C', 'Производство прочих приборов, датчиков, аппаратуры и инструментов для измерения, контроля и испытаний', '');
INSERT INTO "public"."okved_2" VALUES ('26.51.7', '26.51', 'C', 'Производство приборов и аппаратуры для автоматического регулирования или управления', '');
INSERT INTO "public"."okved_2" VALUES ('26.51.8', '26.51', 'C', 'Производство частей приборов и инструментов для навигации, управления, измерения, контроля, испытаний и прочих целей', '');
INSERT INTO "public"."okved_2" VALUES ('26.52', '26.5', 'C', 'Производство часов', 'Эта группировка включает:
- производство наручных и настенных часов, таймеров и их деталей

Эта группировка также включает
- производство настенных и наручных часов всех видов, включая секундомеры и хронометры для панелей управления;
- производство корпусов настенных и наручных часов, включая корпуса из драгоценных металлов;
- производство оборудования для хронометража, записи, регистрации и иного отображения временных интервалов путем движения часов или путем синхронизации двигателя, например: счетчиков времени парковки; бытовых и промышленных таймеров времени; штампов с индексацией времени и даты;
- производство устройств с таймерами и подобных устройств с часами или с синхронными двигателями: временных замков с блокировкой на определенноевремя;
- производство деталей наручных и настенных часов: механизмов для наручных и настенных часов, часовых пружин, камней, дисков, стрелок, пластин, соединителей и прочих деталей; часовых корпусов из любых материалов

Эта группировка не включает:
-производство браслетов для часов из неметаллических материалов (из ткани, кожи, пластмассы), см. 15.12;
- производство браслетов для часов из драгоценных металлов, см. 32.12;
- производство браслетов для часов из недрагоценных металлов, см. 32.13');
INSERT INTO "public"."okved_2" VALUES ('26.52.1', '26.52', 'C', 'Производство часов всех видов и прочих приборов времени', '');
INSERT INTO "public"."okved_2" VALUES ('26.52.2', '26.52', 'C', 'Производство часовых механизмов, деталей и составных частей часов и приборов времени', '');
INSERT INTO "public"."okved_2" VALUES ('26.6', '26', 'C', 'Производство облучающего и электротерапевтического оборудования, применяемого в медицинских целях', '');
INSERT INTO "public"."okved_2" VALUES ('26.60', '26.6', 'C', 'Производство облучающего и электротерапевтического оборудования, применяемого в медицинских целях', 'Эта группировка включает:
- производство облучающих аппаратов и электронных ламп (например, промышленных, диагностических, терапевтических, применяемых в медицинских целях, исследовательских, научных): бета-, гамма-, рентгеновское или прочее излучающее оборудование;
- производство компьютерных томографов;
- производство электронных термографов;
- производство дисплеев отображения магнитного резонанса;
- производство ультразвукового оборудования, применяемого в медицинских целях;
- производство электрокардиографов;
- производство электрического эндоскопического оборудования, применяемого в медицинских целях;
- производство лазерного оборудования, применяемого в медицинских целях;
- производство электронных кардиостимуляторов;
- производствослуховых аппаратов

Эта группировка также включает:
- производство оборудования для облучения продуктов питания и молочной продукции');
INSERT INTO "public"."okved_2" VALUES ('26.60.1', '26.60', 'C', 'Производство аппаратов, применяемых в медицинских целях, основанных на использовании рентгеновского, альфа-, бета- и гамма-излучений', '');
INSERT INTO "public"."okved_2" VALUES ('26.60.2', '26.60', 'C', 'Производство гемодиализного, диатермического, наркозного оборудования, применяемого в медицинских целях', '');
INSERT INTO "public"."okved_2" VALUES ('26.60.3', '26.60', 'C', 'Производство оборудования для переливания крови', '');
INSERT INTO "public"."okved_2" VALUES ('26.60.4', '26.60', 'C', 'Производство инструмента, оборудования и приспособлений, применяемых в медицинских целях', '');
INSERT INTO "public"."okved_2" VALUES ('26.60.5', '26.60', 'C', 'Производство диагностического и терапевтического оборудования, применяемого в медицинских целях', '');
INSERT INTO "public"."okved_2" VALUES ('26.60.6', '26.60', 'C', 'Производство компьютерных томографов', '');
INSERT INTO "public"."okved_2" VALUES ('26.60.7', '26.60', 'C', 'Производство ультразвукового оборудования, применяемого в медицинских целях', '');
INSERT INTO "public"."okved_2" VALUES ('26.60.9', '26.60', 'C', 'Производство прочего оборудования, применяемого в медицинских целях', '');
INSERT INTO "public"."okved_2" VALUES ('26.7', '26', 'C', 'Производство оптических приборов, фото- и кинооборудования', '');
INSERT INTO "public"."okved_2" VALUES ('28.29.43', '28.29.4', 'C', 'Производство торговых автоматов', '');
INSERT INTO "public"."okved_2" VALUES ('26.70', '26.7', 'C', 'Производство оптических приборов, фото- и кинооборудования', 'Эта группировка включает:
- производство оптической аппаратуры и линз, такой как бинокли, микроскопы (кроме электронных и протонных), телескопы, призмы и линзы (кроме офтальмологических);
- нанесение покрытия или полировку линз (кроме офтальмологических);
- установку линз (кроме офтальмологических);
- производство фотооборудования, такого как фотокамеры и экспонометры

Эта группировка также включает:
- производство оптических зеркал;
- производство оптических систем обнаружения оружия;
- производство оборудования оптического позиционирования на местности;
- производство оптических увеличительных инструментов;
- производство точных инструментов для оптических приборов;
- производство оптических компараторов;
- производство пленочных и цифровых фото- и кинокамер;
- производство проекторов для кинопленок и слайдов;
- производство кино- и фотопроекторов;
- производство оптических контрольно-измерительных приборов и инструментов (например, противопожарной сигнализации и фотоэкспонометров);
-производство линз, оптических микроскопов, биноклей и телескопов;
- производство лазерной аппаратуры;
- производство оптических прицелов и приборов определения координат целей

Эта группировка не включает:
- производство компьютерных проекторов, см.26.20;
- производство профессиональных теле- и видеокамер, см. 26.30;
- производство домашних видеокамер, см. 26.40;
- производство готового оборудования с использованием лазерных компонентов, см. соответствующую группировку производства по типу оборудования (например, лазерное оборудование, применяемое в медицинских целях, см. 26.60);
- производство светокопировальной техники, см. 28.23;
- производство офтальмологических приборов, см. 32.50');
