INSERT INTO "public"."okved_2" VALUES ('26.80', '26.8', 'C', 'Производство незаписанных магнитных и оптических технических носителей информации', 'Эта группировка включает:
- производство магнитных и оптических носителей информации

Эта группировка включает:
- производство незаписанных (пустых) магнитных аудио- и видеопленок;
- производство незаписанных магнитных аудио- и видеокассет;
- производство незаписанных дискет;
- производство незаписанных оптических дисков;
- производство накопителей на жестких дисках

Эта группировка не включает:
- копирование носителей записи (компьютерных дисков, аудио- и видеопленок и т. д.), см. 18.2');
INSERT INTO "public"."okved_2" VALUES ('27', 'C', 'C', 'Производство электрического оборудования', 'Эта группировка включает:
- производство аппаратуры, производящей, распределяющей и использующей электроэнергию, включая производство электроосветительного и сигнального оборудования, а также бытовой электротехники

Эта группировка не включает:
- производство электронных изделий, см. 26.');
INSERT INTO "public"."okved_2" VALUES ('27.1', '27', 'C', 'Производство электродвигателей, генераторов, трансформаторов и распределительных устройств, а также контрольно-измерительной аппаратуры', 'Эта группировка включает:
- производство распределителей электроэнергии и специальных трансформаторов, электродвигателей, генераторов и турбогенераторных установок');
INSERT INTO "public"."okved_2" VALUES ('27.11', '27.1', 'C', 'Производство электродвигателей, электрогенераторов и трансформаторов', 'Эта группировка включает:
- производство всех электродвигателей и трансформаторов переменного тока, постоянного и переменного/постоянного тока

Эта группировка включает:
- производство электродвигателей (кроме стартеров для двигателей внутреннего сгорания) и электрогенераторов всех типов;
- производство распределительных устройств и трансформаторов;
- производство трансформаторов дуговой сварки;
- производство флуоресцентных балластных резисторов (трансформаторов);
- производство трансформаторовдля распределительных подстанций;
- производство передатчиков и регуляторов распределения напряжения;
- производство генераторов электроэнергии (кроме заряжающихся от батарей генераторов переменного тока для двигателей внутреннего сгорания);
- производство моторно-генераторных агрегатов (кроме турбогенераторных установок);
- перемотку арматуры в заводских условиях

Эта группировка не включает:
- производство трансформаторов разъемного типа и выключателей, см. 26.11;
- производство электрическогооборудования для сварки и пайки, см. 27.90;
- производство твердотельных инверторов, выпрямителей и конвертеров, см. 27.90;
- производство турбогенераторных установок, см. 28.11;
- производство стартеров и генераторов для двигателей внутреннего сгорания, см. 29.31');
INSERT INTO "public"."okved_2" VALUES ('27.11.1', '27.11', 'C', 'Производство электродвигателей, генераторов и трансформаторов, кроме ремонта', '');
