INSERT INTO "public"."okved_2" VALUES ('27.12', '27.1', 'C', 'Производство электрической распределительной и регулирующей аппаратуры', 'Эта группировка включает:
- производство выключателей электропитания;
- производство сетевых фильтров для электросети;
- производство пультов управления для распределения электроэнергии;
- производство электротехнических реле;
- производство кабелейдля распределительных щитов электроэнергии;
- производство электрических плавких предохранителей;
- производство переключателей электрического оборудования;
- производство выключателей электропитания (кроме кнопочных, поворотных, катушечных, тумблерных);
- производство генераторных установок для пусковых двигателей

Эта группировка не включает:
- производство средств экологического контроля и аппаратуры управления производственными процессами, см. 26.51;
- производство выключателей для электрических цепей, таких как кнопочные щелчковые комнатные выключатели, см. 27.33');
INSERT INTO "public"."okved_2" VALUES ('27.20', '27.2', 'C', 'Производство электрических аккумуляторов и аккумуляторных батарей', 'Эта группировка включает:
- производство неперезаряжающихся и перезаряжающихся батарей

Эта группировка включает:
- производство первичных ячеек и первичных батарей: ячейки, содержащие диоксид марганца, диоксид ртути, окись серебра и т. д.;
- производство электрических аккумуляторов, включая следующие их части: сепараторы, контейнеры, покрытия;
- производство свинцовых кислотных батарей;
- производство никелево-кадмиевых батарей;
- производство никелево-магниевых батарей;
- производство литиевыхбатарей;
- производство сухих гальванических элементов;
- производство наливных гальванических элементов');
INSERT INTO "public"."okved_2" VALUES ('27.20.1', '27.20', 'C', 'Производство первичных элементов, батарей первичных элементов и их частей', '');
INSERT INTO "public"."okved_2" VALUES ('27.20.2', '27.20', 'C', 'Производство аккумуляторов, в том числе для автомобилей, аккумуляторных батарей и их составных частей', '');
INSERT INTO "public"."okved_2" VALUES ('27.20.21', '27.20.2', 'C', 'Производство аккумуляторов для автомобилей', '');
INSERT INTO "public"."okved_2" VALUES ('27.20.22', '27.20.2', 'C', 'Производство аккумуляторных батарей и их частей', '');
