INSERT INTO "public"."okved_2" VALUES ('27.20.3', '27.20', 'C', 'Производство солнечных батарей для наземного энергообеспечения и их составных частей', '');
INSERT INTO "public"."okved_2" VALUES ('27.3', '27', 'C', 'Производство кабелей и кабельной арматуры', 'Эта группировка включает:
- производство проводных устройств, передающих и непередающих электрический ток, проводных устройств для электросхем независимо от материала

Эта группировка также включает:
- производство изолированных проводов и волоконно-оптических кабелей');
INSERT INTO "public"."okved_2" VALUES ('27.31', '27.3', 'C', 'Производство волоконно-оптических кабелей', 'Эта группировка включает:
- производство волоконно-оптических кабелей для передачи данных или прямой трансляции изображений

Эта группировка не включает:
- производство стекловолокон или жил кабеля, см. 23.14;
- производство оптического кабеля или устройств с соединителями и прочими соединителями локальной сети, см. в зависимости от применения, например 26.11');
INSERT INTO "public"."okved_2" VALUES ('27.32', '27.3', 'C', 'Производство прочих проводов и кабелей для электронного и электрического оборудования', 'Эта группировка включает:
- производство изолированных проводов и кабелей, изготовленных из меди, стали, алюминия

Эта группировка не включает:
- производство (вытяжку) проволоки, см. 24.34, 24.41, 24.42, 24.43, 24.44, 24.45;
- производство кабелей для компьютеров и принтеров, кабелей USB и подобных кабельных устройств или сборок, см. 26.11;
- производство электрических устройств с изолированным проводом и разъемами, см. 27.90;
- производство кабельных устройств, жгутов электропроводки и подобныхкабельных устройств для автомобилей, см. 29.31');
INSERT INTO "public"."okved_2" VALUES ('27.32.1', '27.32', 'C', 'Производство кабелей для телефонной связи', '');
INSERT INTO "public"."okved_2" VALUES ('27.32.2', '27.32', 'C', 'Производство силовых кабелей', '');
INSERT INTO "public"."okved_2" VALUES ('27.32.3', '27.32', 'C', 'Производство обмоточных эмалированных кабелей', '');
INSERT INTO "public"."okved_2" VALUES ('27.33', '27.3', 'C', 'Производство электроустановочных изделий', 'Эта группировка включает:
- производство устройств, проводящих и не проводящих электрический ток для электрических схем, независимо от использованного материала

Эта группировка включает:
- производство шин, электрических проводников (кроме распределителей);
- производство защитных выключателей заземления;
- производство патронов для ламп;
- производство разрядников и катушек индуктивности для люминесцентных ламп;
- производство электрических выключателей (кнопочных, нажимных, поворотных, тумблерных);
- производство электрических розеток или гнезд;
- производство коробок для электрических проводов (например, кабельных, выходных, распределительных коробок);
- производство электрической проводки и приспособлений;
- производство подвесных линийэлектропередач;
- производство пластмассовых проводов, не предназначенных для передачи тока, включая пластмассовые кабельные коробки, лицевые панели и подобные детали, пластмассовые детали воздушных столбовых линий связи и кожухов для выключателей

Эта группировка не включает:
- производство керамических диэлектриков, см. 23.43;
- производство электронных разъемных соединителей и розеток, см. 26.11');
INSERT INTO "public"."okved_2" VALUES ('27.4', '27', 'C', 'Производство электрических ламп и осветительного оборудования', '');
INSERT INTO "public"."okved_2" VALUES ('27.40', '27.4', 'C', 'Производство электрических ламп и осветительного оборудования', 'Эта группировка включает:
- производство электрических ламп и электронных ламп, их составных частей и деталей (кроме стеклянных оболочек для электрических лампочек), электрической осветительной арматуры и деталей светильников, кроме проводов, находящихся под напряжением;
- производство газоразрядных ламп, ламп накаливания, флуоресцентных, ультрафиолетовых, инфракрасных и прочих ламп и устройств к ним;
- производство осветительных приборов, крепящихся непосредственно к потолку;
- производство люстр;
- производство настольных ламп (светильников);
- производство елочных гирлянд;
- производство электрических каминов;
- производство ручных электрических фонарей;
- производство прожекторов;
- производство электрических инсектицидных ламп;
- производство фонарей (например, карбидных, электрических, газовых, газолиновых);
- производство уличных осветительных приборов (кроме светофоров);
- производство осветительного оборудования для транспортных средств (например, автомобилей, самолетов, лодок)

Эта группировка также включает:
- производство неэлектрического осветительного оборудования');
INSERT INTO "public"."okved_2" VALUES ('28.29.5', '28.29', 'C', 'Производство посудомоечных машин промышленного типа', '');
INSERT INTO "public"."okved_2" VALUES ('28.29.6', '28.29', 'C', 'Производство оборудования для обработки материалов с использованием процессов, включающих изменение температуры, не включенного в другие группировки', '');
INSERT INTO "public"."okved_2" VALUES ('28.29.7', '28.29', 'C', 'Производство неэлектрического оборудования и инструментов для пайки мягким и твердым припоем или сварки, машин и аппаратов для газотермического напыления', '');
INSERT INTO "public"."okved_2" VALUES ('27.5', '27', 'C', 'Производство бытовых приборов', 'Эта группировка включает:
- производство электрических приборов и электрической бытовой техники, таких как: вентиляторы, пылесосы, полотеры, кухонные приборы, кухонное оборудование, стиральные машины, холодильники, морозильные камеры и шкафы, а такжепрочей электрической и неэлектрической бытовой техники, такой как посудомоечные машины, водонагреватели и мусоросборники

Эта группировка также включает:
- производство приборов, работающих на электричестве, газе и на прочих источниках энергии');
INSERT INTO "public"."okved_2" VALUES ('27.51', '27.5', 'C', 'Производство бытовых электрических приборов', 'Эта группировка включает:
- производство бытовых электрических приборов и оборудования, включая: холодильники, морозильники, посудомоечные машины, мойки и сушилки, пылесосы, полотеры, измельчители мусора, мельницы, блендеры, соковыжималки, консервныеножи, электробритвы, электрические зубные щетки и прочие электрические предметы для личного использования, точилки для ножей, вытяжные шкафы, электрические водонагреватели, электроодеяла, фены, щетки и бигуди для завивки, электрические утюги, обогреватели помещений и переносные вентиляторы для использования дома, электропечи, микроволновые печи, кухонные плиты, тостеры, чайники и кофеварки, сковороды, жаровни, утятницы, грили, обжарочные аппараты, электрические бытовые обогреватели помещений ит. д.

Эта группировка не включает:
- производство промышленных холодильников и морозильников, кондиционеров для помещений, вентиляторов, вытяжных шкафов, оборудования промышленного типа для термической обработки продуктов, оборудования для прачечных,химчисток и гладилен, промышленных пылесосов, см. 28;
- производство швейных машин для домашнего использования, см. 28.94;
- установку центральных систем очистки воздуха, см. 43.29');
INSERT INTO "public"."okved_2" VALUES ('27.51.1', '27.51', 'C', 'Производство стиральных машин', '');
INSERT INTO "public"."okved_2" VALUES ('27.51.2', '27.51', 'C', 'Производство холодильников и морозильников', '');
INSERT INTO "public"."okved_2" VALUES ('27.51.3', '27.51', 'C', 'Производство пылесосов', '');
INSERT INTO "public"."okved_2" VALUES ('27.51.4', '27.51', 'C', 'Производство посудомоечных машин', '');
INSERT INTO "public"."okved_2" VALUES ('27.51.5', '27.51', 'C', 'Производство электропечей', '');
INSERT INTO "public"."okved_2" VALUES ('27.51.6', '27.51', 'C', 'Производство микроволновых печей', '');
INSERT INTO "public"."okved_2" VALUES ('27.52', '27.5', 'C', 'Производство бытовых неэлектрических приборов', 'Эта группировка включает:
- производство бытовых неэлектрических приборов и нагревательных устройств: неэлектрические обогреватели помещений, кухонные плиты, жаровни, печи, водонагреватели, устройства для приготовления пищи, подогревающие переносныеустройства (для поддержания пищи в теплом состоянии)');
INSERT INTO "public"."okved_2" VALUES ('27.9', '27', 'C', 'Производство прочего электрического оборудования', '');
INSERT INTO "public"."okved_2" VALUES ('27.90', '27.9', 'C', 'Производство прочего электрического оборудования', 'Эта группировка включает:
- производство различного электрического оборудования, кроме двигателей, генераторов и трансформаторов, батарей и аккумуляторов, проводов и кабелей, светильников и бытовых приборов

Эта группировка включает:
- производство за рядных устройств для аккумуляторных батарей;
- производство электрических устройств для открывания и закрывания дверей;
- производство электрических звонков;
- производство удлинителей, сделанных из готового изолированного провода;
- производство при боров для ультразвуковой очистки (кроме лабораторной и зубоврачебной техники);
- производство твердотельных преобразователей, выпрямителей, топливных элементов, регулируемых и нерегулируемых источников электропитания;
- производство блоков непрерывно го электропитания (бесперебойных источников питания);
- производство ограничителей напряжения (за исключением напряжения на уровне распределения);
- производство шнуров, кабелей, удлинителей и прочих установок с электрическими изолированными проводам и и контактами;
- производство графитных электродов, контактов, и других графитных электрических изделий;
- производство ускорителей частиц;
- производство радиационных аппаратов;
- производство радионуклидных энергетических устройств;
- производство электрических конденсаторов, резисторов и подобных компонентов;
- производство электромагнитов;
- производство сирен;
- производство электронных табло;
- производство электрических визуальных средств отображения информации;
- производство электричес кого сигнального оборудования, такого как светофоры и сигнальные устройства для пешеходов;
- производство электрических изоляторов (кроме стеклянных или фарфоровых);
- производство оборудования для электрической сварки и пайки, включая бытовые ручные паяльники

Эта группировка не включает:
- производство фарфоровых электрических изоляторов, см. 23.43;
- производство углеродных и графитовых волокон и изделий (кроме электродов и электрических деталей), см. 23.99;
- производство электронных вып');
INSERT INTO "public"."okved_2" VALUES ('28', 'C', 'C', 'Производство машин и оборудования, не включенных в другие группировки', 'Эта группировка включает:
- производство машин и оборудования, которые оказывают на материалы механическое или термическое воздействие или при помощи которых выполняются операции с материалами (такие как обработка, напыление, взвешивание или упаковка), включая производство их деталей и составных частей, которые производят и используют энергию
В эту группировку включено производство стационарных и передвижных или переносимых устройств, независимо от того изготовлены они для промышленности, строительства, сельского хозяйства или бытового назначения. Производство специального оборудования для перевозки пассажиров и грузов в пределах ограниченного пространства также включено в данную группировку. В этой группировке разделено производство машинспециального назначения, т. е. машин для ограниченного использования в промышленности или в небольшой группе секторов промышленности, и универсальных машин, которые используются в широком диапазоне секторов промышленности

Эта группировка также включает:
- производство прочих машин специального назначения, не входящих в другие группировки данной классификации, и не используемых в промышленном производстве, таких как развлекательное оборудование для выставок, автоматическое оборудование кегельбанов и т. п.');
INSERT INTO "public"."okved_2" VALUES ('28.1', '28', 'C', 'Производство машин и оборудования общего назначения', '');
INSERT INTO "public"."okved_2" VALUES ('28.11', '28.1', 'C', 'Производство двигателей и турбин, кроме авиационных, автомобильных и мотоциклетных двигателей', 'Эта группировка включает:
- производство поршневых двигателей внутреннего сгорания, кроме автомобильных, авиационных и мотоциклетных двигателей: судовые и железнодорожные двигатели;
- производство поршней, поршневых колец, карбюраторов и прочих комплектующих изделий и составных частей для всех двигателей внутреннего сгорания и дизельных двигателей;
- производство впускных и выпускных клапанов для двигателей внутреннего сгорания;
- производство турбин и составных частей к ним: паровых турбин и прочих турбин, работающих на пару, гидравлических турбин, водяных колес и регуляторов к ним, ветровых турбин, газовых турбин, кроме турбореактивных или турбовинтовых авиационных двигателей;
- производство установок типа котел-турбина;
- производство турбогенераторных установок;
- производство двигателей для промышленного применения

Эта группировка не включает:
- производство электрогенераторов (кроме турбогенераторных установок), см. 27.11;
- производство генераторных установок для первичных двигателей (за исключением турбогенераторных установок), см. 27.11;
- производство электрооборудования и деталей для двигателей внутреннего сгорания, см. 29.31;
- производство автомобильных, авиационных или мотоциклетных двигателей, см. 29.10, 30.30, 30.91;
- производство турбореактивных и турбовинтовых двигателей, см. 30.30');
INSERT INTO "public"."okved_2" VALUES ('28.11.1', '28.11', 'C', 'Производство двигателей, кроме авиационных, автомобильных и мотоциклетных', '');
INSERT INTO "public"."okved_2" VALUES ('28.11.2', '28.11', 'C', 'Производство турбин', '');
INSERT INTO "public"."okved_2" VALUES ('28.11.21', '28.11.2', 'C', 'Производство паровых турбин', '');
INSERT INTO "public"."okved_2" VALUES ('28.11.22', '28.11.2', 'C', 'Производство гидравлических турбин и водяных колес', '');
INSERT INTO "public"."okved_2" VALUES ('28.11.23', '28.11.2', 'C', 'Производство газовых турбин, кроме турбореактивных и турбовинтовых', '');
INSERT INTO "public"."okved_2" VALUES ('28.12', '28.1', 'C', 'Производство гидравлического и пневматического силового оборудования', 'Эта группировка включает:
- производство гидравлических и пневматических комплектующих изделий и составных частей (включая гидравлические насосы, гидравлические двигатели, гидравлические и пневматические цилиндры, гидравлические и пневматические клапаны, гидравлические и пневматические шланги и приспособления);
- производство аппаратуры, очищающей воздух для использования в пневматических системах;
- производство гидравлических систем;
- производство гидроприводного оборудования;
- производствогидростатических трансмиссий

Эта группировка не включает:
- производство компрессоров, см. 28.13;
- производство насосов для негидравлической аппаратуры, см. 28.13;
- производство клапанов для негидравлической аппаратуры, см. 28.14;
- производство механического трансмиссионного оборудования, см. 28.15');
INSERT INTO "public"."okved_2" VALUES ('28.12.1', '28.12', 'C', 'Производство гидравлических и пневматических силовых установок и двигателей', '');
INSERT INTO "public"."okved_2" VALUES ('28.12.2', '28.12', 'C', 'Производство гидравлических насосов', '');
INSERT INTO "public"."okved_2" VALUES ('28.13', '28.1', 'C', 'Производство прочих насосов и компрессоров', 'Эта группировка включает:
- производство воздушных или вакуумных насосов, воздушных или прочих газовых компрессоров;
- производство насосов для жидкостей, снабженных или нет измерительным устройством;
- производство насосов, разработанных для установ ки на двигатели внутреннего сгорания: масляных, водяных и топливных насосов для автомашин и т.д.

Эта группировка также включает:
- производство ручных насосов;
- производство насосов для ядерных установок и радиохимического производства;
- производст во насосов турбомолекулярных глубокого вакуума');
INSERT INTO "public"."okved_2" VALUES ('28.14', '28.1', 'C', 'Производство арматуры трубопроводной (арматуры)', 'Эта группировка включает:
- производство запорной, регулирующей, предохранительной, обратной, распределительно-смесительной, разделительной, комбинированной арматуры для трубопроводов, сосудов, котлов, цистерн, баков и аналогичных емкостей (клапаны, краны, задвижки, затворы дисковые);
- производство арматуры санитарно-технической (краны, клапаны для раковин, моек, биде, унитазов, ванн и аналогичная арматура);
- производство арматуры трубопроводной для отопительных систем (краны, клапаны и аналог ичная арматура);
- производство арматуры трубопроводной для уранодобывающего производства;
- производство оголовков технических средств для уранодобывающего производства;
- производство пакеров для уранодобывающего производства;
- производство армату ры трубопроводной для области использования атомной энергии

Эта группировка не включает:
- производство клапанов из неупрочненной резины, стекла или керамических материалов, см. 22.19, 23.19 или 23.44;
- производство впускных и выпускных клапанов дви гателей внутреннего сгорания, см. 28.11;
- производство гидравлических и пневматических клапанов и воздухоочистного оборудования для использования в пневматических системах, см. 28.12');
INSERT INTO "public"."okved_2" VALUES ('28.15', '28.1', 'C', 'Производство подшипников, зубчатых передач, элементов механических передач и приводов', 'Эта группировка включает:
- производство шариковых и роликовых подшипников и их составных частей;
- производство механического силового трансмиссионного оборудования: трансмиссии и кривошипно-шатунные механизмы, включая распределительные валы, коленчатые валы, кривошипы и т. д., корпуса подшипников качения и скольжения;
- производство зубчатых колес, зубчатых передач и коробок передач, а также прочих устройств для переключения скорости вращения;
- производство муфт сцепления и приводных муфт;
-производство маховиков и шкивов;
- производство шарнирных соединений;
- производство приводных цепей

Эта группировка не включает:
- производство прочих цепей, см. 25.93;
- производство гидравлического трансмиссионного оборудования, см. 28.12;
- производство гидростатических передач, см. 28.12;
- производство электромагнитных муфт, см. 29.31;
- производство узлов трансмиссионного оборудования, применяемого в качестве деталей в автомобилях или самолетах, см. 29, 30');
INSERT INTO "public"."okved_2" VALUES ('28.15.1', '28.15', 'C', 'Производство шариковых и роликовых подшипников', '');
INSERT INTO "public"."okved_2" VALUES ('28.15.2', '28.15', 'C', 'Производство корпусов подшипников и подшипников скольжения, зубчатых колес, зубчатых передач и элементов приводов', 'Эта группировка включает:
- производство шарнирных цепей из черных металлов;
- производство передаточных валов, в том числе кулачковых и коленчатых валов, и кривошипов;
- производство корпусов подшипников и подшипников скольжения;
- производство зубчатых колес в сборе с валами, зубчатых передач, шариковых ходовых винтов, коробок передач и прочих редукционных механизмов;
- производство гидродинамических передач (гидромуфт и гидротрансформаторов);
- производство фрикционных вариаторов и фрикционных ременных и цепных передач;
- производство маховиков и шкивов, включая полиспасты;
- производство муфт и шарнирных соединений, включая универсальные шарниры Гука, карданы');
INSERT INTO "public"."okved_2" VALUES ('28.15.9', '28.15', 'C', 'Производство прочих подшипников', '');
INSERT INTO "public"."okved_2" VALUES ('28.2', '28', 'C', 'Производство прочих машин и оборудования общего назначения', '');
INSERT INTO "public"."okved_2" VALUES ('28.3', '28', 'C', 'Производство машин и оборудования для сельского и лесного хозяйства', '');
INSERT INTO "public"."okved_2" VALUES ('28.21', '28.2', 'C', 'Производство печей, термокамер и печных горелок', 'Эта группировка включает:
- производство электрических и прочих промышленных и лабораторных печей и духовок, включая установки для сжигания отходов;
- производство горелок (камер сгорания);
- производство стационарных электрических каминов, электрических обогревателей для плавательных бассейнов;
- производство бытового неэлектрического обогревательного оборудования, такого как солнечные обогреватели, паровое отопление, масляные обогреватели и подобное отопительное оборудование;
- производство бытовых электрических печей (с нагнетанием воздуха электрическим способом, тепловых насосов и т. д.), неэлектрических бытовых печей с нагнетанием воздуха

Эта группировка также включает:
- производство механических топок, решеток и разгрузчиков пепла ит. д.');
INSERT INTO "public"."okved_2" VALUES ('28.21.1', '28.21', 'C', 'Производство неэлектрических печей, горелок и устройств для них', '');
INSERT INTO "public"."okved_2" VALUES ('28.21.2', '28.21', 'C', 'Производство электрических печей', '');
INSERT INTO "public"."okved_2" VALUES ('28.22', '28.2', 'C', 'Производство подъемно-транспортного оборудования', 'Эта группировка включает:
- производство грузоподъемного и погрузочно-разгрузочного оборудования с ручным управлением или электроприводом: тали и подъемники, лебедки, кабестаны и домкраты, мачтовые краны, подъемные краны, передвижные подъемные каркасы, погрузчики для длинномерных материалов и т. д., строительные погрузчики, используемые на предприятиях, снабженные или не снабженные подъемным или манипуляционным оборудованием, самоходные или несамоходные (включая ручные тележки и тачки), механические манипуляторы и промышленные роботы, специально разработанные для грузоподъемных и погрузочно-разгрузочных работ;
- производство конвейеров и т. д.;
- производство подъемников, эскалаторов и подвижных дорожек;
- производство деталей, предназначенных для грузоподъемного и погрузочно-разгрузочного оборудования

Эта группировка не включает:
- производство промышленных роботов для многократного использования, см. 28.99;
- производство подъемных механизмов непрерывного действия и конвейеров для подземного использования, см. 28.92;
- производство ковшей, экскаваторов и ковшевых погрузчиков, см. 28.92;
- производство плавучих кранов, железнодорожных подъемных кранов, автомобильных кранов, см. 30.11, 30.20;
- установку (монтаж) лифтов и подъемников, см. 43.29');
INSERT INTO "public"."okved_2" VALUES ('28.22.1', '28.22', 'C', 'Производство талей и подъемников', '');
INSERT INTO "public"."okved_2" VALUES ('28.22.2', '28.22', 'C', 'Производство лебедок и кабестанов', '');
INSERT INTO "public"."okved_2" VALUES ('28.22.3', '28.22', 'C', 'Производство домкратов и подъемных механизмов для транспортных средств', '');
INSERT INTO "public"."okved_2" VALUES ('28.22.4', '28.22', 'C', 'Производство подъемных кранов', '');
INSERT INTO "public"."okved_2" VALUES ('28.22.41', '28.22.4', 'C', 'Производство подъемных кранов для строительства', '');
INSERT INTO "public"."okved_2" VALUES ('28.22.42', '28.22.4', 'C', 'Производство прочих подъемных кранов', '');
INSERT INTO "public"."okved_2" VALUES ('28.22.5', '28.22', 'C', 'Производство автопогрузчиков и тягачей, используемых на железнодорожных платформах', '');
INSERT INTO "public"."okved_2" VALUES ('28.22.6', '28.22', 'C', 'Производство лифтов, скриповых подъемников, эскалаторов и движущихся пешеходных дорожек', '');
INSERT INTO "public"."okved_2" VALUES ('28.22.7', '28.22', 'C', 'Производство пневматических подъемников и конвейеров и прочего оборудования непрерывного действия для товаров или материалов', '');
INSERT INTO "public"."okved_2" VALUES ('28.22.9', '28.22', 'C', 'Производство прочего грузоподъемного, транспортирующего и погрузочно-разгрузочного оборудования', '');
INSERT INTO "public"."okved_2" VALUES ('28.23', '28.2', 'C', 'Производство офисной техники и оборудования (кроме компьютеров и периферийного оборудования)', 'Эта группировка включает:
- производство счетных машин;
- производство вычислительных машин для кассовых аппаратов;
- производство калькуляторов, электронных или неэлектронных;
- производство франкировальных машин, почтовых сортирующих машин (машин для заполнения конвертов, заклеивания и адресации, машин для открытия, сортировки, сканирования);
- производство пишущих машинок;
- производство машин для стенографии;
- производство офисного скрепляющего оборудования (пластикового и ленточного);
- производство машин для выписки чеков;
- производство машин для упаковывания и счета денег;
- производство точилок для карандашей;
- производство степлеров и приспособлений для разжатия скоб;
- производство машин для подсчета голосов;
- производство держателей для клейкой ленты;
- производство перфораторов;
- производство кассовых аппаратов, билетно-кассовых машин, машин для обмена валют;
- производство фотокопировальных машин;
- производство порошковых картриджей;
- производство школьных, пластиковых и маркерных досок;
- производство диктофонов

Эта группировка не включает:
- производство компьютеров и периферийного оборудования, см. 26.20');
INSERT INTO "public"."okved_2" VALUES ('28.23.1', '28.23', 'C', 'Производство пишущих машин, машин для обработки текста, калькуляторов, счетных машин и их частей', 'Эта группировка включает:
- производство механических и электрических пишущих машин;
- производство машин для обработки текстов;
- производство калькуляторов, кассовых аппаратов, франкировальных машин, билетнокассовых машин, машин для обмена валют ит. п.');
INSERT INTO "public"."okved_2" VALUES ('28.23.2', '28.23', 'C', 'Производство фотокопировальных машин, офисных машин для офсетной печати и прочих офисных машин и оборудования и их составных частей', 'Эта группировка включает:
- производство фотокопировальных и термокопировальных машин;
- производство копировально-множительного оборудования (гектографов, ротаторов, листовых офсетных копировальных аппаратов для офисов), адресных машин;
- производство других офисных машин и оборудования: машин для сортирования, упаковывания и счета монет, машин для заполнения конвертов, почтообрабатывающих машин, заточных машинок для карандашей, перфораторов, скобосшивателей, офисных машин для уничтожения документов и т. п., машин для выдачи банкнот (банкоматов)');
INSERT INTO "public"."okved_2" VALUES ('28.92.27', '28.92.2', 'C', 'Производство прочих экскаваторов и самоходных ковшовых погрузчиков', '');
INSERT INTO "public"."okved_2" VALUES ('28.92.28', '28.92.2', 'C', 'Производство отвалов бульдозеров', '');
INSERT INTO "public"."okved_2" VALUES ('28.92.29', '28.92.2', 'C', 'Производство автомобилей-самосвалов, предназначенных для использования в условиях бездорожья', '');
INSERT INTO "public"."okved_2" VALUES ('28.24', '28.2', 'C', 'Производство ручных инструментов с механизированным приводом', 'Эта группировка включает:
- производство ручных инструментов с электрическим или неэлектрическим двигателем или пневматическим приводом, таких как: дисковые или ножовочные пилы; цепные пилы; дрели и перфораторы, ручные шлифовальные станки, пневматические пистолеты, амортизаторы, маршрутизаторы, дробилки, скоросшиватели, пневматические клепальные молотки, строгальные станки, ножницы и вырубные ножницы, пневматические гаечные ключи, пороховые пистолеты

Эта группировка не включает:
- производство запасных составных частей для ручных инструментов, см. 25.73;
- производство электрического ручного паяльного и сварочного оборудования, см. 27.90');
INSERT INTO "public"."okved_2" VALUES ('28.25', '28.2', 'C', 'Производство промышленного холодильного и вентиляционного оборудования', 'Эта группировка включает:
- производство холодильного или замораживающего промышленного оборудования, включая комплектующие элементы и части для них;
- производство машин для кондиционирования воздуха, включая кондиционеры для автомашин;
- производство небытовых вентиляторов;
- производство теплообменных устройств;
- производство машин для сжижения воздуха или газов;
- производство потолочных вентиляторов (фронтальных вентиляторов и т. д.)

Эта группировка не включает:
- производство бытового холодильного или морозильного оборудования, см. 27.51;
- производство бытовых вентиляторов, см. 27.51');
INSERT INTO "public"."okved_2" VALUES ('28.25.1', '28.25', 'C', 'Производство теплообменных устройств, оборудования для кондиционирования воздуха промышленного холодильного и морозильного оборудования, производство оборудования для фильтрования и очистки газов', '');
INSERT INTO "public"."okved_2" VALUES ('28.25.11', '28.25.1', 'C', 'Производство теплообменных устройств и машин для сжижения воздуха или прочих газов', '');
INSERT INTO "public"."okved_2" VALUES ('28.25.12', '28.25.1', 'C', 'Производство оборудования для кондиционирования воздуха', '');
INSERT INTO "public"."okved_2" VALUES ('28.25.13', '28.25.1', 'C', 'Производство промышленного холодильного и морозильного оборудования', '');
INSERT INTO "public"."okved_2" VALUES ('28.25.14', '28.25.1', 'C', 'Производство оборудования для фильтрования и очистки газов', '');
INSERT INTO "public"."okved_2" VALUES ('28.25.2', '28.25', 'C', 'Производство вентиляторов', '');
INSERT INTO "public"."okved_2" VALUES ('28.29', '28.2', 'C', 'Производство прочих машин и оборудования общего назначения, не включенного в другие группировки', 'Эта группировка включает:
- производство весов (кроме чувствительных лабораторных весов): бытовых и магазинных весов, платформенных весов, мостовых весов, разновесов и т. д.;
- производство оборудования для фильтрования и очистки жидкостей;
- производство оборудования для рассеивания, разбрызгивания или распыления жидкости или порошка: краскопульты, огнетушители, пескоструйные машины, пароструйные моечные установки и т. д.;
- производство фасовочного и упаковочного оборудования: заполняющие, запечатывающие, штемпелевальные, навинчивающие пробки, маркировочные машины и т. д.;
- производство машин для мойки и сушки бутылок и газирования напитков;
- производство очистительных или перегонных аппаратов для нефтеперегонных заводов, химической промышленности, производства напитков и т. д.;
- производство газовых генераторов;
- производство каландров и прочих роликовых механизмов и цилиндров (кроме машин для обработки металла и стекла);
-производство центрифуг (кроме молочных сепараторов и сушилок для одежды);
- производство прокладок и подобных изделий, сделанных из сочетания материалов или нескольких слоев того же самого материала;
- производство торговых автоматов');
INSERT INTO "public"."okved_2" VALUES ('28.29.1', '28.29', 'C', 'Производство газогенераторов, аппаратов для дистилляции и фильтрования', '');
