INSERT INTO "public"."okved_2" VALUES ('28.30.81', '28.30.8', 'C', 'Производство машин для очистки, сортировки или калибровки яиц, фруктов или прочих сельскохозяйственных продуктов, кроме семян, зерна или сухих бобовых культур', '');
INSERT INTO "public"."okved_2" VALUES ('28.30.82', '28.30.8', 'C', 'Производство доильных аппаратов', '');
INSERT INTO "public"."okved_2" VALUES ('28.30.83', '28.30.8', 'C', 'Производство оборудования для приготовления кормов для животных', '');
INSERT INTO "public"."okved_2" VALUES ('28.30.84', '28.30.8', 'C', 'Производство инкубаторов и брудеров для птицеводства', '');
INSERT INTO "public"."okved_2" VALUES ('28.30.85', '28.30.8', 'C', 'Производство машин и оборудования для содержания птицы', '');
INSERT INTO "public"."okved_2" VALUES ('28.30.89', '28.30.8', 'C', 'Производство прочих машин и оборудования для сельского хозяйства, садоводства, птицеводства или пчеловодства, не включенных в другие группировки', 'Производство прочих машин и оборудования для сельского хозяйства, садоводства, птицеводства или пчеловодства, не включенных в другие группировки');
INSERT INTO "public"."okved_2" VALUES ('28.4', '28', 'C', 'Производство станков, машин и оборудования для обработки металлов и прочих твердых материалов', 'Эта группировка включает:
- производство машин и оборудования для обработки металлов, например производство станков для механической обработки металлов и прочих материалов (древесины, кости, камня, твердой резины, твердой пластмассы, холодного стеклаи т. д.), включая оборудование, использующее лазерные лучи, ультразвуковые волны, плазменную дугу, магнитные импульсы и т. д.');
INSERT INTO "public"."okved_2" VALUES ('28.41', '28.4', 'C', 'Производство металлообрабатывающего оборудования', 'Эта группировка включает:
- производство станков для обработки металлов, включая станки с использованием лазерных лучей, ультразвуковых волн, плазменных дуг, магнитных импульсов и т. д.;
- производство станков для обточки, шлифовки, заточки, вальцовки, проката, строгания, сверления и т. д.;
- производство штамповочных или прессовочных станков;
- производство вырубных прессов, гидравлических прессов, гидравлических тормозов, отбойных молотков, горизонтально-ковочных машин и т. д.;
- производствоволочильных станков, прокатных станов или машин для производства проволоки

Эта группировка не включает:
- производство запасных инструментов, см. 25.73;
- производство электрических машин для сварки и пайки, см. 27.90');
INSERT INTO "public"."okved_2" VALUES ('28.41.1', '28.41', 'C', 'Производство металлообрабатывающих станков', '');
INSERT INTO "public"."okved_2" VALUES ('28.41.2', '28.41', 'C', 'Производство кузнечно-прессового оборудования', '');
INSERT INTO "public"."okved_2" VALUES ('28.92.3', '28.92', 'C', 'Производство прочих машин для выемки грунта', '');
INSERT INTO "public"."okved_2" VALUES ('45.20.2', '45.20', 'G', 'Техническое обслуживание и ремонт прочих автотранспортных средств', '');
INSERT INTO "public"."okved_2" VALUES ('28.49', '28.4', 'C', 'Производство прочих станков', 'Эта группировка включает:
- производство станков для обработки древесины, кости, камня, твердой резины, твердой пластмассы, холодного стекла и т. д., включая аппаратуру, использующую лазерные лучи, ультразвуковые волны, плазменную дугу, магнитные импульсы и т. д.;
- производство держателей для рабочих частей станков;
- производство делительных головок и прочих специализированных деталей станков;
- производство стационарных машин для прибивания, соединения скобами, склеивания или иной сборки деталей из древесины, пробки, кости, твердой резины или пластмассы и т. д.;
- производство постоянных ротационных или роторно-вращательных забойных двигателей, клепальных машин, резаков для листового металла и т. д.;
- производство станков для изготовления древесностружечных плит и т. п.;
- производство станков для нанесения гальванопокрытия

Эта группировка также включает:
- производство деталей и сопутствующих частей для перечисленных станков

Эта группировка не включает:
- производство сменных инструментов для станков (сверл, пробойников, метчиков, резцов, фрез, инструментов для обточки, полотен пил, ножей и т. д.), см. 25.73;
- производство электрических ручных паяльников и паяльных горелок, см. 27.90;
- производство ручных инструментов с механическим приводом, см. 28.24;
- производство машин, используемых на металлургических или литейных заводах, см. 28.91;
- производство машин для горнодобывающей промышленности и карьерных работ, см. 28.92');
INSERT INTO "public"."okved_2" VALUES ('28.49.1', '28.49', 'C', 'Производство станков для обработки камня, дерева и аналогичных твердых материалов', '');
