INSERT INTO "public"."okved_2" VALUES ('28.49.2', '28.49', 'C', 'Производство оборудования для нанесения гальванического покрытия', '');
INSERT INTO "public"."okved_2" VALUES ('28.49.3', '28.49', 'C', 'Производство оправок для крепления инструмента', '');
INSERT INTO "public"."okved_2" VALUES ('28.49.4', '28.49', 'C', 'Производство делительных головок и прочих специальных приспособлений для станков', '');
INSERT INTO "public"."okved_2" VALUES ('28.9', '28', 'C', 'Производство прочих машин специального назначения', 'Эта группировка включает:
- производство машин специального назначения, т. е. машин для индивидуального использования в промышленности или небольших группах промышленности
В то время как большинство вышеприведенных машин используется для широкого круга производственных процессов, таких как производство пищевых продуктов или текстиля

Эта группировка также включает:
- виды деятельности по производству машин, характерных для прочих целей (не для промышленных производств), таких как авиационное, навигационное оборудование или оборудование для аттракционов и игровых автоматов');
INSERT INTO "public"."okved_2" VALUES ('28.91', '28.9', 'C', 'Производство машин и оборудования для металлургии', 'Эта группировка включает:
- производство машин и оборудования для обработки горячего металла: конвертеров, изложниц, ковшей, литейных машин;
- производство прокатных станов и валков для них

Эта группировка не включает:
- производство волочильных станов, см. 28.41;
- производство оборудования для отливок и литейных форм (кроме изложниц), см. 25.73;
- производство оборудования для изготовления литейных форм, см. 28.99');
