INSERT INTO "public"."okved_2" VALUES ('29', 'C', 'C', 'Производство автотранспортных средств, прицепов и полуприцепов', 'Эта группировка включает:
- производство автотранспортных средств для перевозки пассажиров или грузов

Эта группировка также включает:
- производство различных комплектующих и принадлежностей, производство трейлеров и полуприцепов

Эта группировка не включает:
- техническое обслуживание, содержание и ремонт автотранспортных средств, см. 45.20');
INSERT INTO "public"."okved_2" VALUES ('29.1', '29', 'C', 'Производство автотранспортных средств', '');
INSERT INTO "public"."okved_2" VALUES ('29.10', '29.1', 'C', 'Производство автотранспортных средств', 'Эта группировка включает:
- производство легковых автомобилей;
- производство грузовых автомобилей в виде фургонов, грузовиков, внедорожных тягачей для полуприцепов и т. п.;
- производство автобусов, троллейбусов и пассажирских вагонов;
- производство двигателей для автотранспортных средств;
- производство шасси для автотранспортных средств;
- производство прочих автотранспортных средств: снегоходов, гольф-каров, наземно-водных автотранспортных средств, пожарных машин, машин для уборки улиц и дорог, мобильных библиотек, бронированных автомобилей и т. д., грузовиков с автобетономешалками;
- производство вездеходов, картов и прочих машин этого вида, включая гоночные

Эта группировка также включает:
- капитальный заводской ремонт двигателей дляавтотранспортных средств');
INSERT INTO "public"."okved_2" VALUES ('29.10.1', '29.10', 'C', 'Производство двигателей внутреннего сгорания автотранспортных средств', '');
