INSERT INTO "public"."okved_2" VALUES ('29.10.4', '29.10', 'C', 'Производство грузовых автомобилей', '');
INSERT INTO "public"."okved_2" VALUES ('29.10.5', '29.10', 'C', 'Производство автомобилей специального назначения', '');
INSERT INTO "public"."okved_2" VALUES ('29.2', '29', 'C', 'Производство кузовов для автотранспортных средств; производство прицепов и полуприцепов', '');
INSERT INTO "public"."okved_2" VALUES ('29.20', '29.2', 'C', 'Производство кузовов для автотранспортных средств; производство прицепов и полуприцепов', 'Эта группировка включает:
- производство автомобильных кузовов, включая кабины для водителей;
- оснащение всех типов автотранспортных средств, трейлеров и полуприцепов;
- производство трейлеров и полуприцепов: цистерн, отсоединяемых прицепов, фургонов и т. п.;
- производство грузовых контейнеров для перевозки одним или несколькими видами транспорта

Эта группировка не включает:
- производство прицепов и полуприцепов, специально разработанных для использования в сельском хозяйстве, см. 28.30;
- производство запасных частей и принадлежностей для автотранспортных средств, см. 29.32;
- производство транспортных средств, приводимых в движение при использовании животных в качестве тягловой силы, см. 30.99');
INSERT INTO "public"."okved_2" VALUES ('29.20.1', '29.20', 'C', 'Производство кузовов для легковых автомобилей', '');
INSERT INTO "public"."okved_2" VALUES ('29.20.2', '29.20', 'C', 'Производство кузовов для грузовых автомобилей', '');
