INSERT INTO "public"."okved_2" VALUES ('29.31', '29.3', 'C', 'Производство электрического и электронного оборудования для автотранспортных средств', 'Эта группировка включает:
- производство электрического оборудования для транспортных средств, такого как генераторы, генераторы переменного тока, свечи зажигания, электропроводки системы зажигания, системы автоматического открывания/закрывания окони дверей, регуляторы напряжения и т. п.

Эта группировка не включает:
- производство батарей для транспортных средств, см. 27.20;
- производство осветительного оборудования для автотранспортных средств, см. 27.40;
- производство насосов для автотранспортных средств и двигателей, см. 28.13');
INSERT INTO "public"."okved_2" VALUES ('29.32', '29.3', 'C', 'Производство прочих комплектующих и принадлежностей для автотранспортных средств', 'Эта группировка включает:
- производство различных комплектующих и принадлежностей для автотранспортных средств: тормозов, коробок передач, осей, ходовых колес, амортизаторов, радиаторов, глушителей, выхлопных труб, каталитических дожигателей выхлопных газов, муфт сцеплений, рулевых колес, рулевых колонок, рулевых приводов;
- производство комплектующих и аксессуаров для кузовов автотранспортных средств: ремней безопасности, воздушных подушек, дверей, бамперов;
- производство сидений для автомобилей

Эта группировка не включает:
- производство шин, см. 22.11;
- производство резиновых шлангов и ремней и прочих резиновых изделий, см. 22.19;
- производство клапанов, поршневых колец и карбюраторов, см. 28.11;
- обслуживание, ремонт и переоборудование автотранспортных средств, см. 45.20');
INSERT INTO "public"."okved_2" VALUES ('29.32.1', '29.32', 'C', 'Производство сидений для автотранспортных средств', '');
INSERT INTO "public"."okved_2" VALUES ('29.32.2', '29.32', 'C', 'Производство ремней безопасности, подушек безопасности, их частей и принадлежностей кузовов', '');
INSERT INTO "public"."okved_2" VALUES ('29.32.3', '29.32', 'C', 'Производство частей и принадлежностей для автотранспортных средств, не включенных в другие группировки', '');
INSERT INTO "public"."okved_2" VALUES ('30', 'C', 'C', 'Производство прочих транспортных средств и оборудования', 'Эта группировка включает:
- строительство транспортных средств, таких как корабли и суда, лодки;
- производство железнодорожных составов и локомотивов, воздушных и космических судов и комплектующих изделий');
INSERT INTO "public"."okved_2" VALUES ('30.1', '30', 'C', 'Строительство кораблей, судов и лодок', 'Эта группировка включает:
- строительство кораблей, судов, лодок и прочих плавучих сооружений для транспортировки и прочих коммерческих целей, а также для спорта и отдыха');
INSERT INTO "public"."okved_2" VALUES ('30.11', '30.1', 'C', 'Строительство кораблей, судов и плавучих конструкций', 'Эта группировка включает:
- строительство кораблей, судов и плавучих конструкций

Эта группировка включает:
- строительство кораблей;
- строительство судов: пассажирских, грузовых, танкеров, ледоколов, газовозов, рефрижераторов, буксиров, толкачей и т. д.;
- строительство судов для добычи (вылова) рыбы и перерабатывающих плавучих рыбозаводов;
- строительство транспортных средств на воздушной подушке, за исключением судов для спорта и отдыха;
- строительство подводных аппаратов: спасательных, исследовательских и специального назначения;
- строительство буровых платформ, плавучих или расположенных на воде;
- строительство плавсредств: плавучих доков, понтонов, кессонов для подводных работ, плавучих или наземных пристаней, бакенов, плавучих резервуаров, барж, маяков, плавучих кранов, надувных плотов, не предназначенных для целей отдыха и т. д.;
- строительство морских плавучих платформ и конструкций для подготовки к пуску и запуска ракет космического назначения (морской старт);
- производство составных частей конструкций корпусов кораблей, судов и плавсредств;
- строительство судов технического флота (землеснаряды, землесосы и т. д.)

Эта группировка также включает:
- ремонт и техническое обслуживание судов в заводских условиях

Эта группировка не включает:
- производство комплектующих изделий для судов: производство парусов, см. 13.92;
- производство судовых винтов и лопастей, см. 25.99;
- производство железных или стальных якорей, см. 25.99;
- производство судовых двигателей, см.28.11;
- производство навигационного оборудования для судов, см. 26.51;
- производство осветительного оборудования для судов, см. 27.40;
- производство наземно-водных автотранспортных средств, см. 29.10;
- производство надувных плотов и лодок для спорта и отдыха, см. 30.12;
- специализированный ремонт, технический уход и содержание кораблей, судов и плавучих конструкций, см. 33.15;
- демонтаж кораблей и судов, см. 38.31');
INSERT INTO "public"."okved_2" VALUES ('30.12', '30.1', 'C', 'Строительство прогулочных и спортивных судов', 'Эта группировка включает:
- производство надувных плотов и лодок;
- строительство парусных лодок и яхт со вспомогательным двигателем или без вспомогательного двигателя;
- строительство моторных яхт и лодок;
- строительство скоростных судов для отдыха, в том числе на воздушной подушке;
- производство плавсредств по индивидуальным проектам;
- производство прочих спортивных и прогулочных лодок, включая каноэ, катамараны, байдарки, гребные лодки, плоскодонные гребные лодки

Эта группировка не включает:
- производство частей прогулочных и спортивных лодок: парусов, см. 13.92;
- производство железных или стальных якорей, см. 25.99;
- производство двигателей для морских транспортных средств, см. 28.11;
- производство парусных досок и досок для серфинга, см. 32.30;
- обслуживание и ремонт прогулочных судов, см. 33.15');
INSERT INTO "public"."okved_2" VALUES ('30.2', '30', 'C', 'Производство железнодорожных локомотивов и подвижного состава', '');
INSERT INTO "public"."okved_2" VALUES ('32.99.8', '32.99', 'C', 'Производство изделий народных художественных промыслов', '');
INSERT INTO "public"."okved_2" VALUES ('32.99.9', '32.99', 'C', 'Производство прочих изделий, не включенных в другие группировки', '');
INSERT INTO "public"."okved_2" VALUES ('35.22.12', '35.22.1', 'D', 'Распределение природного, сухого (отбензиненного) газа по газораспределительным сетям по тарифам, не регулируемым государством', '');
INSERT INTO "public"."okved_2" VALUES ('30.20', '30.2', 'C', 'Производство железнодорожных локомотивов и подвижного состава', 'Эта группировка включает:
- производство электро-, дизельных, паровых и прочих железнодорожных локомотивов;
- производство самодвижущихся железнодорожных или трамвайных вагонов, фургонов и грузовиков, транспортных средств для обслуживания;
- производство железнодорожных или трамвайных подвижных составов, несамодвижущихся: пассажирских, грузовых вагонов, вагонов-цистерн, самодвижущихся вагонов, товарных вагонов, крановых платформ, цистерн для перевозки горючих материалов и т. д.;
- производство специализированных комплектующих для железнодорожных или трамвайных локомотивов или подвижных составов: валов, осей, шпинделей, колес, тормозов и комплектующих для них, рычагов, муфт и соединяющих устройств, буферов и комплектующих, амортизаторов, оснований фургонов и локомотивов, кузовов, коридорных соединений и т. д.

Эта группировка также включает:
- производство рельсовых тележек и локомотивов для горнодобывающей промышленности;
- производство механического и электромеханического сигнального оборудования, оборудования для контроля безопасности и для управления движением на железнодорожных, трамвайных, внутренних водных путях, автотрассах, парковках, летных полях и т. д.;
- производство сидений для железнодорожных вагонов');
INSERT INTO "public"."okved_2" VALUES ('30.20.1', '30.20', 'C', 'Производство железнодорожных локомотивов', '');
