INSERT INTO "public"."okved_2" VALUES ('30.20.32', '30.20.3', 'C', 'Производство немоторных пассажирских железнодорожных, трамвайных вагонов и вагонов метро, багажных, почтовых и прочих вагонов специального назначения, кроме вагонов, предназначенных для ремонта и технического обслуживания путей', '');
INSERT INTO "public"."okved_2" VALUES ('30.20.33', '30.20.3', 'C', 'Производство несамоходных железнодорожных, трамвайных и прочих вагонов для перевозки грузов', '');
INSERT INTO "public"."okved_2" VALUES ('30.20.4', '30.20', 'C', 'Производство частей железнодорожных локомотивов, трамвайных и прочих моторных вагонов и подвижного состава; производство путевого оборудования и устройств для железнодорожных, трамвайных и прочих путей, механического и электромеханического оборудован ия для управления движением', '');
INSERT INTO "public"."okved_2" VALUES ('30.20.9', '30.20', 'C', 'Предоставление услуг по восстановлению и оснащению (завершению) железнодорожных локомотивов, трамвайных моторных вагонов и прочего подвижного состава', '');
INSERT INTO "public"."okved_2" VALUES ('30.3', '30', 'C', 'Производство летательных аппаратов, включая космические, и соответствующего оборудования', '');
INSERT INTO "public"."okved_2" VALUES ('30.30', '30.3', 'C', 'Производство летательных аппаратов, включая космические, и соответствующего оборудования', 'Эта группировка включает:
- производство самолетов для перевозки грузов или пассажиров, для использования в целях обороны, спортивных или прочих целях;
- производство вертолетов;
- производство планеров, дельтапланов;
- производство воздухоплавательных аппаратов (дирижаблей, аэростатов, шаров-зондов);
- производство беспилотных комплексов и летательных аппаратов;
- производство комплектующих и принадлежностей для воздушных судов данного класса: основных комплектующих, таких как, фюзеляжи, крылья, двери, рули управления/штурвалы, шасси, баки для горючего, открытые кабины самолетов и т. д., пропеллеров, моторов вертолетов и лопастей пропеллеров, типичных моторов и двигателей для воздушных судов, комплектующих для турбореактивных и турбовинтовых воздушных судов;
- производство наземных летательных тренажеров;
- производство пусковых летательных аппаратов, искусственных спутников, планетарных зондов, орбитальных станций, челноков;
- производство оборудования стартовых комплексов для ракетной и космической техники;
- производство межконтинентальных баллистических ракет

Эта группировка также включает:
- капитальный ремонт и реконструкцию летательных аппаратов и их двигателей;
- производство сидений для летательных аппаратов

Эта группировка не включает:
- производство парашютов, см. 13.92;
- производство боевого оружия и боеприпасов, см. 25.40;
- производство оборудования связи для спутников, см. 26.30;
- производство инструментовки для самолета и аэронавигационных инструментов, см.26.51;
- производство воздушных навигационных систем, см. 26.51;
- производство осветительного оборудования для самолетов, см. 27.40;
- производство двигателей для летательных аппаратов и прочих электрических частей для двигателей внутреннего сгорания, см. 27.90;
- производство поршней, поршневых колец и карбюраторов, см. 28.11;
- производство пускового механизма самолета, катапульты авианосца и похожих устройств, см. 28.99');
INSERT INTO "public"."okved_2" VALUES ('30.30.1', '30.30', 'C', 'Производство силовых установок и двигателей для летательных аппаратов, включая космические; наземных тренажеров для летного состава; их частей', '');
