INSERT INTO "public"."okved_2" VALUES ('30.30.14', '30.30.1', 'C', 'Производство наземных тренажеров для летного состава и их частей', '');
INSERT INTO "public"."okved_2" VALUES ('30.30.2', '30.30', 'C', 'Производство аэростатов, дирижаблей, планеров, дельтапланов и прочих безмоторных летательных аппаратов', '');
INSERT INTO "public"."okved_2" VALUES ('30.30.3', '30.30', 'C', 'Производство вертолетов, самолетов и прочих летательных аппаратов', '');
INSERT INTO "public"."okved_2" VALUES ('30.30.31', '30.30.3', 'C', 'Производство вертолетов', '');
