INSERT INTO "public"."okved_2" VALUES ('30.30.39', '30.30.3', 'C', 'Производство прочих летательных аппаратов', '');
INSERT INTO "public"."okved_2" VALUES ('30.30.4', '30.30', 'C', 'Производство космических аппаратов (в том числе спутников), ракет-носителей', '');
INSERT INTO "public"."okved_2" VALUES ('30.30.41', '30.30.4', 'C', 'Производство автоматических космических аппаратов', '');
INSERT INTO "public"."okved_2" VALUES ('30.30.42', '30.30.4', 'C', 'Производство пилотируемых и беспилотных космических кораблей и станций, включая орбитальные, межпланетные, многоразового использования', '');
INSERT INTO "public"."okved_2" VALUES ('30.30.43', '30.30.4', 'C', 'Производство ракет-носителей', '');
INSERT INTO "public"."okved_2" VALUES ('30.40', '30.4', 'C', 'Производство военных боевых машин', 'Эта группировка включает:
- производство гусеничных и колесных машин (танков, боевых машин пехоты и десанта, гусеничных БТР, бронемашин и др.);
- производство бронированных наземно-водных военных транспортных средств;
- производство прочих военных боевых транспортных средств

Эта группировка не включает:
- производство оружия и боеприпасов, см. 25.40');
INSERT INTO "public"."okved_2" VALUES ('30.9', '30', 'C', 'Производство транспортных средств и оборудования, не включенных в другие группировки', 'Эта группировка включает:
- производство транспортного оборудования, кроме автомобильного и рельсового, водного, воздушного или космического транспортного оборудования и военных транспортных средств');
INSERT INTO "public"."okved_2" VALUES ('30.91', '30.9', 'C', 'Производство мотоциклов', 'Эта группировка включает:
- производство мотоциклов, мопедов и прочих подобных транспортных средств со вспомогательным двигателем;
- производство двигателей для мотоциклов;
- производство колясок для мотоциклов;
- производство комплектующих и принадлежностей для мотоциклов

Эта группировка не включает:
- производство велосипедов, см. 30.92;
- производство инвалидных колясок, см. 30.92');
INSERT INTO "public"."okved_2" VALUES ('30.92', '30.9', 'C', 'Производство велосипедов и инвалидных колясок', 'Эта группировка включает:
- производство немоторизированных велосипедов и прочих подобных транспортных средств, включая трехколесные велосипеды, тандемы, детские велосипеды и трехколесные велосипеды;
- производство деталей и запасных частей для велосипедов;
- производство инвалидных колясок с двигателем или без двигателя;
- производство деталей и запасных частей для инвалидных колясок;
- производство детских колясок

Эта группировка не включает:
- производство велосипедов со вспомогательным двигателем, см. 30.91;
- производство игрушек с колесами, предназначенных для езды, включая пластмассовые велосипеды и трехколесные велосипеды, см. 32.40');
INSERT INTO "public"."okved_2" VALUES ('30.92.1', '30.92', 'C', 'Производство велосипедов', '');
INSERT INTO "public"."okved_2" VALUES ('30.92.2', '30.92', 'C', 'Производство инвалидных колясок', '');
INSERT INTO "public"."okved_2" VALUES ('30.92.3', '30.92', 'C', 'Производство частей и принадлежности велосипедов и инвалидных колясок', '');
INSERT INTO "public"."okved_2" VALUES ('30.92.4', '30.92', 'C', 'Производство детских колясок и их частей', '');
INSERT INTO "public"."okved_2" VALUES ('30.99', '30.9', 'C', 'Производство прочих транспортных средств и оборудования, не включенных в другие группировки', 'Эта группировка включает:
- производство транспортных средств с ручным управлением: багажных грузовых средств, ручных тележек, саней, тележек для покупок в универсамах и т. д.;
- производство транспортных средств, управляемых животными: одноместных двуколок, повозок, катафалков и т. д.

Эта группировка не включает:
- производство тележек, имеющих или не имеющих подъемные устройства или погрузочноразгрузочные устройства, самодвижущихся или нет, которые используются на заводах (включая ручные тележки и тачки), см. 28.22;
- производство декоративных тележек-подносов для ресторанов, тележек для супермаркетов, см. 31.01');
INSERT INTO "public"."okved_2" VALUES ('31', 'C', 'C', 'Производство мебели', 'Эта группировка включает:
- производство мебели и соответствующих изделий из любых материалов, за исключением камня, бетона и керамики
Технология производства мебели заключается в использовании стандартных методов формовки материалов и сборки компонентов, включая резку, прессовку и ламинирование. Важным аспектом производственного процесса является разработка изделий с учетом их эстетических и функциональных характеристик. Некоторые из процессов, используемых в производстве мебели, подобны процессам, которые используются в прочих видах производств. Например, фрезерование и сборка происходят и при производстве деревянных связок, изготовление которых включено в группировку 16. Однако производство деревянной мебели от производства изделий из дерева отличает множество процессов. Точно также при производстве металлической мебели используются технологии, которые также используются в производстве строительных конструкций, включенных в группировку 25. Процесс изготовления пластиковой мебели подобен процессу формовки прочих пластиковых изделий. Однако изготовление мебели из пластмасс является более специализированным видом производства');
INSERT INTO "public"."okved_2" VALUES ('31.0', '31', 'C', 'Производство мебели', '');
INSERT INTO "public"."okved_2" VALUES ('31.01', '31.0', 'C', 'Производство мебели для офисов и предприятий торговли', 'Эта группировка включает:
- производство мебели различного назначения из широкого круга материалов (кроме камня, бетона или керамики)

Эта группировка включает:
- производство стульев и сидений для офисов, рабочих помещений, гостиниц, ресторанов и общественных помещений;
- производство стульев и сидений для театров, кинотеатров и прочих зрелищных заведений;
- производство специальной мебели для магазинов: касс, витрин, полок и т. д.;
- производство офисной мебели;
- производство скамей, табуретов, шкафов и столов для лабораторий и прочей лабораторной мебели;
- производство мебели для церквей, школ, ресторанов

Эта группировка также включает:
- производство декоративных тележек для ресторанов, таких как тележки под десерт, пищевые фургоны
Этагруппировка не включает:
- производство школьных досок, см. 28.23;
- производство автомобильных сидений, см. 29.32;
- производство сидений для железнодорожных вагонов, см. 30.20;
- производство сидений для самолетов, см. 30.30;
- производство медицинской мебели, включая мебель для хирургии, стоматологии или ветеринарии, см. 32.50;
- установку модульной мебели и перегородок, установку лабораторного мебельного оборудования, см. 43.32');
INSERT INTO "public"."okved_2" VALUES ('31.02', '31.0', 'C', 'Производство кухонной мебели', 'Эта группировка включает:
- производство кухонной мебели;
- изготовление кухонной мебели по индивидуальным заказам населения');
INSERT INTO "public"."okved_2" VALUES ('35.22.2', '35.22', 'D', 'Распределение сжиженных углеводородных газов по газораспределительным сетям', '');
INSERT INTO "public"."okved_2" VALUES ('45.20.3', '45.20', 'G', 'Мойка автотранспортных средств, полирование и предоставление аналогичных услуг', '');
INSERT INTO "public"."okved_2" VALUES ('31.03', '31.0', 'C', 'Производство матрасов', 'Эта группировка включает:
- производство матрасов: пружинных, набивных или отделанных снаружи поддерживающим материалом, из пористой резины или пенопластовых матрасов;
- производство поддерживающих материалов для матрасов

Эта группировка не включает:
- производство надувных резиновых матрасов, см. 22.19;
- производство резиновых матрасов, наполненных водой, см. 22.19');
INSERT INTO "public"."okved_2" VALUES ('31.09', '31.0', 'C', 'Производство прочей мебели', 'Эта группировка включает:
- производство диванов, диванов-кроватей и диванных наборов;
- производство садовых стульев и сидений;
- производство мебели для спален, гостиных комнат, садов и т.д.;
- производство корпусов для швейных машин, телевизоров и т.д.;
- производство мебели лабораторной для работы с радиоактивными веществами

Эта группировка также включает:
- отделку, такую как обивка стульев и сидений;
- отделку мебели, такую как напыление, роспись, полировка и обивка');
INSERT INTO "public"."okved_2" VALUES ('32', 'C', 'C', 'Производство прочих готовых изделий', 'Эта группировка включает:
- производство различных товаров, не вошедших в другие группировки
Так как это остаточная группировка, то перечисленные в этой группировке процессы производства, исходные материалы и использование произведенных товаров могутшироко варьироваться, в ней не применимо обычное деление на группировки');
INSERT INTO "public"."okved_2" VALUES ('32.1', '32', 'C', 'Производство ювелирных изделий, бижутерии и подобных товаров', 'Эта группировка включает:
- производство ювелирных изделий и искусственных ювелирных украшений;
- изготовление ювелирных изделий и аналогичных изделий по индивидуальному заказу населения');
INSERT INTO "public"."okved_2" VALUES ('32.11', '32.1', 'C', 'Чеканка монет', 'Эта группировка включает:
- производство монет, включая монеты, используемые в качестве платежного средства, из драгоценных металлов или из недрагоценных металлов');
INSERT INTO "public"."okved_2" VALUES ('32.12', '32.1', 'C', 'Производство ювелирных изделий и аналогичных изделий', 'Эта группировка включает:
- производство обработанных жемчужин;
- производство драгоценных и полудрагоценных камней в обработанном виде, включая производство камней промышленного качества, синтетических или восстановленных драгоценных или полудрагоценных камней;
- обработку алмазов;
- производство ювелирных украшений из драгоценных металлов или основных компонентов сплава из драгоценных металлов или со вставкой драгоценных или полудрагоценных камней или сочетания драгоценного металла и драгоценных или полудрагоценных камней или прочих подобных материалов;
- производство изделий из основных компонентов сплава из драгоценных металлов, таких как: столовая посуда, столовые приборы и утварь, туалетные принадлежности, офисные и письменные принадлежности, предметы для религиозных обрядов и т.д.;
- производство технических или лабораторных изделий из сплавов, включающих драгоценные металлы (кроме инструментов и их деталей): литейных форм, лопаточек, ванночек со слоем металла, нанесенным гальваническим способом и т.д.;
- производство ремешков из металла, браслетов, часовых ремешков и портсигаров из драгоценных металлов;
- изготовление ювелирных изделий и аналогичных изделий по индивидуальному заказу населения

Эта группировка также включает:
- гравировку изделий личного туалета из драгоценных и недрагоценных металлов');
INSERT INTO "public"."okved_2" VALUES ('32.12.1', '32.12', 'C', 'Производство изделий технического назначения из драгоценных металлов', '');
INSERT INTO "public"."okved_2" VALUES ('32.12.2', '32.12', 'C', 'Производство изделий технического назначения из драгоценных камней', '');
INSERT INTO "public"."okved_2" VALUES ('32.12.3', '32.12', 'C', 'Обработка алмазов', '');
INSERT INTO "public"."okved_2" VALUES ('32.12.4', '32.12', 'C', 'Обработка драгоценных, полудрагоценных, поделочных и синтетических камней, кроме алмазов и янтаря; производство изделий из полудрагоценных, поделочных и синтетических камней, кроме янтаря', '');
INSERT INTO "public"."okved_2" VALUES ('32.12.5', '32.12', 'C', 'Производство ювелирных изделий, медалей из драгоценных металлов и драгоценных камней', '');
INSERT INTO "public"."okved_2" VALUES ('32.13', '32.1', 'C', 'Производство бижутерии и подобных товаров', 'Эта группировка включает:
- производство украшений для одежды и бижутерии: колец, ожерелий, браслетов и подобных украшений, сделанных из основного сплава и с покрытием из драгоценных металлов, украшений, содержащих искусственные камни, такие как искусственные драгоценные камни, искусственные бриллианты и подобные;
- производство металлических браслетов для часов (кроме браслетов из драгоценных металлов);
- изготовление бижутерии, подобных товаров, металлических браслетов для часов (кроме браслетов из драгоценных металлов) по индивидуальному заказу населения

Эта группировка не включает:
- производство украшений из драгоценных металлов или покрытых драгоценными металлами, см. 32.12;
- производство ювелирных украшений, содержащих настоящие драгоценные камни, см. 32.12;
- производство браслетов для часов из драгоценных металлов, см. 32.12');
INSERT INTO "public"."okved_2" VALUES ('32.2', '32', 'C', 'Производство музыкальных инструментов', '');
INSERT INTO "public"."okved_2" VALUES ('35.22', '35.2', 'D', 'Распределение газообразного топлива по газораспределительным сетям', 'Эта группировка включает:
- распределение газообразного топлива всех видов по газораспределительным сетям

Эта группировка не включает:
- транспортировку газа (на дальние расстояние) по трубопроводам, см. 49.50');
INSERT INTO "public"."okved_2" VALUES ('35.22.1', '35.22', 'D', 'Распределение природного, сухого (отбензиненного) газа по газораспределительным сетям', '');
INSERT INTO "public"."okved_2" VALUES ('46.11.1', '46.11', 'G', 'Деятельность агентов по оптовой торговле живыми животными', '');
INSERT INTO "public"."okved_2" VALUES ('32.20', '32.2', 'C', 'Производство музыкальных инструментов', 'Эта группировка включает:
- производство струнных инструментов;
- производство клавишных инструментов, включая электронные пианино;
- производство клавишных органов, включая фисгармонии и подобные клавишные инструменты с проскакивающими металлическими язычками;
- производство аккордеонов и подобных инструментов, включая губные гармошки;
- производство духовых инструментов;
- производство ударных музыкальных инструментов;
- производство электромузыкальных инструментов;
- производство музыкальныхшкатулок, шарманок, каллиоп и т. д.;
- производство деталей и составных частей для инструментов, таких как метрономы, камертоны, камертоны-трубки, перфокарты, диски и ролики для механических музыкальных автоматов и т. д.

Эта группировка также включает:
- производство свистков, рупоров, громкоговорителей и прочих инструментов, в которых звуковой сигнал подается голосом

Эта группировка не включает:
- копирование предварительно записанного звука и видеопленок и дисков, см. 18.2;
- производство микрофонов, усилителей, громкоговорителей, наушников и подобных компонентов, см. 26.40;
- производство проигрывателей, магнитофонов и т. п., см. 26.40;
- производство игрушечных музыкальных инструментов, см. 32.40;
- ремонт органов и прочих историческихмузыкальных инструментов, см. 33.19;
- издание предварительно записанного звука на видеопленках и дисках, см. 59.20;
- настройку пианино, см. 95.29');
INSERT INTO "public"."okved_2" VALUES ('32.3', '32', 'C', 'Производство спортивных товаров', '');
INSERT INTO "public"."okved_2" VALUES ('32.30', '32.3', 'C', 'Производство спортивных товаров', 'Эта группировка включает:
- производство спортивного снаряжения и спортивных товаров (кроме одежды и обуви)

Эта группировка включает:
- производство предметов и оборудования для спортивных игр на открытом воздухе и игр в помещении из широкого набораматериалов: твердых, мягких и надувных шаров, ракеток, воланов и теннисных мячей, лыж, креплений и лыжных палок, лыжных ботинок, досок для плавания и для серфинга, рыболовного снаряжения для спортивной рыбалки, включая рыболовные сачки, снаряжения для спортивной охоты и альпинизма и т. д., кожаных перчаток для спортивных состязаний и спортивных головных уборов, бассейнов для плавания и т. д., коньков, включая роликовые коньки т. д., спортивных луков и арбалетов, оборудования для спортивных залов, спортивно-оздоровительных центров или спортплощадок

Эта группировка не включает:
- производство лодочных парусов, см. 13.92;
- производство спортивной одежды, см. 14.19;
- производство конской сбруи, см. 15.12;
- производство хлыстов и шпор для верховой езды, см. 15.12;
- производство спортивной обуви, см. 15.20;
- производство спортивного оружия и боеприпасов, см. 25.40;
- производство металлических блинов и гирь для тяжелой атлетики, см. 25.99;
- производство спортивных транспортных средств,кроме саней и т. п., см. 29, 30;
- производство лодок, см. 30.12;
- производство бильярдных столов, см. 32.40;
- производство наушников (например, для плавания и защиты от шума), см. 32.99;
- ремонт спортивных товаров, см. 95.29');
INSERT INTO "public"."okved_2" VALUES ('32.4', '32', 'C', 'Производство игр и игрушек', '');
INSERT INTO "public"."okved_2" VALUES ('32.40', '32.4', 'C', 'Производство игр и игрушек', 'Эта группировка включает:
- производство кукол, игрушек и игр (включая электронные игры), уменьшенных моделей детских транспортных средств (кроме металлических велосипедов и трехколесных велосипедов)

Эта группировка включает:
- производство кукол и предметов одежды кукол, частей и принадлежностей;
- производство движущихся фигур;
- производство игрушечных животных;
- производство игрушечных музыкальных инструментов;
- производство игральных карт;
- производство настольных и подобных игр;
- производство электронных игр;
- производство уменьшенных моделей, электрических поездов и подобных им, конструкторов и т. п.;
- производство жетонных автоматов, бильярда, специальных столов для игр в казино и т. п.;
- производство автоматов для ярмарок инастольных или комнатных игр;
- производство колесных двигающихся игрушек, включая пластмассовые велосипеды и трехколесные велосипеды;
- производство головоломок и подобных им предметов

Эта группировка не включает:
- производство пультов для видеоигр, см. 26.40;
- производство велосипедов, см. 30.92;
- производство предметов для розыгрышей и сувениров, см. 32.99;
- написание и выпуск компьютерных программ для игровых приставок, см. 58.21, 62.01');
INSERT INTO "public"."okved_2" VALUES ('32.5', '32', 'C', 'Производство медицинских инструментов и оборудования', '');
INSERT INTO "public"."okved_2" VALUES ('32.50', '32.5', 'C', 'Производство медицинских инструментов и оборудования', 'Производство медицинских инструментов и оборудования 
Эта группировка включает: - производство установок для лабораторий, хирургических и медицинских инструментов, хирургических приборов и запасных частей, стоматологического оборудования и расходных м атериалов, ортодонтических товаров, стоматологических и ортодонтических протезов 
Эта группировка включает: - производство медицинской, стоматологической и подобной мебели, где дополнительные специальные функции определяют цель применения продукта, та кого как стоматологические кресла со встроенными гидравлическими функциями; - производство хирургических салфеток и стерильных простыней и бинтов; - производство стоматологических наполнителей и пломб (кроме смеси для зубных протезов), зубного воска и прочих компонентов для изготовления зубных пломб; - производство гипса для восстановления костей; - производство стоматологических лабораторных печей; - производство лабораторных аппаратов для ультразвуковой очистки; - производство лабораторных сте рилизаторов; - производство лабораторных дистилляторов, лабораторных центрифуг; -производство ортопедической обуви (в том числе ортопедической обуви сложной, которая предназначена для людей с нарушениями статодинамических функций, вследствие заболева ний, последствий травм, деформации стоп и голеностопного сустава, аномалий развития нижней конечности и т.д., а также ортопедической обуви малосложной); -производство вкладных корригирующих элементов для ортопедической обуви (в том числе стелек, полу стелек) 
Эта группировка не включает: - производство креплений для зубных протезов, см. 20.42; - производство пропитанного упаковочного материала, бинтов и салфеток, применяемых в медицинских целях; - производство облучающего и электротерапевтического оборудования, применяемого в медицинских целях, см. 21.20, 26.60; - производство инвалидных кресел, см. 30.92; - деятельность оптиков, см. 47.78');
INSERT INTO "public"."okved_2" VALUES ('32.9', '32', 'C', 'Производство изделий, не включенных в другие группировки', '');
INSERT INTO "public"."okved_2" VALUES ('32.91', '32.9', 'C', 'Производство метел и щеток', 'Эта группировка включает:
- производство метел и щеток, включая щетки, являющиеся составными частями машин, ручных механических щеток для пола, швабр, метелок из перьев, малярных кистей, малярных валиков, резиновых скребков, прочих метел, щеток и т.п.;
- производство щеток для одежды и обуви;
- производство зубных щеток');
INSERT INTO "public"."okved_2" VALUES ('32.99', '32.9', 'C', 'Производство прочих готовых изделий, не включенных в другие группировки', 'Эта группировка включает:
- производство оборудования для обеспечения безопасности: производство несгораемой и защитной одежды, привязных ремней для электромонтеров и прочих поясов для профессионального использования, пробковых защитных средств, пластмассовых касок и прочих средств личной безопасности из пластмассы (спортивные шлемы), средств противопожарной защиты, металлических защитных головных уборов и прочих металлических средств личной безопасности, защитных наушников (например, для плавания и защиты от шума);
- производство противогазов;
- производство ручек и карандашей всех видов;
- производство стержней для карандашей;
- производство штемпелей для запечатывания, проставления дат, номеров и оттисков печатей, ручных устройств для печати или печатания ярлыков, ручных печатающих устройств, готовых лент для пишущей машинки и чернильных подушечек;
- производство глобусов;
- производство зонтов, зонтиков от солнца, тростей;
- производство кнопок, кнопочных закрепителей, гвоздиков, застежек-молний;
- производство зажигалок

Эта группировка не включает:
- изготовление фитилей для зажигалок, см. 13.96;
- изготовление рабочей одежды и одежды для сферы услуг (например, лабораторных халатов, рабочих комбинезонов, спецодежды), см. 14.12;
- производство мелких сувениров из бумаги, см. 17.29');
INSERT INTO "public"."okved_2" VALUES ('32.99.1', '32.99', 'C', 'Производство головных защитных уборов и прочих средств защиты', '');
INSERT INTO "public"."okved_2" VALUES ('32.99.2', '32.99', 'C', 'Производство пишущих принадлежностей', '');
INSERT INTO "public"."okved_2" VALUES ('32.99.3', '32.99', 'C', 'Производство зонтов, тростей, пуговиц, кнопок, застежек-молний', '');
INSERT INTO "public"."okved_2" VALUES ('32.99.4', '32.99', 'C', 'Производство изделий из волоса человека или животных; производство аналогичных изделий из текстильных материалов', '');
INSERT INTO "public"."okved_2" VALUES ('32.99.5', '32.99', 'C', 'Производство зажигалок и прочих курительных принадлежностей', '');
INSERT INTO "public"."okved_2" VALUES ('32.99.6', '32.99', 'C', 'Производство изделий для праздников, карнавалов или прочих изделий для увеселения', '');
INSERT INTO "public"."okved_2" VALUES ('32.99.7', '32.99', 'C', 'Производство приборов, аппаратуры и моделей, предназначенных для демонстрационных целей', '');
INSERT INTO "public"."okved_2" VALUES ('33', 'C', 'C', 'Ремонт и монтаж машин и оборудования', 'Эта группировка включает:
- специализированный ремонт изделий, произведенных в промышленном секторе с целью восстановления и введения в эксплуатацию металлических изделий, машин, оборудования и прочих приборов
Данная группировка также включает общееили постоянное обслуживание таких изделий для гарантии их надежной эффективной работы и предотвращения поломок и лишнего ремонта. Данная группировка касается только входящей в эту группировку специализированной деятельности по ремонту и обслуживанию.В значительной степени ремонт также выполняют производители оборудования и других товаров, и в этом случае предметы классифицируются, исходя из принципа добавленной стоимости, вследствие чего такая смешанная деятельность часто присваивается производству товара. Тот же самый принцип применяется при сочетании торговли и ремонта. Восстановление или переборка машин и оборудования считается обрабатывающим производством и включается в прочие разделы данной группировки');
INSERT INTO "public"."okved_2" VALUES ('33.1', '33', 'C', 'Ремонт и монтаж металлических изделий, машин и оборудования', 'Эта группировка включает:
- специализированный ремонт изделий, произведенных в промышленном секторе экономики с целью ремонта и введения в эксплуатацию металлических изделий, машин, оборудования и прочих подобных товаров
В нее включено регламентное или постоянное обслуживание таких изделий по гарантии их надежной эффективной работы и предотвращения поломок

Эта группировка не включает:
- ремонт и заводскую переборку машин и оборудования, см. соответствующие группировки 25-30;
- чистку промышленной аппаратуры, см. 81.22;
- ремонт и техническое обслуживание компьютеров и коммуникационного оборудования, см. 95.1;
- ремонт и обслуживание бытовой техники, см. 95.2');
INSERT INTO "public"."okved_2" VALUES ('33.11', '33.1', 'C', 'Ремонт металлоизделий', 'Эта группировка включает:
- ремонт и обслуживание металлических изделий, перечисленных в группировке 25

Эта группировка включает:
- ремонт металлических резервуаров, бассейнов и контейнеров;
- ремонт и обслуживание труб и трубопроводов;
- ремонт передвижных сварочных установок;
- ремонт стальных тарных барабанов;
- ремонт и обслуживание парогенераторов;
- ремонт и обслуживание вспомогательных двигателей-генераторов для использования с парогенераторами, таких как конденсаторы, кондиционеры, нагреватели, паросборники и аккумуляторы;
- ремонт и обслуживание ядерных реакторов, кроме сепараторов изотопов;
- ремонт и обслуживание деталей котлов на судах и энергетических котлов;
- ремонт листовой обшивки котлов центрального отопления и радиаторов;
- ремонт и обслуживание огнестрельного оружия и артиллерийских орудий (включая ремонт спортивных и любительских ружей);
- ремонт и обслуживание тележек для супермаркетов

Эта группировка не включает:
- заточку лезвий и полотен пил, см. 33.12;
- ремонт систем центрального отопления и т. д., см. 43.22;
- ремонт механических запирающихся устройств, сейфов и т. д., см. 80.20');
INSERT INTO "public"."okved_2" VALUES ('33.12', '33.1', 'C', 'Ремонт машин и оборудования', 'Эта группировка включает:
- ремонт и техническое обслуживание машин и оборудования, например, заточку резцов или монтаж станков;
- сварочные работы (например, общего направления или для автомобилей);
- ремонт сельскохозяйственных и прочих тяжелых машин и оборудования (например, грузоподъемников и прочего погрузочно-разгрузочного оборудования, станков, промышленных холодильников, строительного оборудования и оборудования для горнодобывающей промышленности), включая машины и оборудование группировки 28.

Эта группировка также включает:
- ремонт и обслуживание двигателей, кроме автомобильных;
- ремонт и обслуживание насосов, компрессоров и подобного оборудования;
- ремонт и обслуживание гидравлической аппаратуры;
- ремонт и замену клапанов;
- ремонт электрических приводов и движущих элементов;
- ремонт и обслуживание производственных печей и горелок;
- ремонт и обслуживание подъемно-транспортного и погрузочно-разгрузочного оборудования;
- ремонт и обслуживание промышленного оборудования для охлаждения и кондиционирования воздуха;
- ремонт и обслуживание универсальных машин;
- ремонт ручных инструментов с механическим приводом;
- ремонт и обслуживание металлорежущих и формовочных станков и принадлежностей;
- ремонт и обслуживание прочих станков;
- ремонт и обслуживание сельскохозяйственных тракторов;
- ремонт и обслуживание сельскохозяйственных и лесозаготовочных машин;
- ремонт и обслуживание металлургических производств;
- ремонт и обслуживание машин, используемых в горнодобывающей промышленности, строительстве, добыче нефти и газа;
- ремонт, обслуживание и модернизация машин и оборудования объектов использования атомной энергии');
INSERT INTO "public"."okved_2" VALUES ('33.13', '33.1', 'C', 'Ремонт электронного и оптического оборудования', 'Эта группировка включает:
- ремонт и обслуживание товаров, отнесенных к группировкам 26.5, 26.6 и 26.7, кроме бытовой техники

Эта группировка включает:
- ремонт и техническое обслуживание измерительной, испытательной и аппаратуры контроля, группировки 26.5, такой как: инструменты для авиационных двигателей, оборудование для проверки автомобильных выхлопов, метеорологические инструменты, оборудование для испытания физических, электрических и химических свойств материалов и инспекционное оборудование, исследовательские научные инструменты, инструменты лучевого обнаружения и контроля;
- ремонт и обслуживание облучающего и электротерапевтического оборудования, применяемого в медицинских целях, группировки 26.60, таких как: датчики магнитного резонанса, ультразвуковое оборудование, электрокардиостимуляторы, слуховые аппараты, электрокардиографы, эндоскопическое оборудование, аппаратуры для облучения;
- ремонт и техническое обслуживание оптических инструментов и оборудования группировки 26.70, не находящихся главным образом в коммерческом использовании, таких как: биноклей, микроскопов (кроме электронных и протонных микроскопов), телескопов, призм и линз (кроме офтальмологических), фотографического оборудования

Эта группировка не включает:
- ремонт и обслуживание светокопировальных машин, см. 33.12;
- ремонт и обслуживание компьютеров и периферийного оборудования, см. 95.11;
- ремонт и обслуживание компьютерных проекторов, см. 95.11;
- ремонт и обслуживание коммуникационного оборудования, см. 95.12;
- ремонт и обслуживание телекамер и видеокамер, см. 95.12;
- ремонт любительских видеокамер, см. 95.21;
- ремонт настенных и наручных часов, см. 95.25');
INSERT INTO "public"."okved_2" VALUES ('35.21', '35.2', 'D', 'Производство газа', 'Эта группировка включает:
- выработку газа для поставки, получаемого посредством карбонизации угля, от побочных продуктов сельского хозяйства или от иных отходов;
- производство газообразного топлива с определенной удельной теплотой сгорания путем очистки и смешивания газов различного типа, включая природный газ

Эта группировка не включает:
- добычу природного газа, см. 06.20;
- работу коксовых печей, см. 19.10;
- производство очищенных нефтепродуктов, см. 19.20;
- производство промышленных газов, см. 20.11');
