INSERT INTO "public"."okved_2" VALUES ('45.2', '45', 'G', 'Техническое обслуживание и ремонт автотранспортных средств', '');
INSERT INTO "public"."okved_2" VALUES ('45.20', '45.2', 'G', 'Техническое обслуживание и ремонт автотранспортных средств', 'Эта группировка включает:
- ремонт транспортных средств, включая: механический ремонт, ремонт электрических систем, ремонт системы впрыскивания, текущее техническое обслуживание транспортных средств, ремонт кузова, ремонт ходовой части, мойку и полировку, покраску и рисование, ремонт лобового стекла и окон, ремонт автомобильных кресел;
- шиномонтаж и все виды связанных с ним работ;
- антикоррозийную обработку;
- установку дополнительного оборудования (сигнализация, радиоаппаратура, дополнительные фары и т.п.), запасных частей и принадлежностей, не относящихся непосредственно к производственному процессу;
- предпродажную подготовку;
- техническую помощь на дорогах;
- транспортирование неисправных автотранспортных средств к месту их ремонта или стоянки

Эта группировка не включает:
- восстановление протекторов автомобильных покрышек и шиноремонт, см. 22.11');
INSERT INTO "public"."okved_2" VALUES ('46.38.2', '46.38', 'G', 'Торговля оптовая прочими пищевыми продуктами', '');
INSERT INTO "public"."okved_2" VALUES ('45.3', '45', 'G', 'Торговля автомобильными деталями, узлами и принадлежностями', 'Эта группировка включает:
- оптовую и розничную торговлю всеми видами запасных частей, компонентов, инструментов и принадлежностей для транспортных средств, такими как: резиновые покрышки и камеры, свечи зажигания, аккумуляторы, осветительное оборудование и прочие детали');
INSERT INTO "public"."okved_2" VALUES ('45.31', '45.3', 'G', 'Торговля оптовая автомобильными деталями, узлами и принадлежностями', '');
