INSERT INTO "public"."okved_2" VALUES ('45.31.2', '45.31', 'G', 'Деятельность агентов по оптовой торговле автомобильными деталями, узлами и принадлежностями', '');
INSERT INTO "public"."okved_2" VALUES ('45.32', '45.3', 'G', 'Торговля розничная автомобильными деталями, узлами и принадлежностями', '');
