INSERT INTO "public"."okved_2" VALUES ('45.32.22', '45.32.2', 'G', 'Торговля розничная автомобильными деталями, узлами и принадлежностями по почтовым заказам', '');
INSERT INTO "public"."okved_2" VALUES ('45.32.29', '45.32.2', 'G', 'Торговля розничная автомобильными деталями, узлами и принадлежностями прочая, не включенная в другие группировки', '');
INSERT INTO "public"."okved_2" VALUES ('45.4', '45', 'G', 'Торговля мотоциклами, их деталями, узлами и принадлежностями; техническое обслуживание и ремонт мотоциклов', '');
INSERT INTO "public"."okved_2" VALUES ('45.40', '45.4', 'G', 'Торговля мотоциклами, их деталями, узлами и принадлежностями; техническое обслуживание и ремонт мотоциклов', 'Эта группировка включает:
- оптовую и розничную торговлю мотоциклами, включая мопеды;
- оптовую и розничную торговлю запасными частями и принадлежностями для мотоциклов (включая торговлю, осуществляемую комиссионными агентами и почтовыми компаниями);
- техническое обслуживание и ремонт мотоциклов

Эта группировка не включает:
- оптовую торговлю велосипедами, а также запасными частями и принадлежностями к ним, см. 46.49;
- розничную торговлю велосипедами и запасными частями и принадлежностями к ним, см. 47.64;
- прокат мотоциклов, см. 77.39;
- ремонт и техническое обслуживание велосипедов, см. 95.29');
INSERT INTO "public"."okved_2" VALUES ('45.40.1', '45.40', 'G', 'Торговля оптовая мотоциклами, их деталями, узлами и принадлежностями', '');
INSERT INTO "public"."okved_2" VALUES ('45.40.2', '45.40', 'G', 'Торговля розничная мотоциклами, их деталями, составными частями и принадлежностями в специализированных магазинах', '');
INSERT INTO "public"."okved_2" VALUES ('45.40.3', '45.40', 'G', 'Торговля розничная мотоциклами, их деталями, узлами и принадлежностями прочая', '');
INSERT INTO "public"."okved_2" VALUES ('45.40.4', '45.40', 'G', 'Деятельность агентов по оптовой торговле мотоциклами, их деталями, узлами и принадлежностями', '');
INSERT INTO "public"."okved_2" VALUES ('45.40.5', '45.40', 'G', 'Техническое обслуживание и ремонт мотоциклов и мототранспортных средств', 'Эта группировка включает:
- все виды ремонта и технического обслуживания мотоциклов, мотороллеров, мопедов, мотовелосипедов, снегоходов и др. аналогичных транспортных средств');
INSERT INTO "public"."okved_2" VALUES ('46', 'G', 'G', 'Торговля оптовая, кроме оптовой торговли автотранспортными средствами и мотоциклами', 'Эта группировка включает:
- оптовую торговлю за собственный счет, за вознаграждение или на договорной основе (на основе отчисления комиссий), связанную с оптовой торговлей на внутреннем и внешнем рынках (импорт/экспорт)

Эта группировка не включает:
-оптовую торговлю транспортными средствами, мотоциклами, домами на колесах, см. 45.1, 45.4;
- оптовую торговлю автомобильными принадлежностями, см. 45.31, 45.40;
- аренду, лизинг товаров, см. 77;
- упаковку твердых товаров и розлив в бутылки жидких товаров, включая их смешивание и фильтрацию для третьих лиц, см. 82.92');
INSERT INTO "public"."okved_2" VALUES ('46.1', '46', 'G', 'Торговля оптовая за вознаграждение или на договорной основе', 'Эта группировка включает:
- деятельность комиссионных агентов, товарных брокеров и прочих оптовых торговцев, которые торгуют от имени и за счет других лиц;
- деятельность лиц, вовлеченных в посредническую деятельность или совершающих деятельность отимени принципала, а так же в информационно-коммуникационной сети Интернет;
- деятельность оптовых аукционных домов, включая оптовые аукционы, размещенные в информационно-коммуникационной сети Интернет');
INSERT INTO "public"."okved_2" VALUES ('46.11', '46.1', 'G', 'Деятельность агентов по оптовой торговле сельскохозяйственным сырьем, живыми животными, текстильным сырьем и полуфабрикатами', '');
INSERT INTO "public"."okved_2" VALUES ('46.12', '46.1', 'G', 'Деятельность агентов по оптовой торговле топливом, рудами, металлами и химическими веществами', 'Эта группировка включает:
- оптовую торговлю, осуществляемую агентами, занимающимися продажей топлива, руд, металлов, химических веществ, включая удобрения

Эта группировка не включает:
- оптовую торговлю от собственного имени, см. 46.2-46.9;
- розничную торговлю, осуществляемую комиссионными агентами вне магазинов, см. 47.99');
