INSERT INTO "public"."okved_2" VALUES ('47.11.3', '47.11', 'G', 'Деятельность по розничной торговле большим товарным ассортиментом с преобладанием продовольственных товаров в неспециализированных магазинах', '');
INSERT INTO "public"."okved_2" VALUES ('47.19', '47.1', 'G', 'Торговля розничная прочая в неспециализированных магазинах', 'Эта группировка включает:
- розничную торговлю широким ассортиментом товаров, из которых продукты питания, напитки или табачные изделия не преобладают;
- деятельность универсальных магазинов, торгующих товарами общего ассортимента, включая одежду, мебель, бытовые приборы, скобяные изделия, косметику, ювелирные изделия, игрушки, спортивные товары и т. д.');
