INSERT INTO "public"."okved_2" VALUES ('H', '', 'H', 'ТРАНСПОРТИРОВКА И ХРАНЕНИЕ', 'Этот раздел включает:
- перевозку грузов и пассажиров, подчиняющуюся либо не подчиняющуюся расписанию по железной дороге, трубопроводам, автомобильной дороге, водным или воздушным транспортом, а также сопряженную с ней деятельность, такую как деятельность вокзалов и терминалов, стоянок для транспортных средств, обработку и хранение груза и т. д.
Этот раздел также включает:
- аренду транспортных средств с водителем или оператором
Этот раздел не включает:
- капитальный ремонт или обслуживание транспортных средств, кроме автомобильных, см. 33.1;
- строительство, содержание и ремонт автомобильных дорог, железнодорожных путей, портов, аэродромов, см. 42;
- техническое обслуживание и ремонт автотранспортных средств, см. 45.20;
- аренду транспортных средств без водителя либо оператора, см. 77.1, 77.3
Этот раздел также включает:
- деятельность почтовой связи');
INSERT INTO "public"."okved_2" VALUES ('49', 'H', 'H', 'Деятельность сухопутного и трубопроводного транспорта', 'Эта группировка включает:
- перевозку пассажиров и грузов по автомобильным дорогам и железнодорожным путям, а также транспортировку грузов по трубопроводам');
INSERT INTO "public"."okved_2" VALUES ('49.1', '49', 'H', 'Деятельность железнодорожного транспорта: междугородные и международные пассажирские перевозки', '');
INSERT INTO "public"."okved_2" VALUES ('49.10', '49.1', 'H', 'Деятельность железнодорожного транспорта: междугородные и международные пассажирские перевозки', 'Эта группировка включает:
- железнодорожные пассажирские перевозки с использованием передвижного состава по основным путям сообщения, расположенным на обширной географической территории;
- пассажирские перевозки по железным дорогам междугородного сообщения;
- услуги спальных вагонов или вагонов-ресторанов как неотъемлемую часть деятельности железнодорожных компаний

Эта группировка не включает:
- деятельность пассажирского транспорта, осуществляющего внутригородские и пригородные перевозки пассажиров, см. 49.31;
- деятельность пассажирских вокзалов и терминалов, см. 52.21;
- деятельность инфраструктуры железнодорожного транспорта, а также связанную с этим деятельность, в том числе маневровые работы и формирование поездов, см. 52.21;
- услугиспальных вагонов и вагонов-ресторанов, если они предоставляются отдельными фирмами, см. 55.90, 56.10');
INSERT INTO "public"."okved_2" VALUES ('49.10.1', '49.10', 'H', 'Перевозка пассажиров железнодорожным транспортом в междугородном сообщении', '');
INSERT INTO "public"."okved_2" VALUES ('49.10.11', '49.10.1', 'H', 'Перевозка пассажиров железнодорожным транспортом в междугородном сообщении в регулируемом секторе', '');
INSERT INTO "public"."okved_2" VALUES ('49.10.12', '49.10.1', 'H', 'Перевозка пассажиров железнодорожным транспортом в междугородном сообщении в нерегулируемом секторе', '');
INSERT INTO "public"."okved_2" VALUES ('49.10.2', '49.10', 'H', 'Перевозка пассажиров железнодорожным транспортом в международном сообщении', '');
INSERT INTO "public"."okved_2" VALUES ('49.2', '49', 'H', 'Деятельность железнодорожного транспорта: грузовые перевозки', '');
INSERT INTO "public"."okved_2" VALUES ('49.39.13', '49.39.1', 'H', 'Специальные перевозки (для собственных нужд) автобусами', '');
INSERT INTO "public"."okved_2" VALUES ('49.39.2', '49.39', 'H', 'Перевозка пассажиров фуникулерами, подвесными канатными дорогами и лыжными подъемниками, не являющимися частью внутригородской, пригородной или городской и пригородной транспортных систем', '');
INSERT INTO "public"."okved_2" VALUES ('49.39.3', '49.39', 'H', 'Перевозки пассажиров сухопутным транспортом по заказам', '');
INSERT INTO "public"."okved_2" VALUES ('49.20', '49.2', 'H', 'Деятельность железнодорожного транспорта: грузовые перевозки', 'Эта группировка включает:
- перевозку грузов по железнодорожным путям общего пользования и необщего пользования

Эта группировка не включает:
- складирование и хранение грузов, см. 52.10;
- деятельность грузовых терминалов, см. 52.21;
- деятельность инфраструктуры железнодорожного транспорта, а также связанную с этим деятельность, в том числе маневровые работы и формирование поездов, см. 52.21;
- погрузочно-разгрузочные работы, см. 52.24');
INSERT INTO "public"."okved_2" VALUES ('49.20.1', '49.20', 'H', 'Перевозка опасных грузов', 'Эта группировка включает:
- перевозку грузов, представляющих собой опасность для человека и окружающей среды, а также требующих специальных условий при перевозке');
INSERT INTO "public"."okved_2" VALUES ('49.20.9', '49.20', 'H', 'Перевозка прочих грузов', '');
INSERT INTO "public"."okved_2" VALUES ('49.3', '49', 'H', 'Деятельность прочего сухопутного пассажирского транспорта', 'Эта группировка включает:
- пассажирские перевозки наземным транспортом, кроме перевозок, осуществляемых железнодорожным транспортом

Эта группировка также включает:
- железнодорожный транспорт, если он является частью городских или пригородных транспортных систем');
INSERT INTO "public"."okved_2" VALUES ('49.31', '49.3', 'H', 'Деятельность сухопутного пассажирского транспорта: перевозки пассажиров в городском и пригородном сообщении', 'Эта группировка включает:
- перевозки пассажиров в городском и пригородном сообщении по установленным маршрутам, подчиняющиеся расписанию, с посадкой и высадкой пассажиров на установленных в расписании остановках, а также в любом не запрещенном прави лами дорожного движения месте по маршруту регулярных перевозок
Перевозки могут осуществляться автобусами, трамваями, троллейбусами, железнодорожным транспортом, метрополитеном и т. д.

Эта группировка также включает:
- перевозки железнодорожным трансп ортом, если они являются составной частью городских или пригородных транспортных систем;
- деятельность фуникулеров, подвесных канатных дорог, если они являются составной частью городских или пригородных транспортных систем');
INSERT INTO "public"."okved_2" VALUES ('49.31.1', '49.31', 'H', 'Перевозка пассажиров железнодорожным транспортом в пригородном сообщении', '');
INSERT INTO "public"."okved_2" VALUES ('49.31.11', '49.31.1', 'H', 'Перевозка пассажиров железнодорожным транспортом в пригородном сообщении в регулируемом секторе', '');
INSERT INTO "public"."okved_2" VALUES ('49.31.12', '49.31.1', 'H', 'Перевозка пассажиров железнодорожным транспортом в пригородном сообщении в нерегулируемом секторе', '');
INSERT INTO "public"."okved_2" VALUES ('49.31.2', '49.31', 'H', 'Регулярные перевозки пассажиров прочим сухопутным транспортом в городском и пригородном сообщении', '');
INSERT INTO "public"."okved_2" VALUES ('49.31.21', '49.31.2', 'H', 'Регулярные перевозки пассажиров автобусами в городском и пригородном сообщении', '');
INSERT INTO "public"."okved_2" VALUES ('49.31.22', '49.31.2', 'H', 'Регулярные перевозки пассажиров троллейбусами в городском и пригородном сообщении', '');
INSERT INTO "public"."okved_2" VALUES ('49.31.23', '49.31.2', 'H', 'Регулярные перевозки пассажиров трамваями в городском и пригородном сообщении', '');
INSERT INTO "public"."okved_2" VALUES ('49.31.24', '49.31.2', 'H', 'Перевозка пассажиров метрополитеном', '');
INSERT INTO "public"."okved_2" VALUES ('49.31.25', '49.31.2', 'H', 'Перевозка пассажиров фуникулерами, подвесными канатными дорогами и подъемниками, являющимися частью городской или пригородной транспортной системы', '');
INSERT INTO "public"."okved_2" VALUES ('49.32', '49.3', 'H', 'Деятельность легкового такси и арендованных легковых автомобилей с водителем', 'Эта группировка включает:
 - перевозки пассажиров и багажа легковым такси, а также перевозки пассажиров и багажа арендованными легковыми автомобилями с водителем');
INSERT INTO "public"."okved_2" VALUES ('49.39', '49.3', 'H', 'Деятельность прочего сухопутного пассажирского транспорта, не включенная в другие группировки', 'Эта группировка включает:
- регулярные перевозки пассажиров автобусами в междугородном и международном сообщении, перевозки автобусами по заказам, в том числе перевозки пассажиров по туристским или экскурсионным маршрутам, и прочие перевозки автобуса ми в городском, пригородном, междугородном и международном сообщении;
- перевозку пассажиров фуникулерами и подвесными канатными дорогами, если они не являются частью городских или пригородных транспортных систем

Эта группировка также включает:
- пер евозку для собственных нужд (в т.ч. школьными и служебными автобусами);
- перевозку пассажиров транспортными средствами, приводимыми в движение при использовании людей или животных в качестве тягловой силы');
INSERT INTO "public"."okved_2" VALUES ('49.39.1', '49.39', 'H', 'Регулярные перевозки пассажиров сухопутным транспортом, кроме железнодорожного транспорта, в междугородном и международном сообщении, а также специальные перевозки (для собственных нужд)', '');
INSERT INTO "public"."okved_2" VALUES ('49.39.31', '49.39.3', 'H', 'Перевозки пассажиров арендованными автобусами с водителем', 'Эта группировка включает:
- перевозки пассажиров арендованными автобусами с водителем на определенный промежуток времени, обычно независящие от расстояния.
Арендатор определяет, как и когда будут использоваться транспортные средства, устанавливает ра списание, маршруты и решает прочие эксплуатационные вопросы

Эта группировка не включает:
- регулярные перевозки пассажиров автобусами в городском и пригородном сообщении, см. 49.31.21;
- регулярные перевозки пассажиров автобусами в междугородном сооб щении, см. 49.39.11;
- регулярные перевозки пассажиров автобусами в международном сообщении, см.49.39.12');
INSERT INTO "public"."okved_2" VALUES ('49.39.32', '49.39.3', 'H', 'Перевозка пассажиров автобусами по туристическим или экскурсионным маршрутам', '');
INSERT INTO "public"."okved_2" VALUES ('49.39.33', '49.39.3', 'H', 'Перевозка пассажиров автобусами в городском и пригородном сообщении по заказам, за исключением перевозки арендованными автобусами с водителем и по туристическим или экскурсионным маршрутам', '');
INSERT INTO "public"."okved_2" VALUES ('49.39.34', '49.39.3', 'H', 'Перевозка пассажиров автобусами в междугородном и международном сообщении по заказам, за исключением перевозки арендованными автобусами с водителем и по туристическим или экскурсионным маршрутам', '');
INSERT INTO "public"."okved_2" VALUES ('49.39.35', '49.39.3', 'H', 'Перевозка пассажиров транспортными средствами, приводимыми в движение человеком или животными', '');
INSERT INTO "public"."okved_2" VALUES ('49.39.39', '49.39.3', 'H', 'Перевозки пассажиров сухопутным транспортом прочие, не включенные в другие группировки', '');
INSERT INTO "public"."okved_2" VALUES ('49.4', '49', 'H', 'Деятельность автомобильного грузового транспорта и услуги по перевозкам', 'Эта группировка включает:
- все виды перевозок грузов наземным транспортом, кроме перевозок железнодорожным транспортом');
INSERT INTO "public"."okved_2" VALUES ('49.41', '49.4', 'H', 'Деятельность автомобильного грузового транспорта', 'Эта группировка включает:
- все виды перевозок грузов автомобильным транспортом по автомобильным дорогам: опасных грузов, крупногабаритных и/или тяжеловесных грузов, грузов в контейнерах и транспортных пакетах, скоропортящихся грузов, массовых навалочных грузов, сельскохозяйственных грузов, грузов строительной отрасли, грузов промышленных предприятий, прочих грузов

Эта группировка также включает:
- аренду грузовых автомобилей с водителем;
- деятельность по перевозке грузов транспортными средствами, приводимыми в движение людьми или животными в качестве тягловой силы');
INSERT INTO "public"."okved_2" VALUES ('49.41.1', '49.41', 'H', 'Перевозка грузов специализированными автотранспортными средствами', '');
INSERT INTO "public"."okved_2" VALUES ('49.41.2', '49.41', 'H', 'Перевозка грузов неспециализированными автотранспортными средствами', '');
INSERT INTO "public"."okved_2" VALUES ('49.41.3', '49.41', 'H', 'Аренда грузового автомобильного транспорта с водителем', '');
INSERT INTO "public"."okved_2" VALUES ('49.42', '49.4', 'H', 'Предоставление услуг по перевозкам', 'Эта группировка включает:
- услуги по перевозке на автомобильном транспорте, оказываемые при переезде физическим и юридическим лицам');
INSERT INTO "public"."okved_2" VALUES ('49.5', '49', 'H', 'Деятельность трубопроводного транспорта', '');
INSERT INTO "public"."okved_2" VALUES ('49.50', '49.5', 'H', 'Деятельность трубопроводного транспорта', 'Эта группировка включает: - транспортировку газов, жидкостей, воды, жидких цементных растворов, а также прочих видов грузов по трубопроводам 
Эта группировка также включает: - работу насосных, компрессорных и распределительных станций, сухопутную к онвейерную транспортировку угля');
INSERT INTO "public"."okved_2" VALUES ('49.50.1', '49.50', 'H', 'Транспортирование по трубопроводам нефти и нефтепродуктов', '');
INSERT INTO "public"."okved_2" VALUES ('49.50.11', '49.50.1', 'H', 'Транспортирование по трубопроводам нефти', '');
INSERT INTO "public"."okved_2" VALUES ('49.50.12', '49.50.1', 'H', 'Транспортирование по трубопроводам нефтепродуктов', '');
INSERT INTO "public"."okved_2" VALUES ('49.50.2', '49.50', 'H', 'Транспортирование по трубопроводам газа и продуктов его переработки', '');
INSERT INTO "public"."okved_2" VALUES ('49.50.21', '49.50.2', 'H', 'Транспортирование по трубопроводам газа', '');
INSERT INTO "public"."okved_2" VALUES ('49.50.22', '49.50.2', 'H', 'Транспортирование по трубопроводам продуктов переработки газа', '');
INSERT INTO "public"."okved_2" VALUES ('49.50.3', '49.50', 'H', 'Сухопутная конвейерная транспортировка угля', 'Программа развития угольной промышленности России на период до 2035 года, утвержденная распоряжением Правительства Российской Федерации от 13 июня 2020 года № 1582-р (подпрограмма 2)');
INSERT INTO "public"."okved_2" VALUES ('50.20.23', '50.20.2', 'H', 'Перевозка прочих жидкостей или газов морскими судами-танкерами каботажного плавания', '');
INSERT INTO "public"."okved_2" VALUES ('50.20.24', '50.20.2', 'H', 'Перевозка контейнерных грузов судами-контейнеровозами каботажного плавания', '');
INSERT INTO "public"."okved_2" VALUES ('50.20.25', '50.20.2', 'H', 'Перевозка сухих сыпучих грузов морскими судами каботажного плавания', '');
INSERT INTO "public"."okved_2" VALUES ('50.20.29', '50.20.2', 'H', 'Перевозка прочих грузов морскими судами каботажного плавания', '');
INSERT INTO "public"."okved_2" VALUES ('50', 'H', 'H', 'Деятельность водного транспорта', 'Эта группировка включает:
- перевозку пассажиров или грузов по воде, осуществляемую по расписанию или не по расписанию

Эта группировка также включает:
- деятельность судов буксировщиков и судов, занятых буксировкой и методом толкания, экскурсионных,круизных и прогулочных судов, паромов и т. д.
Решающим критерием для разделения деятельности между морским и внутренним водным транспортом является тип используемого судна, а не вид водной среды. Перевозка на морских судах классифицирована в группировках 50.1 и 50.2, в то время как перевозка на прочих транспортных средствах классифицирована в группировках 50.3 и 50.4

Эта группировка не включает:
- деятельность ресторанов и баров, находящихся на борту судов, см. 56.10, 56.30, если она осуществляется обособленной организацией');
INSERT INTO "public"."okved_2" VALUES ('50.1', '50', 'H', 'Деятельность морского пассажирского транспорта', 'Эта группировка включает:
- перевозку пассажиров на транспортных средствах, предназначенных для работы в морских или прибрежных водах');
INSERT INTO "public"."okved_2" VALUES ('50.10', '50.1', 'H', 'Деятельность морского пассажирского транспорта', 'Эта группировка включает:
- перевозку пассажиров в морских и прибрежных водах, осуществляемую по расписанию либо не по расписанию;
- деятельность экскурсионных, круизных или прогулочных судов;
- перевозку пассажиров на паромах, водных такси и т. д.

Эта группировка также включает:
- аренду прогулочных судов, предназначенных для эксплуатации в морских и прибрежных водах с экипажем (например, для рыбалки)');
INSERT INTO "public"."okved_2" VALUES ('50.10.1', '50.10', 'H', 'Перевозка пассажиров морскими судами заграничного плавания', '');
INSERT INTO "public"."okved_2" VALUES ('50.10.11', '50.10.1', 'H', 'Перевозка пассажиров морскими судами заграничного плавания, подчиняющимися расписанию', '');
INSERT INTO "public"."okved_2" VALUES ('50.10.12', '50.10.1', 'H', 'Перевозка пассажиров морскими судами заграничного плавания, не подчиняющимися расписанию', '');
INSERT INTO "public"."okved_2" VALUES ('50.10.2', '50.10', 'H', 'Перевозка пассажиров морскими судами каботажного плавания', '');
INSERT INTO "public"."okved_2" VALUES ('50.10.21', '50.10.2', 'H', 'Перевозка пассажиров морскими судами каботажного плавания, подчиняющимися расписанию', '');
INSERT INTO "public"."okved_2" VALUES ('50.10.22', '50.10.2', 'H', 'Перевозка пассажиров морскими судами каботажного плавания, не подчиняющимися расписанию', '');
INSERT INTO "public"."okved_2" VALUES ('50.10.3', '50.10', 'H', 'Аренда морских судов заграничного и каботажного плавания для перевозки пассажиров с экипажем', '');
INSERT INTO "public"."okved_2" VALUES ('50.10.31', '50.10.3', 'H', 'Аренда морских судов заграничного плавания для перевозки пассажиров с экипажем', '');
INSERT INTO "public"."okved_2" VALUES ('50.10.32', '50.10.3', 'H', 'Аренда морских судов каботажного плавания для перевозки пассажиров с экипажем', '');
INSERT INTO "public"."okved_2" VALUES ('50.10.39', '50.10.3', 'H', 'Аренда прочих морских судов для перевозки пассажиров с экипажем', '');
INSERT INTO "public"."okved_2" VALUES ('50.2', '50', 'H', 'Деятельность морского грузового транспорта', 'Эта группировка включает:
- перевозку грузов на транспортных средствах, предназначенных для работы в морских или прибрежных водах');
INSERT INTO "public"."okved_2" VALUES ('50.20', '50.2', 'H', 'Деятельность морского грузового транспорта', 'Эта группировка включает:
- перевозку грузов в морских и прибрежных водах, осуществляемую по расписанию либо не по расписанию;
- перевозку грузов на несамоходных судах методом буксировки или толкания, а также буксировку крупногабаритных объектов (например, нефтяных платформ)

Эта группировка также включает:
- аренду судов с экипажем, предназначенных для эксплуатации в морских и прибрежных водах, для перевозки грузов');
