INSERT INTO "public"."okved_2" VALUES ('50.20.2', '50.20', 'H', 'Перевозка грузов морскими судами каботажного плавания', '');
INSERT INTO "public"."okved_2" VALUES ('50.20.21', '50.20.2', 'H', 'Перевозка замороженных или охлажденных грузов судами-рефрижераторами каботажного плавания', '');
INSERT INTO "public"."okved_2" VALUES ('50.20.22', '50.20.2', 'H', 'Перевозка нефти морскими судами-танкерами каботажного плавания', 'Перевозка нефти морскими судами-танкерами каботажного плавания');
