INSERT INTO "public"."okved_2" VALUES ('50.3', '50', 'H', 'Деятельность внутреннего водного пассажирского транспорта', 'Эта группировка включает:
- перевозку пассажиров по внутренним водным путям на судах, не предназначенных для морских перевозок;
- перевозку пассажиров по морским трассам на судах смешанного (река-море) плавания');
INSERT INTO "public"."okved_2" VALUES ('50.30', '50.3', 'H', 'Деятельность внутреннего водного пассажирского транспорта', 'Эта группировка включает:
- перевозку пассажиров по внутренним водным путям, в том числе в акваториях речных портов;
- перевозку пассажиров по морским трассам на судах смешанного (река-море) плавания

Эта группировка также включает:
- аренду судов с экипажем для перевозки пассажиров по внутренним водным путям и по морским трассам на судах смешанного (река-море) плавания');
INSERT INTO "public"."okved_2" VALUES ('50.30.1', '50.30', 'H', 'Перевозка пассажиров по внутренним водным путям', '');
INSERT INTO "public"."okved_2" VALUES ('50.30.2', '50.30', 'H', 'Аренда судов внутреннего водного транспорта для перевозки пассажиров с экипажем', '');
INSERT INTO "public"."okved_2" VALUES ('50.4', '50', 'H', 'Деятельность внутреннего водного грузового транспорта', 'Эта группировка включает:
- перевозку грузов по внутренним водным путям на судах, не предназначенных для морских перевозок;
- перевозку грузов по морским трассам на судах смешанного (река-море) плавания');
INSERT INTO "public"."okved_2" VALUES ('50.40', '50.4', 'H', 'Деятельность внутреннего водного грузового транспорта', 'Эта группировка включает:
- перевозку грузов по внутренним водным путям, в том числе в акваториях речных портов;
- перевозку грузов по морским трассам на судах смешанного (река - море) плавания;
- транспортирование (перевозку) ядерных материалов, радиоактивных веществ, радиационных источников, частей ядерных установок, радиоактивных отходов по внутренним водным путям.

Эта группировка также включает:
- аренду судов с экипажем для перевозки грузов по внутренним водным путям и по морским трассам насудах смешанного (река - море) плавания');
INSERT INTO "public"."okved_2" VALUES ('50.40.1', '50.40', 'H', 'Перевозка грузов по внутренним водным путям', '');
INSERT INTO "public"."okved_2" VALUES ('50.40.2', '50.40', 'H', 'Буксировка и маневровые услуги на внутренних водных путях', '');
INSERT INTO "public"."okved_2" VALUES ('50.40.3', '50.40', 'H', 'Аренда судов внутреннего водного транспорта для перевозки грузов с экипажем', '');
INSERT INTO "public"."okved_2" VALUES ('51', 'H', 'H', 'Деятельность воздушного и космического транспорта', 'Эта группировка включает:
- пассажирские и грузовые перевозки воздушным транспортом или в космическом пространстве

Эта группировка не включает:
- опыление сельскохозяйственных культур, см. 01.61;
- капитальный ремонт самолетов и двигателей для самолетов, см. 33.16;
- деятельность аэропортов, см. 52.23;
- воздушную рекламу, см. 73.11;
- аэрофотосъемку, см. 74.20');
INSERT INTO "public"."okved_2" VALUES ('51.1', '51', 'H', 'Деятельность пассажирского воздушного транспорта', '');
INSERT INTO "public"."okved_2" VALUES ('51.10', '51.1', 'H', 'Деятельность пассажирского воздушного транспорта', 'Эта группировка включает:
- перевозку пассажиров воздушным транспортом по регулярным маршрутам и в соответствии с регулярным расписанием;
- чартерные перевозки пассажиров;
- экскурсионные полеты и полеты для научных целей

Эта группировка также включает:
- аренду воздушного судна с экипажем с целью перевозки пассажиров;
- деятельность авиации общего назначения, такую как перевозка пассажиров аэроклубами в целях обучения или отдыха');
INSERT INTO "public"."okved_2" VALUES ('51.10.1', '51.10', 'H', 'Перевозка воздушным пассажирским транспортом, подчиняющимся расписанию', '');
INSERT INTO "public"."okved_2" VALUES ('51.10.2', '51.10', 'H', 'Перевозка воздушным пассажирским транспортом, не подчиняющимся расписанию', '');
INSERT INTO "public"."okved_2" VALUES ('51.10.3', '51.10', 'H', 'Аренда воздушного судна с экипажем для перевозки пассажиров', '');
INSERT INTO "public"."okved_2" VALUES ('51.2', '51', 'H', 'Деятельность грузового воздушного транспорта и космического транспорта', '');
INSERT INTO "public"."okved_2" VALUES ('51.21', '51.2', 'H', 'Деятельность грузового воздушного транспорта', 'Эта группировка включает:
- перевозку грузов воздушным транспортом по регулярным маршрутам и в соответствии с расписанием;
- перевозку грузов воздушным транспортом не по расписанию

Эта группировка также включает:
- аренду воздушного судна перевозки грузов с экипажем');
INSERT INTO "public"."okved_2" VALUES ('51.21.1', '51.21', 'H', 'Перевозка воздушным грузовым транспортом, подчиняющимся расписанию', '');
INSERT INTO "public"."okved_2" VALUES ('51.21.2', '51.21', 'H', 'Перевозка воздушным грузовым транспортом, не подчиняющимся расписанию', '');
INSERT INTO "public"."okved_2" VALUES ('51.21.3', '51.21', 'H', 'Аренда грузовых воздушных судов с экипажем', '');
INSERT INTO "public"."okved_2" VALUES ('51.22', '51.2', 'H', 'Деятельность космического транспорта', 'Эта группировка включает:
- деятельность, связанную с запуском космических объектов в космическое пространство;
- деятельность, связанную с доставкой космонавтов и полезных грузов на космические объекты;
- деятельность, связанную с непосредственным проведением работ по исследованию и использованию космического пространства');
INSERT INTO "public"."okved_2" VALUES ('51.22.1', '51.22', 'H', 'Перевозка пассажиров космическим транспортом', '');
INSERT INTO "public"."okved_2" VALUES ('51.22.2', '51.22', 'H', 'Перевозка грузов космическим транспортом', '');
INSERT INTO "public"."okved_2" VALUES ('51.22.3', '51.22', 'H', 'Запуск ракет космического назначения и выведение космических объектов на орбиту', '');
INSERT INTO "public"."okved_2" VALUES ('51.22.4', '51.22', 'H', 'Деятельность космических лабораторий', '');
INSERT INTO "public"."okved_2" VALUES ('52', 'H', 'H', 'Складское хозяйство и вспомогательная транспортная деятельность', 'Эта группировка включает:
- складирование (хранение) и вспомогательную деятельность при перевозке, такую как деятельность транспортной инфраструктуры (аэропортов, портов, туннелей, мостов и т. д.);
- деятельность транспортных агентств;
- погрузочно-разгрузочные работы');
INSERT INTO "public"."okved_2" VALUES ('52.1', '52', 'H', 'Деятельность по складированию и хранению', '');
INSERT INTO "public"."okved_2" VALUES ('52.10', '52.1', 'H', 'Деятельность по складированию и хранению', 'Эта группировка включает:
- деятельность инфраструктуры для хранения и складирования всех видов грузов, деятельность зернохранилищ, элеваторов, складов для генеральных грузов, складов-рефрижераторов (холодильных складов), бункеров и т.д.;
- хранениетоваров в зонах свободной торговли;
- замораживание продуктов;
- хранение ядерных материалов и радиоактивных веществ');
INSERT INTO "public"."okved_2" VALUES ('52.10.1', '52.10', 'H', 'Хранение и складирование замороженных или охлажденных грузов', '');
INSERT INTO "public"."okved_2" VALUES ('52.10.2', '52.10', 'H', 'Хранение и складирование жидких или газообразных грузов', '');
INSERT INTO "public"."okved_2" VALUES ('52.10.21', '52.10.2', 'H', 'Хранение и складирование нефти и продуктов ее переработки', '');
INSERT INTO "public"."okved_2" VALUES ('52.10.22', '52.10.2', 'H', 'Хранение и складирование газа и продуктов его переработки', '');
INSERT INTO "public"."okved_2" VALUES ('52.10.23', '52.10.2', 'H', 'Хранение и складирование прочих жидких или газообразных грузов', '');
INSERT INTO "public"."okved_2" VALUES ('52.10.3', '52.10', 'H', 'Хранение и складирование зерна', '');
INSERT INTO "public"."okved_2" VALUES ('52.10.4', '52.10', 'H', 'Хранение ядерных материалов и радиоактивных веществ', '');
INSERT INTO "public"."okved_2" VALUES ('52.2', '52', 'H', 'Деятельность транспортная вспомогательная', 'Эта группировка включает:
- вспомогательную деятельность, связанную с перевозкой пассажиров и грузов, такую как управление объектами транспортной инфраструктуры или деятельность, связанную с погрузочно-разгрузочными работами непосредственно до или после перевозки или между сегментами перевозочного процесса

Эта группировка также включает:
- эксплуатацию и обслуживание всех транспортных средств');
INSERT INTO "public"."okved_2" VALUES ('52.21', '52.2', 'H', 'Деятельность вспомогательная, связанная с сухопутным транспортом', 'Эта группировка включает:
- деятельность, связанную с перевозкой пассажиров, животных или грузов, такую как: деятельность железнодорожных вокзалов и терминалов, автовокзалов и автостанций, перегрузочных товарных станций и т. п.;
- деятельность (экспл уатацию) железнодорожной инфраструктуры;
- деятельность (эксплуатацию) автомобильных дорог, мостов, туннелей, автомобильных стоянок или гаражей, стоянок для велосипедов, стоянок для автофургонов в зимнее время;
- маневровые работы и формирование поез дов;
- буксировку и техническую помощь на дороге

Эта группировка также включает:
- сжижение газа для перевозки');
INSERT INTO "public"."okved_2" VALUES ('52.21.1', '52.21', 'H', 'Деятельность вспомогательная, связанная с железнодорожным транспортом', '');
INSERT INTO "public"."okved_2" VALUES ('52.21.11', '52.21.1', 'H', 'Предоставление железнодорожных маневровых или буксировочных услуг', 'Эта группировка включает:
- железнодорожные маневровые или буксировочные услуги, например перемещение вагонов между сортировочными станциями, заводскими подъездными путями и т. п.');
INSERT INTO "public"."okved_2" VALUES ('52.21.12', '52.21.1', 'H', 'Деятельность железнодорожных пассажирских вокзалов и грузовых терминалов', 'Эта группировка включает:
- услуги железнодорожных пассажирских вокзалов (продажа билетов, предварительный заказ билетов, камеры хранения багажа);
- услуги по управлению железнодорожной инфраструктурой;
- прочие вспомогательные услуги для железнодорожного транспорта, не включенные в другие группировки

Эта группировка не включает:
- маневровые услуги, см. 52.21.11;
- услуги по обработке железнодорожных грузов в отношении контейнеризованных грузов, см. 52.24.12;
- услуги по обработке железнодорожных грузов в отношении неконтейнеризованных грузов или багажа пассажиров, см. 52.24.19');
INSERT INTO "public"."okved_2" VALUES ('52.21.19', '52.21.1', 'H', 'Деятельность вспомогательная прочая, связанная с железнодорожным транспортом', '');
INSERT INTO "public"."okved_2" VALUES ('52.21.2', '52.21', 'H', 'Деятельность вспомогательная, связанная с автомобильным транспортом', '');
INSERT INTO "public"."okved_2" VALUES ('52.21.21', '52.21.2', 'H', 'Деятельность автовокзалов и автостанций', 'Эта группировка включает:
- услуги автовокзалов и автостанций, связанные с перевозками пассажиров автобусами в городском, пригородном, междугородном, международном сообщении (продажа билетов, предварительный заказ билетов, камеры хранения багажа)');
INSERT INTO "public"."okved_2" VALUES ('52.21.22', '52.21.2', 'H', 'Деятельность по эксплуатации автомобильных дорог и автомагистралей', 'Эта группировка включает:
- содержание и эксплуатацию автомагистралей, автомобильных дорог, в том числе проходящих по улицам населенных пунктов, а также иных проездов для автомобилей, имеющих твердое покрытие

Эта группировка не включает:
- услуги по обработке багажа и грузов, см. 52.24.19;
- выполнение архитектурных, проектных, инженерных работ, инженерных изысканий, связанных с содержанием и эксплуатацией указанных в данном пункте сооружений, см.71');
INSERT INTO "public"."okved_2" VALUES ('52.21.23', '52.21.2', 'H', 'Деятельность по эксплуатации мостов и тоннелей', 'Эта группировка включает:
- содержание и эксплуатацию мостов, включая эстакады, путепроводы, другие подобные искусственные дорожные сооружения и защитные дорожные сооружения;
- содержание и эксплуатацию тоннелей

Эта группировка не включает:
- выполнение архитектурных, проектных, инженерных работ, инженерных изысканий, связанных с содержанием и эксплуатацией указанных в данном пункте сооружений, см. 71.1');
INSERT INTO "public"."okved_2" VALUES ('52.21.24', '52.21.2', 'H', 'Деятельность стоянок для транспортных средств', 'Эта группировка включает:
- услуги стоянок, парковок, площадок отдыха на автомобильных дорогах, иных сооружений, предназначенных для остановки автотранспортных средств');
INSERT INTO "public"."okved_2" VALUES ('52.21.25', '52.21.2', 'H', 'Деятельность по буксировке автотранспортных средств', '');
INSERT INTO "public"."okved_2" VALUES ('52.21.29', '52.21.2', 'H', 'Деятельность вспомогательная прочая, связанная с автомобильным транспортом', '');
INSERT INTO "public"."okved_2" VALUES ('52.21.3', '52.21', 'H', 'Деятельность вспомогательная, связанная с трубопроводным транспортом', '');
INSERT INTO "public"."okved_2" VALUES ('52.22', '52.2', 'H', 'Деятельность вспомогательная, связанная с водным транспортом', 'Эта группировка включает:
- деятельность, связанную с перевозкой водным транспортом пассажиров, животных или грузов, включая: деятельность терминальных мощностей, таких как порты и пирсы, эксплуатацию шлюзов и т. д., навигационное обеспечение, лоцманскую проводку судов и проводку судов к причалу;
- деятельность по разгрузке судов лихтером и спасению судов;
- деятельность маяков

Эта группировка не включает:
- погрузочно-разгрузочные работы, см. 52.24;
- деятельность причалов для прогулочных судов, см. 93.29');
INSERT INTO "public"."okved_2" VALUES ('52.22.1', '52.22', 'H', 'Деятельность вспомогательная, связанная с морским транспортом', '');
