INSERT INTO "public"."okved_2" VALUES ('52.22.12', '52.22.1', 'H', 'Обеспечение судоходства в морских и прибрежных водах, включая лоцманскую проводку судов', '');
INSERT INTO "public"."okved_2" VALUES ('52.22.13', '52.22.1', 'H', 'Деятельность по постановке судов к причалу, осуществление швартовых операций с судами в морских портах', '');
INSERT INTO "public"."okved_2" VALUES ('52.22.14', '52.22.1', 'H', 'Деятельность по навигационному обеспечению судоходства на морском транспорте', 'Эта группировка включает:
- деятельность береговых служб, систем управления движением судов');
INSERT INTO "public"."okved_2" VALUES ('52.22.15', '52.22.1', 'H', 'Деятельность аварийно-спасательная и судоподъемная на морском транспорте', '');
INSERT INTO "public"."okved_2" VALUES ('52.22.16', '52.22.1', 'H', 'Снабженческое (шипчандлерское) обслуживание судов, включая бункеровку судов топливом, обслуживание судов в период стоянки в портах: агентирование судов, обследовательское (сюрвейерское) обслуживание судов на морском транспорте', '');
INSERT INTO "public"."okved_2" VALUES ('52.22.17', '52.22.1', 'H', 'Производство водолазных работ по обслуживанию морских судов', '');
INSERT INTO "public"."okved_2" VALUES ('52.22.18', '52.22.1', 'H', 'Деятельность ледокольного флота на морском транспорте', '');
INSERT INTO "public"."okved_2" VALUES ('52.22.19', '52.22.1', 'H', 'Деятельность вспомогательная, связанная морским транспортом, прочая, не включенная в другие группировки', '');
INSERT INTO "public"."okved_2" VALUES ('52.22.2', '52.22', 'H', 'Деятельность вспомогательная, связанная с внутренним водным транспортом', '');
INSERT INTO "public"."okved_2" VALUES ('52.22.21', '52.22.2', 'H', 'Деятельность инфраструктуры речных портов и гидротехнических сооружений', '');
INSERT INTO "public"."okved_2" VALUES ('52.22.22', '52.22.2', 'H', 'Обеспечение судоходства по внутренним водным путям, в том числе лоцманская проводка судов', '');
INSERT INTO "public"."okved_2" VALUES ('52.22.23', '52.22.2', 'H', 'Деятельность по постановке судов к причалу, осуществление швартовых операций в речных портах на внутреннем водном транспорте', '');
INSERT INTO "public"."okved_2" VALUES ('52.22.24', '52.22.2', 'H', 'Деятельность по навигационному обеспечению судоходства на внутреннем водном транспорте', 'Эта группировка включает:
- деятельность береговых служб, систем управления движением судов');
INSERT INTO "public"."okved_2" VALUES ('52.22.25', '52.22.2', 'H', 'Деятельность аварийно-спасательная и судоподъемная на внутреннем водном транспорте', '');
INSERT INTO "public"."okved_2" VALUES ('52.22.26', '52.22.2', 'H', 'Снабженческое (шипчандлерское) обслуживание судов, включая бункеровку судов топливом, обслуживание судов в период стоянки в портах: агентирование судов, обследовательское (сюрвейерское) обслуживание судов на внутреннем водном транспорте', '');
INSERT INTO "public"."okved_2" VALUES ('52.22.27', '52.22.2', 'H', 'Производство водолазных работ по обслуживанию судов на внутреннем водном транспорте', '');
INSERT INTO "public"."okved_2" VALUES ('52.22.28', '52.22.2', 'H', 'Деятельность ледокольного флота на внутреннем водном транспорте', '');
INSERT INTO "public"."okved_2" VALUES ('52.22.29', '52.22.2', 'H', 'Деятельность вспомогательная, связанная с внутренним водным транспортом, прочая, не включенная в другие группировки', '');
INSERT INTO "public"."okved_2" VALUES ('52.23', '52.2', 'H', 'Деятельность вспомогательная, связанная с воздушным и космическим транспортом', 'Эта группировка включает:
- деятельность, связанную с перевозкой воздушным и космическим транспортом пассажиров, космонавтов, животных или грузов, включая: деятельность (эксплуатацию) зданий и сооружений, таких как терминалы авиаперевозчиков и пр.;
-управление аэропортами и воздушным движением;
- наземное обслуживание на аэродромах и космодромах

Эта группировка также включает:
- тушение пожаров и предупреждение пожароопасных ситуаций на аэродромах и космодромах');
INSERT INTO "public"."okved_2" VALUES ('52.23.1', '52.23', 'H', 'Деятельность вспомогательная, связанная с воздушным транспортом', '');
INSERT INTO "public"."okved_2" VALUES ('52.23.11', '52.23.1', 'H', 'Деятельность аэропортовая', '');
INSERT INTO "public"."okved_2" VALUES ('52.23.12', '52.23.1', 'H', 'Обеспечение обслуживания (управления) воздушного движения', '');
INSERT INTO "public"."okved_2" VALUES ('52.23.13', '52.23.1', 'H', 'Выполнение авиационных работ', 'Эта группировка включает:
- работы, выполняемые с использованием полетов гражданских воздушных судов в сельском хозяйстве, строительстве, для охраны окружающей среды, оказания медицинской помощи и других целей');
INSERT INTO "public"."okved_2" VALUES ('52.23.19', '52.23.1', 'H', 'Деятельность вспомогательная прочая, связанная с воздушным транспортом', '');
INSERT INTO "public"."okved_2" VALUES ('52.23.2', '52.23', 'H', 'Деятельность вспомогательная, связанная с космическим транспортом', '');
INSERT INTO "public"."okved_2" VALUES ('52.23.21', '52.23.2', 'H', 'Деятельность наземных центров управления полетами космических объектов в космическом пространстве и центров (пунктов) космической связи', '');
INSERT INTO "public"."okved_2" VALUES ('52.23.22', '52.23.2', 'H', 'Деятельность поисковых и аварийно-спасательных служб, в том числе по эвакуации спускаемых аппаратов (капсул), составных частей ракет космического назначения', '');
INSERT INTO "public"."okved_2" VALUES ('52.23.23', '52.23.2', 'H', 'Деятельность, связанная с подготовкой космонавтов для работы непосредственно в космическом пространстве', '');
INSERT INTO "public"."okved_2" VALUES ('52.23.29', '52.23.2', 'H', 'Деятельность вспомогательная прочая, связанная с космическим транспортом', '');
INSERT INTO "public"."okved_2" VALUES ('52.24', '52.2', 'H', 'Транспортная обработка грузов', 'Эта группировка включает:
- погрузку и разгрузку грузов и багажа пассажиров независимо от вида транспорта, используемого для перевозки;
- погрузку-выгрузку опасных грузов на железнодорожном транспорте;
- стивидорную деятельность;
- загрузку и разгрузку грузовых железнодорожных вагонов

Эта группировка не включает:
- деятельность терминалов, см. 52.21, 52.22 и 52.23');
INSERT INTO "public"."okved_2" VALUES ('52.24.1', '52.24', 'H', 'Транспортная обработка контейнеров', '');
INSERT INTO "public"."okved_2" VALUES ('52.24.2', '52.24', 'H', 'Транспортная обработка прочих грузов', '');
INSERT INTO "public"."okved_2" VALUES ('53.20', '53.2', 'H', 'Деятельность почтовой связи прочая и курьерская деятельность', 'Эта группировка включает:
- деятельность по погрузке, сортировке, перевозке и доставке (внутренней или международной) почтовых писем и (почтовых) пакетов, а также посылок почтовыми службами, работающими согласно установленным обязательствам по обслуживанию;
- предоставлению услуг по доставке почты на дом
Перевозка почты может осуществляться личным (частным) транспортом или общественным транспортом

Эта группировка также включает:
- услуги по доставке на дом

Эта группировка не включает:
- грузовойтранспорт, см. (согласно виду транспорта) 49.20, 49.41, 50.20, 50.40, 51.21, 51.22');
INSERT INTO "public"."okved_2" VALUES ('68.31.31', '68.31.3', 'L', 'Предоставление консультационных услуг при купле-продаже жилого недвижимого имущества за вознаграждение или на договорной основе', '');
INSERT INTO "public"."okved_2" VALUES ('52.29', '52.2', 'H', 'Деятельность вспомогательная прочая, связанная с перевозками', 'Эта группировка включает:
- отправление грузов;
- подготовку или организацию перевозки грузов сухопутным, водным или воздушным транспортом;
- организацию отправки партий грузов или поштучных отправлений сухопутным, воздушным или водным транспортом (включая сбор и распределение грузов);
- подготовку транспортной документации и путевых листов;
- предоставление услуг таможенных брокеров;
- деятельность экспедиторов морского грузового и воздушного транспортов;
- посреднические операции по фрахту грузового места на судне или в самолете;
- транспортную обработку грузов, например временную упаковку в ящики с целью обеспечения защиты груза во время перевозки, выгрузку, отбор проб и взвешивание товаров

Эта группировка не включает:
- деятельность почтовой связи и курьерскую деятельность, см. 53;
- деятельность, связанную со страхованием наземных, водных, воздушных и космических средств, см. 65.12;
- деятельность туроператоров и туристических агентств, см. 79.11, 79.12;
- деятельность, связаннуюс содействием туристам, см. 79.90');
INSERT INTO "public"."okved_2" VALUES ('53', 'H', 'H', 'Деятельность почтовой связи и курьерская деятельность', 'Эта группировка включает:
- почтовую и курьерскую деятельность, такую как погрузка, перевозка и доставка писем и посылок в различные места, местную доставку и услуги курьера, а также деятельность по осуществлению почтовых переводов денежных средств');
INSERT INTO "public"."okved_2" VALUES ('53.1', '53', 'H', 'Деятельность почтовой связи общего пользования', '');
INSERT INTO "public"."okved_2" VALUES ('53.10', '53.1', 'H', 'Деятельность почтовой связи общего пользования', 'Эта группировка включает:
- деятельность почтовых служб общего пользования, выполняемую одним или несколькими определенными поставщиками обслуживания: услуги по приему, пересылке, доставке (вручению) различных письменных сообщений, предметов, товаровв почтовых отправлениях (внутренних и международных)

Эта группировка также включает:
- прочие виды услуг почты общего пользования, необходимые для обеспечения общепринятых служебных обязательств, таких как: пересылка письменной корреспонденции, пересылка посылочной почты, пересылка газет и других периодических изданий, почтовые переводы денежных средств, доставка и выплата пенсий и пособий, прием, погрузка, сортировка, перевозка, доставка, вручение внутренней и международной почты почтовыми службами общего пользования (перевозка может осуществляться личным (частным) транспортом или общественным транспортом), сбор писем, посылок, иных почтовых отправлений из почтовых ящиков, из почтовых отделений и на дому (в организациях)

Эта группировка не включает:
- деятельность, связанную с почтово-сберегательными счетами и почтово-сберегательными банками, см. 64.19');
INSERT INTO "public"."okved_2" VALUES ('53.10.1', '53.10', 'H', 'Деятельность почтовой связи, связанная с пересылкой газет и других периодических изданий', 'Эта группировка включает:
- сбор (прием), перевозку и доставку как внутреннюю, так и международную, газет, журналов и прочих периодических изданий, осуществляемых службами почтовой связи общего пользования');
INSERT INTO "public"."okved_2" VALUES ('53.10.2', '53.10', 'H', 'Деятельность почтовой связи, связанная с пересылкой письменной корреспонденции', 'Эта группировка включает:
- прием (сбор), перевозку, доставку(вручение) почтовых карточек, писем, бандеролей, мелких пакетов, мешков "М", секограмм, почтовых отправлений "Отправления 1-го класса", почтовых отправлений "Мультиконверт", осуществляемыхслужбами почтовой связи общего назначения');
INSERT INTO "public"."okved_2" VALUES ('53.10.3', '53.10', 'H', 'Деятельность почтовой связи, связанная с пересылкой посылочной почты', 'Эта группировка включает:
- прием, обработку (сортировку), перевозку, доставку (вручение) посылок, мешков, ящиков, контейнеров и других почтовых вещей, осуществляемых почтовыми службами');
INSERT INTO "public"."okved_2" VALUES ('53.10.4', '53.10', 'H', 'Деятельность почтовой связи дополнительная', 'Эта группировка включает:
- дополнительные услуги, связанные с приемом, пересылкой, доставкой (вручением) письменной корреспонденции, посылок, отправлений EMS, почтовых переводов, осуществляемые почтовыми службами');
INSERT INTO "public"."okved_2" VALUES ('53.10.9', '53.10', 'H', 'Деятельность почтовой связи общего пользования прочая', 'Эта группировка включает:
- почтовые переводы денежных средств;
- доставку и выплату пенсий и пособий;
- прием подписки на периодические издания, осуществляемые операторами почтовой связи общего пользования

Эта группировка не включает:
- деятельность, связанную с почтовыми безналичными расчетами (жирорасчетами) и почтово-сберегательными банками, а также прочую финансовую деятельность, выполняемую операторами почтовой связи, см. 64.19');
INSERT INTO "public"."okved_2" VALUES ('53.2', '53', 'H', 'Деятельность почтовой связи прочая и курьерская деятельность', '');
INSERT INTO "public"."okved_2" VALUES ('53.20.1', '53.20', 'H', 'Деятельность специальной почтовой связи', 'Эта группировка включает:
- деятельность по приему, обработке, хранению, перевозке, доставке (вручению) с вооруженной охраной почтовых отправлений, содержащих государственную, коммерческую, служебную и иные охраняемые законом тайны, а также высокоценных отправлений (денежных и валютных средств, ценных бумаг и т. п.)');
INSERT INTO "public"."okved_2" VALUES ('53.20.2', '53.20', 'H', 'Деятельность фельдъегерской связи', '');
INSERT INTO "public"."okved_2" VALUES ('53.20.21', '53.20.2', 'H', 'Деятельность федеральной фельдъегерской связи', 'Эта группировка включает:
- деятельность по обеспечению сохранности и оперативной доставке отправлений особой важности, совершенно секретных, секретных и иных служебных отправлений на государственном и межгосударственном уровнях');
INSERT INTO "public"."okved_2" VALUES ('53.20.22', '53.20.2', 'H', 'Деятельность фельдъегерско-почтовой связи', 'Эта группировка включает:
- деятельность по обеспечению получения и отправки (доставки) секретных почтовых отправлений и телеграмм Вооруженных Сил Российской Федерации');
INSERT INTO "public"."okved_2" VALUES ('53.20.29', '53.20.2', 'H', 'Деятельность почтовой связи прочая, не включенная в другие группировки', '');
INSERT INTO "public"."okved_2" VALUES ('53.20.3', '53.20', 'H', 'Деятельность курьерская', '');
INSERT INTO "public"."okved_2" VALUES ('53.20.31', '53.20.3', 'H', 'Деятельность по курьерской доставке различными видами транспорта', '');
INSERT INTO "public"."okved_2" VALUES ('53.20.32', '53.20.3', 'H', 'Деятельность по доставке еды на дом', '');
INSERT INTO "public"."okved_2" VALUES ('53.20.39', '53.20.3', 'H', 'Деятельность курьерская прочая', '');
INSERT INTO "public"."okved_2" VALUES ('I', '', 'I', 'ДЕЯТЕЛЬНОСТЬ ГОСТИНИЦ И ПРЕДПРИЯТИЙ ОБЩЕСТВЕННОГО ПИТАНИЯ', 'Этот раздел включает:
- предоставление мест для краткосрочного проживания, а также предоставление полного ассортимента продуктов питания и напитков, пригодных для непосредственного потребления. Объем и тип дополнительных услуг, предоставляемых в рамках данного раздела, может значительно варьироваться
Этот раздел не включает:
- предоставление услуг долгосрочного проживания, так как это классифицируется в разделе, описывающем операции по недвижимости (раздел L);
- приготовление пищи или напитков,которые либо не являются пригодными для непосредственного потребления, либо продаются через независимые каналы распределения, т. е. при помощи оптовой или розничной торговли
Классификация приготовления данных продуктов питания приводится в разделе C(ОБРАБАТЫВАЮЩИЕ ПРОИЗВОДСТВА)');
INSERT INTO "public"."okved_2" VALUES ('55', 'I', 'I', 'Деятельность по предоставлению мест для временного проживания', 'Эта группировка включает:
- предоставление мест для временного проживания туристам, лицам, прибывающим с деловыми целями, и другим клиентам, а также деятельность по предоставлению более длительного проживания отдельным категориям лиц, таких как, например, студенты и наемные рабочие
Некоторые предприятия предоставляют не только места для проживания, но и питание и возможности для отдыха и развлечений

Эта группировка не включает:
- аренду квартир для долгосрочного проживания, как основного места жительства, обычно арендуемых на срок от месяца до года, отнесенных к группировке 68.20');
INSERT INTO "public"."okved_2" VALUES ('55.1', '55', 'I', 'Деятельность гостиниц и прочих мест для временного проживания', '');
INSERT INTO "public"."okved_2" VALUES ('55.10', '55.1', 'I', 'Деятельность гостиниц и прочих мест для временного проживания', 'Эта группировка включает: - предоставление мест посетителям для проживания на срок от дня или недели, преимущественно для временного пребывания Она включает в себя предоставление меблированных гостиничных номеров различных категорий с заправкой посте');
INSERT INTO "public"."okved_2" VALUES ('55.2', '55', 'I', 'Деятельность по предоставлению мест для краткосрочного проживания', '');
INSERT INTO "public"."okved_2" VALUES ('55.20', '55.2', 'I', 'Деятельность по предоставлению мест для краткосрочного проживания', 'Эта группировка включает: - предоставление мест клиентам для временного проживания на ежедневной или еженедельной основе, с предоставлением отдельной площади, состоящей из полностью меблированных комнат или помещений с местами для проживания и сна, а также с местами для приготовления и потребления пищи, с кухонными принадлежностями и полностью оборудованной кухней Это может быть комната или квартира в отдельно стоящих многоэтажных зданиях или в группах зданий, или одноэтажные бунгало, шале, котт еджи, домики, а также помещения, предоставляемые по договору краткосрочного найма, при этом возможно предоставление минимального объема дополнительных услуг 
Эта группировка также включает: - жилье, предоставляемое детскими лагерями на время школьных каникул и в остальное время, домами отдыха, в том числе детскими, гостевыми квартирами, молодежными общежитиями, туристическими базами, лагерями, в том числе горными 
Эта группировка не включает: - предоставление меблированных гостиничных номеров разл ичных категорий с заправкой постели, сменой постельного белья и ежедневной уборкой, предоставлением кулинарной продукции и напитков, см. 55.10; - предоставление домов и меблированных или немеблированных квартир для долгосрочного проживания, обычно на ежемесячной или ежегодной основе, см. 68.20; - деятельность по организации отдыха детей и их оздоровления, см. 85.41.91');
INSERT INTO "public"."okved_2" VALUES ('55.3', '55', 'I', 'Деятельность по предоставлению мест для временного проживания в кемпингах, жилых автофургонах и туристических автоприцепах', '');
INSERT INTO "public"."okved_2" VALUES ('56.21', '56.2', 'I', 'Деятельность предприятий общественного питания по обслуживанию торжественных мероприятий', 'Эта группировка включает:
- услуги по приготовлению и поставке продуктов питания по договоренности с заказчиком с доставкой по указанному адресу, или по какому-либо определенному случаю

Эта группировка не включает:
- изготовление скоропортящихся продуктов для перепродажи, см. 10.89;
- розничную продажу скоропортящихся продуктов, см. 47');
INSERT INTO "public"."okved_2" VALUES ('68.31.32', '68.31.3', 'L', 'Предоставление консультационных услуг при купле-продаже нежилого недвижимого имущества за вознаграждение или на договорной основе', '');
INSERT INTO "public"."okved_2" VALUES ('55.30', '55.3', 'I', 'Деятельность по предоставлению мест для временного проживания в кемпингах, жилых автофургонах и туристических автоприцепах', 'Эта группировка включает: - предоставление мест для временного проживания в постройках на территории кемпинга, на территории стоянок для жилых автофургонов оздоровительных, рыбацких и охотничьих лагерей; - предоставление стояночных мест и обслуживани е жилых автофургонов 
Эта группировка также включает: - предоставление защитных убежищ или простого бивака для размещения палаток и/или спальных мешков 
Эта группировка не включает: - деятельность по организации отдыха детей и их оздоровления, см. 85.4 1.91');
INSERT INTO "public"."okved_2" VALUES ('55.9', '55', 'I', 'Деятельность по предоставлению прочих мест для временного проживания', '');
INSERT INTO "public"."okved_2" VALUES ('55.90', '55.9', 'I', 'Деятельность по предоставлению прочих мест для временного проживания', 'Эта группировка включает:
- предоставление временного или долгосрочного жилья в одноместной или общей комнате, или общежитиях для студентов, приезжих (сезонных) рабочих, школьников во время каникул, слушателей различных учебных заведений и других лиц

Эта группировка также включает:
- общежития для студентов, школы-интернаты, общежития для рабочих, пансионаты, железнодорожные спальные вагоны');
INSERT INTO "public"."okved_2" VALUES ('56', 'I', 'I', 'Деятельность по предоставлению продуктов питания и напитков', 'Эта группировка включает:
- услуги по предоставлению продуктов питания и напитков, готовых к употреблению непосредственно на месте и предлагаемых в традиционных ресторанах, заведениях самообслуживания, на предприятиях питания, отпускающих продукцию на вынос, а также прочих предприятиях питания, работающих на постоянной или временной основе, с предоставлением мест для сидения или без
Определяющим фактором является сам факт предложения продуктов питания, готовых к непосредственному употреблению наместе, а не вид учреждения, их предоставляющего

Эта группировка не включает:
- производство продуктов питания, не предназначенных для непосредственного употребления на месте, или полуфабрикатов, или готовых продуктов, которые не являются продуктамипитания, см. 10, 11;
- продажу продуктов несобственного производства, которые не являются продуктами питания, или не предназначены для употребления на месте, см. раздел G');
INSERT INTO "public"."okved_2" VALUES ('56.1', '56', 'I', 'Деятельность ресторанов и услуги по доставке продуктов питания', '');
INSERT INTO "public"."okved_2" VALUES ('56.10', '56.1', 'I', 'Деятельность ресторанов и услуги по доставке продуктов питания', 'Эта группировка включает:
- услуги по предоставлению питания потребителям, независимо от того, подаются ли они в специальных местах общепита или в ресторанах самообслуживания, едят их в помещении, забирают с собой или заказывают для доставки на дом;
- подготовку и подачу пищи для непосредственного потребления с транспортных средств или передвижных лавок;
- деятельность ресторанов, кафе, ресторанов быстрого обслуживания, мест с предоставлением еды на вынос, вагончиков для продажи мороженого, передвижных вагончиков для продажи пищи, деятельность по приготовлению пищи в торговых палатках

Эта группировка также включает:
- деятельность ресторанов и баров, связанную с доставкой продуктов питания потребителям отдельными подразделениями предприятия');
INSERT INTO "public"."okved_2" VALUES ('56.10.1', '56.10', 'I', 'Деятельность ресторанов и кафе с полным ресторанным обслуживанием, кафетериев, ресторанов быстрого питания и самообслуживания', '');
INSERT INTO "public"."okved_2" VALUES ('56.10.2', '56.10', 'I', 'Деятельность по приготовлению и/или продаже пищи, готовой к непосредственному употреблению на месте, с транспортных средств или передвижных лавок', '');
INSERT INTO "public"."okved_2" VALUES ('56.10.21', '56.10.2', 'I', 'Деятельность предприятий общественного питания с обслуживанием на вынос', '');
INSERT INTO "public"."okved_2" VALUES ('56.10.22', '56.10.2', 'I', 'Деятельность передвижных продовольственных лавок по приготовлению и/или продаже пищи, готовой к употреблению', '');
INSERT INTO "public"."okved_2" VALUES ('56.10.23', '56.10.2', 'I', 'Деятельность вагончиков, палаток по приготовлению и продаже мороженого', '');
INSERT INTO "public"."okved_2" VALUES ('56.10.24', '56.10.2', 'I', 'Деятельность рыночных киосков и торговых палаток по приготовлению пищи', '');
INSERT INTO "public"."okved_2" VALUES ('56.10.3', '56.10', 'I', 'Деятельность ресторанов и баров по обеспечению питанием в железнодорожных вагонахресторанах и на судах', 'Эта группировка не включает:
- розничную продажу продуктов питания через торговые автоматы, см. 47.99;
- предоставление услуг пунктов питания по сниженным ценам, см. 56.29');
INSERT INTO "public"."okved_2" VALUES ('56.2', '56', 'I', 'Деятельность предприятий общественного питания по обслуживанию торжественных мероприятий и прочим видам организации питания', '');
INSERT INTO "public"."okved_2" VALUES ('56.29', '56.2', 'I', 'Деятельность предприятий общественного питания по прочим видам организации питания', 'Эта группировка включает:
- приготовление и поставку организациям, по договоренности с заказчиком, продуктов питания предприятиями общественного питания на протяжении определенного длительного периода времени, и продажу кулинарной продукции в спортивных и подобных им сооружениях по сниженным ценам
Продукты питания обычно готовятся на центральном предприятии

Эта группировка включает:
- деятельность организаций общественного питания, поставляющих готовую пищу (например, транспортным и строительнымкомпаниям, туристическим группам, личному составу вооруженных сил и другим группам потребителей);
- деятельность по доставке продуктов питания спортивным и прочим учреждениям (по сниженным ценам);
- деятельность столовых, буфетов или кафетериев (в офисах, больницах, школах, институтах и пр.) на основе льготных цен на питание

Эта группировка не включает:
- приготовление скоропортящихся продуктов для перепродажи, см. 10.89;
- розничную продажу скоропортящихся продуктов, см. 47');
INSERT INTO "public"."okved_2" VALUES ('56.29.1', '56.29', 'I', 'Деятельность организаций общественного питания, поставляющих готовую пищу (для транспортных и строительных компаний, туристическим группам, личному составу вооруженных сил, предприятиям розничной торговли и другим группам потребителей) по договору', '');
INSERT INTO "public"."okved_2" VALUES ('56.29.2', '56.29', 'I', 'Деятельность столовых и буфетов при предприятиях и учреждениях', '');
INSERT INTO "public"."okved_2" VALUES ('56.29.3', '56.29', 'I', 'Деятельность по доставке продуктов питания учебным, спортивным и прочим учреждениям (по льготным ценам)', '');
INSERT INTO "public"."okved_2" VALUES ('56.29.4', '56.29', 'I', 'Деятельность социальных столовых, буфетов или кафетериев (в офисах, больницах, школах, институтах и пр.) на основе льготных цен на питание', '');
INSERT INTO "public"."okved_2" VALUES ('56.3', '56', 'I', 'Подача напитков', '');
INSERT INTO "public"."okved_2" VALUES ('56.30', '56.3', 'I', 'Подача напитков', 'Эта группировка включает:
- изготовление и продажу напитков для непосредственного употребления внутри заведений

Эта группировка включает:
- деятельность баров, таверн, коктейльных залов, дискотек и танцевальных площадок (c преобладающим обслуживаниемнапитками), пивных баров, буфетов, фито-баров, автоматов по продаже напитков

Эта группировка не включает:
- перепродажу упакованных/готовых напитков, см. 47;
- розничную продажу напитков через торговые автоматы, см. 47.99;
- функционирование дискотек и танцевальных площадок без обслуживания напитками, см. 93.29');
INSERT INTO "public"."okved_2" VALUES ('J', '', 'J', 'ДЕЯТЕЛЬНОСТЬ В ОБЛАСТИ ИНФОРМАЦИИ И СВЯЗИ', 'Этот раздел включает:
- производство и передачу материалов информационного и культурного назначения, предоставление средств передачи и размещения этих материалов, а также деятельность в области связи, информационных технологий и технологий обработкиданных и прочую деятельность по предоставлению информационных услуг
Главными элементами этого раздела являются издательская деятельность, включая выпуск программного обеспечения (группировка 58), съемка кинофильмов и звукозапись (группировка 59), деятельность в области теле- и радиовещания (группировка 60), деятельность в области телекоммуникаций (группировка 61), информационные технологии (группировка 62) и прочие информационные услуги (группировка 63). Издательская деятельность включает приобретение авторских прав на содержание материала (информационных продуктов) и распространение данного содержания широкой общественности путем организации или участия в воспроизведении и распространении этого содержания в различных формах. Все возможныеформы издания (включая печатную, электронную и звуковую форму, информационно-коммуникационную сеть Интернет, создание мультимедийных продуктов, например справочников на CD-ROM и т. д.) включены в данный раздел.
Деятельность, связанная с производствоми распространением телерадиопрограмм, включена в группировки 59, 60 и 61, которые посвящены различным стадиям данного процесса. Отдельные элементы, такие как производство кинофильмов, телесериалов и т. д., отражены в группировке 59, тогда как производство готовых программ для телерадиоканалов из компонентов, произведенных в рамках группировки 59 или прочих компонентов (например, программы новостей в прямом эфире), включено в группировку 60 . Трансляция готовых телерадиопрограмм без любого изменения содержания включена в группировку 61 . Такая трансляция в соответствии с описанием группировки 61 может осуществляться через системы наземного эфирного, спутникового, кабельного телерадиовещания, проводного радиовещания или с использованием информа');
INSERT INTO "public"."okved_2" VALUES ('58', 'J', 'J', 'Деятельность издательская', 'Эта группировка включает:
- издание книг, брошюр, рекламных бюллетеней, словарей, энциклопедий, атласов, карт и таблиц;
- издание газет, журналов и периодических изданий, каталогов и списков рассылки и прочих изданий, а также выпуск программного обеспечения
Издательская деятельность включает:
- обеспечение воспроизведения содержания (информационной продукции), в том числе приобретение авторских прав на него, среди неограниченного круга лиц путем организации или участия в воспроизведении и распространении этого содержания в различных формах

Эта группировка также включает:
- все возможные формы издательской деятельности (печатная, электронная или звуковая, в информационно-коммуникационной сети Интернет, в виде мультимедийных продуктов, например справочников на СD-RОМ и т. д.), кроме выпуска кинофильмов

Эта группировка не включает:
- выпуск кинофильмов, видеокассет и кинофильмов на DVD и подобных носителях, см. 59;
- производство оригинальных матриц (мастер-копий) или звукового материаладля записи, см. 59;
- печать и полиграфию, см. 18.11, 18.12;
- копирование (массовое воспроизводство) записанных носителей, см. 18.20');
INSERT INTO "public"."okved_2" VALUES ('58.1', '58', 'J', 'Издание книг, периодических публикаций и другие виды издательской деятельности', 'Эта группировка включает:
- издание книг, газет, журналов и прочих периодических изданий, справочников, каталогов и списков рассылки, а также прочих публикаций, таких как фотографии, гравюры, открытки, расписания, эмблемы, плакаты и репродукции произведений искусства (эти издания характеризуются интеллектуальным творческим потенциалом, вложенным в их создание, и обычно защищены авторским правом)');
INSERT INTO "public"."okved_2" VALUES ('58.11', '58.1', 'J', 'Издание книг', 'Эта группировка включает:
- издание книг в печатном и электронном виде (на компакт-дисках, электронных носителях, в аудиоформате или в информационно-коммуникационной сети Интернет)

Эта группировка также включает:
- издание книг, брошюр, рекламных буклетов и аналогичных изданий, включая издание словарей и энциклопедий;
- издание атласов, карт и таблиц;
- издание звуковых книг;
- издание энциклопедий и т. д. на CD-ROM и др.');
INSERT INTO "public"."okved_2" VALUES ('58.11.1', '58.11', 'J', 'Издание книг, брошюр, рекламных буклетов и аналогичных изданий, включая издание словарей и энциклопедий, в том числе для слепых, в печатном виде', '');
INSERT INTO "public"."okved_2" VALUES ('58.11.2', '58.11', 'J', 'Издание книг, брошюр, рекламных буклетов и аналогичных изданий, включая издание словарей и энциклопедий на электронных носителях', '');
INSERT INTO "public"."okved_2" VALUES ('58.11.3', '58.11', 'J', 'Издание атласов, карт и таблиц, в том числе для слепых, в печатном виде', '');
INSERT INTO "public"."okved_2" VALUES ('58.11.4', '58.11', 'J', 'Издание атласов, карт и таблиц на электронных носителях', '');
INSERT INTO "public"."okved_2" VALUES ('58.12', '58.1', 'J', 'Издание адресных справочников и списков адресатов', 'Эта группировка включает:
- издание унифицированных списков (баз данных), форма которых, в отличие от содержания, защищена авторским правом
Эти списки могут быть изданы в печатной или электронной форме

Эта группировка включает:
- издание списков подписчиков;
- издание телефонных справочников;
- издание прочих каталогов и сборников, например сводов законов, справочников лекарственных препаратов и т. д.');
INSERT INTO "public"."okved_2" VALUES ('58.12.1', '58.12', 'J', 'Издание справочников в печатном виде', '');
INSERT INTO "public"."okved_2" VALUES ('58.12.2', '58.12', 'J', 'Издание справочников на электронных носителях', '');
INSERT INTO "public"."okved_2" VALUES ('58.13', '58.1', 'J', 'Издание газет', 'Эта группировка включает:
- издание газет, включая рекламные, издаваемые не реже четырех раз в неделю
Издание может осуществляться в печатной или электронной форме, включая публикации в информационно-коммуникационной сети Интернет

Эта группировка невключает:
- деятельность информационных агентств, см. 63.91');
INSERT INTO "public"."okved_2" VALUES ('58.13.1', '58.13', 'J', 'Издание газет в печатном виде', '');
INSERT INTO "public"."okved_2" VALUES ('58.13.2', '58.13', 'J', 'Издание газет на электронных носителях', '');
INSERT INTO "public"."okved_2" VALUES ('58.14', '58.1', 'J', 'Издание журналов и периодических изданий', 'Эта группировка включает:
- публикацию периодических изданий и журналов, выходящих реже четырех раз в неделю. Издание может осуществляться в печатной или электронной форме, включая публикацию в информационно-коммуникационной сети Интернет

Эта группировка также включает:
- издание программ радио- и телевизионных передач');
INSERT INTO "public"."okved_2" VALUES ('58.14.1', '58.14', 'J', 'Издание журналов и периодических публикаций в печатном виде', '');
INSERT INTO "public"."okved_2" VALUES ('58.14.2', '58.14', 'J', 'Издание журналов и периодических публикаций на электронных носителях', '');
INSERT INTO "public"."okved_2" VALUES ('58.19', '58.1', 'J', 'Виды издательской деятельности прочие', 'Эта группировка включает:
- издание (включая интерактивное): каталогов, фотографий, эстампов и открыток, иллюстрированных, поздравительных почтовых карточек, форм и бланков, плакатов, художественных репродукций, рекламной продукции, прочей печатной продукции, интерактивных статистических отчетов и прочей подобной информации, изготовлению и печатание визитных карточек и пригласительных билетов на семейные торжества

Эта группировка не включает:
- издание рекламных газет, см. 58.13;
- выпуск интерактивного программного обеспечения (предоставление прикладного хостинга, предоставление прикладных программ), см. 63.11');
INSERT INTO "public"."okved_2" VALUES ('58.2', '58', 'J', 'Издание программного обеспечения', '');
INSERT INTO "public"."okved_2" VALUES ('58.21', '58.2', 'J', 'Издание компьютерных игр', 'Эта группировка включает:
- издание компьютерных игр для любых платформ');
INSERT INTO "public"."okved_2" VALUES ('58.29', '58.2', 'J', 'Издание прочих программных продуктов', 'Эта группировка включает:
- издание готовых программных продуктов (программных продуктов общего пользования), включая перевод или адаптацию программных продуктов общего пользования для конкретного рынка за собственный счет: операционные системы, приложения для бизнеса и прочие приложения

Эта группировка не включает:
- воспроизведение программного обеспечения, см. 18.20;
- розничную торговлю готового программного обеспечения, см. 47.41;
- производство программного обеспечения, не связанного с изданием, включая перевод или адаптацию программного обеспечения общего пользования, для конкретных приложений, за вознаграждение или на договорной основе, см. 62.01;
- интерактивное предоставление программного обеспечения (предоставление прикладного хостинга, предоставление прикладных программ), см. 63.11');
INSERT INTO "public"."okved_2" VALUES ('59', 'J', 'J', 'Производство кинофильмов, видеофильмов и телевизионных программ, издание звукозаписей и нот', 'Эта группировка включает:
- производство художественных и документальных фильмов, отснятых на кинопленку, цифровые видеодиски (DVD), видеопленку для демонстрации в кинотеатрах или для показа по телевидению;
- вспомогательную деятельность, такую как:монтажно-компоновочные работы, прокат кинофильмов, распространение видеопродукции и демонстрация телевизионных передач и кинофильмов, закупка и продажа кинофильмов и прочих, отснятых на пленку, материалов

Эта группировка также включает:
- деятельность по изданию звукозаписей (т. е. выпуск оригинальных звукозаписей, их рекламу и распространение, тиражирование музыкальных произведений);
- деятельность студий звукозаписи');
INSERT INTO "public"."okved_2" VALUES ('59.1', '59', 'J', 'Производство кинофильмов, видеофильмов и телевизионных программ', 'Эта группировка включает:
- производство художественных и документальных кинофильмов, отснятых на пленке, видеокассетах, записанных на электронный диск или другие носители для прямого проецирования в кинотеатрах или показа по телевидению;
- вспомогательную деятельность в области производства кинофильмов, видеопродукции и телевизионных передач (дублирование, монтаж фильмов, обработка кинопленок, редактирование, наложение субтитров и т. п.);
- распространение и показ кинофильмов и других материалов, записанных на пленку (видеокассеты, цифровые видеодиски и т. д.);
- покупку и продажу прав на распространение кинофильмов или любых прочих записанных на пленку материалов');
INSERT INTO "public"."okved_2" VALUES ('59.11', '59.1', 'J', 'Производство кинофильмов, видеофильмов и телевизионных программ', 'Производство кинофильмов, видеофильмов и телевизионных программ 
Эта группировка включает: - производство кинофильмов, видео- и телевизионных фильмов (телесериалов, документальных фильмов, анимационных фильмов и т.д.) или телевизионной рекламы Эта гру ппировка не включает: - копирование фильмов (кроме воспроизведения записанных на пленку кинофильмов для показа в кинотеатрах), а также копирование аудио- и видеокассет с компакт-дисков или цифровых видеодисков с оригинальной матрицы, см. 18.20; - опт овую торговлю видеокассетами, компакт-дисками, цифровыми видеодисками с записями, см. 46.43; - оптовую торговлю чистыми видеокассетами, компакт-дисками, см. 46.52; - розничную торговлю видеокассетами, компакт-дисками, цифровыми видеодисками, см. 47.6 3; - монтаж телевизионных программ, см. 59.12; - звукозапись и запись книг на магнитные, электронные и цифровые носители, см. 59.20; - телевещание, см. 60.2; - создание телевизионных программ для показа на телеканале, см. 60.2; - обработку пленок, к роме используемых в кинопромышленности, см. 74.20; - деятельность личных продюсеров или театральных агентов или агентств, см. 74.90; - прокат видеокассет и цифровых видеодисков для широкого круга потребителей, см. 77.22; - наложение субтитров в режим е реального времени (одновременно) для телепередач в прямом эфире, встреч, конференций и т.д., см. 82.99; - самостоятельную деятельность актеров, художников-мультипликаторов, режиссеров, театральных художников-декораторов и технических специалистов, см. 90.03');
INSERT INTO "public"."okved_2" VALUES ('59.12', '59.1', 'J', 'Деятельность монтажно-компоновочная в области производства кинофильмов, видеофильмов и телевизионных программ', 'Эта группировка включает:
- монтаж телевизионных фильмов, например редактирование, перезапись с пленки на пленку, дублирование, наложение субтитров, включение сведений об авторах, наложение сурдоперевода, производство компьютерной графики, наложениеанимационных и специальных эффектов, проявку и закрепление кинопленок, а также деятельность лабораторий по проявке кинопленки и деятельность специальных лабораторий по созданию анимационных фильмов

Эта группировка также включает:
- деятельность хранилищ киноматериалов и др.');
INSERT INTO "public"."okved_2" VALUES ('59.13', '59.1', 'J', 'Деятельность по распространению кинофильмов, видеофильмов и телевизионных программ', 'Эта группировка включает:
- распространение (включая продажу или предоставление напрокат) кинофильмов, видеокассет, цифровых видеодисков и видеофильмов в кинотеатрах, телевизионных сетях и студиях телевещания, а также выставках

Эта группировка такжевключает:
- приобретение прав на распространение кинофильмов, видеокассет и цифровых видеодисков

Эта группировка не включает:
- копирование фильмов, а также копирование аудио- и видеозаписей, компакт-дисков с оригинальной матрицы, см. 18.20;
- оптовую продажу видеокассет и цифровых видеодисков с записями, см. 46.43;
- розничную торговлю видеокассетами и цифровыми видеодисками с записями, см. 47.63');
INSERT INTO "public"."okved_2" VALUES ('59.14', '59.1', 'J', 'Деятельность в области демонстрации кинофильмов', 'Эта группировка включает:
- деятельность по показу кинофильмов или видеороликов в кинотеатрах, на открытых площадках или в прочих местах, предназначенных для просмотра фильмов;
- деятельность кинематографических клубов');
INSERT INTO "public"."okved_2" VALUES ('59.2', '59', 'J', 'Деятельность в области звукозаписи и издания музыкальных произведений', '');
INSERT INTO "public"."okved_2" VALUES ('63.12.1', '63.12', 'J', 'Деятельность сетевых изданий', 'Эта группировка включает:
- деятельность зарегистрированных СМИ, представляющих собой сайты в информационно-коммуникационной сети Интернет, по производству и распространению текстовых, фото-, видео-, мультимедиа и других информационных и новостных материалов');
INSERT INTO "public"."okved_2" VALUES ('59.20', '59.2', 'J', 'Деятельность в области звукозаписи и издания музыкальных произведений', 'Эта группировка включает:
- производство оригинальной звуковой продукции, такой как звукозаписи и видеозаписи на магнитные, электронные и цифровые носители;
- деятельность по рекламе и выпуску аудиопродукции;
- оптовую или розничную торговлю или прямую продажу потребителям
Эта деятельность может быть объединена с выпуском оригинальных матриц (мастер-копий) в той же организации (в противном случае организация, осуществляющая эту деятельность, должна получить права на воспроизведение и распространение мастер-копий)

Эта группировка также включает:
- услуги звукозаписи в студии (или в другом помещении), в том числе производство записанных на пленку (т. е. не идущих в прямом эфире) радиопередач;
- деятельность по изданию музыки, т. е. деятельность по приобретению и регистрации авторских прав на музыкальные композиции, рекламу, разрешение и использование этих композиций для звукозаписи, на радио, на телевидении, в кинофильмах, концертах, печатных изданиях и на других носителях (организации,занятые такой деятельностью, могут владеть авторскими правами или действовать как администраторы авторских прав на музыку от имени владельцев авторского права), а также издание музыкальных и нотных тетрадей');
INSERT INTO "public"."okved_2" VALUES ('59.20.1', '59.20', 'J', 'Издание аудиовизуальных произведений на магнитных, электронных и цифровых носителях', '');
INSERT INTO "public"."okved_2" VALUES ('59.20.2', '59.20', 'J', 'Деятельность студий звукозаписи', '');
INSERT INTO "public"."okved_2" VALUES ('59.20.3', '59.20', 'J', 'Издание музыкальных и нотных тетрадей, в том числе для слепых', '');
INSERT INTO "public"."okved_2" VALUES ('60', 'J', 'J', 'Деятельность в области телевизионного и радиовещания', 'Эта группировка включает:
- деятельность по производству телевизионных и радиопрограмм;
- приобретение прав на вещание телевизионных и радиопрограмм;
- деятельность по распространению телевизионных и радиопрограмм по сетям наземного эфирного, кабельного, спутникового телерадиовещания, проводного радиовещания или с использованием информационно-коммуникационной сети Интернет

Эта группировка также включает:
- передачу дополнительных данных, обычно объединяемых с телевизионным и радиовещанием

Эта группировка также включает:
- выпуск программ адресной передачи (программ ограниченного формата, таких как новости и репортажи, трансляция спортивных состязаний, образовательные программы и программы для молодежи) за вознаграждение или на основании подписки для третьей стороны для последующего телерадиовещания широкой общественности');
INSERT INTO "public"."okved_2" VALUES ('60.1', '60', 'J', 'Деятельность в области радиовещания', '');
INSERT INTO "public"."okved_2" VALUES ('60.10', '60.1', 'J', 'Деятельность в области радиовещания', 'Эта группировка включает:
- производство готовых радиопрограмм (например, выпусков новостей, репортажей с места событий, рекламы на радио, образовательных программ, радиоспектаклей и т. п.) из фрагментов программ (например, звуковых сообщений, материалов, фонограмм и т. д.), права на использование которых приобретаются у третьих лиц, из самостоятельно созданных фрагментов радиопрограмм или их сочетания;
- приобретение прав на использование готовых радиопрограмм в составе радиоканала;
- производство радиоканала по заказу организации, осуществляющей радиовещание, приобретение прав на вещание радиоканала;
- вещание радиоканалов по сетям наземного эфирного, кабельного, спутникового телерадиовещания, проводного радиовещания или с использованиеминформационно-коммуникационной сети Интернет;
- передачу дополнительных данных, объединенных с радиовещанием

Эта группировка не включает:
- производство записанных на различные виды носителей радиопрограмм, см. 59.20;
- деятельность по трансляции радиоканалов по сетям наземного эфирного, кабельного, спутникового телерадиовещания, проводного радиовещания или с использованием информационно-коммуникационной сети Интернет, см. 61;
- деятельность по формированию пакетов радиоканалов (в том числе мультиплексов) для последующей трансляции по сетям наземного эфирного, кабельного, спутникового телерадиовещания, проводного радиовещания или с использованием информационно-коммуникационной сети Интернет, см. 61');
INSERT INTO "public"."okved_2" VALUES ('60.2', '60', 'J', 'Деятельность в области телевизионного вещания', '');
INSERT INTO "public"."okved_2" VALUES ('60.20', '60.2', 'J', 'Деятельность в области телевизионного вещания', 'Эта группировка включает:
- производство готовых телевизионных программ (например, выпусков новостей, телевизионных сериалов, образовательных программ, ток-шоу и т. п.) из фрагментов программ (например, звуковых и/или видеосообщений, материалов, компьютерной графики или анимационных материалов, фонограмм и т. д.), права на использование которых приобретаются у третьих лиц, из самостоятельно созданных фрагментов телевизионных программ или их сочетания;
- приобретение прав на использование готовыхтелевизионных программ в составе телевизионного канала;
- производство телевизионного канала по заказу организации, осуществляющей телевизионное вещание;
- приобретение прав на вещание телевизионного канала;
- вещание телевизионных каналов по сетямназемного эфирного, кабельного, спутникового телерадиовещания или с использованием информационно-коммуникационной сети Интернет для неограниченного круга зрителей, а также для ограниченного круга подписчиков (в том числе за плату);
- вещание отдельных телевизионных программ телевизионного канала (например, кинофильмов, телевизионных фильмов, видеозаписей спортивных соревнований) по запросу зрителя, в том числе за плату;
- передачу дополнительных данных, объединенных с телевизионным вещанием
Этагруппировка не включает:
- производство элементов телевизионных программ (кинофильмов, документальных фильмов, ток-шоу, рекламы и т. д.), не связанных с телевизионным вещанием, см. 59;
- трансляцию телевизионных каналов по сетям наземного эфирного, кабельного, спутникового телевизионного вещания или с использованием информационно-коммуникационной сети Интернет, см. 61;
- формирование пакетов телевизионных каналов для последующей трансляции по сетям наземного эфирного, кабельного, спутникового телевизионного вещания или с использованием информационно-коммуникационной сети Интернет, см. 61');
INSERT INTO "public"."okved_2" VALUES ('61', 'J', 'J', 'Деятельность в сфере телекоммуникаций', 'Эта группировка включает:
- деятельность по передаче голоса, данных, текста, звука, видео
Средства передачи, с помощью которых осуществляются эти виды деятельности, могут базироваться на одной технологии или комбинации технологий. Общей особенностьюклассифицируемых в данной группировке видов деятельности является передача контента без участия в его создании. Деление на категории в этой группировке производится в соответствии с типом используемой инфраструктуры

Эта группировка также включает:
-деятельность по трансляции телерадиоканалов по сетям наземного эфирного, кабельного, спутникового телерадиовещания, проводного радиовещания или с использованием информационно-коммуникационной сети Интернет;
- деятельность по формированию пакетов телерадиоканалов для последующей трансляции по сетям наземного эфирного, кабельного, спутникового телерадиовещания, проводного радиовещания или с использованием информационно-коммуникационной сети Интернет');
INSERT INTO "public"."okved_2" VALUES ('61.1', '61', 'J', 'Деятельность в области связи на базе проводных технологий', '');
INSERT INTO "public"."okved_2" VALUES ('79.90.2', '79.90', 'N', 'Деятельность по предоставлению экскурсионных туристических услуг', '');
INSERT INTO "public"."okved_2" VALUES ('61.10', '61.1', 'J', 'Деятельность в области связи на базе проводных технологий', 'Эта группировка включает:
- оказание услуг связи с использованием проводной инфраструктуры сетей связи: предоставление доступа к линии связи, предоставление телефонных соединений, оказание услуг сети передачи данных, предоставление доступа к информационно-коммуникационной сети Интернет, оказание услуг связи для целей кабельного вещания, оказание услуг связи для целей проводного радиовещания и оповещения, оказание услуг телеграфной связи, оказание услуг по аренде каналов, оказание услуг по присоединению сетей и услуг по пропуску трафика

Эта группировка включает:
- деятельность по эксплуатации и обслуживанию инфраструктуры проводных средств связи для предоставления услуг связи
Средства передачи, с помощью которых осуществляются эти виды деятельности, могут базироваться на одной технологии или их комбинации, в том числе с использованием радиорелейных, спутниковых линий связи и средств абонентского радиодоступа

Эта группировка также включает:
- покупку прав доступа и емкости сети у владельцев и операторов сетей и предоставление, с использованием этой емкости, услуг проводной связи предприятиям и домохозяйствам;
- деятельность по трансляции телерадиоканалов по сетям кабельного телерадиовещания или с использованием информационно-коммуникационной сети Интернет;
- деятельность по формированию пакетов телерадиоканалов для последующей трансляции по сетям кабельного телерадиовещания, проводного радиовещания или с использованием информационно-коммуникационной сети Интернет

Эта группировка не включает:
- перепродажу услуг связи, см. 61.90');
INSERT INTO "public"."okved_2" VALUES ('61.10.1', '61.10', 'J', 'Деятельность по предоставлению услуг телефонной связи', 'Эта группировка также включает:
- деятельность по предоставлению соединений с таксофонов всех видов');
INSERT INTO "public"."okved_2" VALUES ('61.10.2', '61.10', 'J', 'Деятельность по предоставлению услуг по передаче данных для целей передачи голосовой информации (IР-телефония)', '');
INSERT INTO "public"."okved_2" VALUES ('61.10.3', '61.10', 'J', 'Деятельность по предоставлению услуг по передаче данных и услуг доступа к информационно-коммуникационной сети Интернет', '');
INSERT INTO "public"."okved_2" VALUES ('61.10.4', '61.10', 'J', 'Деятельность в области документальной электросвязи', '');
INSERT INTO "public"."okved_2" VALUES ('61.10.5', '61.10', 'J', 'Деятельность по трансляции телерадиоканалов по сетям кабельного телерадиовещания', '');
INSERT INTO "public"."okved_2" VALUES ('61.10.6', '61.10', 'J', 'Деятельность операторов связи по присоединению и пропуску трафика', 'Эта группировка включает:
- услуги завершения вызова на сеть другого оператора связи;
- услуги завершения вызова на сеть оператора связи;
- услуги транзита вызова');
INSERT INTO "public"."okved_2" VALUES ('61.10.8', '61.10', 'J', 'Деятельность операторов связи по присоединению и пропуску международного трафика', 'Эта группировка включает:
- услуги по присоединению;
- услуги завершения вызова на сеть другого оператора связи;
- услуги завершения вызова на сеть оператора связи;
- услуги транзита вызова;
- услуги инициирования вызова');
INSERT INTO "public"."okved_2" VALUES ('61.10.9', '61.10', 'J', 'Деятельность в области связи на базе проводных технологий прочая', '');
INSERT INTO "public"."okved_2" VALUES ('61.2', '61', 'J', 'Деятельность в области связи на базе беспроводных технологий', '');
INSERT INTO "public"."okved_2" VALUES ('61.20', '61.2', 'J', 'Деятельность в области связи на базе беспроводных технологий', 'Эта группировка включает:
- эксплуатацию, обслуживание или предоставление доступа к средствам передачи голоса, данных, текста, звуковых и видеосигналов с использованием инфраструктуры беспроводной электросвязи;
- обслуживание и эксплуатацию сетей пейджинговой связи, а также сетей подвижной радиотелефонной связи и других сетей беспроводной связи;
- формирование пакетов телерадиоканалов для последующей трансляции по сетям эфирного телерадиовещания;
- трансляцию телерадиоканалов по сетям эфирного телерадиовещания

Эта группировка также включает:
- приобретение прав доступа и емкости сети у владельцев и операторов сетей и предоставление, с использованием этой емкости, услуг беспроводной связи (кроме спутниковой) предприятиям и домохозяйствам;
-предоставление доступа в информационно-коммуникационную сеть Интернет оператором беспроводной сети
Средства передачи обеспечивают ненаправленную передачу сигналов с помощью радиоволн и могут базироваться на одной технологии или комбинации технологий

Эта группировка не включает:
- перепродажу услуг связи, см. 61.90');
INSERT INTO "public"."okved_2" VALUES ('61.20.1', '61.20', 'J', 'Деятельность по предоставлению услуг подвижной связи для целей передачи голоса', '');
INSERT INTO "public"."okved_2" VALUES ('61.20.2', '61.20', 'J', 'Деятельность по предоставлению услуг подвижной связи для целей передачи данных', '');
INSERT INTO "public"."okved_2" VALUES ('61.20.3', '61.20', 'J', 'Деятельность по предоставлению услуг подвижной связи для доступа к информационно-коммуникационной сети Интернет', '');
INSERT INTO "public"."okved_2" VALUES ('61.20.4', '61.20', 'J', 'Деятельность по предоставлению услуг связи для целей открытого эфирного вещания', '');
INSERT INTO "public"."okved_2" VALUES ('61.20.5', '61.20', 'J', 'Деятельность по предоставлению услуг цифрового телерадиовещания на базе беспроводных технологий', '');
INSERT INTO "public"."okved_2" VALUES ('61.3', '61', 'J', 'Деятельность в области спутниковой связи', 'Эта группировка не включает:
- деятельность торговых посредников при предоставлении услуг связи, см. 61.90');
INSERT INTO "public"."okved_2" VALUES ('61.30', '61.3', 'J', 'Деятельность в области спутниковой связи', 'Эта группировка включает:
- эксплуатацию, поддержание или обеспечение доступа к средствам передачи голосовых данных, информации, текста, звуковых и видеоданных с использованием спутниковой системы передачи данных;
- трансляцию телерадиоканалов по сетям спутникового телерадиовещания;
- формирование пакетов телерадиоканалов для последующей трансляции по сетям спутникового телерадиовещания

Эта группировка также включает:
- предоставление доступа в информационно-коммуникационную сеть Интернет оператором спутниковой связи

Эта группировка не включает:
- перепродажу телекоммуникационных услуг, см. 61.90');
INSERT INTO "public"."okved_2" VALUES ('61.30.1', '61.30', 'J', 'Деятельность по предоставлению услуг доступа к информационно-коммуникационной сети Интернет оператором спутниковой связи', '');
INSERT INTO "public"."okved_2" VALUES ('61.30.2', '61.30', 'J', 'Деятельность по предоставлению услуг трансляции телерадиоканалов по сетям спутникового телерадиовещания', '');
INSERT INTO "public"."okved_2" VALUES ('61.9', '61', 'J', 'Деятельность в области телекоммуникаций прочая', '');
INSERT INTO "public"."okved_2" VALUES ('61.90', '61.9', 'J', 'Деятельность в области телекоммуникаций прочая', 'Эта группировка включает:
- предоставление специализированных услуг, организованных с использованием телекоммуникационных приложений, таких как слежение за спутниками, телеметрическая связь и радиолокационные операционные станции;
- управление спутниковыми терминалами и сопутствующим оборудованием, подключенными к одной или нескольким наземным системам связи и способными передавать сигналы в системы спутниковой связи или принимать сигналы из таких систем;
- предоставление доступа в информационно-коммуникационную сеть Интернет посредством телефонной линии (Dial-up);
- услуги телефонной связи и доступа к информационно-коммуникационной сети Интернет в пунктах коллективного пользования и пунктах коллективного доступа;
- предоставление услуг попередаче данных для целей передачи голосовой информации через платформу доступа (IР-телефония);
- перепродажа сетевых ресурсов связи (т. е. покупка и перепродажа емкости сети без предоставления дополнительных услуг)

Эта группировка не включает:
- предоставление доступа в информационно-коммуникационную сеть Интернет операторами системы передачи данных, см. 61.10, 61.20, 61.30');
INSERT INTO "public"."okved_2" VALUES ('62', 'J', 'J', 'Разработка компьютерного программного обеспечения, консультационные услуги в данной области и другие сопутствующие услуги', 'Эта группировка включает:
- проведение экспертизы в области информационных технологий: разработку, изменения, апробацию и поддержку программного обеспечения, планирование и проектирование компьютерных систем, объединяющих компьютерное оборудование, программное обеспечение и коммуникационные технологии;
- интерактивное управление и эксплуатацию заказчиком компьютерной системы и/или средств обработки данных;
- прочие профессиональные и технические виды деятельности с использованием компьютеров');
INSERT INTO "public"."okved_2" VALUES ('62.0', '62', 'J', 'Разработка компьютерного программного обеспечения, консультационные услуги в данной области и другие сопутствующие услуги', '');
INSERT INTO "public"."okved_2" VALUES ('62.01', '62.0', 'J', 'Разработка компьютерного программного обеспечения', 'Эта группировка включает:
- разработку, модернизацию, тестирование и поддержку программного обеспечения

Эта группировка включает:
- разработку структуры и содержания и/или написание компьютерной программы, необходимой для создания и реализации поставленной задачи, в том числе: системного программного обеспечения (в том числе обновления и исправления), приложений программного обеспечения (в том числе обновления и исправления), баз данных, wеb-страниц;
- настройку программного обеспечения, т. е. внесение изменений и настройку существующего приложения таким образом, чтобы оно функционировало в рамках информационной системы заказчика

Эта группировка не включает:
- издание пакетов с программным обеспечением, см. 58.29;
- перевод или адаптацию программного обеспечения общего пользования для конкретного рынка за собственный счет, см. 58.29;
- планирование и проектирование компьютерных систем, которые объединяют компьютерное оборудование, программное обеспечение и технологии передачи данных, даже при условии предоставления программного обеспечения в качестве его неотъемлемой части, см 62.02');
INSERT INTO "public"."okved_2" VALUES ('62.02', '62.0', 'J', 'Деятельность консультативная и работы в области компьютерных технологий', 'Эта группировка включает:
- планирование и проектирование компьютерных систем, которые объединяют компьютерную технику, программное обеспечение и технологии передачи данных
Услуги могут включать соответствующее обучение пользователей
Эта группировкане включает:
- продажу аппаратных средств вычислительной техники или программного обеспечения, см. 46.51, 47.41;
- установку универсальных ЭВМ и аналоговых компьютеров, см. 33.20;
- установку (настройку) персональных компьютеров, см. 62.09;
- установку программного обеспечения для восстановления компьютера после сбоя, см. 62.09');
INSERT INTO "public"."okved_2" VALUES ('62.02.1', '62.02', 'J', 'Деятельность по планированию, проектированию компьютерных систем', '');
INSERT INTO "public"."okved_2" VALUES ('62.02.2', '62.02', 'J', 'Деятельность по обследованию и экспертизе компьютерных систем', '');
INSERT INTO "public"."okved_2" VALUES ('62.02.3', '62.02', 'J', 'Деятельность по обучению пользователей', '');
INSERT INTO "public"."okved_2" VALUES ('62.02.4', '62.02', 'J', 'Деятельность по подготовке компьютерных систем к эксплуатации', '');
INSERT INTO "public"."okved_2" VALUES ('62.02.9', '62.02', 'J', 'Деятельность консультативная в области компьютерных технологий прочая', '');
INSERT INTO "public"."okved_2" VALUES ('62.03', '62.0', 'J', 'Деятельность по управлению компьютерным оборудованием', 'Эта группировка включает:
- предоставление услуг по управлению на месте и эксплуатации компьютерных систем клиента и/или средств обработки данных, а также соответствующие услуги поддержки');
INSERT INTO "public"."okved_2" VALUES ('62.03.1', '62.03', 'J', 'Деятельность по управлению компьютерными системами', '');
INSERT INTO "public"."okved_2" VALUES ('62.03.11', '62.03.1', 'J', 'Деятельность по управлению компьютерными системами непосредственно', '');
INSERT INTO "public"."okved_2" VALUES ('62.03.12', '62.03.1', 'J', 'Деятельность по управлению компьютерными системами дистанционно', '');
INSERT INTO "public"."okved_2" VALUES ('62.03.13', '62.03.1', 'J', 'Деятельность по сопровождению компьютерных систем', '');
INSERT INTO "public"."okved_2" VALUES ('62.03.19', '62.03.1', 'J', 'Деятельность по управлению компьютерным оборудованием прочая, не включенная в другие группировки', '');
INSERT INTO "public"."okved_2" VALUES ('63.9', '63', 'J', 'Деятельность в области информационных услуг прочая', 'Эта группировка включает:
- деятельность информационных агентств;
- деятельность по предоставлению всех прочих информационных услуг

Эта группировка не включает:
- деятельность библиотек и архивов, см. 91.01');
INSERT INTO "public"."okved_2" VALUES ('68.31.4', '68.31', 'L', 'Предоставление консультационных услуг по аренде недвижимого имущества за вознаграждение или на договорной основе', '');
INSERT INTO "public"."okved_2" VALUES ('68.31.41', '68.31.4', 'L', 'Предоставление консультационных услуг по аренде жилого недвижимого имущества за вознаграждение или на договорной основе', '');
INSERT INTO "public"."okved_2" VALUES ('62.09', '62.0', 'J', 'Деятельность, связанная с использованием вычислительной техники и информационных технологий, прочая', 'Эта группировка включает:
- прочие информационные технологии, связанные с работой на компьютере, не включенные в другие группировки, в том числе: предоставление услуг по восстановлению компьютера после сбоя, установку (настройку) персональных компьютеров, установку программного обеспечения

Эта группировка не включает:
- установку специализированных цифровых и аналоговых компьютеров, см. 33.20;
- разработку компьютерного программного обеспечения, см. 62.01;
- консультирование в области компьютерных систем, см. 62.02;
- управление компьютерными техническими средствами, см. 62.03;
- обработку данных и хостинг, см. 63.11');
INSERT INTO "public"."okved_2" VALUES ('63', 'J', 'J', 'Деятельность в области информационных технологий', 'Эта группировка включает:
- деятельность порталов поиска в информационно-коммуникационной сети Интернет, обработку данных, по созданию, изменению и использованию баз данных и хостинг;
- прочую деятельность, прежде всего по предоставлению информации');
INSERT INTO "public"."okved_2" VALUES ('63.1', '63', 'J', 'Деятельность по обработке данных, предоставление услуг по размещению информации, деятельность порталов в информационно-коммуникационной сети Интернет', 'Эта группировка включает:
- создание инфраструктуры для хостинга, обработку данных и деятельность, связанную с обработкой данных;
- предоставление систем поиска и прочих порталов для информационно-коммуникационной сети Интернет');
INSERT INTO "public"."okved_2" VALUES ('63.11', '63.1', 'J', 'Деятельность по обработке данных, предоставление услуг по размещению информации и связанная с этим деятельность', 'Эта группировка включает:
- создание инфраструктуры для хостинга;
- услуги в области обработки данных и деятельность, связанную с обработкой данных;
- проведение специальных действий, таких как: web-хостинг, услуги потоковой передачи данных;
- интерактивное предоставление программного обеспечения (предоставление прикладного хостинга, предоставление прикладных программ);
- услуг приложений;
- общее предоставление распределенных по времени технических компьютерных средств заказчикам;
- обработку данных: полную обработку данных, предоставленных заказчиком;
- создание специальных отчетов на основании данных, предоставленных заказчиком;
- предоставление услуг по вводу данных

Эта группировка не включает:
- деятельность, в которой пользователь использует компьютеры только в качестве инструмента, она должна быть отнесена к группировке в соответствии с характером оказываемых услуг');
INSERT INTO "public"."okved_2" VALUES ('63.11.1', '63.11', 'J', 'Деятельность по созданию и использованию баз данных и информационных ресурсов', 'Эта группировка включает:
- проектирование и разработку баз данных (разработку концепций, структуры, состава баз данных);
- реализацию разработанных баз данных;
- формирование и ведение баз данных, в том числе сбор данных из одного или более источников, а также ввод, верификацию и актуализацию данных;
- администрирование баз данных, в том числе обеспечение возможности доступа к базе данных в режиме непосредственного или телекоммуникационного доступа;
- поиск данных, их отбор и сортировку по запросам, предоставление отобранных данных пользователям, в том числе в режиме непосредственного доступа;
- создание информационных ресурсов различных уровней (федеральных, ведомственных, корпоративных, ресурсов предприятий);
- разработку, адаптацию, модификацию баз данных, установку, тестирование и сопровождение баз данных

Эта группировка не включает:
- разработку программного обеспечения для работы с базами данных, см. 62');
INSERT INTO "public"."okved_2" VALUES ('63.11.9', '63.11', 'J', 'Деятельность по предоставлению услуг по размещению информации прочая', '');
INSERT INTO "public"."okved_2" VALUES ('63.12', '63.1', 'J', 'Деятельность web-порталов', 'Эта группировка включает:
- функционирование web-сайтов с использованием поисковой системы для создания и поддержки обширной базы данных Интернет-адресов, содержащихся в легко доступной форме;
- функционирование прочих web-сайтов, которые действуют как порталы информационно-коммуникационной сети Интернет (например, медиа-сайты, предлагающие периодически обновляемое содержание, СМИ, размещаемые в Интернете)

Эта группировка не включает:
- издание книг, газет, журналов и т. д. через информационно-коммуникационную сеть Интернет, см. 58;
- вещание через информационно-коммуникационную сеть Интернет, см. 60');
INSERT INTO "public"."okved_2" VALUES ('71.20.4', '71.20', 'M', 'Испытания, исследования и анализ целостных механических и электрических систем, энергетическое обследование', '');
INSERT INTO "public"."okved_2" VALUES ('63.91', '63.9', 'J', 'Деятельность информационных агентств', 'Эта группировка включает:
- деятельность информационных агентств: по сбору, обработке информации, производству и распространению новостных материалов, фотографий и других информационных материалов, по предоставлению научно-технической, правовой, статистической, социальноэкономической, финансовой, коммерческой, отраслевой и прочей информации;
- деятельность журналистов и фоторепортеров

Эта группировка не включает:
- деятельность независимых фотокорреспондентов, см. 74.20;
- деятельность независимых журналистов, см. 90.03');
INSERT INTO "public"."okved_2" VALUES ('63.99', '63.9', 'J', 'Деятельность информационных служб прочая, не включенная в другие группировки', 'Эта группировка включает:
- деятельность прочих информационных служб, не включенную в другие группировки: предоставление компьютерных информационных услуг телефонной связи, предоставление услуг службами информационного поиска по договору или на платной основе, предоставление услуг по составлению обзоров новостей, услуги по подборке

Эта группировка не включает:
- деятельность телефонных справочных центров, см. 82.20');
INSERT INTO "public"."okved_2" VALUES ('63.99.1', '63.99', 'J', 'Деятельность по оказанию консультационных и информационных услуг', '');
INSERT INTO "public"."okved_2" VALUES ('63.99.11', '63.99.1', 'J', 'Деятельность по оказанию компьютерных информационных услуг телефонной связи', '');
INSERT INTO "public"."okved_2" VALUES ('63.99.12', '63.99.1', 'J', 'Деятельность по оказанию услуг службами информационного поиска по договору или на платной основе', '');
INSERT INTO "public"."okved_2" VALUES ('63.99.2', '63.99', 'J', 'Деятельность по оказанию услуг по составлению обзоров новостей, услуг по подборке печатных изданий и подобной информации', '');
INSERT INTO "public"."okved_2" VALUES ('K', '', 'K', 'ДЕЯТЕЛЬНОСТЬ ФИНАНСОВАЯ И СТРАХОВАЯ', 'Этот раздел включает:
- финансовые услуги, включая страхование, перестрахование, пенсионное страхование, а также деятельность по предоставлению финансовых услуг
Этот раздел также включает:
- деятельность, связанную с финансовыми активами, деятельность холдинговых компаний, трастов, различного рода фондов и подобных им финансовых организаций');
INSERT INTO "public"."okved_2" VALUES ('64', 'K', 'K', 'Деятельность по предоставлению финансовых услуг, кроме услуг по страхованию и пенсионному обеспечению', 'Эта группировка включает:
- деятельность, связанную с получением и перераспределением финансовых средств, кроме средств, предназначенных для целей страхования, пенсионного обеспечения или обязательного социального страхования

Эта группировка не включает:
- страхование и деятельность по негосударственному пенсионному обеспечению, см. 65;
- обязательное социальное страхование и государственное пенсионное обеспечение, см. 84.30;
- управление имуществом, находящимся в государственной собственности,см. 68.2, 68.3');
INSERT INTO "public"."okved_2" VALUES ('64.1', '64', 'K', 'Денежное посредничество', 'Эта группировка включает:
- получение денежно-кредитными учреждениями средств в форме перемещаемых депозитов (т. е. средств, закрепленных в денежном выражении), которые поступают на нерегулярной основе и не от финансовых источников (кроме деятельности Центрального банка)');
INSERT INTO "public"."okved_2" VALUES ('64.11', '64.1', 'K', 'Деятельность Центрального банка Российской Федерации (Банка России)', 'Эта группировка включает:
- во взаимодействии с Правительством Российской Федерации разработку и проведение единой государственной денежно-кредитной политики;
- монопольное осуществление эмиссии наличных денег и организацию наличного денежного обращения;
- выполнение функции кредитора последней инстанции кредитных организаций, организацию системы их рефинансирования;
- установление правил осуществления расчетов в Российской Федерации;
- установление правил проведения банковских операций;
- обслуживание счетов бюджетов всех уровней бюджетной системы Российской Федерации;
- эффективное управление золотовалютными резервами;
- принятие решения о государственной регистрации кредитных организаций, выдачу кредитным организациям лицензии на осуществление банковских операций, приостановление их действия и отзыв;
- надзор за деятельностью кредитных организаций и банковских групп;
- осуществление самостоятельно или по поручению Правительства Российской Федерации всех видов банковских операций и иных сделок, необходимых для выполнения функций Банка России;
- организацию и осуществление валютного регулирования и валютного контроля в соответствии с законодательством Российской Федерации;
- определение порядка осуществления расчетов с международными организациями, иностранными государствами, а также с юридическими и физическими лицами;
- установление правил бухгалтерского учета и отчетности для банковской системы Российской Федерации;
- установление и публикацию официальных курсов иностранных валют по отношению к рублю;
- участие в разработке прогноза платежного баланса Российской Федерации и организации составления платежного баланса Российской Федерации;
- установление порядка и условий осуществления валютными биржами деятельности поорганизации проведения операций по покупке и продаже иностранной валюты, осуществлению выдачи, приостановлению и отзыву разрешений валютным биржам на организацию проведения операций по покупке и продаже иностранной валюты;
- анализ и прогнозированиес');
INSERT INTO "public"."okved_2" VALUES ('64.19', '64.1', 'K', 'Денежное посредничество прочее', 'Эта группировка включает:
- аккумулирование свободных денежных средств различных экономических субъектов и предоставление их от имени организации на определенных условиях
Данные виды деятельности осуществляются кредитными организациями (банками и небанковскими кредитными организациями) на основании лицензии, выдаваемой Банком России

Эта группировка также включает:
- привлечение денежных средств физических и юридических лиц во вклады;
- размещение привлеченных средств от своего имени и за свой счет;
- открытие и ведение банковских счетов физических и юридических лиц;
- осуществление расчетов по поручению физических и юридических лиц, в том числе банковкорреспондентов, по их банковским счетам;
- инкассацию денежных средств, векселей, платежных и расчетных документов и кассовое обслуживание физических и юридических лиц;
- привлечение во вклады и размещение драгоценных металлов;
- выдачу банковских гарантий;
- осуществление переводов денежных средств по поручению физических лиц без открытия банковских счетов, за исключением почтовых переводов

Эта группировка не включает:
- предоставление кредитов на покупку домов специализированными учреждениями, не принимающими депозиты, см. 64.92;
- деятельность по обработке сделок и расчетов по кредитным карточкам, см. 66.19;
- деятельность по приему платежей физических лиц платежными агентами (юридическими лицами или индивидуальными предпринимателями) и банковскими платежными агентами (организациями, не являющимися кредитными организациями ииндивидуальными предпринимателями), см. 66.19');
INSERT INTO "public"."okved_2" VALUES ('64.2', '64', 'K', 'Деятельность холдинговых компаний', '');
INSERT INTO "public"."okved_2" VALUES ('64.20', '64.2', 'K', 'Деятельность холдинговых компаний', 'Эта группировка включает:
- деятельность холдинговых компаний, т. е. подразделений, владеющих активами (контрольным пакетом акций) группы дочерних корпораций с целью контроля и управления ими
Холдинговые компании данной группировки не предоставляют никаких услуг другим компаниям, акциями которых они владеют, т. е. они не управляют и не контролируют другие подразделения

Эта группировка не включает:
- управление активами компаний и предприятий, стратегическое планирование и принятие решений компанией, см. 70.10');
INSERT INTO "public"."okved_2" VALUES ('64.3', '64', 'K', 'Деятельность инвестиционных фондов и аналогичных финансовых организаций', '');
INSERT INTO "public"."okved_2" VALUES ('64.30', '64.3', 'K', 'Деятельность инвестиционных фондов и аналогичных финансовых организаций', 'Эта группировка включает:
- деятельность юридических лиц по привлечению денежных средств и иного имущества путем размещения акций в целях их объединения и последующего инвестирования в объекты, предусмотренные Федеральным законом "Об инвестиционных фондах"
Эти организации получают проценты, дивиденды и прочие доходы от собственности и не получают доход от продажи услуг

Эта группировка включает:
- деятельность акционерных инвестиционных фондов, паевых акционерных фондов, открытых инвестиционных фондов;
- закрытых инвестиционных фондов, инвестиционных трастовых фондов, трастов, осуществляющих управление от имени совладельцев в соответствии с трастовым соглашением, завещанием или соглашением агентства

Эта группировка не включает:
- деятельность инвестиционных фондов, которые получают доход от продажи товаров или услуг, см. группировку ОКВЭД согласно их основной деятельности;
- деятельность холдинговых компаний, см. 64.20;
- пенсионное страхование, см. 65.30;
- деятельность по управлению активами, см. 66.30');
INSERT INTO "public"."okved_2" VALUES ('64.9', '64', 'K', 'Деятельность по предоставлению прочих финансовых услуг, кроме услуг по страхованию и пенсионному обеспечению', 'Эта группировка включает:
- предоставление финансовых услуг, за исключением деятельности по предоставлению финансовых услуг финансовыми организациями

Эта группировка не включает:
- страхование и пенсионное обеспечение, см.65');
INSERT INTO "public"."okved_2" VALUES ('64.91', '64.9', 'K', 'Деятельность по финансовой аренде (лизингу/сублизингу)', 'Эта группировка включает:
- деятельность компаний, оказывающих услуги по предоставлению имущества в лизинг
(сублизинг) в качестве лизингодателя (сублизингодателя)

Эта группировка не включает:
- операционный лизинг, см. 77');
INSERT INTO "public"."okved_2" VALUES ('64.91.1', '64.91', 'K', 'Деятельность по финансовой аренде (лизингу/сублизингу) племенных животных', '');
INSERT INTO "public"."okved_2" VALUES ('64.91.2', '64.91', 'K', 'Деятельность по финансовой аренде (лизингу/сублизингу) в прочих областях, кроме племенных животных', '');
INSERT INTO "public"."okved_2" VALUES ('64.92', '64.9', 'K', 'Предоставление займов и прочих видов кредита', 'Эта группировка включает:
- деятельность по финансовому обслуживанию (т. е. предоставление денежных средств учреждениями, не вовлеченными в денежное посредничество в случаях, когда предоставление кредита может принимать различные формы, такие как ссуды, ипотека, кредитные карточки и т. д.)

Эта группировка включает:
- деятельность по предоставлению следующих видов услуг: предоставление потребительского кредита, финансирование международной торговли, предоставление промышленными банками долгосрочного финансирования промышленности, предоставление денежного займа, не связанного с банковской системой, предоставление кредитов на покупку домов специализированными учреждениями, не принимающими депозиты, предоставление услуг ломбардами и ростовщиками

Эта группировка не включает:
- предоставление кредитов на покупку домов специализированными учреждениями, принимающими депозиты, см. 64.19;
- операционный лизинг, согласно типу лизинговых товаров, см. 77;
- предоставление прав на выдачу средств в членских организациях, см. 94.99');
INSERT INTO "public"."okved_2" VALUES ('64.92.1', '64.92', 'K', 'Деятельность по предоставлению потребительского кредита', '');
INSERT INTO "public"."okved_2" VALUES ('64.92.2', '64.92', 'K', 'Деятельность по предоставлению займов промышленности', '');
INSERT INTO "public"."okved_2" VALUES ('64.92.3', '64.92', 'K', 'Деятельность по предоставлению денежных ссуд под залог недвижимого имущества', '');
INSERT INTO "public"."okved_2" VALUES ('64.92.4', '64.92', 'K', 'Деятельность по предоставлению кредитов на покупку домов специализированными учреждениями, не принимающими депозиты', '');
INSERT INTO "public"."okved_2" VALUES ('64.92.6', '64.92', 'K', 'Деятельность по предоставлению ломбардами краткосрочных займов под залог движимого имущества', '');
INSERT INTO "public"."okved_2" VALUES ('64.92.7', '64.92', 'K', 'Деятельность микрофинансовая', 'Эта группировка включает:
- деятельность юридических лиц, имеющих статус микрофинансовой организации, а также иных юридических лиц, имеющих право на осуществление микрофинансовой деятельности по предоставлению микрозаймов (микрофинансирование)');
INSERT INTO "public"."okved_2" VALUES ('66.30', '66.3', 'K', 'Деятельность по управлению фондами', 'Эта группировка включает:
- деятельность по управлению портфелями активов и фондами за вознаграждение или на договорной основе в интересах физических лиц, юридических лиц и прочих клиентов

Эта группировка не включает:
- деятельность по управлению капиталом, см. 64.99');
INSERT INTO "public"."okved_2" VALUES ('64.99', '64.9', 'K', 'Предоставление прочих финансовых услуг, кроме услуг по страхованию и пенсионному обеспечению, не включенных в другие группировки', 'Эта группировка включает:
- прочие виды деятельности в сфере финансовых услуг, прежде всего связанные с распределением финансовых средств, кроме предоставления займов, включая факторинговые услуги, заключение свопов, опционов и прочих срочных сделок;
- деятельность, связанную с частным инвестированием, например деятельность инвестиционных фондов (кроме акционерных);
- деятельность компаний по венчурному инвестированию и пр.

Эта группировка не включает:
- финансовый лизинг, см. 64.91;
- операционный лизинг, согласно типу лизинговых товаров, см. 77;
- страхование и деятельность по негосударственному пенсионному обеспечению, см. 65;
- обязательное социальное страхование и государственное пенсионное обеспечение, см. 84.30;
- поручительскую деятельность в членских организациях, см. 94.99;
- операции с ценными бумагами по поручению других лиц, см. 66.12;
- покупку, продажу и аренду недвижимости, см. 68;
- инкассацию векселей без долговой скупки, см. 82.91;
- деятельность по управлению холдинговыми компаниями, см. 64.20');
INSERT INTO "public"."okved_2" VALUES ('64.99.1', '64.99', 'K', 'Вложения в ценные бумаги', 'Эта группировка включает:
- капиталовложения в акции, облигации, векселя, ценные бумаги акционерных фондов и паевых инвестиционных фондов и т. п.');
INSERT INTO "public"."okved_2" VALUES ('64.99.2', '64.99', 'K', 'Деятельность дилерская', 'Эта группировка включает:
- проведение операций с ценными бумагами, осуществляемые за собственный счет

Эта группировка не включает:
- проведение операций с ценными бумагами по поручению других лиц, см. 66.12');
INSERT INTO "public"."okved_2" VALUES ('64.99.3', '64.99', 'K', 'Капиталовложения в уставные капиталы, венчурное инвестирование, в том числе посредством инвестиционных компаний', 'Эта группировка включает:
- капиталовложения в собственность, осуществляемые, в основном, за счет других финансовых посредников, например траст-компаний

Эта группировка не включает:
- покупку, продажу и аренду недвижимого имущества, см. 68');
INSERT INTO "public"."okved_2" VALUES ('64.99.4', '64.99', 'K', 'Заключение свопов, опционов и других срочных сделок', '');
INSERT INTO "public"."okved_2" VALUES ('64.99.5', '64.99', 'K', 'Предоставление факторинговых услуг', '');
INSERT INTO "public"."okved_2" VALUES ('64.99.6', '64.99', 'K', 'Деятельность по финансовой взаимопомощи', '');
INSERT INTO "public"."okved_2" VALUES ('64.99.7', '64.99', 'K', 'Деятельность специализированного депозитария инвестиционных фондов, паевых инвестиционных фондов, негосударственных пенсионных фондов', '');
INSERT INTO "public"."okved_2" VALUES ('64.99.8', '64.99', 'K', 'Деятельность ипотечных агентов, управляющих ипотечным покрытием; деятельность специализированных депозитариев ипотечного покрытия', '');
INSERT INTO "public"."okved_2" VALUES ('64.99.9', '64.99', 'K', 'Деятельность жилищных накопительных кооперативов', '');
INSERT INTO "public"."okved_2" VALUES ('65', 'K', 'K', 'Страхование, перестрахование, деятельность негосударственных пенсионных фондов, кроме обязательного социального обеспечения', 'Эта группировка включает:
- ежегодное страхование, а также правила страхования и реинвестирования для создания пакета финансовых активов для разрешения будущих претензий
Также содержит предоставление прямого страхования и перестрахования');
INSERT INTO "public"."okved_2" VALUES ('65.1', '65', 'K', 'Страхование', 'Эта группировка включает:
- страхование жизни с существенным элементом сбережения или без него, а также иное страхование

Эта группировка не включает:
- деятельность в области обязательного социального страхования, государственного пенсионного обеспечения, см. 84.30;
- деятельность по предоставлению социальной помощи и социальных услуг, см. 88.10, 88.9;
- вспомогательную деятельность в сфере страхования и негосударственного пенсионного обеспечения, см. 66.2');
INSERT INTO "public"."okved_2" VALUES ('65.11', '65.1', 'K', 'Страхование жизни', 'Эта группировка включает:
- ежегодное страхование жизни, оформление страховых полисов выплат по недееспособности, несчастному случаю со смертельным исходом и страховых полисов по разрыву отношений (с элементом существенных сбережений либо без него)');
INSERT INTO "public"."okved_2" VALUES ('65.12', '65.1', 'K', 'Страхование, кроме страхования жизни', 'Эта группировка включает:
- предоставление страховых услуг, кроме страхования жизни: страхование от несчастного случая и пожара, добровольное медицинское страхование, страхование туристов, страхование имущества, страхование рисков, страхование наземных, водных, воздушных и космических транспортных средств, страхование на случай денежных убытков и гражданской ответственности');
INSERT INTO "public"."okved_2" VALUES ('65.12.1', '65.12', 'K', 'Страхование медицинское', 'Эта группировка включает:
- добровольное медицинское страхование (ДМС), осуществляемое за счет прибыли предприятий и организаций или личных средств граждан путем заключения страховых договоров на получение дополнительного медицинского обслуживания, сверх установленного программами социального страхования. ДМС страхует не здоровье, но затраты на лечение; последние возмещаются застрахованному клиенту обыкновенно по этапу медицинского вмешательства (фармакология, диагностика, стационар) или по видам оказанной медицинской помощи (стоматология, гинекология, косметология, случай смерти), или по долям расходов на оплату оказанной медицинской помощи (полное возмещение, процентное возмещение, возмещение в пределах определенной суммы)
Эта группировкане включает:
- деятельность, связанную с управлением социальными программами в области здравоохранения, см. 84.12;
- страхование от несчастных случаев и болезней, см. 65.12.5;
- деятельность, связанную с предоставлением пособий по болезни, материнству, по случаю потери трудоспособности, государственное медицинское страхование, см. 84.30;
- предоставление социальной помощи и социальных услуг, см. 88.10, 88.9');
INSERT INTO "public"."okved_2" VALUES ('66.30.1', '66.30', 'K', 'Управление инвестиционными фондами', '');
INSERT INTO "public"."okved_2" VALUES ('66.30.2', '66.30', 'K', 'Управление фондами денежного рынка', '');
INSERT INTO "public"."okved_2" VALUES ('65.12.2', '65.12', 'K', 'Страхование имущества', 'Страхование имущества - вид деятельности по добровольному имущественному страхованию, предусматривающий страхование предметов домашней обстановки, обихода и потребления, используемых в личном хозяйстве и предназначенных для удовлетворения бытовых и культурных потребностей семьи

Эта группировка включает:
- страхование загородных домов; квартир; внутренней отделки помещений; средств наземного, водного и воздушного транспорта, грузов; домашнего имущества; оборудования; бань, гаражей, хозяйственныхпостроек, заборов, теплиц и т. п. предметов ландшафтного дизайна; строительных материалов; предметов искусства, антиквариат и т. п.; товарно-материальных ценностей; земельных участков; сооружений над местами захоронения от пожара, залива, от стихийных бедствий; от механических повреждений; от противоправных действий третьих лиц

Эта группировка не включает:
- страхование рисков, см. 65.12.5');
INSERT INTO "public"."okved_2" VALUES ('65.12.3', '65.12', 'K', 'Страхование гражданской ответственности', 'Эта группировка включает:
- страхование гражданской ответственности (владельцев автотранспортных средств, перевозчиков, предприятий - источников повышенной опасности);
- страхование ответственности работодателя на случай причинения вреда здоровью работника;
- страхование персональной ответственности перед третьими лицами из-за небрежности страхователя или членов его семьи;
- страхование ответственности производителя товара (посредника или продавца) перед потребителями и другими лицами за вред, болезнь или убыток (ущерб), возникающие в результате потребления товара;
- страхование ответственности за нанесение вреда экологии;
- страхование ответственности судовладельцев;
- страхование профессиональной ответственности (например, адвоката, нотариуса, врача и других специалистов);
- страхование ответственности владельца автотранспортного средства при выезде за рубеж;
- другие виды страхования ответственности

Эта группировка не включает:
- услуги по страхованию рисков, см. 65.12.5');
INSERT INTO "public"."okved_2" VALUES ('65.12.4', '65.12', 'K', 'Страхование от несчастных случаев и болезней', 'Эта группировка не включает:
- страхование жизни, см. 65.11;
- добровольное медицинское страхование, см. 65.12.1');
INSERT INTO "public"."okved_2" VALUES ('65.12.5', '65.12', 'K', 'Страхование рисков', 'Риски, подлежащие страхованию, дифференцируются по причинам возникновения, времени возникновения, характеру учета и степени тяжести последствий, сфере возникновения и т. д.

Эта группировка включает:
- страхование строительных и пусконаладочных рисков;
- страхование рисков, связанных с космической деятельностью, имущества, оборудования от поломок;
- страхование рисков от перерывов в производстве, страхование сделки (неисполнения договорных обязательств) и т. п.

Эта группировка не включает:
- страхование личного имущества, см. 65.12.2;
- страхование ответственности, см. 65.12.3;
- оценку претензий по страхованию и урегулирование претензий по страхованию, см. 66.21');
INSERT INTO "public"."okved_2" VALUES ('65.12.6', '65.12', 'K', 'Страхование для путешественника, выезжающего за пределы постоянного проживания', 'Эта группировка включает:
- страхование путешественников во время поездок по России, ближнему и дальнему зарубежью на время туристической поездки, отдыха, посещения родственников и знакомых, деловых поездок, командировок и т. п.
Страхованию подлежат:медицинские и медико-транспортные расходы, транспортные расходы, оплата расходов по срочным сообщениям (телефонные переговоры, передача факсимильных сообщений), посмертная репатриация, юридические консультации, помощь при потере или хищении документов, страхование багажа, страхование на случай вынужденного отказа от поездки, оплата расходов, связанных с утратой или повреждением личного автотранспортного средства в результате аварии или поломки, страхование любителей подводного плавания или зимних видов спорта и т. п.

Эта группировка не включает:
- деятельность, связанную с управлением социальными программами в области здравоохранения, см. 84.12;
- страхование от несчастных случаев и болезней, см. 65.12.4;
- деятельность, связанную с предоставлением пособий по болезни, материнству, по случаю потери трудоспособности, государственное медицинское страхование, см. 84.30;
- предоставление социальной помощи и социальных услуг, см. 88.10, 88.9;
- страхование рисков, см. 65.12.5;
- страхованиежизни, см. 65.11;
- добровольное медицинское страхование, см. 65.12.1;
- страхование личного имущества, см. 65.12.2;
- страхование ответственности, см. 65.12.3;
- оценку претензий по страхованию и урегулирование претензий по страхованию, см. 66.21');
INSERT INTO "public"."okved_2" VALUES ('65.12.9', '65.12', 'K', 'Прочие виды страхования, не включенные в другие группировки', 'Эта группировка включает:
- виды страхования, не включенные в другие группировки, например: страхование детей, страхование животных, ипотечное страхование и т. д.');
INSERT INTO "public"."okved_2" VALUES ('65.2', '65', 'K', 'Перестрахование', '');
INSERT INTO "public"."okved_2" VALUES ('66.30.3', '66.30', 'K', 'Управление пенсионными накоплениями негосударственных пенсионных фондов', '');
INSERT INTO "public"."okved_2" VALUES ('66.30.4', '66.30', 'K', 'Управление пенсионными резервами негосударственных пенсионных фондов', '');
INSERT INTO "public"."okved_2" VALUES ('66.30.5', '66.30', 'K', 'Управление страховыми резервами субъектов страхового дела', '');
INSERT INTO "public"."okved_2" VALUES ('66.30.6', '66.30', 'K', 'Управление на основе индивидуальных договоров доверительного управления активами', '');
INSERT INTO "public"."okved_2" VALUES ('66.30.9', '66.30', 'K', 'Другие виды деятельности по управлению активами', '');
INSERT INTO "public"."okved_2" VALUES ('65.20', '65.2', 'K', 'Перестрахование', 'Перестрахование - это действие, в процессе которого страховщик на основании договора передает другому страховщику (перестраховщику) некоторую часть своих обязательств перед клиентами, т. е. страховая компания покупает для самой себя страховой полис.Допускается последовательное заключение двух или даже нескольких контрактов перестрахования

Эта группировка включает:
- деятельность, предполагающую полное или частичное возмещение риска по действующим страховым полисам, выданным другими страховщиками');
INSERT INTO "public"."okved_2" VALUES ('65.3', '65', 'K', 'Деятельность негосударственных пенсионных фондов', '');
INSERT INTO "public"."okved_2" VALUES ('65.30', '65.3', 'K', 'Деятельность негосударственных пенсионных фондов', 'Эта группировка включает:
- деятельность юридических лиц (негосударственных пенсионных фондов): по негосударственному пенсионному обеспечению (аккумулирование пенсионных взносов, размещение и организацию размещения пенсионных резервов, учет пенсионных обязательств фондов, и выплату негосударственных пенсий участникам негосударственного пенсионного фонда), в качестве страховщика по обязательному пенсионному страхованию (аккумулирование средств пенсионных накоплений, организацию инвестирования средств пенсионных накоплений, учет средств пенсионных накоплений застрахованных лиц, назначение и выплату накопительной части трудовой пенсии застрахованным лицам)

Эта группировка также включает:
- единовременную выплату средств пенсионных накоплений;
- срочную пенсионную выплату застрахованным лицам

Эта группировка не включает:
- управление активами негосударственных пенсионных фондов, см. 66.30;
- обязательное социальное страхование, государственное пенсионное обеспечение, см. 84.30');
INSERT INTO "public"."okved_2" VALUES ('66', 'K', 'K', 'Деятельность вспомогательная в сфере финансовых услуг и страхования', 'Эта группировка включает:
- предоставление услуг, являющихся составной частью или тесно связанных с деятельностью по финансовому посредничеству
Выделение группировок этого раздела основано на типах финансовых операций или привлеченных средств');
INSERT INTO "public"."okved_2" VALUES ('66.1', '66', 'K', 'Деятельность вспомогательная в сфере финансовых услуг, кроме страхования и пенсионного обеспечения', 'Эта группировка включает:
- функции управления и контроля над негосударственными финансовыми рынками, а также финансовое посредничество для покупки и продажи акций, опционов, облигаций и заключения товарных договоров');
INSERT INTO "public"."okved_2" VALUES ('66.11', '66.1', 'K', 'Управление финансовыми рынками', 'Эта группировка включает:
- управление и контроль над финансовыми рынками, не являющимися представителями государственной власти: товарными биржами; фьючерсными биржами; биржами ценных бумаг; фондовыми биржами; биржами фондовых или товарных опционов;
- управление, контроль и надзор за деятельностью поднадзорных организаций в области рынков ценных бумаг
- деятельность по любому виду клиринга');
INSERT INTO "public"."okved_2" VALUES ('66.11.1', '66.11', 'K', 'Деятельность по организации торговли на финансовых рынках', '');
INSERT INTO "public"."okved_2" VALUES ('66.11.2', '66.11', 'K', 'Управление и контроль за деятельностью фондовых, товарных, валютных и валютнофондовых бирж', '');
INSERT INTO "public"."okved_2" VALUES ('66.11.3', '66.11', 'K', 'Деятельность регистраторов по ведению реестра владельцев ценных бумаг', '');
INSERT INTO "public"."okved_2" VALUES ('66.11.4', '66.11', 'K', 'Деятельность по обеспечению эффективности функционирования финансовых рынков', '');
INSERT INTO "public"."okved_2" VALUES ('66.11.5', '66.11', 'K', 'Деятельность по определению взаимных обязательств (клиринг)', 'Эта группировка включает:
деятельность по любому виду клиринга');
INSERT INTO "public"."okved_2" VALUES ('66.12', '66.1', 'K', 'Деятельность брокерская по сделкам с ценными бумагами и товарами', 'Эта группировка включает:
- деятельность на финансовых рынках по поручению других лиц (например, фондовых брокеров) и связанная с этим деятельность;
- биржевые операции с фондовыми ценностями;
- биржевые операции с товарными контрактами;
- деятельность пунктов по обмену валют и т. д.

Эта группировка не включает:
- дилерскую деятельность по операциям на рынке ценных бумаг, осуществляемым от своего имени и за свой счет, см. 64.99;
- деятельность по предоставлению посреднических услуг по управлениюпортфелем активов за вознаграждение или на договорной основе, см. 66.30');
INSERT INTO "public"."okved_2" VALUES ('66.12.1', '66.12', 'K', 'Деятельность биржевых посредников и биржевых брокеров, совершающих товарные фьючерсные и опционные сделки в биржевой торговле', '');
INSERT INTO "public"."okved_2" VALUES ('66.12.2', '66.12', 'K', 'Деятельность по управлению ценными бумагами', '');
INSERT INTO "public"."okved_2" VALUES ('66.12.3', '66.12', 'K', 'Деятельность эмиссионная', '');
INSERT INTO "public"."okved_2" VALUES ('71.20.5', '71.20', 'M', 'Технический осмотр автотранспортных средств', '');
INSERT INTO "public"."okved_2" VALUES ('66.19', '66.1', 'K', 'Деятельность вспомогательная прочая в сфере финансовых услуг, кроме страхования и пенсионного обеспечения', 'Эта группировка включает:
- вспомогательную деятельность в сфере финансового посредничества, не классифицированную в других группировках, такую как: деятельность по обработке финансовых сделок и расчетов, включая сделки по платежным карточкам, деятел ьность по предоставлению консультационных услуг по инвестированию, деятельность ипотечных консультантов и брокеров

Эта группировка также включает:
- деятельность по предоставлению посреднических услуг в сфере поручительства, доверительного управления и хранения ценных бумаг за вознаграждение или на договорной основе;
- деятельность по приему платежей физических лиц платежными агентами (юридическими лицами или индивидуальными предпринимателями) и банковскими платежными агентами (организациями, не являющимися кредитными организациями и индивидуальными предпринимателями);
- рейтинговая деятельность');
INSERT INTO "public"."okved_2" VALUES ('66.19.1', '66.19', 'K', 'Деятельность по предоставлению брокерских услуг по ипотечным операциям', '');
INSERT INTO "public"."okved_2" VALUES ('66.19.3', '66.19', 'K', 'Деятельность по предоставлению услуг по обработке наличных денег', '');
INSERT INTO "public"."okved_2" VALUES ('66.19.4', '66.19', 'K', 'Деятельность по предоставлению консультационных услуг по вопросам финансового посредничества', '');
INSERT INTO "public"."okved_2" VALUES ('66.19.5', '66.19', 'K', 'Предоставление услуг по хранению ценностей, депозитарная деятельность', '');
INSERT INTO "public"."okved_2" VALUES ('66.19.6', '66.19', 'K', 'Деятельность по приему платежей физических лиц платежными агентами', 'Эта группировка включает:
- деятельность по приему платежным агентом от плательщика денежных средств, направленных на исполнение денежных обязательств физического лица перед поставщиком по оплате товаров (работ, услуг), а также направленных органам государственной власти, органам местного самоуправления и бюджетным учреждениям, находящимся в их ведении, в рамках выполнения ими функций, установленных законодательством Российской Федерации');
INSERT INTO "public"."okved_2" VALUES ('66.19.61', '66.19.6', 'K', 'Деятельность операторов по приему платежей физических лиц', '');
INSERT INTO "public"."okved_2" VALUES ('66.19.62', '66.19.6', 'K', 'Деятельность платежных субагентов по приему платежей физических лиц', '');
INSERT INTO "public"."okved_2" VALUES ('66.2', '66', 'K', 'Деятельность вспомогательная в сфере страхования и пенсионного обеспечения', 'Эта группировка включает:
- деятельность агентов (брокеров) по продаже ежегодных страховок и страховых полисов, а также предоставление сотрудникам прочих страховых, пенсионных выплат и связанных с ними услуг, таких как претензии по изменению размеравыплат и передача ответственности третьим лицам');
INSERT INTO "public"."okved_2" VALUES ('66.21', '66.2', 'K', 'Оценка рисков и ущерба', 'Эта группировка включает:
- предоставление услуг в области страхования, таких как составление и подача страховых исков, например оценка претензий по страхованию: обоснование претензий по страхованию, оценка суммы страхового риска, оценка страхового риска и убытков, урегулирование претензий по страхованию

Эта группировка не включает:
- оценку недвижимого имущества, см. 68.31;
- оценку в других целях, см. 74.90;
- расследование страховых случаев, см. 80.30');
INSERT INTO "public"."okved_2" VALUES ('66.22', '66.2', 'K', 'Деятельность страховых агентов и брокеров', 'Эта группировка включает:
- деятельность страховых агентов и брокеров (страховых посредников) по продаже, ведению переговоров или запросам полисов страхования и перестрахования');
INSERT INTO "public"."okved_2" VALUES ('66.29', '66.2', 'K', 'Деятельность вспомогательная прочая в сфере страхования и пенсионного обеспечения', 'Эта группировка включает:
- деятельность, приравненную или тесно связанную со страхованием и добровольным пенсионным страхованием (кроме финансовых посредников, специалистов по оценке страхового риска и убытков и деятельности страховых агентов); управление сохранностью имущества;
- услуги по делопроизводству

Эта группировка не включает:
- деятельность по спасению судов на море, см. 52.22');
INSERT INTO "public"."okved_2" VALUES ('66.29.1', '66.29', 'K', 'Деятельность страховых актуариев', '');
INSERT INTO "public"."okved_2" VALUES ('66.29.2', '66.29', 'K', 'Деятельность распорядителей спасательными работами', 'Эта группировка не включает:
- деятельность по спасению судов на море, см. 52.22');
INSERT INTO "public"."okved_2" VALUES ('66.29.9', '66.29', 'K', 'Деятельность вспомогательная прочая в сфере страхования, кроме обязательного социального страхования', '');
INSERT INTO "public"."okved_2" VALUES ('66.3', '66', 'K', 'Деятельность по управлению фондами', '');
INSERT INTO "public"."okved_2" VALUES ('68.31.3', '68.31', 'L', 'Предоставление консультационных услуг при купле-продаже недвижимого имущества за вознаграждение или на договорной основе', '');
INSERT INTO "public"."okved_2" VALUES ('L', '', 'L', 'ДЕЯТЕЛЬНОСТЬ ПО ОПЕРАЦИЯМ С НЕДВИЖИМЫМ ИМУЩЕСТВОМ', 'Этот раздел включает:
- деятельность арендодателей, агентов или брокеров в одной или нескольких из следующих областей: покупка или продажа недвижимости, сдача внаем недвижимости, предоставление других услуг в сфере недвижимости, таких как оценивание,страхование или деятельность доверенных лиц
Деятельность по предоставлению посреднических услуг в этом разделе также может осуществляться с собственной или арендованной недвижимостью и может осуществляться за вознаграждение или на договорной основе
Этот раздел также включает:
- информацию о владельцах недвижимости');
INSERT INTO "public"."okved_2" VALUES ('68', 'L', 'L', 'Операции с недвижимым имуществом', '');
INSERT INTO "public"."okved_2" VALUES ('68.1', '68', 'L', 'Покупка и продажа собственного недвижимого имущества', '');
INSERT INTO "public"."okved_2" VALUES ('68.10', '68.1', 'L', 'Покупка и продажа собственного недвижимого имущества', 'Эта группировка включает:
- покупку и продажу собственного недвижимого имущества: многоквартирных зданий, жилых домов, квартир, нежилых зданий и помещений, в том числе выставочных залов, складских помещений, магазинов и торговых мест, земельных участков

Эта группировка также включает:
- разделение недвижимого имущества в виде земли на участки без их благоустройства');
INSERT INTO "public"."okved_2" VALUES ('68.10.1', '68.10', 'L', 'Подготовка к продаже собственного недвижимого имущества', '');
INSERT INTO "public"."okved_2" VALUES ('68.10.11', '68.10.1', 'L', 'Подготовка к продаже собственного жилого недвижимого имущества', '');
INSERT INTO "public"."okved_2" VALUES ('68.10.12', '68.10.1', 'L', 'Подготовка к продаже собственного нежилого недвижимого имущества', '');
INSERT INTO "public"."okved_2" VALUES ('68.10.2', '68.10', 'L', 'Покупка и продажа собственного недвижимого имущества', '');
INSERT INTO "public"."okved_2" VALUES ('68.10.21', '68.10.2', 'L', 'Покупка и продажа собственного жилого недвижимого имущества', '');
INSERT INTO "public"."okved_2" VALUES ('68.10.22', '68.10.2', 'L', 'Покупка и продажа собственных нежилых зданий и помещений', '');
INSERT INTO "public"."okved_2" VALUES ('68.10.23', '68.10.2', 'L', 'Покупка и продажа земельных участков', '');
INSERT INTO "public"."okved_2" VALUES ('68.2', '68', 'L', 'Аренда и управление собственным или арендованным недвижимым имуществом', '');
INSERT INTO "public"."okved_2" VALUES ('68.20', '68.2', 'L', 'Аренда и управление собственным или арендованным недвижимым имуществом', 'Эта группировка включает:
- сдачу в аренду и эксплуатацию собственного или арендованного недвижимого имущества: многоквартирных зданий и других жилых домов, квартир, нежилых зданий и помещений, включая выставочные залы и складские помещения, земельных участков;
- предоставление в аренду домов, меблированных и немеблированных квартир или многоквартирных помещений, предназначенных для долговременного проживания, обычно на ежемесячной или ежегодной основе

Эта группировка также включает:
- строительство зданий для собственного пользования;
- эксплуатацию стоянок для передвижных домов');
INSERT INTO "public"."okved_2" VALUES ('68.20.1', '68.20', 'L', 'Аренда и управление собственным или арендованным жилым недвижимым имуществом', '');
INSERT INTO "public"."okved_2" VALUES ('68.20.2', '68.20', 'L', 'Аренда и управление собственным или арендованным нежилым недвижимым имуществом', '');
INSERT INTO "public"."okved_2" VALUES ('68.3', '68', 'L', 'Операции с недвижимым имуществом за вознаграждение или на договорной основе', '');
INSERT INTO "public"."okved_2" VALUES ('68.31', '68.3', 'L', 'Деятельность агентств недвижимости за вознаграждение или на договорной основе', 'Эта группировка включает:
- предоставление агентствами услуг по работе с недвижимым имуществом: предоставление посреднических услуг в покупке, продаже и аренде недвижимого имущества, предоставление консультационных услуг при покупке, продаже и аренденедвижимого имущества;
- деятельность агентов по поручительству

Эта группировка не включает:
- деятельность в области права, см. 69.10');
INSERT INTO "public"."okved_2" VALUES ('68.31.1', '68.31', 'L', 'Предоставление посреднических услуг при купле-продаже недвижимого имущества за вознаграждение или на договорной основе', '');
INSERT INTO "public"."okved_2" VALUES ('68.31.11', '68.31.1', 'L', 'Предоставление посреднических услуг при купле-продаже жилого недвижимого имущества за вознаграждение или на договорной основе', '');
INSERT INTO "public"."okved_2" VALUES ('68.31.12', '68.31.1', 'L', 'Предоставление посреднических услуг при купле-продаже нежилого недвижимого имущества за вознаграждение или на договорной основе', '');
INSERT INTO "public"."okved_2" VALUES ('68.31.2', '68.31', 'L', 'Предоставление посреднических услуг по аренде недвижимого имущества за вознаграждение или на договорной основе', '');
INSERT INTO "public"."okved_2" VALUES ('68.31.21', '68.31.2', 'L', 'Предоставление посреднических услуг по аренде жилого недвижимого имущества за вознаграждение или на договорной основе', '');
INSERT INTO "public"."okved_2" VALUES ('68.31.22', '68.31.2', 'L', 'Предоставление посреднических услуг по аренде нежилого недвижимого имущества за вознаграждение или на договорной основе', '');
INSERT INTO "public"."okved_2" VALUES ('68.31.42', '68.31.4', 'L', 'Предоставление консультационных услуг по аренде нежилого недвижимого имущества за вознаграждение или на договорной основе', '');
INSERT INTO "public"."okved_2" VALUES ('68.31.5', '68.31', 'L', 'Предоставление посреднических услуг при оценке недвижимого имущества за вознаграждение или на договорной основе', '');
INSERT INTO "public"."okved_2" VALUES ('68.31.51', '68.31.5', 'L', 'Предоставление посреднических услуг при оценке жилого недвижимого имущества за вознаграждение или на договорной основе', '');
INSERT INTO "public"."okved_2" VALUES ('68.31.52', '68.31.5', 'L', 'Предоставление посреднических услуг при оценке нежилого недвижимого имущества за вознаграждение или на договорной основе', '');
INSERT INTO "public"."okved_2" VALUES ('68.32', '68.3', 'L', 'Управление недвижимым имуществом за вознаграждение или на договорной основе', 'Эта группировка включает:
- деятельность учреждений по сбору арендной платы

Эта группировка не включает:
- деятельность в области права, см. 69.10;
- деятельность служб коммунальной поддержки (сочетание услуг, таких как уборка, содержание и проведение мелких ремонтных работ, вывоз мусора, охрана помещений и обеспечение безопасности), см. 81.10;
- управление объектами, такими как военные базы, тюрьмы и прочие объекты (кроме компьютерного управления объектами), см. 81.10');
INSERT INTO "public"."okved_2" VALUES ('68.32.1', '68.32', 'L', 'Управление эксплуатацией жилого фонда за вознаграждение или на договорной основе', '');
INSERT INTO "public"."okved_2" VALUES ('68.32.2', '68.32', 'L', 'Управление эксплуатацией нежилого фонда за вознаграждение или на договорной основе', '');
INSERT INTO "public"."okved_2" VALUES ('M', '', 'M', 'ДЕЯТЕЛЬНОСТЬ ПРОФЕССИОНАЛЬНАЯ, НАУЧНАЯ И ТЕХНИЧЕСКАЯ', 'Этот раздел включает:
- специализированную профессиональную, научную и техническую деятельность
Эта деятельность требует длительного обучения и предоставления специализированных знаний и навыков');
INSERT INTO "public"."okved_2" VALUES ('69', 'M', 'M', 'Деятельность в области права и бухгалтерского учета', 'Эта группировка включает:
- представление интересов одной стороны против другой стороны в судах или других судебных органах лицом, или под наблюдением лица, являющегося членом суда, такого как консультант или представитель в гражданских делах, консультант или представитель в уголовных делах, консультант или представитель в связи с трудовыми спорами
Также включена деятельность по подготовке правовых документов, таких как свидетельства о регистрации компании, партнерские договора или прочие документы, касающиеся деятельности по созданию компании, патентов и всех видов авторских прав, подготовки актов, завещаний, дарственных и т. п., а также прочая деятельность государственных нотариусов, нотариусов по гражданским делам, судебных приставов, арбитров, третейских судей, патентных поверенных

Эта группировка также включает:
- деятельность по оказанию услуг по ведению бухгалтерского учета, включая составление бухгалтерской (финансовой) отчетности;
- деятельность по проведению финансового аудита;
- деятельность по налоговому консультированию');
INSERT INTO "public"."okved_2" VALUES ('69.1', '69', 'M', 'Деятельность в области права', '');
INSERT INTO "public"."okved_2" VALUES ('69.10', '69.1', 'M', 'Деятельность в области права', 'Эта группировка включает:
- представление интересов одной стороны против другой стороны в судах или других судебных органах: консультирование и представительство в гражданских делах, консультирование и представительство в уголовных делах, консультирование и представительство в связи с трудовыми спорами;
- предоставление рекомендаций и консультаций по общим вопросам, включая подготовку юридических документов: свидетельств о регистрации компаний, уставов организаций и аналогичных документов, связанных с созданием и деятельностью компаний, патентов и авторских свидетельств; юридических актов (завещаний, доверенностей и т. п.);
- работу государственных нотариусов, нотариусов по гражданским делам, судебных приставов, арбитров, лиц, назначаемых судом для снятия свидетельских показаний, третейских судей, патентных поверенных

Эта группировка не включает:
- деятельность судов, см. 84.23');
INSERT INTO "public"."okved_2" VALUES ('69.2', '69', 'M', 'Деятельность по оказанию услуг в области бухгалтерского учета, по проведению финансового аудита, по налоговому консультированию', '');
INSERT INTO "public"."okved_2" VALUES ('69.20', '69.2', 'M', 'Деятельность по оказанию услуг в области бухгалтерского учета, по проведению финансового аудита, по налоговому консультированию', 'Эта группировка включает:
- деятельность по ведению (восстановлению) бухгалтерского учета, в том числе по составлению бухгалтерской (финансовой) отчетности, бухгалтерскому консультированию;
- деятельность по проведению аудита бухгалтерской (финансовой) отчетности организаций и оказанию сопутствующих аудиту услуг, осуществляемая аудиторскими организациями и индивидуальными аудиторами;
- налоговое консультирование и представление клиентов в налоговых органах, в том числе подготовку налоговой документации

Эта группировка не включает:
- обработку и формирование сводных данных, см. 63.11;
- управленческое консультирование, связанное с системами бухгалтерского учета, процедурами управления бюджетом, см. 70.22;
- взыскание платежей по счетам, см.82.91');
INSERT INTO "public"."okved_2" VALUES ('74.90.24', '74.90.2', 'M', 'Деятельность, направленная на установление рыночной или иной стоимости прав требования, обязательств (долгов)', '');
INSERT INTO "public"."okved_2" VALUES ('69.20.1', '69.20', 'M', 'Деятельность по проведению финансового аудита', 'Эта группировка включает:
- деятельность по проведению аудита бухгалтерской (финансовой) отчетности организаций и оказанию сопутствующих аудиту услуг, осуществляемая аудиторскими организациями и индивидуальными аудиторами');
INSERT INTO "public"."okved_2" VALUES ('69.20.2', '69.20', 'M', 'Деятельность по оказанию услуг в области бухгалтерского учета', 'Эта группировка включает:
- деятельность по ведению (восстановлению) бухгалтерского учета, включая составление бухгалтерской (финансовой) отчетности, бухгалтерскому консультированию; по принятию, своду и консолидации бухгалтерской (финансовой) отчетности');
INSERT INTO "public"."okved_2" VALUES ('69.20.3', '69.20', 'M', 'Деятельность области налогового консультирования', 'Эта группировка включает:
- налоговое консультирование;
- представление клиентов в налоговых органах, в том числе подготовку налоговой документации');
INSERT INTO "public"."okved_2" VALUES ('70', 'M', 'M', 'Деятельность головных офисов; консультирование по вопросам управления', 'Эта группировка включает:
- предоставление консультационных услуг или оказание оперативной помощи по проблемам управления, таких как стратегическое и оперативное планирование, финансовое планирование и составление бюджета, маркетинговые цели и политика, практика и планирование работы с персоналом, планирование производства и контроля производства

Эта группировка также включает:
- деятельность, связанную с наблюдением и управлением за другими подразделениями компании, т. е. деятельность головныхофисов');
INSERT INTO "public"."okved_2" VALUES ('70.1', '70', 'M', 'Деятельность головных офисов', '');
INSERT INTO "public"."okved_2" VALUES ('70.10', '70.1', 'M', 'Деятельность головных офисов', 'Эта группировка включает:
- наблюдение и управление другими подразделениями компании, осуществление оперативного или стратегического планирования и выработку принятия решений в компании, осуществление оперативного контроля и управления ежедневной деятельностью соответствующих подразделений данной компании или предприятия

Эта группировка включает:
- деятельность головных офисов;
- деятельность централизованных административных отделов;
- деятельность корпоративных офисов;
- деятельность районныхи областных офисов;
- деятельность вспомогательных управленческих офисов

Эта группировка не включает:
- деятельность холдинг-компаний, не участвующих в управлении, см. 64.20');
INSERT INTO "public"."okved_2" VALUES ('70.10.1', '70.10', 'M', 'Деятельность по управлению финансово-промышленными группами', '');
INSERT INTO "public"."okved_2" VALUES ('70.10.2', '70.10', 'M', 'Деятельность по управлению холдинг-компаниями', '');
INSERT INTO "public"."okved_2" VALUES ('70.2', '70', 'M', 'Консультирование по вопросам управления', '');
INSERT INTO "public"."okved_2" VALUES ('70.21', '70.2', 'M', 'Деятельность в сфере связей с общественностью', 'Эта группировка включает:
- консультирование, выдачу рекомендаций и оказание оперативной помощи компаниям, включая деятельность по лоббированию, в сфере связей с общественностью и коммуникации, компаниям и прочим организациям

Эта группировка не включает:
- деятельность рекламных агентств и медиа-агентств, см. 73.1;
- исследование рынка и опрос общественного мнения, см. 73.20');
INSERT INTO "public"."okved_2" VALUES ('70.22', '70.2', 'M', 'Консультирование по вопросам коммерческой деятельности и управления', 'Эта группировка включает:
- предоставление консультационных услуг;
- выдачу рекомендаций и оказание оперативной помощи компаниям и прочим организациям в сфере управления, таких как корпоративное стратегическое и оперативное планирование, реструктуризация производственных процессов, оптимизация управления, сокращение затрат и прочие финансовые вопросы, маркетинговые цели и политика, практика и планирование работы с персоналом, компенсационные и пенсионные стратегии, планирование и управление производством
Предоставление этих услуг компаниям или иным организациям может включать консультирование, выдачу рекомендаций или оказание помощи по следующим направлениям:
- разработка процедур и методов бухгалтерского учета, программ учета затрат, бюджетирования;
- консультирование и оказание помощи компаниям и иным организациям в сфере планирования, организации, эффективности и контроля управленческой информации и т. п.

Эта группировка не включает:
- разработку систем бухгалтерского программного обеспечения, см. 62.01;
- юридические консультации и посредничество, см. 69.10;
- бухгалтерский учет и аудит, консультирование по вопросам налогообложения, см. 69.20;
- консультирование по строительству и архитектуре, см. 71.11, 71.12;
- консультирование в области экологии, агрономии, безопасности и прочую подобную деятельность по консультированию, см. 74.90;
- консультирование по размещению или найму персонала, см. 78.10;
- консультирование по вопросам образования, см. 85');
INSERT INTO "public"."okved_2" VALUES ('71', 'M', 'M', 'Деятельность в области архитектуры и инженерно-технического проектирования; технических испытаний, исследований и анализа', 'Эта группировка включает:
- предоставление архитектурных, инженерных услуг, услуг по изготовлению чертежей, строительному обследованию, топографической съемке и услуг по картографии

Эта группировка также включает:
- оказание услуг по проведению физических, химических и прочих испытаний с целью анализа;
- оказание услуг по управлению проектами строительства, выполнению строительного контроля и авторского надзора');
INSERT INTO "public"."okved_2" VALUES ('71.12.13', '71.12.1', 'M', 'Разработка проектов по кондиционированию воздуха, холодильной технике, санитарной технике и мониторингу загрязнения окружающей среды, строительной акустике', '');
INSERT INTO "public"."okved_2" VALUES ('71.1', '71', 'M', 'Деятельность в области архитектуры, инженерных изысканий и предоставление технических консультаций в этих областях', 'Эта группировка включает:
- предоставление архитектурных, инженерно-технических услуг, услуг по разработке чертежей, по строительным изыскательским работам, услуг по картографии и т. п.;
- оказание услуг по управлению проектами строительства, выполнению строительного контроля и авторского надзора');
INSERT INTO "public"."okved_2" VALUES ('71.11', '71.1', 'M', 'Деятельность в области архитектуры', 'Эта группировка включает:
- консультативные услуги в области архитектурных работ, включая разработку архитектурной концепции, подготовку архитектурных решений зданий и сооружений, градостроительное проектирование, включая ландшафтную архитектуру
Этагруппировка не включает:
- консультирование в области вычислительной техники, см. 62.02, 62.09;
- оформление (дизайн) помещений, см. 74.10');
INSERT INTO "public"."okved_2" VALUES ('71.11.1', '71.11', 'M', 'Деятельность в области архитектуры, связанная с созданием архитектурного объекта', 'Эта группировка также включает:
- разработку проектной документации по консервации, ремонту, реставрации, приспособлению и воссозданию объектов культурного наследия

Эта группировка не включает:
- разработку проектной документации по консервации, ремо нту, реставрации, приспособлению и воссозданию объектов культурного наследия (в части инженерно-технической проектной документации), см. 71.12.12;
- разработку проектной документации (как архитектурной так и инженерно-технической) по консервации, рем онту, реставрации, приспособлению и воссозданию объектов культурного наследия (в части ландшафтной архитектуры), см. 71.11.3');
INSERT INTO "public"."okved_2" VALUES ('71.11.2', '71.11', 'M', 'Деятельность по территориальному планированию и планировке территории', '');
INSERT INTO "public"."okved_2" VALUES ('71.11.3', '71.11', 'M', 'Деятельность в области ландшафтной архитектуры и консультативные услуги в области архитектуры', 'Эта группировка также включает:
- разработку проектной документации по консервации, ремонту, реставрации, приспособлению и воссозданию объектов культурного наследия');
INSERT INTO "public"."okved_2" VALUES ('71.12', '71.1', 'M', 'Деятельность в области инженерных изысканий, инженерно-технического проектирования, управления проектами строительства, выполнения строительного контроля и авторского надзора, предоставление технических консультаций в этих областях', 'Эта группировка включает:
- инженерно-техническое проектирование, т.е. применение инженерно-технических правил проектирования машин, материалов, инструментов, сооружений, технологий, а также консультирование в области: машиностроения, промышленных пр оцессов и оборудования, проектирования, связанного со строительством инженерных сооружений, включая гидротехнические сооружения, транспортное строительство, разработки проектов водоснабжения, разработки проектов промышленных процессов и производств, относящихся к электротехнике, электронной технике, горному делу, химической технологии, машиностроению, а также в области промышленного строительства, системотехники и техники безопасности;
- разработку проектов по кондиционированию воздуха, холодиль ной технике, санитарной технике и мониторингу загрязнения окружающей среды, строительной акустике и т.п.;
- геофизические, геологические и сейсмологические работы;
- геодезические, гидрологические изыскательские работы, изыскательские работы по изуче нию недр;
- картографическую деятельность

Эта группировка также включает:
- проектирование зданий и сооружений, предназначенных для проведения ядерно-опасных и радиационно-опасных работ в сфере ядерных оружейных технологий;
- энергосервис
Эта группир овка не включает:
- разведочное бурение, см. 09.10, 09.90;
- разработку или выпуск необходимого программного обеспечения, см. 58.29, 62.01;
- деятельность консультантов в области вычислительной техники, см. 62.02, 62.09;
- технические испытания, иссл едования, см. 71.20;
- научные исследования и разработки, см. 72.19;
- промышленный дизайн, см. 74.10;
- аэрофотосъемку, см. 74.20');
INSERT INTO "public"."okved_2" VALUES ('71.12.1', '71.12', 'M', 'Деятельность, связанная с инженерно-техническим проектированием, управлением проектами строительства, выполнением строительного контроля и авторского надзора', 'Эта группировка также включает:
- авторский и технический надзор при проведении работ по сохранению и воссозданию объекта культурного наследия;
- разработку проектной документации по консервации, ремонту, реставрации, приспособлению и воссозданию объ ектов культурного наследия;
- разработку проектной документации по инженерному укреплению объектов культурного наследия');
INSERT INTO "public"."okved_2" VALUES ('71.12.11', '71.12.1', 'M', 'Разработка проектов тепло-, водо-, газоснабжения', '');
INSERT INTO "public"."okved_2" VALUES ('71.12.12', '71.12.1', 'M', 'Разработка проектов промышленных процессов и производств, относящихся к электротехнике, электронной технике, горному делу, химической технологии, машиностроению, а также в области промышленного строительства, системотехники и техники безопасности', 'Эта группировка также включает:
- разработку проектной документации по консервации, ремонту, реставрации, приспособлению и воссозданию объектов культурного наследия;
- разработку проектной документации по инженерному укреплению объектов культурного н аследия

Эта группировка не включает:
- разработку проектной документации (в части инженерно-технической проектной документации в области ландшафтной архитектуры) по консервации, ремонту, реставрации, приспособлению и воссозданию объектов культурного наследия, см. 71.11.3');
INSERT INTO "public"."okved_2" VALUES ('71.12.2', '71.12', 'M', 'Деятельность заказчика-застройщика, генерального подрядчика', 'Эта группировка включает:
- организацию реализации инвестиционного проекта (выполнение предпроектной подготовки, анализ возможностей участников инвестиционно-строительного процесса, планирование строительства, не включая проектные, изыскательные, научно-исследовательские, опытноконструкторские, строительно-монтажные, отделочные работы, сейсмические исследования и другие работы, связанные со строительством и ремонтом объектов производственного и непроизводственного назначения)
В задачи заказчика-застройщика может входить весь комплекс организационноуправленческих работ, обеспечивающих строительство "под ключ" (за счет переданных ему по договору с инвестором денежных средств)');
INSERT INTO "public"."okved_2" VALUES ('71.12.3', '71.12', 'M', 'Работы геолого-разведочные, геофизические и геохимические в области изучения недр и воспроизводства минерально-сырьевой базы', 'Эта группировка включает: - работы по геологическому изучению недр, в том числе региональному, предназначенные для сбора информации о структуре недр и местонахождении залежей полезных ископаемых и подземных вод: проведение наземных маршрутов геологи ческого содержания при геологической съемке, геологическом доизучении ранее заснятых площадей, комплексной съемке, гидрогеологическом доизучении ранее заснятых площадей, поисках и поисково-оценочных работах, работах общего назначения; отбор и обработ ка проб горных пород и полезных ископаемых; проведение геохимических работ; проведение гидрогеологических работ; проведение геоэкологических работ; проведение полевых сейсморазведочных работ; проведение работ с применением методов электроразведки; пр оведение работ с применением методов гравиразведки и магниторазведки; проведение аэрогеофизических работ; проведение геофизических исследований скважин; проведение работ по бурению глубоких скважин различных категорий, включая опорные, параметрически е, поисковые, поисково-оценочные и разведочные; проходка поверхностных и подземных горных выработок; проведение морских геолого-геофизических работ; проведение инженерно-геологических работ; проведение лабораторных работ; проведение топогеодезических работ; создание государственной сети опорных геолого-геофизических профилей, параметрических и сверхглубоких скважин; мониторинг состояния недр (наблюдение за состоянием подземных вод, экзогенных и эндогенных геологических процессов); - тематические и опытно-методические работы, связанные с геологическим изучением недр');
INSERT INTO "public"."okved_2" VALUES ('71.12.4', '71.12', 'M', 'Деятельность геодезическая и картографическая', '');
INSERT INTO "public"."okved_2" VALUES ('71.12.41', '71.12.4', 'M', 'Деятельность геодезическая, кроме создания геодезической, нивелирной и гравиметрической сетей', 'Эта группировка включает: - геодезические работы по определению координат и (или) высот точек земной поверхности, пространственных объектов, изменений во времени указанных координат и высот, по определению параметров фигуры Земли, ее гравитационного поля в этих целях
Эта группировка не включает: - деятельность по созданию геодезических сетей (в том числе геодезических сетей специального назначения), государственных нивелирных сетей и государственных гравиметрических сетей, см. 71.12.45');
INSERT INTO "public"."okved_2" VALUES ('71.12.42', '71.12.4', 'M', 'Деятельность картографическая, кроме создания топографических карт и планов', 'Эта группировка включает: - картографические работы по сбору и обработке пространственных данных в целях обеспечения возможности их последующего отображения на планах, картах и в атласах (в том числе в электронной форме);- деятельность в областях наи менований географических объектов и создания и ведения картографо-геодезических фондов
Эта группировка не включает: - фотограмметрические и топографические работы, работы по созданию специальных и государственных топографических карт и (или) планов ил и иных картографических материалов, см. 71.12.44');
INSERT INTO "public"."okved_2" VALUES ('71.12.43', '71.12.4', 'M', 'Деятельность гидрографическая изыскательская', 'Деятельность гидрографическая изыскательская');
INSERT INTO "public"."okved_2" VALUES ('71.12.44', '71.12.4', 'M', 'Деятельность по созданию топографических карт и планов', 'Эта группировка включает:- фотограмметрические и топографические работы, в том числе создание государственных топографических карт и государственных топографических планов, в том числе специальных');
INSERT INTO "public"."okved_2" VALUES ('71.12.45', '71.12.4', 'M', 'Создание геодезической, нивелирной, гравиметрической сетей', 'Эта группировка включает:- деятельность по созданию геодезических сетей (в том числе геодезических сетей специального назначения), государственных нивелирных сетей и государственных гравиметрических сетей');
INSERT INTO "public"."okved_2" VALUES ('71.12.5', '71.12', 'M', 'Деятельность в области гидрометеорологии и смежных с ней областях, мониторинга состояния окружающей среды, ее загрязнения', '');
INSERT INTO "public"."okved_2" VALUES ('71.12.51', '71.12.5', 'M', 'Деятельность наблюдательной гидрометеорологической сети', 'Эта группировка включает:
- получение и хранение метеорологических, климатических, аэрологических, гидрологических, океанологических, агрометеорологических характеристик и параметров;
- получение и хранение данных об уровнях загрязнения окружающей среды');
INSERT INTO "public"."okved_2" VALUES ('71.12.52', '71.12.5', 'M', 'Проведение гелиофизических и геофизических работ', '');
INSERT INTO "public"."okved_2" VALUES ('71.20.2', '71.20', 'M', 'Судебно-экспертная деятельность', '');
INSERT INTO "public"."okved_2" VALUES ('71.20.3', '71.20', 'M', 'Испытания и анализ физико-механических свойств материалов и веществ', '');
INSERT INTO "public"."okved_2" VALUES ('77.33.2', '77.33', 'N', 'Аренда и лизинг вычислительных машин и оборудования', '');
INSERT INTO "public"."okved_2" VALUES ('71.12.53', '71.12.5', 'M', 'Деятельность по мониторингу загрязнения окружающей среды для физических и юридических лиц', 'Эта группировка включает:
- проведение наблюдений и определение уровней загрязнения окружающей среды по специальным программам;
- прогнозирование загрязнения атмосферного воздуха при неблагоприятных метеорологических условиях для рассеивания примесейв атмосфере;
- подготовку и согласование проектных материалов, обосновывающих нормативы допустимых выбросов и сбросов загрязняющих веществ в окружающую среду');
INSERT INTO "public"."okved_2" VALUES ('71.12.54', '71.12.5', 'M', 'Работы полевые и изыскания в области гидрометеорологии и смежных с ней областях, экспедиционные обследования объектов окружающей среды с целью оценки уровней загрязнения', 'Эта группировка также включает:
- проведение изыскательских работ в целях сохранения и воссоздания объектов культурного наследия: экологических изысканий');
INSERT INTO "public"."okved_2" VALUES ('71.12.55', '71.12.5', 'M', 'Деятельность по обработке и предоставлению гидрометеорологической информации органам государственной власти и населению', 'Эта группировка включает:
- предоставление предупреждений об опасных гидрометеорологических явлениях, предоставление информации об экстремально высоком и аварийном загрязнении окружающей среды;
- предоставление информации об экстремально высоком и аварийном загрязнении окружающей среды;
- составление и предоставление гидрометеорологических прогнозов общего назначения;
- предоставление информации общего назначения об уровнях загрязнения окружающей среды');
INSERT INTO "public"."okved_2" VALUES ('71.12.56', '71.12.5', 'M', 'Обеспечение гидрометеорологическое деятельности физических и юридических лиц', 'Эта группировка включает:
- гидрометеорологическое обеспечение деятельности сухопутного, воздушного, водного транспорта, энергетики и связи;
- гидрометеорологическое обеспечение работ по добыче, транспортировке и переработке нефти и газа;
- гидромете орологическое обеспечение лова рыбы;
- гидрометеорологическое обеспечение строительных работ, а также прочих работ с использованием подъемно-транспортного оборудования;
- гидрометеорологическое обеспечение жилищно-коммунального хозяйства;
- гидромете орологическое обеспечение функционирования гидротехнических сооружений и объектов;
- гидрометеорологическое обеспечение предприятий и организаций агропромышленного комплекса;
- гидрометеорологическое обеспечение работ по защите лесов от пожаров;
- ги дрометеорологические изыскания и гидрометеорологические экспертизы для проектирования и строительства зданий и сооружений

Эта группировка также включает:
- проведение изыскательских работ в целях сохранения и воссоздания объектов культурного наследия : гидрометеорологических изысканий');
INSERT INTO "public"."okved_2" VALUES ('71.12.57', '71.12.5', 'M', 'Деятельность, связанная с активными воздействиями на метеорологические и геофизические процессы и явления', 'Эта группировка включает:
- деятельность, связанную с активными воздействиями на градовые процессы для защиты производства сельскохозяйственных культур;
- деятельность по предупредительному спуску снежных лавин;
- деятельность по искусственному регулированию осадков, в том числе по вызыванию осадков с целью тушения лесных пожаров;
- деятельность по рассеиванию туманов');
INSERT INTO "public"."okved_2" VALUES ('71.12.6', '71.12', 'M', 'Деятельность в области технического регулирования, стандартизации, метрологии, аккредитации, каталогизации продукции', '');
INSERT INTO "public"."okved_2" VALUES ('71.12.61', '71.12.6', 'M', 'Деятельность в области технического регулирования и стандартизации', '');
INSERT INTO "public"."okved_2" VALUES ('71.12.62', '71.12.6', 'M', 'Деятельность в области метрологии', '');
INSERT INTO "public"."okved_2" VALUES ('71.12.63', '71.12.6', 'M', 'Деятельность в области аккредитации', '');
INSERT INTO "public"."okved_2" VALUES ('71.12.64', '71.12.6', 'M', 'Государственный контроль (надзор) за соблюдением требований технических регламентов', '');
INSERT INTO "public"."okved_2" VALUES ('71.12.65', '71.12.6', 'M', 'Федеральный государственный метрологический надзор', '');
INSERT INTO "public"."okved_2" VALUES ('71.12.66', '71.12.6', 'M', 'Деятельность в области каталогизации продукции', '');
INSERT INTO "public"."okved_2" VALUES ('71.2', '71', 'M', 'Технические испытания, исследования, анализ и сертификация', '');
INSERT INTO "public"."okved_2" VALUES ('71.20', '71.2', 'M', 'Технические испытания, исследования, анализ и сертификация', 'Эта группировка включает: - выполнение физических, химических и прочих аналитических исследований всех видов материалов и веществ, таких как: акустические и вибрационные испытания, испытания и анализ состава минералов и содержания примесей, испытания и анализ в области гигиены питания, включая ветеринарный контроль и контроль за производством продуктов питания, испытания и анализ физических свойств материалов, таких как геометрические размеры, износостойкость, радиоактивность и т.п., испытания к ачества и надежности изделий, испытания работоспособности готовой продукции: моторов, автомобилей, электронных устройств и т.д., неразрушающие испытания и анализ сварных швов и стыков, испытания и анализ на наличие повреждений; - испытания и расчеты экологических показателей: загрязнения воздуха, воды и т.д.; - сертификацию продукции, включая товары народного потребления, автомобили, летательные аппараты, резервуары давления, ядерные установки и т.д.; - регулярные испытания и анализ безопасности автомобильных дорог; - испытания и анализ с использованием моделей или макетов транспортных и других средств (например, самолетов, ракет, судов, дамб и т.д.); - деятельность в области обеспечения безопасности лабораторий 
Эта группировка также включа ет: - летные испытания авиационной, ракетной и космической техники; - судебно-экспертную деятельность; - государственную экспертизу проектной документации и результатов инженерных изысканий для объектов культурного наследия; - мониторинг состояния об ъектов культурного наследия, территорий объектов культурного наследия, зон охраны объектов культурного наследия, территорий исторических поселений; - мониторинг проведения работ по сохранению объектов культурного наследия; - экспертизу проектной док ументации на проведение работ по региональному геологическому изучению недр, геологическому изучению недр, включая поиски и оценку месторождений полезных ископаемых, разведке месторождений полезных ископаемых; - государственную экспертизу запасов');
INSERT INTO "public"."okved_2" VALUES ('71.20.1', '71.20', 'M', 'Испытания и анализ состава и чистоты материалов и веществ: анализ химических и биологических свойств материалов и веществ; испытания и анализ в области гигиены питания, включая ветеринарный контроль и контроль за производством продуктов питания', '');
INSERT INTO "public"."okved_2" VALUES ('71.20.6', '71.20', 'M', 'Экспертиза проектной документации, запасов полезных ископаемых и подземных вод, геологической информации о предоставляемых в пользование участках недр, результатов инженерных изысканий', 'Эта группировка включает: - экспертизу проектной документации на проведение работ по региональному геологическому изучению недр, геологическому изучению недр, включая поиски и оценку месторождений полезных ископаемых, разведке месторождений полезных ископаемых; - государственную экспертизу запасов полезных ископаемых, и подземных вод, геологической информации о предоставляемых');
INSERT INTO "public"."okved_2" VALUES ('71.20.61', '71.20.6', 'M', 'Экспертиза проектной документации, запасов полезных ископаемых и подземных вод, геологической информации о предоставляемых в пользование участках недр, результатов инженерных изысканий государственная', 'Эта группировка также включает: - государственную экспертизу проектной документации и результатов инженерных изысканий для объектов культурного наследия; - экспертизу проектной документации на проведение работ по региональному геологическому изучени ю недр, геологическому изучению недр, включая поиски и оценку месторождений полезных ископаемых, разведке месторождений полезных ископаемых; - государственную экспертизу запасов полезных ископаемых и подземных вод, геологической информации о предоста вляемых в пользование участках недр');
INSERT INTO "public"."okved_2" VALUES ('71.20.62', '71.20.6', 'M', 'Экспертиза проектной документации и результатов инженерных изысканий негосударственная', '');
INSERT INTO "public"."okved_2" VALUES ('71.20.7', '71.20', 'M', 'Деятельность по оценке условий труда', '');
INSERT INTO "public"."okved_2" VALUES ('71.20.8', '71.20', 'M', 'Сертификация продукции, услуг и организаций', '');
INSERT INTO "public"."okved_2" VALUES ('71.20.9', '71.20', 'M', 'Деятельность по техническому контролю, испытаниям и анализу прочая', 'Эта группировка также включает:
- мониторинг состояния объектов культурного наследия, территорий объектов культурного наследия, зон охраны объектов культурного наследия, территорий исторических поселений;
- мониторинг проведения работ по сохранению о бъектов культурного наследия');
INSERT INTO "public"."okved_2" VALUES ('72', 'M', 'M', 'Научные исследования и разработки', 'Эта группировка включает:
- деятельность трех видов научных исследований и разработок:
1) фундаментальные научные исследования - экспериментальная или теоретическая деятельность, направленная на получение новых знаний об основных закономерностях строения, функционирования и развития человека, общества, природы;
2) прикладные научные исследования - исследования, направленные преимущественно на применение новых знаний для достижения практических целей и решения конкретных задач;
3) экспериментальные разработки - деятельность, основанная на знаниях, приобретенных в результате проведения научных исследований или на основе практического опыта и направленная на сохранение жизни и здоровья человека, создание новых материалов, продуктов, процессов,устройств, услуг, систем или методов и их дальнейшее совершенствование
Исследовательская и экспериментальная деятельность разделяются на две категории: естественные и технические науки, общественные и гуманитарные науки

Эта группировка не включает:
- исследование конъюнктуры рынка, см. 73.20');
INSERT INTO "public"."okved_2" VALUES ('72.1', '72', 'M', 'Научные исследования и разработки в области естественных и технических наук', 'Эта группировка включает:
- фундаментальные исследования, прикладные исследования и экспериментальные разработки в области естественных и технических наук');
INSERT INTO "public"."okved_2" VALUES ('72.11', '72.1', 'M', 'Научные исследования и разработки в области биотехнологии', 'Эта группировка включает:
- научные исследования и разработки в области биотехнологии - ДНК/РНК: геномы, фармакогеномика, генные исследования, генная инженерия, последовательность/синтез/ампликация ДНК/РНК, исследование экспрессии генов, использование антисмысловой технологии и др.; белков и прочих молекул: синтез и инженерия белков и пептидов (включая крупные молекулы гормонов); методики улучшенной поставки крупномолекулярных лекарств, протеомика, выделение и очистка белков, передача сигналов,выявление клеточных рецепторов;
- выращивание клеточных культур тканей: культуры клеток и тканей, гистологическая инженерия (включая клеточные каркасы и биомедицинские разработки), клеточный сплав, стимуляторы вакцины/свободные стимуляторы, манипуляции с эмбрионами;
- методики биотехнологических процессов: брожение с использованием биореакторов, биообработка, биовыщелачивание, биодефибрирование, биосульфуризация, биовосстановление, биофильтрация и фиторемедиация;
- генные и РНК векторы: генная терапия, вирусные векторы;
- биоинформатику: создание баз данных по геномам, последовательности белка; моделирование сложных биологических процессов, включая системную биологию;
- нанобиотехнологии: применение инструментов и процессов нано- и микроконструирования для создания устройств по изучению биосистем и приложений для доставки лекарственных препаратов, диагностики и т. д.');
INSERT INTO "public"."okved_2" VALUES ('74.90.2', '74.90', 'M', 'Деятельность, направленная на установление рыночной или иной стоимости (оценочная деятельность), кроме оценки, связанной с недвижимым имуществом или страхованием', '');
INSERT INTO "public"."okved_2" VALUES ('74.90.21', '74.90.2', 'M', 'Деятельность, направленная на установление рыночной или иной стоимости отдельных материальных объектов (вещей)', '');
INSERT INTO "public"."okved_2" VALUES ('72.19', '72.1', 'M', 'Научные исследования и разработки в области естественных и технических наук прочие', 'Эта группировка включает:
- исследования и экспериментальные разработки в области естественных и технических наук, кроме биотехнологических исследований и экспериментальных разработок: исследования и экспериментальные разработки в области естественны х наук; исследования и экспериментальные разработки в области технических наук; исследования и экспериментальные разработки в области медицинских наук; исследования и экспериментальные разработки в области сельскохозяйственных наук; междисциплинарные исследования и разработки, преимущественно в области естественных и технических наук;
- научные исследования и разработки в области нанотехнологий;
- научные исследования и разработки в области защиты информации;
- проведение научно-исследовательски х работ по сохранению и воссозданию объектов культурного наследия и археологии');
INSERT INTO "public"."okved_2" VALUES ('72.19.1', '72.19', 'M', 'Проведение фундаментальных исследований и научно-исследовательских и опытно-конструкторских работ в области использования атомной энергии и в области ядерной оружейной продукции', '');
INSERT INTO "public"."okved_2" VALUES ('72.19.3', '72.19', 'M', 'Научные исследования и разработки в области нанотехнологий', 'Эта группировка включает:
- научные исследования и разработки, направленные на развитие приемов и методов, применяемых при изучении, проектировании и производстве наноструктур, устройств и систем, включающих целенаправленный контроль и модификацию формы, размера, взаимодействия и интеграции составляющих их наномасштабных элементов (около 1-100 нм), наличие которых приводит к улучшению либо к появлению дополнительных эксплуатационных и/или потребительских характеристик и свойств получаемых продуктов

Эта группировка не включает:
- исследования и разработки в области нанобиотехнологии, см. 72.11');
INSERT INTO "public"."okved_2" VALUES ('72.2', '72', 'M', 'Научные исследования и разработки в области общественных и гуманитарных наук', '');
INSERT INTO "public"."okved_2" VALUES ('72.20', '72.2', 'M', 'Научные исследования и разработки в области общественных и гуманитарных наук', 'Эта группировка включает:
- исследования и разработки в области общественных наук;
- исследования и разработки в области гуманитарных наук;
- междисциплинарные исследования и разработки, преимущественно в области общественных и гуманитарных наук
Этагруппировка не включает:
- исследование конъюнктуры рынка, см. 73.20');
INSERT INTO "public"."okved_2" VALUES ('72.20.1', '72.20', 'M', 'Научные исследования и разработки в области общественных наук', '');
INSERT INTO "public"."okved_2" VALUES ('72.20.2', '72.20', 'M', 'Научные исследования и разработки в области гуманитарных наук', 'Эта группировка также включает:
- проведение историко-архитектурных, историко-градостроительных, архивных и археологических исследований в области сохранения и воссоздания объектов культурного наследия');
INSERT INTO "public"."okved_2" VALUES ('73', 'M', 'M', 'Деятельность рекламная и исследование конъюнктуры рынка', 'Эта группировка включает:
- проведение рекламных кампаний и размещение рекламы в периодических изданиях, газетах, по радио и телевидению или других средствах СМИ, а также услуги в части дизайна видеороликов и сайтов в информационно-коммуникационной сети Интернет');
INSERT INTO "public"."okved_2" VALUES ('73.1', '73', 'M', 'Деятельность рекламная', '');
INSERT INTO "public"."okved_2" VALUES ('73.11', '73.1', 'M', 'Деятельность рекламных агентств', 'Эта группировка включает:
- предоставление всех видов услуг в области рекламы (через заключение субподрядного договора), включая консультирование, творческое обслуживание, изготовление рекламных материалов и закупки
Она включает:
- подготовку и проведение рекламных кампаний: подготовку и размещение рекламных материалов в газетах, периодических изданиях, на радио, телевидении, в информационнокоммуникационной сети Интернет и прочих средствах массовой информации, подготовку и размещение рекламы, например, на афишных тумбах, рекламных щитах, стендах для афиш и объявлений, в витринах, в демонстрационных залах, размещение рекламы на автомобилях и автобусах и т. п., воздушную рекламу, распространение или доставку рекламных материалов или пробных образцов, подготовку стендов и прочих демонстрационных материалов и сайтов;
- проведение маркетинговых исследований и прочие услуги в сфере рекламы, нацеленные на привлечение и удержание клиентов, промо-акции продукции, маркетинговые исследования пунктов продаж, адресную рассылку рекламных материалов, консультирование в области маркетинга');
INSERT INTO "public"."okved_2" VALUES ('73.12', '73.1', 'M', 'Представление в средствах массовой информации', 'Эта группировка включает:
- рекламирование в средствах массовой информации путем продажи времени и места для рекламы');
INSERT INTO "public"."okved_2" VALUES ('73.2', '73', 'M', 'Исследование конъюнктуры рынка и изучение общественного мнения', '');
INSERT INTO "public"."okved_2" VALUES ('74.90.22', '74.90.2', 'M', 'Деятельность, направленная на установление рыночной или иной стоимости совокупности вещей, составляющих имущество лица, в том числе имущество определенного вида (движимое или недвижимое, в том числе предприятия)', '');
INSERT INTO "public"."okved_2" VALUES ('74.90.23', '74.90.2', 'M', 'Деятельность, направленная на установление рыночной или иной стоимости права собственности или иных вещных прав на имущество или отдельные вещи из состава имущества', '');
INSERT INTO "public"."okved_2" VALUES ('73.20', '73.2', 'M', 'Исследование конъюнктуры рынка и изучение общественного мнения', 'Эта группировка включает:
- исследование рынка и внутренних фактических и потенциальных возможностей производственной или посреднической деятельности фирмы с целью анализа структуры и закономерностей динамики рынка и обоснования мероприятий по болееэффективной адаптации производства, технологий и структуры фирмы, а также представляемой фирмой на рынок продукции или услуг к спросу и требованиям конечного потребителя;
- изучение общественного мнения по политическим, экономическим и социальным вопросам, включая статистический анализ получаемой информации');
INSERT INTO "public"."okved_2" VALUES ('73.20.1', '73.20', 'M', 'Исследование конъюнктуры рынка', '');
INSERT INTO "public"."okved_2" VALUES ('73.20.2', '73.20', 'M', 'Деятельность по изучению общественного мнения', '');
INSERT INTO "public"."okved_2" VALUES ('74', 'M', 'M', 'Деятельность профессиональная научная и техническая прочая', 'Эта группировка включает:
- предоставление профессиональных научно-технических услуг (кроме деятельности в области права и бухгалтерского учета, архитектурного дела и инженерно-технического проектирования, технических испытаний и исследований, управления и консультирования в сфере менеджмента, научных исследований и рекламной деятельности)');
INSERT INTO "public"."okved_2" VALUES ('74.1', '74', 'M', 'Деятельность специализированная в области дизайна', '');
INSERT INTO "public"."okved_2" VALUES ('74.10', '74.1', 'M', 'Деятельность специализированная в области дизайна', 'Эта группировка включает:
- моделирование текстильных изделий, одежды, обуви, ювелирных изделий, мебели, других предметов интерьера, модных товаров, а также прочих товаров личного и домашнего пользования;
- промышленный дизайн, с созданием и разработкой проектов и спецификаций, которые оптимизируют использование, стоимость и внешний вид продукции, включая выбор материалов, механизмов, формы, цвета и отделки поверхности продукции с учетом имеющегося спроса, требований безопасности и потребностейрынка в распространении, использовании и обслуживании;
- предоставление услуг графических дизайнеров;
- предоставление услуг декораторов интерьера

Эта группировка не включает:
- дизайн и программирование web-страниц в информационно-коммуникационной сети Интернет, см. 62.01;
- архитектурный дизайн, см. 71.11;
- инженерный дизайн, т. е. применение законов физики и правил инженерного дела при проектировании машин, материалов, инструментов, строений, процессов и систем, см. 71.12');
INSERT INTO "public"."okved_2" VALUES ('74.2', '74', 'M', 'Деятельность в области фотографии', '');
INSERT INTO "public"."okved_2" VALUES ('74.20', '74.2', 'M', 'Деятельность в области фотографии', 'Эта группировка включает:
- деятельность в области фотографии для коммерческих целей: портретные фотографии на документы, школьные и свадебные фотографии и т. п., фотографии для целей рекламы, издательских организаций, журналов мод, операций с недвижимостью или туризма; аэрофотосъемку; видеосъемку церемоний: свадеб, встреч и т. д.;
- обработку фотопленок: проявление, печатание и увеличение с фотографий, негативов или кинопленок, снятых клиентами, лаборатории по проявлению пленки и печати фотографий, моментальную фотографию, помещение диапозитивов в рамки, создание слайдов, пересъемку, восстановление или ретуширование фотографий;
- деятельность фотокорреспондентов

Эта группировка также включает:
- микросъемку документов');
INSERT INTO "public"."okved_2" VALUES ('74.3', '74', 'M', 'Деятельность по письменному и устному переводу', '');
INSERT INTO "public"."okved_2" VALUES ('74.30', '74.3', 'M', 'Деятельность по письменному и устному переводу', '');
INSERT INTO "public"."okved_2" VALUES ('74.9', '74', 'M', 'Деятельность профессиональная, научная и техническая прочая, не включенная в другие группировки', '');
INSERT INTO "public"."okved_2" VALUES ('74.90', '74.9', 'M', 'Деятельность профессиональная, научная и техническая прочая, не включенная в другие группировки', 'Эта группировка включает:
- разнообразные виды деятельности по оказанию коммерческих услуг;
- деятельность, требующую высоких профессиональных знаний и опыта, но не включает повседневные деловые функции, как правило скоротечные;
 - организацию работыброкеров, т.е. организацию купли-продажи фирм малого и среднего бизнеса, включая деловую практику, кроме риэлторства;
- организацию работы брокеров, т.е. организацию купли-продажи патентов;
- аудит бухгалтерских счетов и оценку фрахтовых ставок;
- подготовку метеорологических прогнозов;
- консультирование в части безопасности;
- консультирование в области сельского хозяйства;
- консультирование в области экологии;
- предоставление прочих технических консультаций;
- деятельность консультантов, кроме архитекторов, проектировщиков и консультантов по управлению
 
Эта группировка также включает:
- деятельность агентств и агентов, действующих от имени физических лиц и претендующих на долевое вознаграждение от участия своих клиентов сниматься в кинофильмах, играть в спектаклях и участвовать в других развлекательных мероприятиях или спортивных состязаниях, издавать книги, выставлять художественные работы, фотографии и т.д. от имени издателей, продюсеров и т.д.;
- деятельность оценщиков;
- деятельность в области защиты информации');
INSERT INTO "public"."okved_2" VALUES ('74.90.1', '74.90', 'M', 'Предоставление посреднических услуг по организации покупки и продажи мелких или средних коммерческих предприятий, включая профессиональную практику', '');
INSERT INTO "public"."okved_2" VALUES ('74.90.25', '74.90.2', 'M', 'Деятельность, направленная на установление рыночной или иной стоимости работ, услуг, информации', '');
INSERT INTO "public"."okved_2" VALUES ('74.90.26', '74.90.2', 'M', 'Деятельность, направленная на установление рыночной или иной стоимости иных объектов гражданских прав, в отношении которых законодательством Российской Федерации установлена возможность их участия в гражданском обороте', '');
INSERT INTO "public"."okved_2" VALUES ('74.90.3', '74.90', 'M', 'Предоставление консультационных услуг по вопросам безопасности', '');
INSERT INTO "public"."okved_2" VALUES ('74.90.31', '74.90.3', 'M', 'Предоставление услуг по проведению оценки уязвимости объектов транспортной инфраструктуры и транспортных средств', '');
INSERT INTO "public"."okved_2" VALUES ('74.90.32', '74.90.3', 'M', 'Предоставление услуг по проведению оценки уязвимости объектов промышленного назначения, связи, здравоохранения и т. д.', '');
INSERT INTO "public"."okved_2" VALUES ('74.90.4', '74.90', 'M', 'Предоставление консультационных услуг в области сельского хозяйства', '');
INSERT INTO "public"."okved_2" VALUES ('74.90.5', '74.90', 'M', 'Предоставление консультационных услуг в области экологии', '');
INSERT INTO "public"."okved_2" VALUES ('74.90.6', '74.90', 'M', 'Предоставление прочих технических консультаций, деятельность консультантов, кроме архитекторов, проектировщиков и консультантов по управлению', 'Эта группировка также включает:
- государственную историко-культурную экспертизу');
INSERT INTO "public"."okved_2" VALUES ('74.90.7', '74.90', 'M', 'Деятельность по подготовке метеорологических прогнозов', '');
INSERT INTO "public"."okved_2" VALUES ('74.90.8', '74.90', 'M', 'Деятельность агентств и агентов, действующих от имени физических лиц, и обычно связанную с заключением контрактов (договоров) на участие в кинофильмах, театральных постановках и других развлекательных или спортивных мероприятиях, а также с предложени ем книг, пьес, предметов изобразительного искусства, фотографий и аналогичных предметов издателям, продюсерам', '');
INSERT INTO "public"."okved_2" VALUES ('75', 'M', 'M', 'Деятельность ветеринарная', 'Эта группировка включает:
- деятельность, связанную с лечением и контролем за состоянием здоровья как сельскохозяйственных, так и домашних животных
Эта деятельность осуществляется квалифицированными ветеринарами в ветеринарных лечебницах, а также припосещении псарен и приютов для животных, в частных врачебных или операционных кабинетах или в других местах

Эта группировка также включает:
- деятельность скорой ветеринарной помощи для животных');
INSERT INTO "public"."okved_2" VALUES ('75.0', '75', 'M', 'Деятельность ветеринарная', '');
INSERT INTO "public"."okved_2" VALUES ('75.00', '75.0', 'M', 'Деятельность ветеринарная', 'Эта группировка включает:
- деятельность, связанную с лечением и контролем состояния здоровья сельскохозяйственных животных;
- деятельность, связанную с лечением и контролем состояния здоровья домашних животных

Эта группировка также включает:
- деятельность помощников ветеринара и прочего вспомогательного персонала;
- клинико-патологические и другие виды диагностических работ в отношении животных;
- деятельность скорой ветеринарной помощи для животных');
INSERT INTO "public"."okved_2" VALUES ('75.00.1', '75.00', 'M', 'Деятельность ветеринарная для сельскохозяйственных животных', '');
INSERT INTO "public"."okved_2" VALUES ('75.00.2', '75.00', 'M', 'Деятельность ветеринарная для домашних животных', '');
INSERT INTO "public"."okved_2" VALUES ('N', '', 'N', 'ДЕЯТЕЛЬНОСТЬ АДМИНИСТРАТИВНАЯ И СОПУТСТВУЮЩИЕ ДОПОЛНИТЕЛЬНЫЕ УСЛУГИ', 'Этот раздел включает:
- различную деятельность для поддержки основной деятельности предприятий
Эта деятельность отличается от видов деятельности, перечисленных в разделе М, так как ее основной целью не является передача специализированных знаний');
INSERT INTO "public"."okved_2" VALUES ('77', 'N', 'N', 'Аренда и лизинг', 'Эта группировка включает:
- прокат и аренду материальных и нематериальных активов, включая широкий список товаров, включая автомобили, компьютеры, широкий круг товаров конечного и производственного потребления, предоставляемые клиентам за периодическую арендную плату или лизинговый платеж

Эта группировка подразделяется на: (1) аренду автомашин, (2) аренду товаров для отдыха и спортивного инвентаря, бытовых изделий и предметов личного пользования, (3) аренду прочих видов машин и оборудования производственного назначения, включая транспортное оборудование и (4) аренду продуктов интеллектуальной собственности и подобных им продуктов. В эту группировку включена только аренда с целью эксплуатации

Эта группировка не включает:
- финансовый лизинг,см. 64.91;
- аренду недвижимого имущества, см. раздел L;
- аренду оборудования с оператором, см. соответствующие группировки согласно областям применения этого оборудования, например строительство (раздел F), перевозка и хранение (раздел H)');
INSERT INTO "public"."okved_2" VALUES ('77.1', '77', 'N', 'Аренда и лизинг автотранспортных средств', '');
INSERT INTO "public"."okved_2" VALUES ('77.11', '77.1', 'N', 'Аренда и лизинг легковых автомобилей и легких автотранспортных средств', 'Эта группировка включает:
- аренду таких типов транспортных средств, как легковые автомобили и легкие автофургоны до 3,5 т без водителя

Эта группировка не включает:
- аренду легковых автомобилей с водителем и легких автофургонов с водителем, см. 49.32, 49.39');
INSERT INTO "public"."okved_2" VALUES ('77.12', '77.1', 'N', 'Аренда и лизинг грузовых транспортных средств', 'Эта группировка включает:
- аренду таких типов транспортных средств, как грузовые автомобили, тягачи, прицепы и полуприцепы (массой более 3,5 т) и прицепы для жилья

Эта группировка не включает:
- аренду тягачей или грузовиков с водителем, см. 49.41');
INSERT INTO "public"."okved_2" VALUES ('77.2', '77', 'N', 'Прокат и аренда предметов личного пользования и хозяйственно-бытового назначения', 'Эта группировка включает:
- аренду бытовых изделий и предметов личного пользования, прокат товаров для отдыха и спортивного снаряжения, видеокассет
Эта деятельность также включает:
- краткосрочную аренду товаров, хотя в некоторых случаях товары могутбыть арендованы на более длительные промежутки времени');
INSERT INTO "public"."okved_2" VALUES ('77.21', '77.2', 'N', 'Прокат и аренда товаров для отдыха и спортивных товаров', 'Эта группировка включает:
- прокат товаров для отдыха и спортивного снаряжения: туристических судов, каноэ, парусных шлюпок, велосипедов, пляжных шезлонгов и зонтиков, другого спортивного инвентаря, лыж

Эта группировка не включает:
- прокат прогулочных катеров и лодок с экипажем, см. 50.10, 50.30;
- прокат видеокассет и дисков, см. 77.22;
- прокат прочих бытовых изделий и предметов личного пользования, см. 77.29;
- прокат инвентаря для отдыха и развлечений как неотъемлемой части мест отдыха, см.93.29');
INSERT INTO "public"."okved_2" VALUES ('77.22', '77.2', 'N', 'Прокат видеокассет и аудиокассет, грампластинок, компакт-дисков (CD), цифровых видеодисков (DVD)', 'Эта группировка включает:
- прокат видеокассет и аудиокассет, грампластинок, компакт-дисков (CD), цифровых видеодисков (DVD) и т. п.');
INSERT INTO "public"."okved_2" VALUES ('77.29', '77.2', 'N', 'Прокат и аренда прочих предметов личного пользования и хозяйственно-бытового назначения', 'Эта группировка включает:- прокат и сдачу в аренду всех видов прочих бытовых изделий и предметов личного пользования физическим лицам и промышленным предприятиям (кроме предметов для отдыха и спортивного инвентаря): текстильных изделий, одежды, обуви , изделий из керамики и стекла, кухонной и столовой посуды, электрической и домашней утвари, ювелирных изделий, музыкальных инструментов, театральных декораций и костюмов, книг, газет и журналов, машин и оборудования для самостоятельного изготовления поделок, например инструментов для домашнего ремонта, цветов и растений, электронных бытовых приборов
Эта группировка не включает:- аренду автомобилей, грузовиков, автофургонов и транспортных средств для проведения отдыха и досуга без водителя, см. 7 7.1;- прокат товаров для отдыха и спортивного инвентаря, см. 77.21;- прокат видеокассет и дисков, см. 77.22;- прокат офисной мебели, см. 77.33;- аренду мотоциклов, автофургонов и прицепов для жилья без водителя, см. 77.39;- подготовку белья, рабочей униформы и вещей для стирки, см. 96.01');
INSERT INTO "public"."okved_2" VALUES ('77.29.1', '77.29', 'N', 'Прокат телевизоров, радиоприемников, устройств видеозаписи, аудиозаписи и подобного оборудования', '');
INSERT INTO "public"."okved_2" VALUES ('77.29.2', '77.29', 'N', 'Прокат мебели, электрических и неэлектрических бытовых приборов', '');
INSERT INTO "public"."okved_2" VALUES ('77.29.3', '77.29', 'N', 'Прокат музыкальных инструментов', '');
INSERT INTO "public"."okved_2" VALUES ('77.29.9', '77.29', 'N', 'Прокат прочих бытовых изделий и предметов личного пользования для домашних хозяйств, предприятий и организаций, не включенных в другие группировки', '');
INSERT INTO "public"."okved_2" VALUES ('77.3', '77', 'N', 'Аренда и лизинг прочих машин и оборудования и материальных средств', '');
INSERT INTO "public"."okved_2" VALUES ('77.31', '77.3', 'N', 'Аренда и лизинг сельскохозяйственных машин и оборудования', 'Эта группировка включает:
- аренду сельскохозяйственных тракторов и машин и оборудования для сельского и лесного хозяйства без оператора, включая аренду машин, включенных в группировку 28.30

Эта группировка не включает:
- аренду сельскохозяйственныхтракторов и других видов машин и оборудования для сельского и лесного хозяйства с оператором, см. 01.61, 02.40');
INSERT INTO "public"."okved_2" VALUES ('77.32', '77.3', 'N', 'Аренда и лизинг строительных машин и оборудования', 'Эта группировка включает:
- аренду строительных машин и оборудования без оператора, включая подъемные краны, строительные леса и рабочие платформы без их установки и демонтажа

Эта группировка не включает:
- аренду строительных машин и оборудования соператором, см. 43');
INSERT INTO "public"."okved_2" VALUES ('77.33', '77.3', 'N', 'Аренда и лизинг офисных машин и оборудования, включая вычислительную технику', 'Эта группировка включает:
- прокат и аренду офисных машин и оборудования без оператора: вычислительной техники и вспомогательной вычислительной техники, копировально-множительных машин, пишущих машин и машин для обработки текста, бухгалтерских машини оборудования: кассовых аппаратов, электронных калькуляторов и т. п., офисной мебели');
INSERT INTO "public"."okved_2" VALUES ('77.33.1', '77.33', 'N', 'Аренда и лизинг офисных машин и оборудования', '');
INSERT INTO "public"."okved_2" VALUES ('77.34', '77.3', 'N', 'Аренда и лизинг водных транспортных средств и оборудования', 'Эта группировка включает:
- прокат и аренду водных транспортных средств и оборудования без оператора, включая торговые и прочие суда

Эта группировка не включает:
- прокат и аренду водных транспортных средств и оборудования с оператором, см. 50;
- прокат прогулочных катеров, см. 77.21');
INSERT INTO "public"."okved_2" VALUES ('77.35', '77.3', 'N', 'Аренда и лизинг воздушных судов и авиационного оборудования', 'Эта группировка включает:
- прокат и аренду воздушных транспортных средств без экипажа, включая самолеты и воздушные шары

Эта группировка не включает:
- аренду воздушных транспортных средств с оператором, см. 51');
INSERT INTO "public"."okved_2" VALUES ('77.39', '77.3', 'N', 'Аренда и лизинг прочих видов транспорта, оборудования и материальных средств, не включенных в другие группировки', 'Эта группировка включает:
- прокат и аренду прочего автомобильного транспорта и оборудования, без оператора, используемых как промышленные средства производства: двигателей и турбин; станков, горного и нефтепромыслового оборудования, профессиональнойрадио- и телевизионной аппаратуры и аппаратуры связи, оборудования для производства кинофильмов, контрольноизмерительной аппаратуры, прочих машин и оборудования научного и промышленного назначения;
- прокат и аренду сухопутных транспортных средств соператором (кроме автомобилей): мотоциклов, автофургонов и прицепов для жилья и т. д., железнодорожного транспорта

Эта группировка также включает:
- аренду жилья и офисов;
- аренду животных (например, стад, скаковых лошадей);
- прокат и аренду контейнеров;
- прокат и аренду поддонов');
INSERT INTO "public"."okved_2" VALUES ('77.39.1', '77.39', 'N', 'Аренда и лизинг прочих сухопутных транспортных средств и оборудования', '');
INSERT INTO "public"."okved_2" VALUES ('77.39.11', '77.39.1', 'N', 'Аренда и лизинг прочего автомобильного транспорта и оборудования', '');
INSERT INTO "public"."okved_2" VALUES ('77.39.12', '77.39.1', 'N', 'Аренда и лизинг железнодорожного транспорта и оборудования', '');
INSERT INTO "public"."okved_2" VALUES ('77.39.2', '77.39', 'N', 'Аренда и лизинг прочих машин и оборудования, не включенных в другие группировки', '');
INSERT INTO "public"."okved_2" VALUES ('77.39.21', '77.39.2', 'N', 'Аренда и лизинг двигателей, турбин и станков', '');
INSERT INTO "public"."okved_2" VALUES ('77.39.22', '77.39.2', 'N', 'Аренда и лизинг горного и нефтепромыслового оборудования', '');
INSERT INTO "public"."okved_2" VALUES ('77.39.23', '77.39.2', 'N', 'Аренда и лизинг подъемно-транспортного оборудования', '');
INSERT INTO "public"."okved_2" VALUES ('77.39.24', '77.39.2', 'N', 'Аренда и лизинг профессиональной радио- и телевизионной аппаратуры и аппаратуры связи', '');
INSERT INTO "public"."okved_2" VALUES ('77.39.25', '77.39.2', 'N', 'Аренда и лизинг контрольно-измерительной аппаратуры', '');
INSERT INTO "public"."okved_2" VALUES ('77.39.26', '77.39.2', 'N', 'Аренда и лизинг приборов, аппаратов и прочего оборудования, применяемого в медицинских целях', '');
INSERT INTO "public"."okved_2" VALUES ('77.39.27', '77.39.2', 'N', 'Аренда и лизинг торгового оборудования', '');
INSERT INTO "public"."okved_2" VALUES ('77.39.29', '77.39.2', 'N', 'Аренда и лизинг прочих машин и оборудования научного и промышленного назначения', '');
INSERT INTO "public"."okved_2" VALUES ('77.39.3', '77.39', 'N', 'Аренда и лизинг племенных сельскохозяйственных животных', '');
INSERT INTO "public"."okved_2" VALUES ('77.4', '77', 'N', 'Аренда интеллектуальной собственности и подобной продукции, кроме авторских прав', '');
INSERT INTO "public"."okved_2" VALUES ('77.40', '77.4', 'N', 'Аренда интеллектуальной собственности и подобной продукции, кроме авторских прав', 'Эта группировка включает:
- деятельность по выдаче разрешений третьим лицам на использование продуктов интеллектуальной собственности и подобной продукции, при которой авторский гонорар или лицензионный сбор платятся владельцу продукта (держателю актива)
Аренда этих продуктов может принимать различные формы, например, выдача разрешений на воспроизведение, использование в последующих процессах или при производстве продукции, ведение бизнеса на правах франшизы и т. п. Собственники могут являться или не являться авторами этой продукции

Эта группировка включает:
- аренду продукции интеллектуальной собственности (кроме произведений, охраняемых авторским правом, например, книг или программного обеспечения);
- получение авторских гонораров или лицензионных сборов за использование: патентованных объектов, торговых марок или знаков обслуживания, фирменных знаков, лицензий на разведку, добычу и оценку минерального сырья, франшизы

Эта группировка не включает:
- приобретение прав на издания, см. 58 и 59;
- создание, воспроизведение и распространение произведений, охраняемых авторским правом (книг, программного обеспечения, кинофильмов), см. 58, 59;
- аренду недвижимого имущества, см. 68.20;
- аренду материального имущества, см. 77.1, 77.2, 77.3');
INSERT INTO "public"."okved_2" VALUES ('78', 'N', 'N', 'Деятельность по трудоустройству и подбору персонала', 'Эта группировка включает:
- деятельность по ведению списка вакансий, обращений или размещения заявлений кандидатов, не являющихся служащими бюро трудоустройства;
- снабжение компаний клиентов персоналом на ограниченный промежуток времени и деятельность по обеспечению прочих заявок клиентов на трудовые ресурсы

Эта группировка также включает:
- поиск и подбор вакансий, включая деятельность театральных агентств по подбору персонала

Эта группировка не включает:
- деятельность частных театральных и артистических агентств и агентов по подбору персонала, см. 74.90');
INSERT INTO "public"."okved_2" VALUES ('78.1', '78', 'N', 'Деятельность агентств по подбору персонала', '');
INSERT INTO "public"."okved_2" VALUES ('79.90.1', '79.90', 'N', 'Деятельность по предоставлению туристических информационных услуг', '');
INSERT INTO "public"."okved_2" VALUES ('78.10', '78.1', 'N', 'Деятельность агентств по подбору персонала', 'Эта группировка включает:
- деятельность по ведению списка вакансий занятости и обращений, а также размещения заявлений кандидатов, не являющихся служащими данного бюро трудоустройства

Эта группировка включает:
- поиск персонала, отбор кандидатов и деятельность по трудоустройству, включая назначение на должность;
- функционирование кастинговых агентств, например театральных агентств;
- функционирование бирж трудоустройства в режиме "On-line" в информационно-коммуникационной сети Интернет

Эта группировка не включает:
- деятельность частных театральных и артистических агентств и агентов по подбору персонала, см. 74.90');
INSERT INTO "public"."okved_2" VALUES ('78.2', '78', 'N', 'Деятельность агентств по временному трудоустройству', '');
INSERT INTO "public"."okved_2" VALUES ('78.20', '78.2', 'N', 'Деятельность агентств по временному трудоустройству', 'Эта группировка включает:
- деятельность по найму временной рабочей силы, обеспечению на подрядной основе предприятий наемной рабочей силой, преимущественно для выполнения временной работы
Однако относимые в эту группировку компании не обеспечивают наблюдения за предоставляемыми ими работниками на месте выполнения работ клиента');
INSERT INTO "public"."okved_2" VALUES ('78.3', '78', 'N', 'Деятельность по подбору персонала прочая', '');
INSERT INTO "public"."okved_2" VALUES ('78.30', '78.3', 'N', 'Деятельность по подбору персонала прочая', 'Эта группировка включает:
- деятельность по подбору рабочей силы для компании клиента
Отнесенные в эту группировку компании представляют работодателя по вопросам подбора рабочей силы, уплаты налогов и другим вопросам финансовой и кадровой политики, но они не несут ответственности за руководство служащими. Обычно рабочая сила подбирается на постоянное или временное место работы и компании, отнесенные к этой группировке, обеспечивают предоставление широкого спектра услуг по управлению персоналом

Эта группировка не включает:
- предоставление функций подбора рабочей силы вместе с управлением текущим бизнесом, см. группировку в соответствующей деятельности такой компании;
- подбор рабочей силы для временной замены работников или расширения персонала клиента, см. 78.20');
INSERT INTO "public"."okved_2" VALUES ('79', 'N', 'N', 'Деятельность туристических агентств и прочих организаций, предоставляющих услуги в сфере туризма', 'Эта группировка включает:
- деятельность туристических агентств, прежде всего занятых оказанием услуг в отношении путешествий, туров, перевозкой и размещением частных лиц и коммерческих клиентов, а также другие, связанные с путешествием услуги, включая услуги бронирования

Эта группировка также включает:
- услуги туристических гидов и рекламу туризма');
INSERT INTO "public"."okved_2" VALUES ('79.1', '79', 'N', 'Деятельность туристических агентств и туроператоров', 'Эта группировка включает:
- деятельность агентств, прежде всего занятых продажами путешествий, туров, транспортировкой и размещением частных лиц и коммерческих клиентов, деятельность по подготовке и сборке туров, продаваемых через туристические агентства или непосредственно агентами, например туроператорами');
INSERT INTO "public"."okved_2" VALUES ('79.11', '79.1', 'N', 'Деятельность туристических агентств', 'Эта группировка включает:
- деятельность агентств, прежде всего занятых продажами путешествий, туров, транспортировкой и размещением на оптовой или розничной основе частных лиц и коммерческих клиентов');
INSERT INTO "public"."okved_2" VALUES ('79.12', '79.1', 'N', 'Деятельность туроператоров', 'Эта группировка включает:
- деятельность по организации туров
Туры могут включать: перевозку, размещение, питание, посещение музеев, исторических или культурных учреждений, театральных, музыкальных или спортивных мероприятий');
INSERT INTO "public"."okved_2" VALUES ('79.9', '79', 'N', 'Услуги по бронированию прочие и сопутствующая деятельность', '');
INSERT INTO "public"."okved_2" VALUES ('79.90', '79.9', 'N', 'Услуги по бронированию прочие и сопутствующая деятельность', 'Эта группировка включает:
- услуги туристические прочие, связанные с бронированием: мест в транспорте, гостиницах, ресторанах, пунктах проката автомобилей, развлекательных и спортивных площадках и т. п.;
- оказание прочих услуг, связанных со службойпредварительных заказов;
- продажу билетов на театральные, спортивные и другие развлекательные мероприятия и события;
- услуги по оказанию поддержки и помощи приезжим: предоставление информации по турам, услуги туристских гидов, деятельность, направленную на развитие туризма

Эта группировка не включает:
- деятельность туристических агентств и туроператоров, см. 79.11, 79.12;
- организацию встреч, собраний и конференций, см. 82.30');
INSERT INTO "public"."okved_2" VALUES ('79.90.21', '79.90.2', 'N', 'Деятельность туристических агентств по предоставлению экскурсионных туристических услуг', '');
INSERT INTO "public"."okved_2" VALUES ('79.90.22', '79.90.2', 'N', 'Деятельность самостоятельных экскурсоводов и гидов по предоставлению экскурсионных туристических услуг', '');
INSERT INTO "public"."okved_2" VALUES ('79.90.3', '79.90', 'N', 'Деятельность по предоставлению туристических услуг, связанных с бронированием', '');
INSERT INTO "public"."okved_2" VALUES ('79.90.31', '79.90.3', 'N', 'Деятельность по бронированию билетов на культурно-развлекательные мероприятия', '');
INSERT INTO "public"."okved_2" VALUES ('79.90.32', '79.90.3', 'N', 'Деятельность по оказанию прочих услуг, связанных со службой предварительных заказов', '');
INSERT INTO "public"."okved_2" VALUES ('80', 'N', 'N', 'Деятельность по обеспечению безопасности и проведению расследований', 'Эта группировка включает:
- услуги, связанные с безопасностью, например проведение расследований и деятельность сотрудников охранных служб, услуги патрулей и охранников, сбор и перевозку денег, платежей или других ценностей с использованием персоналаи оборудования для защиты такой собственности в пути, установку систем сигнализации, например охранной и пожарной сигнализации, где деятельность сосредоточивается на удаленном контроле этих систем, но часто включает также продажу, установку и услугиремонта таких систем
Если последние компоненты обеспечиваются отдельно, они исключены из этой группировки и классифицируются как розничная продажа, строительство и т. д.');
INSERT INTO "public"."okved_2" VALUES ('80.1', '80', 'N', 'Деятельность частных охранных служб', '');
INSERT INTO "public"."okved_2" VALUES ('80.10', '80.1', 'N', 'Деятельность частных охранных служб', 'Эта группировка включает:
- предоставление одной или нескольких услуг: охрана и сопровождение, сбор и перевозка денег, осуществление платежей или передача ценностей с использованием персонала и оборудования для защиты такой собственности

Эта группировка включает:
- предоставление бронированных автомобилей;
- услуги телохранителя;
- услуги по предоставлению детекторов лжи;
- снятие отпечатков пальцев;
- услуги охранной службы;
- уничтожение документов и информации на любых носителях в целях безопасности

Эта группировка не включает:
- деятельность по охране общественного порядка и безопасности, см. 84.24');
INSERT INTO "public"."okved_2" VALUES ('80.2', '80', 'N', 'Деятельность систем обеспечения безопасности', '');
INSERT INTO "public"."okved_2" VALUES ('80.20', '80.2', 'N', 'Деятельность систем обеспечения безопасности', 'Эта группировка включает:
- мониторинг или удаленный контроль электронных систем сигнализации безопасности, например охранной и пожарной сигнализации, включая их установку и обслуживание;
- установку, ремонт, восстановление и наладку механических илиэлектронных замковых устройств, сейфов и хранилищ с последующим контролем их состояния или дистанционным наблюдением
Компании, осуществляющие эту деятельность, могут также участвовать в продаже таких систем безопасности, механических или электронныхзамковых устройств, сейфов и хранилищ

Эта группировка не включает:
- установку систем безопасности, таких как охранная и противопожарная сигнализации, без последующего контроля за ними, см. 43.21;
- розничную продажу электрических систем сигнализации, механических или электронных замковых устройств, сейфов и хранилищ в специализированных складах, без контроля, установки или их ремонта, см. 47.59;
- консультирование в области безопасности, см. 74.90;
- предоставление услуг по соблюдению общественного порядка и безопасности, см. 84.24;
- предоставление услуг по изготовлению дубликатов ключей, см. 95.29');
INSERT INTO "public"."okved_2" VALUES ('80.3', '80', 'N', 'Деятельность по расследованию', '');
INSERT INTO "public"."okved_2" VALUES ('80.30', '80.3', 'N', 'Деятельность по расследованию', 'Эта группировка включает:
- проведение детективных расследований;
- привлечение к расследованию частных следователей, независимо от типа клиента или цели расследования');
INSERT INTO "public"."okved_2" VALUES ('81', 'N', 'N', 'Деятельность по обслуживанию зданий и территорий', 'Эта группировка включает:
- предоставление различных вспомогательных услуг в пределах помещений клиента, внутреннюю и внешнюю очистку зданий всех типов, очистку промышленного оборудования, мытье поездов, автобусов, самолетов и т. д., очистку внутренней части автоцистерн и морских танкеров, дезинфекцию и дезинсекцию в зданиях, на судах, в поездах и т. д.

Эта группировка также включает:
- мытье бутылок, уборку улиц, удаление снега и льда, услуги по уходу за территорией, наряду с проектированием ландшафтного дизайна и/или строительством; установку проходов, перегородок, площадок, заборов, изгородей, водоемов и подобных объектов на территории');
INSERT INTO "public"."okved_2" VALUES ('81.1', '81', 'N', 'Деятельность по комплексному обслуживанию помещений', '');
INSERT INTO "public"."okved_2" VALUES ('81.10', '81.1', 'N', 'Деятельность по комплексному обслуживанию помещений', 'Эта группировка включает:
- комплексные услуги в части обслуживания помещений клиента
Эти услуги включают:
- уборку внутренних помещений в зданиях всех типов, ремонт, охрану, удаление отходов, маршрутизацию и прием почты, услуги прачечной и сопутствующие услуги
Эти действия выполняются персоналом, участвующим или не участвующим в основном бизнесе или деятельности клиента

Эта группировка не включает:
- предоставление одной из вспомогательных услуг (например, услуг по уборке внутренних помещений)или обеспечению единственной функции (например, обогрева), см. соответствующую группировку согласно оказываемой услуге;
- предоставление управленческих услуг для полного обеспечения жизнедеятельности предприятия клиента, например гостиницы, ресторана, шахты или больницы, см. группировку в соответствии с эксплуатируемой организацией;
- администрирование сайтов и функционирование компьютерных систем клиента и/или его средств обработки данных, см. 62.03;
- управление исправительными учреждениями наплатной или контрактной основе, см. 84.23');
INSERT INTO "public"."okved_2" VALUES ('81.2', '81', 'N', 'Деятельность по чистке и уборке', 'Эта группировка включает:
- деятельность по общей уборке внутренних помещений в зданиях, внешней очистке зданий, специализированной очистке зданий или другой специализированной очистке, очистке промышленного оборудования, очистке изнутри автоцистерни танкеров, дезинфекции и дезинсекции зданий и промышленного оборудования, мойке бутылей, подметании улиц и уборке снега и льда

Эта группировка не включает:
- защиту растений от болезней и насекомых-вредителей, см. 01.61;
- приведение в порядок новыхзданий после завершения строительства, см. 43.39;
- пароструйную и пескоструйную очистку фасадов зданий, см. 43.99;
- чистку ковров, драпировок, занавесей и штор, см. 96.01');
INSERT INTO "public"."okved_2" VALUES ('81.21', '81.2', 'N', 'Деятельность по общей уборке зданий', 'Эта группировка включает:
- общую (неспециализированную) очистку всех типов зданий: офисных помещений, домов или квартир, фабрик; магазинов, учреждений;
- общую (неспециализированную) очистку прочих деловых и профессиональных помещений и многоквартирных жилых домов
Эта деятельность включает, главным образом, уборку внутренних помещений в зданиях, хотя она может включать очистку прилегающих наружных объектов, таких как окна и проходы

Эта группировка не включает:
- специализированную деятельностьпо уборке, например мойку окон, очистку дымоходов, чистку печных труб, каминов, плит, печей, мусоросжигателей, бойлеров, вентиляционных шахт, вытяжных вентиляторов, см. 81.22');
INSERT INTO "public"."okved_2" VALUES ('81.22', '81.2', 'N', 'Деятельность по чистке и уборке жилых зданий и нежилых помещений прочая', 'Эта группировка включает:
- уборку внутренних помещений в зданиях всех типов, в том числе в учреждениях, офисах, на фабриках, заводах, в магазинах, институтах и других коммерческих и профессиональных учреждениях и в многоквартирных жилых домах;
- чистку печных труб, каминов, плит, печей, мусоросжигателей, бойлеров, вентиляционных шахт, вытяжных вентиляторов;
- чистку производственного оборудования;
- прочую деятельность по очистке зданий и промышленных объектов

Эта группировка не включает:
- пароструйную и пескоструйную очистку фасадов зданий, см. 43.99');
INSERT INTO "public"."okved_2" VALUES ('81.29', '81.2', 'N', 'Деятельность по чистке и уборке прочая', 'Эта группировка включает:
- очистку и обслуживание плавательных бассейнов;
- очистку и мойку поездов, автобусов, самолетов и т. д.;
- очистку внутренних частей автоцистерн и танкеров;
- дезинфекцию и дезинсекцию зданий и оборудования;
- мытье бутылок;
- очистку улиц и зданий от снега и льда;
- предоставление прочих услуг по мытью и уборке

Эта группировка не включает:
- защиту растений от болезней и насекомых-вредителей, см. 01.61;
- мойку автомобилей, см. 45.20.');
INSERT INTO "public"."okved_2" VALUES ('81.29.1', '81.29', 'N', 'Дезинфекция, дезинсекция, дератизация зданий, промышленного оборудования', '');
INSERT INTO "public"."okved_2" VALUES ('81.29.2', '81.29', 'N', 'Подметание улиц и уборка снега', '');
INSERT INTO "public"."okved_2" VALUES ('81.29.9', '81.29', 'N', 'Деятельность по чистке и уборке прочая, не включенная в другие группировки', '');
INSERT INTO "public"."okved_2" VALUES ('81.3', '81', 'N', 'Предоставление услуг по благоустройству ландшафта', '');
INSERT INTO "public"."okved_2" VALUES ('81.30', '81.3', 'N', 'Деятельность по благоустройству ландшафта', 'Эта группировка включает:
- закладку, обработку и обслуживание: парков и садов для частных и общественных жилых домов, общественных и нежилых зданий (школ, больниц, административных зданий, церковных зданий и т. п.), городских территорий (парков, городских зеленых зон, кладбищ и т. п.), зеленых зон вдоль транспортных магистралей (дорог, железнодорожных и трамвайных линий, водных путей, портов), промышленных и торговых зданий, зеленых зон зданий (сады на крышах, озеленение фасадов, внутренних помещений), спортивных площадок, игровых площадок, зон отдыха, полей для гольфа и прочих мест для развлечений и отдыха, стационарных и проточных водных пространств (водоемов, прудов, плавательных бассейнов, рвов, водных трасс, заводских сточных систем);
- озеленение и благоустройство зон для защиты от шума, ветра, эрозии, яркого света и т. п.

Эта группировка не включает:
- посадку для коммерческих целей (для продажи) растений, деревьев, см. 01, 02;
- содержание питомников и лесопитомников, см. 01.30, 02.10;
- поддержание земельных угодий в надлежащем состоянии для сельскохозяйственного использования, см. 01.61;
- строительство и благоустройство зданий и сооружений, см. раздел F;
- ландшафтный дизайн и архитектурное проектирование, см. 71.11');
INSERT INTO "public"."okved_2" VALUES ('82', 'N', 'N', 'Деятельность административно-хозяйственная, вспомогательная деятельность по обеспечению функционирования организации, деятельность по предоставлению прочих вспомогательных услуг для бизнеса', 'Эта группировка включает:
- предоставление широкого диапазона ежедневных административных услуг за вознаграждение или на договорной основе, а также по расширению обычной деятельности служб поддержки предприятия

Эта группировка также включает:
- деятельность служб поддержки, обычно осуществляемую фирмами, не отнесенную к другим группировкам
Фирмы, отнесенные к этой группировке, не подбирают персонал для выполнения полного цикла бизнес-процессов на предприятии');
INSERT INTO "public"."okved_2" VALUES ('82.1', '82', 'N', 'Деятельность административно-хозяйственная и вспомогательная деятельность по обеспечению функционирования организации', 'Эта группировка включает:
- предоставление широкого диапазона ежедневных административных услуг за вознаграждение или на договорной основе, например по финансовому планированию, по выставлению счетов и ведению записей, управлению персоналом и логистике

Эта группировка также включает:
- вспомогательную деятельность для других предприятий за вознаграждение или на договорной основе, расширяющую обычные функции собственной службы поддержки предприятия
Компании, классифицированные в данной группировке, не подбирают персонал для выполнения полного цикла бизнес-процессов. Компании, занятые только одним конкретным видом этой деятельности, классифицированы согласно этому виду деятельности');
INSERT INTO "public"."okved_2" VALUES ('82.11', '82.1', 'N', 'Деятельность административно-хозяйственная комплексная по обеспечению работы организации', 'Эта группировка включает:
- комплексные ежедневные административные услуги, предоставляемые за вознаграждение или на договорной основе, такие как услуги приемной, финансового планирования, регистрации, выставления счетов, руководства персоналом и рассылки почтовых сообщений и т. д.

Эта группировка не включает:
- предоставление только одной из услуг, см. соответствующую этой услуге группировку;
- подбор персонала без руководства им, см. 78');
INSERT INTO "public"."okved_2" VALUES ('82.19', '82.1', 'N', 'Деятельность по фотокопированию и подготовке документов и прочая специализированная вспомогательная деятельность по обеспечению деятельности офиса', 'Эта группировка включает:
- копирование, подготовку документов и прочую специализированную вспомогательную деятельность по поддержке функционирования организации
Включаемая в нее деятельность по копированию и печатанию документов носит краткосрочныйхарактер

Эта группировка включает:
- подготовку документов;
- редактирование или корректирование документов;
- печатание и обработку текстов;
- секретарские услуги;
- переписывание документов и другие секретарские услуги;
- написание писем и резюме;
- услуги аренды почтовых ящиков и других почтовых и посылочных услуг, например по предварительной сортировке, написанию адресов и т. п.;
- фотокопирование;
- изготовление дубликатов;
- ксерокопирование;
- прочие услуги копирования документов (без услуг печати, например офсетной печати, быстрой печати, цифровой печати, услуг предпечатной подготовки)

Эта группировка не включает:
- печать документов (офсетную печать, быструю печать и т. д.), см. 18.12;
- предоставление услуг предпечатной подготовки, см. 18.13;
- разработку и организацию почтовых рекламных кампаний, см. 73.11;
- деятельность в области стенографирования и почтовых отправлений, см. 82.99;
- услуги общественной стенографии, см. 82.99');
INSERT INTO "public"."okved_2" VALUES ('82.2', '82', 'N', 'Деятельность центров обработки телефонных вызовов', '');
INSERT INTO "public"."okved_2" VALUES ('82.20', '82.2', 'N', 'Деятельность центров обработки телефонных вызовов', 'Эта группировка включает:
- деятельность центров обработки телефонных вызовов, осуществляющих обработку телефонных вызовов пользователей с использованием автоматической системы перераспределения вызовов, компьютерной телефонии или системы интерактивного речевого взаимодействия или подобных методов приема заказа, предоставления информации о товаре, оказания помощи по запросу клиента или рассмотрения жалоб клиента, деятельность центров обработки исходящих вызовов, использующих подобные методы дляпродажи и рекламы товаров и услуг потенциальным клиентам, изучения конъюнктуры рынка или проведения опросов общественного мнения и подобной деятельности для клиентов');
INSERT INTO "public"."okved_2" VALUES ('82.3', '82', 'N', 'Деятельность по организации конференций и выставок', '');
INSERT INTO "public"."okved_2" VALUES ('82.30', '82.3', 'N', 'Деятельность по организации конференций и выставок', 'Эта группировка включает:
- организацию, продвижение и/или управление событиями, например деловыми встречами, переговорами и выставками, собраниями, конференциями и съездами, включая подбор персонала для управления помещениями, в которых проходят этисобытия');
INSERT INTO "public"."okved_2" VALUES ('82.9', '82', 'N', 'Деятельность по предоставлению вспомогательных услуг для бизнеса, не включенная в другие группировки', 'Эта группировка включает:
- деятельность агентств по взысканию платежей по счетам кредитных организаций;
- деятельность по оказанию всех вспомогательных услуг, обычно оказываемых организациям и не включенных в другие группировки');
INSERT INTO "public"."okved_2" VALUES ('82.91', '82.9', 'N', 'Деятельность агентств по сбору платежей и бюро кредитной информации', 'Эта группировка включает:
- взыскание платежей по счетам и пересылку собранных платежей клиентам, включая услуги по взысканию долгов;
- сбор информации, например кредитной истории или послужного списка о физических лицах и компаниях и предоставлениеинформации банковским учреждениям, розничным продавцам и прочим, нуждающимся в оценке кредитоспособности этих физических лиц и компаний');
INSERT INTO "public"."okved_2" VALUES ('84.11.13', '84.11.1', 'O', 'Деятельность территориальных органов федеральных органов исполнительной власти в городах и районах субъектов Российской Федерации', '');
INSERT INTO "public"."okved_2" VALUES ('82.92', '82.9', 'N', 'Деятельность по упаковыванию товаров', 'Эта группировка включает:
- деятельность по упаковке за вознаграждение или на договорной основе, независимо от того, автоматизирован или не автоматизирован этот процесс, включая: заполнение бутылок и банок жидкими продуктами, напитками и пищевыми продуктами;
- упаковку твердых товаров в прозрачную (блистерную) упаковку, в фольгу и т. п.;
- безопасную упаковку изделий, применяемых в медицинских целях;
- прикрепление этикеток, нанесение маркировки и надписей на упаковку;
- упаковку посылок и подарков

Эта группировка не включает:
- изготовление безалкогольных напитков и производство минеральной воды, см. 11.07;
- упаковку, связанную с перевозкой, см. 52.29');
INSERT INTO "public"."okved_2" VALUES ('82.99', '82.9', 'N', 'Деятельность по предоставлению прочих вспомогательных услуг для бизнеса, не включенная в другие группировки', 'Эта группировка включает:
- деятельность в области стенографирования и расшифровки записанных материалов, например стенографирование судебных заседаний, услуги общественной стенографии;
- наложение субтитров на телепередачи в прямом эфире, репортажио встречах и конференциях;
- услуги по нанесению кодов адресов;
- услуги печатания штрихового кода;
- услуги организации сбора платежей за вознаграждение или на договорной основе;
- услуги восстановления права собственности;
- деятельность по обеспечению функционирования монетного счетчика времени автостоянки;
- деятельность независимых аукционистов;
- организацию программ привлечения покупателей;
- прочую вспомогательную деятельность, не включенную в другие группировки

Эта группировка не включает:
- предоставление услуг по переписыванию документов, см. 82.19;
- снабжение фильмов и видеороликов заголовками или субтитрами, см. 59.12');
INSERT INTO "public"."okved_2" VALUES ('O', '', 'O', 'ГОСУДАРСТВЕННОЕ УПРАВЛЕНИЕ И ОБЕСПЕЧЕНИЕ ВОЕННОЙ БЕЗОПАСНОСТИ; СОЦИАЛЬНОЕ ОБЕСПЕЧЕНИЕ', 'Этот раздел включает:
- деятельность органов государственной власти и местного самоуправления
Он включает:
- принятие законов и соответствующее им регулирование таких сфер, как налогообложение, национальная оборона, общественный порядок и безопасность, миграция, международная деятельность, финансы, природные ресурсы и охрана окружающей природной среды, образование, наука, культура, здравоохранение, физическая культура и спорт, туризм. Юридический или институциональный статус не является определяющим при отнесении вида деятельности к данному разделу. Это значит, что виды деятельности, классифицированные в других разделах классификатора, не включаются в данный раздел, даже если они осуществляются органами государственной власти и местного самоуправления. Например, государственное регулирование деятельности в области образования включено в данный раздел, сам же процесс обучения в данный раздел не включен (см. раздел Р). Государственное регулирование деятельности в области здравоохранениявключено в данный раздел, в то время как деятельность лечебных учреждений в данный раздел не включена (см. раздел Q)
Этот раздел также включает:
- деятельность в сфере социального обеспечения');
INSERT INTO "public"."okved_2" VALUES ('84', 'O', 'O', 'Деятельность органов государственного управления по обеспечению военной безопасности, обязательному социальному обеспечению', '');
INSERT INTO "public"."okved_2" VALUES ('84.1', '84', 'O', 'Деятельность органов государственного управления и местного самоуправления по вопросам общего и социально-экономического характера', 'Эта группировка включает:
- деятельность государственных органов законодательной и исполнительной власти, органов местного самоуправления в сфере финансов и других сферах, а также мониторинг социально-экономических процессов');
INSERT INTO "public"."okved_2" VALUES ('84.11', '84.1', 'O', 'Деятельность органов государственного управления и местного самоуправления по вопросам общего характера', 'Эта группировка включает:
- законодательную и исполнительную деятельность федеральных органов исполнительной власти, органов исполнительной власти субъектов Российской Федерации и муниципальных органов исполнительной власти;
- управление и надзор задеятельностью в сфере налогообложения: управление налогообложением; сбор налогов, таможенных сборов и пошлин на товары и проверка случаев нарушения налогового и таможенного законодательства;
- управление таможенной деятельностью;
- исполнение бюджетаи управление государственными и муниципальными фондами и государственным и муниципальным долгом;
- администрирование доходов и расходов и контроль за этими видами деятельности;
- управление общими (гражданскими) исследованиями и стратегией развития;
- управление и обеспечение функционирования служб социально-экономического развития, статистических и других служб на разных уровнях государственного управления;
- управление, государственный контроль и надзор за деятельностью в области природопользования и охраны окружающей среды;
- управление, государственный надзор и контроль в области миграции;
- управление, государственный контроль и надзор и контроль в области охраны труда;
- управление региональной, национальной и молодежной политикой;
-повышение эффективности государственного управления

Эта группировка не включает:
- управление государственными зданиям или зданиями, занятыми органами законодательной, исполнительной и судебной власти, см. 68.2, 68.3;
- управление исследованиями и стратегиями развития, направленными на повышение благосостояния людей, см. 84.12;
- управление исследованиями и стратегиями развития, направленными на улучшение экономической деятельности и конкурентоспособности, см. 84.13;
- управление исследованиямии стратегиями развития, направленными на обеспечение военной безопасности, см. 84.22;
- управление государственными архивами, см. 91.01');
INSERT INTO "public"."okved_2" VALUES ('84.11.1', '84.11', 'O', 'Деятельность федеральных органов государственной власти по управлению вопросами общего характера, кроме судебной власти', '');
INSERT INTO "public"."okved_2" VALUES ('84.11.11', '84.11.1', 'O', 'Деятельность федеральных органов государственной власти, кроме полномочных представителей Президента Российской Федерации и территориальных органов федеральных органов исполнительной власти', '');
INSERT INTO "public"."okved_2" VALUES ('84.11.12', '84.11.1', 'O', 'Деятельность полномочных представителей Президента Российской Федерации в регионах Российской Федерации и территориальных органов федеральных органов исполнительной власти в субъектах Российской Федерации (республиках, краях, областях)', '');
INSERT INTO "public"."okved_2" VALUES ('84.11.2', '84.11', 'O', 'Деятельность органов государственной власти по управлению вопросами общего характера, кроме судебной власти, субъектов Российской Федерации', '');
INSERT INTO "public"."okved_2" VALUES ('84.11.21', '84.11.2', 'O', 'Деятельность органов государственной власти субъектов Российской Федерации (республик, краев, областей), кроме судебной власти, представительств исполнительных органов государственной власти субъектов Российской Федерации при Президенте Российской Фе дерации', '');
INSERT INTO "public"."okved_2" VALUES ('84.11.22', '84.11.2', 'O', 'Деятельность органов государственной власти субъектов Российской Федерации по осуществлению своих полномочий в городах и районах', '');
INSERT INTO "public"."okved_2" VALUES ('84.11.23', '84.11.2', 'O', 'Деятельность органов государственной власти субъектов Российской Федерации по осуществлению своих полномочий в сельских населенных пунктах', '');
INSERT INTO "public"."okved_2" VALUES ('84.11.3', '84.11', 'O', 'Деятельность органов местного самоуправления по управлению вопросами общего характера', '');
INSERT INTO "public"."okved_2" VALUES ('84.11.31', '84.11.3', 'O', 'Деятельность органов местного самоуправления сельских поселений', 'Деятельность органов местного самоуправления сельских поселений');
INSERT INTO "public"."okved_2" VALUES ('84.11.32', '84.11.3', 'O', 'Деятельность органов местного самоуправления городских поселений', 'Деятельность органов местного самоуправления городских поселений');
INSERT INTO "public"."okved_2" VALUES ('84.11.33', '84.11.3', 'O', 'Деятельность органов местного самоуправления муниципальных районов', 'Деятельность органов местного самоуправления муниципальных районов');
INSERT INTO "public"."okved_2" VALUES ('84.11.34', '84.11.3', 'O', 'Деятельность органов местного самоуправления муниципальных округов', 'Деятельность органов местного самоуправления муниципальных округов');
INSERT INTO "public"."okved_2" VALUES ('84.11.35', '84.11.3', 'O', 'Деятельность органов местного самоуправления городских округов', 'Деятельность органов местного самоуправления городских округов');
INSERT INTO "public"."okved_2" VALUES ('84.11.4', '84.11', 'O', 'Управление финансовой деятельностью и деятельностью в сфере налогообложения', '');
INSERT INTO "public"."okved_2" VALUES ('84.11.5', '84.11', 'O', 'Управление деятельностью в области прогнозирования и планирования', '');
INSERT INTO "public"."okved_2" VALUES ('84.11.6', '84.11', 'O', 'Управление деятельностью в области фундаментальных исследований', '');
INSERT INTO "public"."okved_2" VALUES ('84.11.7', '84.11', 'O', 'Управление деятельностью в области статистики', '');
INSERT INTO "public"."okved_2" VALUES ('84.11.8', '84.11', 'O', 'Управление имуществом, находящимся в государственной собственности', '');
INSERT INTO "public"."okved_2" VALUES ('84.11.9', '84.11', 'O', 'Управление деятельностью в области антимонопольного контроля', '');
INSERT INTO "public"."okved_2" VALUES ('84.12', '84.1', 'O', 'Государственное регулирование деятельности в области здравоохранения, образования, социально-культурного развития и других социальных услуг, кроме социального обеспечения', 'Эта группировка включает:
- государственное управление программами, направленными на повышение благосостояния людей: охрану здоровья, образование, культуру, спорт, отдых, охрану окружающей среды, жилищное строительство, социальные услуги;
- государственное управление исследованиями и стратегиями социального развития

Эта группировка также включает:
- финансовую поддержку культуры и отдыха;
- государственное управление программами по снабжению питьевой водой;
- государственное управление программами по защите окружающей среды;
- управление жилищными программами

Эта группировка не включает:
- удаление сточных вод и отходов, см. 37,38,39;
- деятельность в области обязательного социального страхования, см. 84.30;
- деятельность в области образования, см. раздел Р;
- деятельность в области медицины, см 86;
- деятельность государственных музеев и прочих учреждений культуры, см. 91;
- деятельность библиотек, государственных архивов, см. 91.01;
- спортивную деятельность, см. 93');
INSERT INTO "public"."okved_2" VALUES ('84.13', '84.1', 'O', 'Регулирование и содействие эффективному ведению экономической деятельности предприятий', 'Эта группировка включает:
- государственное регулирование в: сельском хозяйстве, землепользовании, в области топливно-энергетических и минеральных ресурсов, инфраструктуре экономики, транспорте, связи, сфере деятельности гостиниц и туризма, оптовой ирозничной торговле;
- управление исследованиями и стратегиями развития для улучшения экономической ситуации и конкурентоспособности;
- управление общими вопросами, касающимися занятости рабочей силы;
- реализацию мероприятий, связанных с политикой регионального развития, например по уменьшению безработицы

Эта группировка не включает:
- исследования и экспериментальные разработки, см. 72');
INSERT INTO "public"."okved_2" VALUES ('84.2', '84', 'O', 'Предоставление государственных услуг обществу', 'Эта группировка включает:
- реализацию внешней политики;
- обеспечение национальной обороны и государственной безопасности;
- обеспечение законности, прав и свобод граждан, охраной собственности и общественного порядка');
INSERT INTO "public"."okved_2" VALUES ('84.23.14', '84.23.1', 'O', 'Деятельность районных судов', 'Эта группировка включает:
- деятельность районных судов, которые в пределах своей компетенции рассматривают дела в качестве суда первой и второй инстанции и осуществляют другие полномочия, предусмотренные федеральным конституционным законом, являютсянепосредственно вышестоящей судебной инстанцией по отношению к мировым судьям, действующим на территории соответствующего судебного района');
INSERT INTO "public"."okved_2" VALUES ('84.21', '84.2', 'O', 'Деятельность международная', 'Эта группировка включает:
- управление и функционирование Министерства иностранных дел и дипломатических и консульских миссий, размещенных за границей или при секретариатах международных организаций;
- управление, функционирование и поддержку информационных и культурных служб, сфера деятельности которых распространяется за пределы государственных границ;
- предоставление помощи иностранным государствам, направляемой напрямую или через международные организации;
- предоставление военной помощи иностранным государствам;
- управление внешней торговлей, финансовой международной деятельностью и международным техническим сотрудничеством

Эта группировка не включает:
- международную помощь беженцам или голодающим в зоне бедствия или конфликта, см.88.99');
INSERT INTO "public"."okved_2" VALUES ('84.22', '84.2', 'O', 'Деятельность, связанная с обеспечением военной безопасности', 'Эта группировка включает:
- управление, контроль и регулирование вопросов, связанных с обороной и деятельностью сухопутных, морских, воздушных и космических вооруженных сил: боевых частей сухопутных сил, морского флота и военно-воздушных сил, инженерных и транспортных войск, связи, разведки, материально-технического обеспечения, личного состава штабов, резервных и вспомогательных сил оборонного учреждения, военной логистикой (обеспечение военной техникой, продовольствием и снаряжением, инженерно-техническими сооружениями и т.п.), медицинским обслуживанием личного состава армии в полевых условиях;
- управление, обеспечение функционирования и поддержки сил гражданской обороны;
- управление исследованиями, стратегиями развития и общественнымифондами, направленными на обеспечение национальной безопасности; 
- деятельность в области гражданской обороны в организациях, эксплуатирующих опасные производственные объекты I и II классов опасности, радиационно опасных и ядерно опасных производстви объектов, гидротехнических сооружений высокой опасности.

Эта группировка не включает:
- исследования и экспериментальные разработки, см. 72;
- предоставление военной помощи иностранным государствам, см. 84.21;
- деятельность военных судов, см. 84.23;
- обеспечение населения предметами первой необходимости в случае катастроф, происходящих в мирное время, см. 84.24;
- образование, осуществляемое военными школами, училищами, институтами и академиями, см. 85.4;
- деятельность госпиталей, см. 86.10');
INSERT INTO "public"."okved_2" VALUES ('84.23', '84.2', 'O', 'Деятельность в области юстиции и правосудия', 'Эта группировка включает:
- административные, гражданские и уголовные дела, военные суды и судебную систему, включая законное представительство или когда государством предоставляются деньги или услуги;
- вынесение судебных решений;
- разбирательствопо арбитражным и гражданским делам;
- деятельность по управлению тюрьмами и обеспечению исправительных действий, включая реабилитационную помощь, вне зависимости от того, проводят ли эту деятельность государственные организации или частные на договорной основе или за вознаграждение

Эта группировка не включает:
- консультирование и представительство в гражданских, уголовных и прочих делах, см. 69.10;
- государственное регулирование образовательных учреждений, находящихся в ведении Федеральной службы исполнения наказаний, см. 85;
- государственное регулирование функционирования тюремных больниц, см. 86.10');
INSERT INTO "public"."okved_2" VALUES ('84.23.1', '84.23', 'O', 'Деятельность федеральных судов', '');
INSERT INTO "public"."okved_2" VALUES ('84.23.11', '84.23.1', 'O', 'Деятельность Конституционного суда Российской Федерации', '');
INSERT INTO "public"."okved_2" VALUES ('84.23.12', '84.23.1', 'O', 'Деятельность Верховного суда Российской Федерации', 'Эта группировка включает:
- деятельность Верховного суда Российской Федерации, который является высшим судебным органом по гражданским, уголовным, административным и иным делам, подсудным судам общей юрисдикции и непосредственно вышестоящей судебнойинстанцией по отношению к верховным судам республик, краевым (областным) судам, судам городов федерального значения, судам автономной области и автономных округов, военным судам военных округов, флотов, видов и групп войск;
- осуществление в предусмотренных федеральным законом процессуальных формах судебного надзора за деятельностью судов общей юрисдикции, включая военные и специализированные федеральные суды;
- рассмотрение в пределах своей компетенции дел в качестве суда второй инстанции, в порядке надзора и по вновь открывшимся обстоятельствам, а в случаях, предусмотренных федеральным законом, также и в качестве суда первой инстанции;
- дачу разъяснений по вопросам судебной практики');
INSERT INTO "public"."okved_2" VALUES ('84.23.13', '84.23.1', 'O', 'Деятельность кассационных судов общей юрисдикции, апелляционных судов общей юрисдикции, верховных судов республик, краевых, областных судов, судов городов федерального значения, суда автономной области, судов автономных округов', 'Эта группировка включает:
- деятельность кассационных судов общей юрисдикции, которые в пределах своей компетенции рассматривают дела в качестве суда кассационной инстанции и по новым или вновь открывшимся обстоятельствам, являются вышестоящей судебн ой инстанцией по отношению к действующим на территории соответствующего судебного кассационного округа федеральным судам общей юрисдикции и мировым судьям, если иное не установлено федеральным конституционным законом;
- деятельность апелляционных суд ов общей юрисдикции, которые в пределах своей компетенции рассматривают дела в качестве суда апелляционной инстанции и по новым или вновь открывшимся обстоятельствам, являются непосредственно вышестоящей судебной инстанцией по отношению к действующим на территории соответствующего судебного апелляционного округа верховным судам республик, краевым (областным) судам, судам городов федерального значения, суду автономной области, судам автономных округов, если иное не установлено федеральным констит уционным законом;
- деятельность верховных судов республик, краевых, областных судов, судов городов федерального значения, суда автономной области, судов автономных округов, которые в пределах своей компетенции рассматривают дела в качестве суда перв ой и апелляционной инстанций, по новым или вновь открывшимся обстоятельствам и осуществляют другие полномочия, предусмотренные федеральным конституционным законом, являются непосредственно вышестоящими судебными инстанциями по отношению к районным су дам, действующим на территории соответствующего субъекта Российской Федерации');
INSERT INTO "public"."okved_2" VALUES ('84.23.15', '84.23.1', 'O', 'Деятельность военных судов', 'Эта группировка включает:
- осуществление судебной власти в войсках, органах и формированиях, где федеральным законом предусмотрена военная служба');
INSERT INTO "public"."okved_2" VALUES ('84.23.17', '84.23.1', 'O', 'Деятельность федеральных арбитражных судов округов', 'Эта группировка включает:
- деятельность арбитражных судов округов (арбитражных кассационных судов), которые в пределах своей компетенции рассматривают в соответствии с федеральным законом дела в качестве суда первой инстанции, в качестве суда кассац ионной инстанции и по новым или вновь открывшимся обстоятельствам, являются вышестоящей судебной инстанцией по отношению к действующим на территории соответствующего судебного округа арбитражным апелляционным судам и арбитражным судам субъектов Росси йской Федерации');
INSERT INTO "public"."okved_2" VALUES ('84.23.18', '84.23.1', 'O', 'Деятельность арбитражных апелляционных судов, арбитражных судов субъектов Российской Федерации', 'Эта группировка включает:
- деятельность арбитражных апелляционных судов, которые в пределах своей компетенции рассматривают дела в качестве суда апелляционной инстанции и по новым или вновь открывшимся обстоятельствам;
 -деятельность арбитражных суд ов субъекта Российской Федерации, которые в пределах своей компетенции рассматривают дела в качестве суда первой инстанции и по новым или вновь открывшимся обстоятельствам');
INSERT INTO "public"."okved_2" VALUES ('84.23.19', '84.23.1', 'O', 'Деятельность специализированных судов', '');
INSERT INTO "public"."okved_2" VALUES ('84.23.2', '84.23', 'O', 'Деятельность судов субъектов Российской Федерации', '');
INSERT INTO "public"."okved_2" VALUES ('84.23.21', '84.23.2', 'O', 'Деятельность конституционных (уставных) судов', 'Эта группировка включает:
- рассмотрение вопросов соответствия законов субъекта Российской Федерации, нормативных правовых актов органов государственной власти субъекта Российской Федерации, органов местного самоуправления субъекта Российской Федерации конституции (уставу) субъекта Российской Федерации, а также толкование конституции (устава) субъекта Российской Федерации');
INSERT INTO "public"."okved_2" VALUES ('84.23.22', '84.23.2', 'O', 'Деятельность мировых судей', 'Эта группировка включает:
- рассмотрение мировыми судьями в пределах своей компетенции гражданских, административных и уголовных дел в качестве суда первой инстанции');
INSERT INTO "public"."okved_2" VALUES ('84.23.3', '84.23', 'O', 'Деятельность органов прокуратуры Российской Федерации', '');
INSERT INTO "public"."okved_2" VALUES ('84.23.31', '84.23.3', 'O', 'Деятельность Генеральной прокуратуры Российской Федерации', '');
