INSERT INTO "public"."okved_2" VALUES ('84.23.33', '84.23.3', 'O', 'Деятельность прокуратур городов и районов', '');
INSERT INTO "public"."okved_2" VALUES ('84.23.4', '84.23', 'O', 'Деятельность по управлению и эксплуатации тюрем, исправительных колоний и других мест лишения свободы, а также по оказанию реабилитационной помощи бывшим заключенным', '');
INSERT INTO "public"."okved_2" VALUES ('84.23.5', '84.23', 'O', 'Деятельность Следственного комитета Российской Федерации', 'Эта группировка включает:
- деятельность центрального аппарата Следственного комитета Российской Федерации;
- деятельность Главного военного следственного управления, главных следственных управлений и следственных управлений Следственного комитета Российской Федерации по субъектам Российской Федерации (в том числе подразделений указанных управлений по административным округам) и приравненных к ним специализированных (в том числе военных) следственных управлений и следственных отделов Следственного комитета Российской Федерации

Эта группировка не включает:
- деятельность научных учреждений Следственного комитета Российской Федерации, см. 72;
- деятельность образовательных учреждений Следственного комитета Российской Федерации, см. 80');
INSERT INTO "public"."okved_2" VALUES ('84.23.51', '84.23.5', 'O', 'Деятельность центрального аппарата Следственного комитета Российской Федерации', '');
INSERT INTO "public"."okved_2" VALUES ('84.23.52', '84.23.5', 'O', 'Деятельность Главного военного следственного управления, главных следственных управлений и следственных управлений Следственного комитета Российской Федерации по субъектам Российской Федерации (в том числе подразделений указанных управлений по админи стративным округам) и приравненных к ним специализированных (в том числе военных) следственных управлений и следственных отделов Следственного комитета Российской Федерации', '');
