INSERT INTO "public"."okved_2" VALUES ('72.10.11', '', 'M', 'Проведение исследований в области социально-экономической географии', 'Проведение исследований в области социально-экономической географии');
INSERT INTO "public"."okved_2" VALUES ('84.24', '84.2', 'O', 'Деятельность по обеспечению общественного порядка и безопасности', 'Эта группировка включает:
- деятельность федеральных органов по обеспечению общественного порядка и безопасности;
- деятельность по охране общественного порядка, осуществляемую войсковыми казачьими обществами;
- деятельность специализированных государственных комиссий по расследованию происшествий (например, аварии, катастрофы и т. п.);
- деятельность по обеспечению предметами первой необходимости в случае катастроф, происходящих в мирное время

Эта группировка не включает:
- обеспечение военнойбезопасности, см. 84.22');
INSERT INTO "public"."okved_2" VALUES ('84.25', '84.2', 'O', 'Деятельность по обеспечению безопасности в чрезвычайных ситуациях; деятельность по обеспечению безопасности в области использования атомной энергии', 'Эта группировка включает:
- нормативное правовое регулирование и осуществление государственных мер в области пожарной безопасности;
- организацию и осуществление профилактики пожаров;
- организацию тушения пожаров и проведение аварийно-спасательных работ;
- осуществление государственного пожарного надзора;
- лицензирование деятельности в области пожарной безопасности и подтверждение соответствия продукции и услуг требованиям пожарной безопасности;
- охрану от пожаров организаций и населенных пунктов на договорной основе;
- информационное обеспечение пожарной безопасности;
- содействие деятельности добровольных пожарных, привлечение населения к обеспечению пожарной безопасности;
- государственный и технический надзор за маломерными судами ибазами (сооружениями) для их стоянок, а также за их использованием на водных объектах;
- обеспечение безопасности людей на водных объектах;
- обеспечение функционирования спасательных служб и организаций по предупреждению и ликвидации чрезвычайных ситуаций природного и техногенного характера;
- обеспечение безопасности и спасение людей в зонах чрезвычайных ситуаций

Эта группировка не включает:
- противопожарную защиту лесов, см. 02.40;
- борьбу с огнем в местах добычи нефти и газа, см. 09.10;
-защиту от огня и противопожарную безопасность в аэропортах, не оборудованных специальной техникой, см. 52.23');
INSERT INTO "public"."okved_2" VALUES ('84.25.1', '84.25', 'O', 'Деятельность по обеспечению пожарной безопасности', '');
INSERT INTO "public"."okved_2" VALUES ('84.25.2', '84.25', 'O', 'Деятельность по обеспечению безопасности на водных объектах', '');
INSERT INTO "public"."okved_2" VALUES ('84.25.9', '84.25', 'O', 'Деятельность по обеспечению безопасности в чрезвычайных ситуациях прочая', '');
INSERT INTO "public"."okved_2" VALUES ('84.3', '84', 'O', 'Деятельность в области обязательного социального обеспечения', '');
INSERT INTO "public"."okved_2" VALUES ('84.30', '84.3', 'O', 'Деятельность в области обязательного социального обеспечения', 'Эта группировка включает:
- финансирование и регулирование деятельности, связанной с предоставлением обеспечения в случае трудового увечья и профессионального заболевания, необходимости получения медицинской помощи;
- предоставление трудовой пенсии по старости, трудовой пенсии по инвалидности, трудовой пенсии по случаю потери кормильца, социальной пенсии, пенсии по государственному пенсионному обеспечению; предоставление пособий в связи с рождением ребенка, пособий по временной нетрудоспособности;
- деятельность, связанную с социальной поддержкой безработных граждан, с предоставлением пособий многодетным семьям

Эта группировка не включает:
- добровольное пенсионное страхование и негосударственное пенсионное обеспечение, см. 65.30;
- предоставление социальной помощи и социальных услуг, см. 88.10, 88.99');
INSERT INTO "public"."okved_2" VALUES ('P', '', 'P', 'ОБРАЗОВАНИЕ', 'Этот раздел включает:
- образование как для школьников, так и для подготовки для разных профессий
В Российской Федерации устанавливаются следующие типы образовательных организаций, реализующих основные образовательные программы:
1) дошкольная образовательная организация - образовательная организация, осуществляющая в качестве основной цели ее деятельности образовательную деятельность по образовательным программам дошкольного образования, присмотр и уход за детьми;
2) общеобразовательная организация - образовательная организация, осуществляющая в качестве основной цели ее деятельности образовательную деятельность по образовательным программам начального общего, основного общего и (или) среднего общего образования;
3) профессиональная образовательная организация - образовательная организация, осуществляющая в качестве основной цели ее деятельности образовательную деятельность по образовательным программам среднего профессионального образования;
4) образовательная организация высшего образования - образовательная организация, осуществляющая в качестве основной цели ее деятельности образовательную деятельность по образовательным программам высшего образования и научную деятельность
В Российской Федерации устанавливаются следующие типыобразовательных организаций, реализующих дополнительные образовательные программы
1) организация дополнительного образования - образовательная организация, осуществляющая в качестве основной цели ее деятельности образовательную деятельность по дополнительным общеобразовательным программам;
2) организация дополнительного профессионального образования - образовательная организация, осуществляющая в качестве основной цели ее деятельности образовательную деятельность по дополнительным профессиональным программам
Этот раздел включает:
- государственные, муниципальные, негосударственные (частные) образовательные организации всех видов
Система является многоуровневой: образование как для взрослых, так и для тех, кто осваивает азы грамотности. Може');
INSERT INTO "public"."okved_2" VALUES ('85', 'P', 'P', 'Образование', '');
INSERT INTO "public"."okved_2" VALUES ('85.1', '85', 'P', 'Образование общее', 'Эта группировка включает:
- вид образования, который направлен на развитие личности и приобретение в процессе освоения основных общеобразовательных программ знаний, умений, навыков и формирование компетенции, необходимых для жизни человека в обществе, осознанного выбора профессии и получения профессионального образования');
INSERT INTO "public"."okved_2" VALUES ('85.11', '85.1', 'P', 'Образование дошкольное', 'Эта группировка включает:
- деятельность сети дошкольных образовательных организаций, реализующих общеобразовательные программы дошкольного образования различной направленности, обеспечивающих воспитание и обучение детей (детские сады, подготовительные классы и т. п.)

Эта группировка не включает:
- деятельность по уходу за детьми в дневное время, см. 88.91');
INSERT INTO "public"."okved_2" VALUES ('87', 'Q', 'Q', 'Деятельность по уходу с обеспечением проживания', 'Эта группировка включает:
- обеспечение ухода по месту жительства, объединенного с уходом, наблюдением или прочими типами ухода в случае необходимости
Обеспечение возможностей по уходу на дому является важной частью производственного процесса, представляющего сочетание охраны здоровья и предоставление социальных услуг с медицинским обслуживанием, которое включает уход за больными');
INSERT INTO "public"."okved_2" VALUES ('87.1', '87', 'Q', 'Деятельность по медицинскому уходу с обеспечением проживания', '');
INSERT INTO "public"."okved_2" VALUES ('85.12', '85.1', 'P', 'Образование начальное общее', 'Начальное общее образование направлено на формирование личности обучающегося, развитие его индивидуальных способностей, положительной мотивации и умений в учебной деятельности (овладение чтением, письмом, счетом, основными навыками учебной деятельности, элементами теоретического мышления, простейшими навыками самоконтроля, культурой поведения и речи, основами личной гигиены и здорового образа жизни)

Эта группировка не включает:
- образование взрослых;
- уход за детьми в дневное время, см. 88.91');
INSERT INTO "public"."okved_2" VALUES ('85.13', '85.1', 'P', 'Образование основное общее', 'Основное общее образование направлено на становление и формирование личности обучающегося (формирование нравственных убеждений, эстетического вкуса и здорового образа жизни, высокой культуры межличностного и межэтнического общения, овладение основаминаук, государственным языком Российской Федерации, навыками умственного и физического труда, развитие склонностей, интересов, способности к социальному самоопределению)');
INSERT INTO "public"."okved_2" VALUES ('85.14', '85.1', 'P', 'Образование среднее общее', 'Среднее общее образование направлено на дальнейшее становление и формирование личности обучающегося, развитие интереса к познанию и творческих способностей обучающегося, формирование навыков самостоятельной учебной деятельности на основе индивидуализации и профессиональной ориентации содержания среднего общего образования, подготовку обучающегося к жизни в обществе, самостоятельному жизненному выбору, продолжению образования и началу профессиональной деятельности

Эта группировка не включает:
- образование взрослых');
INSERT INTO "public"."okved_2" VALUES ('85.2', '85', 'P', 'Образование профессиональное', '');
INSERT INTO "public"."okved_2" VALUES ('85.21', '85.2', 'P', 'Образование профессиональное среднее', 'Среднее профессиональное образование направлено на решение задач интеллектуального, культурного и профессионального развития человека и имеет целью подготовку квалифицированных рабочих или служащих и специалистов среднего звена по всем основным направлениям общественно полезной деятельности в соответствии с потребностями общества и государства, а также удовлетворение потребностей личности в углублении и расширении образования');
INSERT INTO "public"."okved_2" VALUES ('85.22', '85.2', 'P', 'Образование высшее', 'Высшее образование имеет целью обеспечение подготовки высококвалифицированных кадров по всем основным направлениям общественно полезной деятельности в соответствии с потребностями общества и государства, удовлетворение потребностей личности в интеллектуальном, культурном и нравственном развитии, углублении и расширении образования, научно-педагогической квалификации');
INSERT INTO "public"."okved_2" VALUES ('85.22.1', '85.22', 'P', 'Образование высшее - бакалавриат', '');
INSERT INTO "public"."okved_2" VALUES ('85.22.2', '85.22', 'P', 'Образование высшее - специалитет', '');
INSERT INTO "public"."okved_2" VALUES ('85.22.3', '85.22', 'P', 'Образование высшее - магистратура', '');
INSERT INTO "public"."okved_2" VALUES ('85.23', '85.2', 'P', 'Подготовка кадров высшей квалификации', '');
INSERT INTO "public"."okved_2" VALUES ('85.3', '85', 'P', 'Обучение профессиональное', 'Профессиональное обучение направлено на приобретение лицами различного возраста профессиональной компетенции, в том числе для работы с конкретным оборудованием, технологиями, аппаратно-программными и иными профессиональными средствами, получение указанными лицами квалификационных разрядов, классов, категорий по профессии рабочего или должности служащего без изменения уровня образования');
INSERT INTO "public"."okved_2" VALUES ('85.30', '85.3', 'P', 'Обучение профессиональное', '');
INSERT INTO "public"."okved_2" VALUES ('85.4', '85', 'P', 'Образование дополнительное', '');
INSERT INTO "public"."okved_2" VALUES ('85.41', '85.4', 'P', 'Образование дополнительное детей и взрослых', '');
INSERT INTO "public"."okved_2" VALUES ('85.41.1', '85.41', 'P', 'Образование в области спорта и отдыха', 'Эта группировка включает: - занятие спортом, групповые или индивидуальные, включая занятия в спортивных лагерях и школах. Обучение может быть предоставлено в различных помещениях, таких как учебные помещения клиента или компании, образовательные орга низации или другие Обучение организуется официально 
Эта группировка включает: - спортивное обучение (баскетбол, бейсбол, крикет, футбол и т.д.); - обучение в спортивных лагерях; - обучение гимнастики; - обучение в школах верховой езды; - обучение пла ванию; - услуги профессиональных спортивных инструкторов, учителей, тренеров; - обучение боевым искусствам; - обучение йоге 
Эта группировка не включает: - занятия спортом в общеобразовательных школах, колледжах, университетах; - образование в области культуры; - деятельность по организации отдыха детей и их оздоровления, см. 85.41.91');
INSERT INTO "public"."okved_2" VALUES ('85.41.2', '85.41', 'P', 'Образование в области культуры', 'Эта группировка включает: - предоставление обучения в сфере искусств, драмы и музыки Организации, предоставляющие такое обучение, могут иметь название школы, студии, классы и т.д. Они предоставляют пособия по обучению, главным образом в качестве хобб и, для отдыха и в целях саморазвития и по окончании такого обучения не выдается профессиональный диплом, не присуждается степень бакалавра или иная образовательная степень 
Эта группировка включает: - занятия с учителем по фортепьяно и другим музыкаль ным инструментам; - художественные школы; - танцевальные занятия и студии; - театральные кружки, школы (за исключением академических); - школы изобразительных искусств (за исключением академических); - школы разного вида искусств (за исключением акад емических); - школы по подготовке фотографов (за исключением платных) 
Эта группировка не включает: - занятия иностранными языками; - деятельность по организации отдыха детей и их оздоровления, см. 85.41.91');
INSERT INTO "public"."okved_2" VALUES ('85.41.9', '85.41', 'P', 'Образование дополнительное детей и взрослых прочее, не включенное в другие группировки', 'Эта группировка включает:
- образование, которое не определяется квалификационным уровнем, академическое образование, центры обучения, предлагающие коррекционные курсы, курсы по подготовке к экзаменам, обучение языкам, компьютерные курсы

Эта группировка также включает:
- дальнейшее образование, а также тренинги и курсы для разных профессий, хобби и занятия для личного роста

Эта группировка также включает:
- лагеря и школы, предоставляющие обучение в областях спорта группам и индивидуально, обучение искусствам, драме или музыке или другое обучение или специальное обучение

Эта группировка не включает:
- обучение религии, см. 94.91');
INSERT INTO "public"."okved_2" VALUES ('85.42', '85.4', 'P', 'Образование профессиональное дополнительное', '');
INSERT INTO "public"."okved_2" VALUES ('85.42.1', '85.42', 'P', 'Деятельность школ подготовки водителей автотранспортных средств', 'Эта группировка включает:
- деятельность по обучению для получения лицензий (удостоверений) на вождение легковых автомобилей, автобусов, грузовых автомобилей и мотоциклов

Эта группировка не включает:
- деятельность школ, предназначенных для профессионального обучения водителей');
INSERT INTO "public"."okved_2" VALUES ('85.42.2', '85.42', 'P', 'Деятельность школ обучения вождению воздушных и плавательных судов, без выдачи коммерческих сертификатов и лицензий', '');
INSERT INTO "public"."okved_2" VALUES ('85.42.9', '85.42', 'P', 'Деятельность по дополнительному профессиональному образованию прочая, не включенная в другие группировки', 'Эта группировка включает:
- курсы по подготовке охранников;
- курсы выживания;
- ораторские курсы;
- курсы скорочтения

Эта группировка также включает:
- обучение работодателей и работников по охране труда;
- подготовку, переподготовку, повышение квалификации и дополнительное профессиональное образование специалистов в области использования атомной энергии');
INSERT INTO "public"."okved_2" VALUES ('Q', '', 'Q', 'ДЕЯТЕЛЬНОСТЬ В ОБЛАСТИ ЗДРАВООХРАНЕНИЯ И СОЦИАЛЬНЫХ УСЛУГ', 'Этот раздел включает:
- предоставление деятельности в области здравоохранения и социальных услуг
Эта деятельность включает:
- широкий диапазон мероприятий - от медицинской помощи, которую обеспечивает обученный медицинский персонал в больницах и других организациях, а также мероприятий по уходу по месту жительства, которые включают некоторые мероприятия по охране здоровья человека, до социальных услуг без привлечения специалистов в области здравоохранения');
INSERT INTO "public"."okved_2" VALUES ('86', 'Q', 'Q', 'Деятельность в области здравоохранения', 'Эта группировка включает:
- деятельность диагностических стационаров и больниц, общих или специализированных, хирургических, психиатрических и наркологических лечебниц, санаториев, профилакториев, частных медицинских лечебниц, интернатов, психиатрических клиник, центров реабилитации, лепрозориев и прочих организаций здравоохранения, которые имеют жилые помещения и проводят диагностику, обеспечивают лечение стационарных больных с любыми медицинскими показаниями

Эта группировка также включает:
- медицинские консультации и лечение в области общей и специализированной медицины терапевтами, врачами-специалистами и хирургами;
- предоставление услуг по общей или специализированной зубоврачебной практике и ортодонтической деятельности;
- деятельность по охране здоровья человека вне деятельности больниц или практикующих врачей, предоставляемой парамедицинскими специалистами, которые имеют юридические права на лечение пациентов');
INSERT INTO "public"."okved_2" VALUES ('86.10', '86.1', 'Q', 'Деятельность больничных организаций', 'Эта группировка включает:
- деятельность лечебно-профилактических организаций, включая деятельность районных, городских и областных больниц, специализированных больниц: психиатрических, наркологических, инфекционных, госпиталей, амбулаторно-поликлинических учреждений, амбулаторий и поликлиник, организаций охраны материнства и детства, включая родильные дома, перинатальные центры, дома ребенка, санаторно-курортные организации (бальнеологические лечебницы, грязелечебницы, курортные поликлиники, санатории, санаториипрофилактории)
Данная деятельность в основном направлена на стационарных больных, осуществляется под прямым контролем врачей, однако включает также амбулаторное лечение больных в поликлиниках, стационарах одного дня и включает, в том числе:
- услуги медицинского и парамедицинского персонала;
- услуги лабораторий и технической базы больниц, включая рентгенологические услуги и анестезию;
- экстренную помощь;
- предоставление услуг операционной, лекарств, питания и другого стационарного обслуживания;
- услуги центров планирования семьи, обеспечивающие медицинское обслуживание с проживанием, например стерилизацию и прерывание беременности

Эта группировка не включает:
- лабораторные испытания и осмотр всех типов материалов и продукции, кроме медицинской, см. 71.20;
- деятельность ветеринаров, см. 75.00;
- мероприятия по здравоохранению военного персонала в полевых условиях, см. 84.22;
- зубоврачебную практику, общую или специализированную, например стоматологию, эндодонтическую и педиатрическую стоматологию; патологию полости рта, ортодонтию, см. 86.23;
- частную консультационную деятельность в больницах, см. 86.2;
- деятельность медицинских лабораторий, см. 86.90;
- перевозку больных любыми санитарно-транспортными средствами, включая самолеты, см. 86.90');
INSERT INTO "public"."okved_2" VALUES ('86.2', '86', 'Q', 'Медицинская и стоматологическая практика', 'Эта группировка включает:
- медицинские консультации и лечение в области общей и специальной медицины, предоставляемые врачами общего профиля, врачами-специалистами и хирургами, стоматологами и т. д.;
- деятельность, осуществляемую в поликлиниках и медпунктах при предприятиях, в школах, домах для престарелых, рабочих и прочих объединениях, а также помощь на дому Пациенты обычно являются амбулаторными и могут направляться к специалистам врачами общего профиля (терапевтами)

Эта группировка также включает:
- частную консультационную деятельность в больницах');
INSERT INTO "public"."okved_2" VALUES ('86.21', '86.2', 'Q', 'Общая врачебная практика', 'Эта группировка включает:
- медицинские консультации и лечение в области общей и специальной медицины, предоставляемые врачами общего профиля

Эта группировка не включает:
- деятельность поликлиник, см. 86.10;
- деятельность среднего медицинского персонала, такого как акушерки, медсестры и физиотерапевты, см. 86.90');
INSERT INTO "public"."okved_2" VALUES ('86.22', '86.2', 'Q', 'Специальная врачебная практика', 'Эта группировка включает:
- медицинские консультации и лечение в области специализированной медицины врачамиспециалистами и хирургами

Эта группировка также включает:
- деятельность центров планирования семьи, обеспечивающие лечение, например: стерилизацию и прерывание беременности, без проживания');
INSERT INTO "public"."okved_2" VALUES ('86.23', '86.2', 'Q', 'Стоматологическая практика', 'Эта группировка включает:
- деятельность в области стоматологии, общую или специализированную, например в области стоматологии, эндодонтической и педиатрической стоматологии, патологии полости рта;
- деятельность в области ортодонтии
Эта группировкатакже включает:
- операционную стоматологическую деятельность');
INSERT INTO "public"."okved_2" VALUES ('86.9', '86', 'Q', 'Деятельность в области медицины прочая', '');
INSERT INTO "public"."okved_2" VALUES ('86.90', '86.9', 'Q', 'Деятельность в области медицины прочая', 'Эта группировка включает:- деятельность по обеспечению здоровья человека, не осуществляемую больницами, врачами или стоматологами;- деятельность медсестер, акушерок, физиотерапевтов или других специалистов среднего медицинского персонала в области оп тометрии, гидротерапии, массажа, трудотерапии, логопедии, ухода за ногами, гомеопатии, мануальной рефлексотерапии, иглоукалывания и т.д.- деятельность по оказанию медико-социального патронажа лицам в возрасте 65 лет и старше.Эти виды деятельности мог ут осуществляться в лечебных организациях, действующих при предприятиях, школах, домах для престарелых, и прочих организациях, а также в частных консультационных кабинетах, на дому у пациентов и в других местах.
Эта группировка также включает:- деятел ьность вспомогательного стоматологического персонала, например, зубных врачей-терапевтов, медицинских сестер при школьных стоматологических кабинетах, стоматологов-гигиенистов, которые могут работать отдельно или под контролем стоматологов;- деятельн ость медицинских лабораторий, таких как рентгеновские лаборатории и прочие диагностические центры; лаборатории по исследованию крови;- деятельность банков крови, спермы, органов для трансплантации и т.п.;- деятельность по перевозке пациентов любыми с анитарно-транспортными средствами, включая самолетыЭти услуги по перевозке оказываются в случае тяжелого состояния пациента');
INSERT INTO "public"."okved_2" VALUES ('86.90.1', '86.90', 'Q', 'Деятельность организаций санитарно-эпидемиологической службы', '');
INSERT INTO "public"."okved_2" VALUES ('86.90.2', '86.90', 'Q', 'Деятельность организаций судебно-медицинской экспертизы', '');
INSERT INTO "public"."okved_2" VALUES ('86.90.3', '86.90', 'Q', 'Деятельность массажных салонов', '');
INSERT INTO "public"."okved_2" VALUES ('86.90.4', '86.90', 'Q', 'Деятельность санаторно-курортных организаций', 'Эта группировка включает:
- медицинскую помощь, осуществляемую медицинскими организациями (санаторно-курортными организациями) в профилактических, лечебных и реабилитационных целях на основе использования природных лечебных ресурсов в условиях пребывания в лечебно-оздоровительных местностях и на курортах');
INSERT INTO "public"."okved_2" VALUES ('86.90.9', '86.90', 'Q', 'Деятельность в области медицины прочая, не включенная в другие группировки', '');
INSERT INTO "public"."okved_2" VALUES ('95.24', '95.2', 'S', 'Ремонт мебели и предметов домашнего обихода', 'Эта группировка включает:
- перетяжку, повторную полировку, ремонт и восстановление мебели, мебельной фурнитуры и деталей мебели включая офисную мебель;
- ремонт и реставрацию антикварной мебели;
- ремонт и восстановление предметов домашнего обихода,включая ремонт и реставрацию зеркал и стекол для мебели, багетных рам, карнизов и т.п;
- сборку мебели');
INSERT INTO "public"."okved_2" VALUES ('87.10', '87.1', 'Q', 'Деятельность по медицинскому уходу с обеспечением проживания', 'Эта группировка включает:
- деятельность домов для престарелых с уходом за больными, санаториев, домов отдыха с уходом за больными, организаций по уходу за больными, интернатов для престарелых

Эта группировка не включает:
- деятельность по оказанию услуг на дому, оказываемых врачами-профессионалами, см. 86;
- деятельность домов для престарелых без минимального ухода за больными или с таким уходом, см. 87.30;
- деятельность организаций, предоставляющих социальные услуги с обеспечением проживания,таких как приюты для сирот, детские дома, интернаты и общежития для детей, временные приюты для бездомных, см. 87.90');
INSERT INTO "public"."okved_2" VALUES ('87.2', '87', 'Q', 'Деятельность по оказанию помощи на дому для лиц с ограниченными возможностями развития, душевнобольным и наркозависимым', '');
INSERT INTO "public"."okved_2" VALUES ('87.20', '87.2', 'Q', 'Деятельность по оказанию помощи на дому для лиц с ограниченными возможностями развития, душевнобольным и наркозависимым', 'Эта группировка включает:
- деятельность по уходу на дому (но не лицензируемое больничное лечение) для людей с олигофренией, психиатрическими заболеваниями или токсикоманией
Пациенты обеспечиваются жильем, питанием, наблюдением и консультациями, а также в небольшом объеме медицинским обслуживанием

Эта группировка включает:
- деятельность больниц для лечения хронического алкоголизма или наркомании;
- деятельность психиатрических санаториев;
- деятельность домов для групп людей с эмоциональными расстройствами;
- деятельность учреждений по уходу за людьми с умственными недостатками;
- деятельность домов для умственно отсталых людей

Эта группировка также включает:
- деятельность по уходу на дому и лечению умственно отсталых людей и токсикоманов');
INSERT INTO "public"."okved_2" VALUES ('87.3', '87', 'Q', 'Деятельность по уходу за престарелыми и инвалидами с обеспечением проживания', '');
INSERT INTO "public"."okved_2" VALUES ('87.30', '87.3', 'Q', 'Деятельность по уходу за престарелыми и инвалидами с обеспечением проживания', '');
INSERT INTO "public"."okved_2" VALUES ('87.9', '87', 'Q', 'Деятельность по уходу с обеспечением проживания прочая', '');
INSERT INTO "public"."okved_2" VALUES ('87.90', '87.9', 'Q', 'Деятельность по уходу с обеспечением проживания прочая', 'Эта группировка включает:
- деятельность, направленную на оказание помощи на дому престарелым и инвалидам с несколько ограниченными возможностями ухода за собой;
- круглосуточную деятельность по обеспечению социальной помощи детям и особым категориямлюдей с ограниченными возможностями, когда медицинское лечение или образование не являются основными;
- деятельность приютов для сирот;
- деятельность детских интернатов и общежитий;
- деятельность временных приютов для бездомных;
- деятельность пооказанию помощи матерям-одиночкам и их детям
Данная деятельность может выполняться государственными или частными организациями

Эта группировка также включает:
- деятельность групповых домов для совместного проживания людей с социальными или личными проблемами, домов для несовершеннолетних преступников и правонарушителей, исправительных учреждений для несовершеннолетних');
INSERT INTO "public"."okved_2" VALUES ('88', 'Q', 'Q', 'Предоставление социальных услуг без обеспечения проживания', 'Эта группировка включает:
- деятельность по предоставлению социальных услуг непосредственно клиентам
Деятельность в этой группировке не включает проживание, за исключением временного');
INSERT INTO "public"."okved_2" VALUES ('88.1', '88', 'Q', 'Предоставление социальных услуг без обеспечения проживания престарелым и инвалидам', '');
INSERT INTO "public"."okved_2" VALUES ('90.01', '90.0', 'R', 'Деятельность в области исполнительских искусств', 'Эта группировка включает:
- организацию и постановку театральных, оперных и балетных представлений, концертов и прочих сценических выступлений;
- деятельность ансамблей, цирков и театральных трупп, оркестров и музыкальных групп;
- деятельность актеров, танцоров, музыкантов, лекторов или ораторов, выступающих индивидуально

Эта группировка не включает:
- деятельность частных театральных или художественных агентов или агентств по оказанию коммерческих услуг, см. 74.90;
- деятельность агентств по организации набора персонала, см. 78.10');
INSERT INTO "public"."okved_2" VALUES ('95.25', '95.2', 'S', 'Ремонт часов и ювелирных изделий', 'Эта группировка включает:
- ремонт настенных и наручных часов и деталей для них, например корпусов часов из любых материалов, шагомеров, хронометров и т. д.;
- ремонт ювелирных изделий

Эта группировка не включает:
- ремонт таймеров, печатей со временной датой, временных замков с блокировкой и подобных устройств с фиксацией времени, см. 33.13');
INSERT INTO "public"."okved_2" VALUES ('95.25.1', '95.25', 'S', 'Ремонт часов', '');
INSERT INTO "public"."okved_2" VALUES ('88.10', '88.1', 'Q', 'Предоставление социальных услуг без обеспечения проживания престарелым и инвалидам', 'Эта группировка включает:
- предоставление услуг социального характера, таких как предоставление консультаций и услуг престарелым и инвалидам, присмотр за больными, на дому либо в иных местах, государственными службами или частными организациями, физическими лицами, организациями, оказывающими помощь при стихийных бедствиях, а также национальными и местными организациями взаимопомощи и специалистами, предоставляющими консультационные услуги, включая: посещение престарелых и инвалидов, деятельность по уходу за престарелыми и пожилыми инвалидами, услуги по профессиональной реабилитации для нетрудоспособных лиц при условии, что объем образовательных услуг ограничен

Эта группировка не включает:
- деятельность по финансированию и управлению программами обязательного социального страхования, см. 84.30;
- деятельность, подобную описанной в группировке см. 88.10, но с обеспечением проживания, см. 87.30;
- деятельность по дневному уходу за детьми с отклонениями в развитии, см. 88.91');
INSERT INTO "public"."okved_2" VALUES ('88.9', '88', 'Q', 'Предоставление прочих социальных услуг без обеспечения проживания', 'Эта группировка также включает:
- дневной уход за детьми (детские ясли, сады), в том числе дневной уход за детьми с отклонениями в развитии');
INSERT INTO "public"."okved_2" VALUES ('88.91', '88.9', 'Q', 'Предоставление услуг по дневному уходу за детьми', 'Эта группировка не включает: - деятельность по организации отдыха детей и их оздоровления, см. 85.41.91');
INSERT INTO "public"."okved_2" VALUES ('88.99', '88.9', 'Q', 'Предоставление прочих социальных услуг без обеспечения проживания, не включенных в другие группировки', 'Эта группировка включает:
- предоставление услуг социального характера, консультаций, материальной помощи
Эти услуги могут предоставляться государственными службами или частными организациями, оказывающими помощь при стихийных бедствиях, а также национальными и местными организациями взаимопомощи, специалистами по: предоставлению социальной помощи детям и подросткам и руководства их воспитанием; усыновлению (удочерению), деятельность по предотвращению жестокого обращения с детьми и другими лицами; консультированию по домашнему бюджету, по вопросам брака и семьи, кредитам и займам; предоставлению социальных услуг на муниципальном уровне; оказанию помощи жертвам стихийных бедствий, беженцам, мигрантам и т. п., в том числе предоставление им места для временного проживания или жилья на длительный срок; профессиональной реабилитации для безработных при условии, что объем образовательных услуг ограничен; определению права на получение социальной помощи, доплаты за аренду жилья (жилищных субсидий) или продовольственных талонов; подготовке к определенному виду деятельности лиц с физическими или умственными недостатками, с ограниченным обучением; сбору средств или иной благотворительной деятельности по оказанию помощи, связанной с предоставлением социальных услуг

Эта группировка не включает:
- финансирование и управление обязательными программами социального обеспечения, см. 84.30;
- предоставление услуг социального характера, подобных описанным в этой группировке, с обеспечением проживания, см. 87.90');
INSERT INTO "public"."okved_2" VALUES ('R', '', 'R', 'ДЕЯТЕЛЬНОСТЬ В ОБЛАСТИ КУЛЬТУРЫ, СПОРТА, ОРГАНИЗАЦИИ ДОСУГА И РАЗВЛЕЧЕНИЙ', 'Данный раздел включает:
- широкий спектр видов деятельности в области культуры, развлечения, отдыха, включая живые выступления, работу выставок, азартные игры, спортивные мероприятия и мероприятия, связанные с отдыхом');
INSERT INTO "public"."okved_2" VALUES ('90', 'R', 'R', 'Деятельность творческая, деятельность в области искусства и организации развлечений', 'Эта группировка включает:
- предоставление услуг в сфере культурно-развлекательного досуга клиентов
В эту группировку также включена:
- зрелищно-развлекательная деятельность, а именно организация и реклама театральных и концертных постановок, развлекательных мероприятий и выставок, создание условий для творческой деятельности в области искусств и организации досуга населения

Эта группировка не включает:
- деятельность музеев всех видов, ботанических и зоологических садов;
- охрану исторических мест и зданий;
- деятельность природных заповедников, см. 91;
- деятельность по организации азартных игр и тотализаторов, см. 92;
- деятельность по организации спортивных, игровых и развлекательных мероприятий, см. 93
Деятельность в области культуры,организации досуга и развлечений включена также в ряд других группировок:
- производство и прокат кино- и видеофильмов, см. 59.11, 59.12, 59.13;
- демонстрация кинофильмов, см. 59.14;
- радио- и телевещание, см. 60.1, 60.2');
INSERT INTO "public"."okved_2" VALUES ('90.0', '90', 'R', 'Деятельность творческая, деятельность в области искусства и организации развлечений', 'Эта группировка включает:
- творческую деятельность и деятельность в сфере исполнительных видов искусства, а также смежные виды деятельности');
INSERT INTO "public"."okved_2" VALUES ('92.2', '92', 'R', 'Деятельность по организации и проведению лотерей', '');
INSERT INTO "public"."okved_2" VALUES ('92.21', '92.2', 'R', 'Деятельность организаторов лотерей', '');
INSERT INTO "public"."okved_2" VALUES ('92.22', '92.2', 'R', 'Деятельность операторов лотерей', '');
INSERT INTO "public"."okved_2" VALUES ('92.23', '92.2', 'R', 'Деятельность распространителей лотерейных билетов', 'Эта группировка включает:
- деятельность по распространению лотерейных билетов среди участников лотереи, прием лотерейных ставок, выплату, передачу или предоставление выигрышей');
INSERT INTO "public"."okved_2" VALUES ('95.25.2', '95.25', 'S', 'Ремонт ювелирных изделий', '');
INSERT INTO "public"."okved_2" VALUES ('90.02', '90.0', 'R', 'Деятельность вспомогательная, связанная с исполнительскими искусствами', 'Эта группировка включает:
- вспомогательную деятельность, связанную с исполнительскими видами искусства при постановке оперных и балетных представлений, концертов и прочих сценических выступлений;
- деятельность режиссеров, продюсеров, художников и монтажеров декораций, рабочих сцены, осветителей и т. д.;
- деятельность продюсеров или антрепренеров по организации мероприятий на собственных театральных площадках или без них

Эта группировка не включает:
- деятельность частных театральных или художественных агентов или агентств по оказанию коммерческих услуг, см. 74.90;
- деятельность агентств по организации набора персонала, см. 78.10');
INSERT INTO "public"."okved_2" VALUES ('90.03', '90.0', 'R', 'Деятельность в области художественного творчества', 'Эта группировка включает:
- деятельность скульпторов, художников, художников-мультипликаторов, граверов, офортистов и т. д., работающих индивидуально;
- деятельность писателей, работающих на индивидуальной основе в области беллетристики, технической литературы и всех остальных жанров, работающих индивидуально;
- деятельность независимых журналистов;
- деятельность по реставрации произведений искусства (картин, скульптур и т. п.)

Эта группировка также включает:
- реставрацию, консервацию и воссоз дание монументальной живописи на объектах культурного наследия

Эта группировка не включает:
- изготовление статуй, за исключением художественных оригиналов, см. 23.70;
- реставрацию органов и других музыкальных инструментов, имеющих историческую ценн ость, см. 33.19;
- производство кино- и видеофильмов, см. 59.11, 59.12;
- реставрацию мебели (кроме реставрации музейных экспонатов), см. 95.24;
- реставрацию, консервацию и воссоздание скульптуры (памятников историческим деятелям и деятелям культуры , садово-парковой скульптуры), относящейся к объектам культурного наследия, см. 42.99;
- реставрацию, консервацию и воссоздание скульптуры (барельефов, горельефов и прочих видов рельефной скульптуры, являющихся элементами декора зданий и сооружений), относящейся к объектам культурного наследия, см. 43.99');
INSERT INTO "public"."okved_2" VALUES ('90.04', '90.0', 'R', 'Деятельность учреждений культуры и искусства', 'Эта группировка включает:
- деятельность концертных и театральных залов и других учреждений культуры

Эта группировка не включает:
- деятельность кинотеатров, см. 59.14;
- деятельность агентств по продаже билетов, см. 79.90;
- деятельность музеев всехвидов, см. 91.02');
INSERT INTO "public"."okved_2" VALUES ('90.04.1', '90.04', 'R', 'Деятельность концертных залов, театров, оперных зданий, мюзик-холлов, включая услуги билетных касс', '');
INSERT INTO "public"."okved_2" VALUES ('90.04.2', '90.04', 'R', 'Деятельность многоцелевых центров и подобных заведений с преобладанием культурного обслуживания', '');
INSERT INTO "public"."okved_2" VALUES ('90.04.3', '90.04', 'R', 'Деятельность учреждений клубного типа: клубов, дворцов и домов культуры, домов народного творчества', '');
INSERT INTO "public"."okved_2" VALUES ('91', 'R', 'R', 'Деятельность библиотек, архивов, музеев и прочих объектов культуры', 'Эта группировка включает:
- деятельность библиотек и архивов;
- деятельность музеев всех видов, ботанических и зоологических садов;
- деятельность по охране исторических мест и зданий;
- деятельность государственных природных заповедников и национальных парков

Эта группировка также включает:
- деятельность по сохранению, изучению и использованию мест, зданий и природных комплексов, имеющих историческое, культурное или образовательное значение (например, объектов мирового наследия и т. д.)');
INSERT INTO "public"."okved_2" VALUES ('91.0', '91', 'R', 'Деятельность библиотек, архивов, музеев и прочих объектов культуры', '');
INSERT INTO "public"."okved_2" VALUES ('91.01', '91.0', 'R', 'Деятельность библиотек и архивов', 'Эта группировка включает:
- деятельность по работе с документами и подбору информации библиотек всех видов, в том числе читальных залов, залов для прослушивания, просмотровых залов, лекториев, планетариев, предоставляющих услуги широкой публике, а также деятельность государственных архивов: подбор специализированных или неспециализированных документов, составление каталогов, выдачу и хранение книг, карт, периодических изданий, фильмов, записей на технических носителях информации, произведений искусств и т. п., поиск требуемой информации и т. п.;
- деятельность библиотек и предоставление услуг по хранению фотографий и кинофильмов');
INSERT INTO "public"."okved_2" VALUES ('91.02', '91.0', 'R', 'Деятельность музеев', 'Эта группировка включает:
- деятельность музеев всех видов: художественных музеев, музеев драгоценностей, мебели, костюмов, керамики, серебра, музеев естественной истории, научных и технологических музеев, исторических музеев, включая военные музеи,прочих специализированных музеев, музеев на открытом воздухе

Эта группировка не включает:
- деятельность коммерческих картинных галерей, см. 47.78;
- реставрацию произведений искусства и музейных экспонатов, см. 90.03;
- деятельность библиотек и архивов, см. 91.01');
INSERT INTO "public"."okved_2" VALUES ('91.03', '91.0', 'R', 'Деятельность по охране исторических мест и зданий, памятников культуры', 'Эта группировка включает:
- функционирование и охрану исторических мест и зданий, памятников культуры

Эта группировка не включает:
- реконструкцию и реставрацию исторических мест и зданий, см. раздел F');
INSERT INTO "public"."okved_2" VALUES ('14.12.1', '14.12', 'C', 'Производство спецодежды, кроме изготовленных по индивидуальному заказу', '');
INSERT INTO "public"."okved_2" VALUES ('91.04', '91.0', 'R', 'Деятельность ботанических садов, зоопарков, государственных природных заповедников и национальных парков', 'Эта группировка включает:
- деятельность ботанических и зоологических садов, включая детские зоопарки;
- деятельность государственных природных заповедников, национальных парков и иных особо охраняемых природных территорий, включая деятельность по сохранению дикой природы

Эта группировка не включает:
- ландшафтную и садовую деятельность, см. 81.30;
- деятельность охотничьих и рыболовных заповедников, см. 93.19');
INSERT INTO "public"."okved_2" VALUES ('91.04.1', '91.04', 'R', 'Деятельность зоопарков', '');
INSERT INTO "public"."okved_2" VALUES ('91.04.2', '91.04', 'R', 'Деятельность государственных природных заповедников (в том числе биосферных)', 'Эта группировка включает:
- осуществление охраны природных территорий в целях сохранения биологического разнообразия и поддержания в естественном состоянии охраняемых природных комплексов и объектов;
- организацию и проведение научных исследований, включая ведение "Летописи природы";
- осуществление государственного экологического мониторинга (государственного мониторинга окружающей среды);
- экологическое просвещение и развитие познавательного туризма;
- содействие в подготовке научных кадров испециалистов в области охраны окружающей среды');
INSERT INTO "public"."okved_2" VALUES ('91.04.3', '91.04', 'R', 'Деятельность национальных парков', 'Эта группировка включает:
- сохранение природных комплексов, уникальных и эталонных природных участков и объектов;
- сохранение историко-культурных объектов;
- экологическое просвещение населения;
- создание условий для регулируемого туризма и отдыха;
- разработку и внедрение научных методов охраны природы и экологического просвещения;
- осуществление государственного экологического мониторинга (государственного мониторинга окружающей среды);
- восстановление нарушенных природных и историко-культурных комплексов и объектов');
INSERT INTO "public"."okved_2" VALUES ('91.04.4', '91.04', 'R', 'Деятельность природных парков', 'Эта группировка включает:
- сохранение природной среды, природных ландшафтов;
- создание условий для отдыха (в том числе массового) и сохранение рекреационных ресурсов;
- разработку и внедрение эффективных методов охраны природы и поддержание экологического баланса в условиях рекреационного использования территорий природных парков');
INSERT INTO "public"."okved_2" VALUES ('91.04.5', '91.04', 'R', 'Деятельность природных заказников', 'Эта группировка включает:
- сохранение и восстановление природных комплексов (природных ландшафтов);
- сохранение и восстановление редких и исчезающих видов растений и животных, в том числе ценных видов в хозяйственном, научном и культурном отношениях;
- сохранение ископаемых объектов;
- сохранение и восстановление ценных водных объектов и экологических систем;
- сохранение ценных объектов и комплексов неживой природы');
INSERT INTO "public"."okved_2" VALUES ('91.04.6', '91.04', 'R', 'Деятельность дендрологических парков и ботанических садов', 'Эта группировка включает:
- создание специальных коллекций растений в целях сохранения и разнообразия и обогащения растительного мира, а также осуществление научной, учебной и просветительской деятельности');
INSERT INTO "public"."okved_2" VALUES ('92', 'R', 'R', 'Деятельность по организации и проведению азартных игр и заключению пари, по организации и проведению лотерей', 'Эта группировка включает:
- работу игорных заведений, таких как казино, залы игровых автоматов;
- деятельность букмекерских контор и тотализаторов;
- организацию и проведение лотерей');
INSERT INTO "public"."okved_2" VALUES ('92.1', '92', 'R', 'Деятельность по организации и проведению азартных игр и заключения пари', '');
INSERT INTO "public"."okved_2" VALUES ('92.11', '92.1', 'R', 'Деятельность казино', 'Эта группировка включает:
- деятельность игорных заведений, в которых осуществляется деятельность по организации и проведению азартных игр с использованием игровых столов или игровых столов и игровых автоматов');
INSERT INTO "public"."okved_2" VALUES ('92.12', '92.1', 'R', 'Деятельность залов игровых автоматов', 'Эта группировка включает:
- деятельность игорных заведений, в которых осуществляется деятельность по организации и проведению азартных игр с использованием игровых автоматов');
INSERT INTO "public"."okved_2" VALUES ('92.13', '92.1', 'R', 'Деятельность по организации заключения пари', 'Эта группировка включает:
- деятельность игорных заведений, пунктов приема ставок букмекерской конторы, в которых организатор азартных игр заключает пари с участниками азартных игр в букмекерской конторе;
- деятельность игорных заведений, пунктов приема ставок тотализатора, в которых организатор азартных игр организует заключение пари между участниками азартных игр в тотализаторе');
INSERT INTO "public"."okved_2" VALUES ('93', 'R', 'R', 'Деятельность в области спорта, отдыха и развлечений', 'Эта группировка включает:
- деятельность в области спорта, отдыха и развлечений (кроме деятельности музеев, сохранения исторических мест и зданий, деятельности ботанических и зоологических садов и природных заповедников, а также деятельности по организации азартных игр)

Эта группировка не включает:
- деятельность в области театрального искусства, музыки и прочих искусств, и организацию развлечений, а именно организацию и постановку театральных, оперных и балетных представлений, концертов и прочих сценических выступлений, см. 90.');
INSERT INTO "public"."okved_2" VALUES ('93.1', '93', 'R', 'Деятельность в области спорта', 'Эта группировка включает:
- деятельность спортивных организаций;
- деятельность спортивных команд или клубов, участвующих, главным образом, в спортивных мероприятиях с продажей билетов зрителям; деятельность самостоятельных спортсменов, участвующих вспортивных мероприятиях или гонках/бегах/скачках с продажей билетов зрителям;
- деятельность владельцев гоночных автомобилей, беговых собак, беговых/скаковых лошадей, при этом владельцы, главным образом, выставляют их для участия в соревнованиях/ гонках/бегах/скачках или для участия в прочих спортивных событиях со зрителями;
- деятельность тренеров в различных видах спорта для поддержки участников спортивных соревнований и мероприятий;
- деятельность владельцев арен и стадионов;
- прочие виды деятельности по организации, рекламе или управлению спортивными мероприятиями, не включенные в другие группировки');
INSERT INTO "public"."okved_2" VALUES ('93.11', '93.1', 'R', 'Деятельность спортивных объектов', 'Эта группировка включает:
- деятельность объектов по проведению спортивных мероприятий для профессионалов или любителей на открытом воздухе или в помещении (открытых, закрытых, под крышей, оборудованных или не оборудованных трибунами для зрителей): футбольных стадионов, хоккейных коробок, площадок для крикета, стадионов для регби;
- деятельность конюшен скаковых и беговых лошадей, псарен и гаражей для спортивных гоночных автомобилей; плавательных бассейнов и стадионов; стадионов для занятий легкой атлетикой;
- деятельность площадок и стадионов для занятий зимними видами спорта, включая арены для хоккея с шайбой; боксерских залов; полей для гольфа; кегельбанов;
- организацию и проведение спортивных мероприятий на открытом воздухе или в закрытом помещении для профессионалов или любителей
Мероприятия проводятся организациями, имеющими свои спортивные объекты

Эта группировка также включает:
- подбор персонала и управление персоналом, обслуживающим эти объекты');
INSERT INTO "public"."okved_2" VALUES ('93.12', '93.1', 'R', 'Деятельность спортивных клубов', 'Эта группировка включает:
- организацию и проведение спортивных мероприятий на открытом воздухе или в закрытом помещении для профессионалов или любителей
Мероприятия проводятся организациями, имеющими или не имеющими свои спортивные объекты

Эта группировка включает:
- деятельность спортивных клубов: футбольных клубов, кегельбанов, плавательных клубов, гольф-клубов, боксерских клубов, клубов любителей зимних видов спорта, шахматных и шашечных клубов, легкоатлетических клубов, стрелковых клубов ит. д.

Эта группировка не включает:
- индивидуальные занятия с тренерами и преподавателями, см. 85.51;
- деятельность спортивных объектов, см. 93.11;
- организацию и проведение спортивных мероприятий на открытом воздухе и в помещении для профессионалов или любителей спортивными клубами, см. 93.11');
INSERT INTO "public"."okved_2" VALUES ('93.13', '93.1', 'R', 'Деятельность фитнес-центров', 'Эта группировка включает:
- деятельность клубов по фитнесу и бодибилдингу

Эта группировка не включает:
- индивидуальные занятия с тренерами и преподавателями, см. 85.51');
INSERT INTO "public"."okved_2" VALUES ('94', 'S', 'S', 'Деятельность общественных организаций', 'Эта группировка включает:
- деятельность организаций, интересы членов которых сосредоточены на обеспечении развития и процветания этих организаций
Эти организации обычно строятся на выборной основе своих членов, но их деятельность может вовлекать и приносить пользу лицам, не являющимся членами этих организаций. Первичные подразделения этой организации разбиваются на группировки по категориям на основе решаемых ими задач, а именно, служат ли они интересам предпринимателей, наемных сотрудников и научного сообщества, см. 94.1, интересам служащих, см. 94.2 или продвигают религиозные, политические, культурные, образовательные или развлекательные идеи и деятельность, см. 94.9');
INSERT INTO "public"."okved_2" VALUES ('93.19', '93.1', 'R', 'Деятельность в области спорта прочая', 'Эта группировка включает:
- деятельность организаторов спортивных мероприятий, имеющих или не имеющих свои спортивные объекты;
- деятельность самостоятельных спортсменов и атлетов, судей, рефери, хронометражистов и т. д.;
- деятельность спортивных лиг;
- деятельность, связанную с рекламой спортивных событий;
- деятельность конюшен скаковых и беговых лошадей, псарен и гаражей для спортивных гоночных автомобилей;
- деятельность охотничьих и рыболовных заповедников;
- деятельность проводников в горах;
- деятельность, связанную со спортивно-любительским рыболовством и охотой

Эта группировка не включает:
- прокат спортивного инвентаря, см. 77.21;
- деятельность спортивных школ и школ спортивных игр, см. 85.51;
- деятельность спортивных инструкторов, преподавателей, тренеров, см. 85.51;
- организацию и проведение спортивных мероприятий на открытом воздухе и в помещении для профессионалов или любителей спортивными клубами с собственными сооружениями или без, см. 93.11;
- деятельность парков ипляжей, см. 93.29');
INSERT INTO "public"."okved_2" VALUES ('93.2', '93', 'R', 'Деятельность в области отдыха и развлечений', 'Эта группировка включает:
- широкий перечень организаций, которые эксплуатируют сооружения или предоставляют услуги по организации досуга и развлечений своим клиентам, в зависимости от их пожеланий

Эта группировка включает:
- деятельность различных аттракционов, включая механические и водные, игры, шоу, тематические выставки и площадки для пикников

Эта группировка не включает:
- деятельность по организации спортивных мероприятий;
- деятельность в области театрального искусства, музыки и прочих видов искусства и организации развлечений');
INSERT INTO "public"."okved_2" VALUES ('93.21', '93.2', 'R', 'Деятельность парков культуры и отдыха и тематических парков', 'Эта группировка включает:
- деятельность развлекательных и тематических парков
Она включает виды деятельности по организации отдыха и развлечений, такие как деятельность парков аттракционов, таких как механизированные горки, водные горки, игры, шоу,деятельность, связанную с организацией ярмарок и пикниковых площадок');
INSERT INTO "public"."okved_2" VALUES ('93.29', '93.2', 'R', 'Деятельность зрелищно-развлекательная прочая', 'Эта группировка включает:
- деятельность в области отдыха и развлечений (кроме развлекательных парков и парков с аттракционами), не включенную в другие группировки:
- эксплуатацию видеоигр, действующих при опускании монет (жетонов);
- деятельность парков отдыха и развлечений (без пансиона);
- деятельность по предоставлению транспортных средств для целей развлечения, например лодок;
- деятельность горнолыжных комплексов;
- деятельность по прокату оборудования для досуга и отдыха как неотъемлемойчасти развлекательного сооружения;
- деятельность по зрелищно-развлекательным ярмаркам и шоу;
- деятельность по представлению кукольных театров, родео;
- деятельность тиров;
- организацию и проведение фейерверков и т. п.;
- деятельность пляжей, включая прокат оборудования (раздевалок на пляже, запирающихся шкафчиков, шезлонгов и т. п.);
- деятельность танцплощадок

Эта группировка также включает:
- деятельность организаторов мероприятий, не связанных со спортом или искусством, с собственными помещениями или без них');
INSERT INTO "public"."okved_2" VALUES ('93.29.1', '93.29', 'R', 'Деятельность парков отдыха и пляжей', '');
INSERT INTO "public"."okved_2" VALUES ('93.29.2', '93.29', 'R', 'Деятельность танцплощадок, дискотек, школ танцев', '');
INSERT INTO "public"."okved_2" VALUES ('93.29.9', '93.29', 'R', 'Деятельность зрелищно-развлекательная прочая, не включенная в другие группировки', '');
INSERT INTO "public"."okved_2" VALUES ('S', '', 'S', 'ПРЕДОСТАВЛЕНИЕ ПРОЧИХ ВИДОВ УСЛУГ', 'Этот раздел включает:
- деятельность общественных объединений, ремонт и обслуживание вычислительной техники, предметов домашнего обихода и личных вещей, а также предоставление различного вида персональных услуг по обслуживанию населения, не включенные в другие группировки');
INSERT INTO "public"."okved_2" VALUES ('94.1', '94', 'S', 'Деятельность коммерческих, предпринимательских и профессиональных организаций', 'Эта группировка включает:
- деятельность организаций, представляющих интересы членов коммерческих организаций и организаций предпринимателей
В случае профессиональных членских организаций данная группировка также включает:
- деятельность по продвижению профессиональных интересов работников данной профессии');
INSERT INTO "public"."okved_2" VALUES ('14.12.2', '14.12', 'C', 'Пошив производственной одежды по индивидуальному заказу населения', '');
INSERT INTO "public"."okved_2" VALUES ('14.13.3', '14.13', 'C', 'Пошив и вязание прочей верхней одежды по индивидуальному заказу населения', '');
INSERT INTO "public"."okved_2" VALUES ('94.11', '94.1', 'S', 'Деятельность коммерческих и предпринимательских членских организаций', 'Эта группировка включает:
- деятельность организаций, интересы членов которых сосредоточены на обеспечении развития и процветания предприятий конкретной сферы деятельности, например торговли, сельского хозяйства и др., или на экономическом развитии иэкономической обстановке конкретного географического района или административной единицы независимо от направления коммерческой деятельности;
- деятельность объединений таких организаций, как торговые палаты, союзы, гильдии и аналогичные организации;
- деятельность по распространению информации, представительство в государственных учреждениях, связи с общественностью и переговоры с профсоюзами

Эта группировка не включает:
- деятельность профессиональных союзов, см. 94.20');
INSERT INTO "public"."okved_2" VALUES ('94.12', '94.1', 'S', 'Деятельность профессиональных членских организаций', 'Эта группировка включает:
- деятельность организаций, интересы членов которых сосредоточены на конкретной отрасли знаний или отрасли профессиональной практической деятельности или технической области, например ассоциации медиков, юристов, бухгалтеров, технических работников, архитекторов и т. д.;
- деятельность ассоциаций специалистов, занятых в научной, образовательной или культурной сфере, например ассоциации писателей, живописцев, исполнителей различных видов искусств, журналистов и т. д.;
-деятельность по распространению информации, установлению критериев оценки практической деятельности и контролю за их соблюдением, представительство в государственных учреждениях и связи с общественностью

Эта группировка также включает:
- деятельностьнаучных обществ');
INSERT INTO "public"."okved_2" VALUES ('94.2', '94', 'S', 'Деятельность профессиональных союзов', '');
INSERT INTO "public"."okved_2" VALUES ('94.20', '94.2', 'S', 'Деятельность профессиональных союзов', 'Эта группировка включает:
- деятельность по защите интересов служащих профсоюзов и объединений профсоюзов

Эта группировка также включает:
- деятельность ассоциаций, члены которых являются сотрудниками, заинтересованными в представлении своих интересов по вопросам зарплаты и условий труда на рабочем месте, а также в осуществлении согласованных действий через данную организацию;
- действия профессиональных союзов предприятий, федераций, организованных по профессиональному, структурному, отраслевому или другому принципу');
INSERT INTO "public"."okved_2" VALUES ('94.9', '94', 'S', 'Деятельность прочих общественных организаций', 'Эта группировка включает:
- деятельность организаций (кроме организаций бизнесменов и предпринимателей, профессиональных организаций, профсоюзов), которые представляют интересы своих членов');
INSERT INTO "public"."okved_2" VALUES ('94.91', '94.9', 'S', 'Деятельность религиозных организаций', 'Эта группировка включает:
- деятельность религиозных организаций в целях совместного исповедания и распространения веры, и не имеет объектов классификации для целей учета экономической деятельности');
INSERT INTO "public"."okved_2" VALUES ('94.92', '94.9', 'S', 'Деятельность политических организаций', 'Эта группировка включает:
- деятельность политических организаций и взаимодействующих с ними организаций, например политических объединений молодежи
Эти организации в основном участвуют в формировании мнений и условий для принятия решений органами общественного управления путем продвижения членов своих групп или сочувствующих в политический аппарат организаций, в вовлечение их в распространение информации, связи с общественностью, сбору средств и т. д.');
INSERT INTO "public"."okved_2" VALUES ('94.99', '94.9', 'S', 'Деятельность прочих общественных организаций, не включенных в другие группировки', 'Эта группировка включает:
- деятельность организаций, не связанных непосредственно с политическими партиями, оказывающих влияние на общественное мнение путем просвещений, политического влияния, сбора средств и т. д.;
- деятельность по формированию гражданских инициатив или движений протеста;
- деятельность экологических и природоохранных движений;
- деятельность организаций общественной поддержки и просвещения;
- деятельность организаций по защите и улучшению положения социальных групп населения, например этнических групп и меньшинств;
- деятельность патриотических ассоциаций, включая ассоциации ветеранов войны;
- деятельность ассоциации потребителей;
- деятельность ассоциации автомобилистов;
- деятельность ассоциации общественных связей, включая клубы знакомств и т. д.;
- деятельность молодежных организаций, студенческих ассоциаций, молодежных клубов и товарищества по интересам и т. д.;
- деятельность организаций культурной и развлекательной направленности (кроме спортивных организаций), например клубы любителей поэзии, литературы и клубы книголюбов, исторические клубы, клубы озеленителей, клубы фотолюбителей и кинолюбителей, музыкальные и художественные клубы, клубы ремесленников и коллекционеров, карнавальные клубы и т. д.
Этагруппировка также включает:
- раздачу подарков членскими организациями или другими организациями');
INSERT INTO "public"."okved_2" VALUES ('14.14.4', '14.14', 'C', 'Пошив нательного белья по индивидуальному заказу населения', '');
INSERT INTO "public"."okved_2" VALUES ('28.41.3', '28.41', 'C', 'Производство аддитивных установок, использующих в качестве сырья металл, керамику и композиты', 'Эта группировка включает: - аддитивные установки, использующие процессы синтеза на подложке, процессы прямого подвода энергии и материала');
INSERT INTO "public"."okved_2" VALUES ('95', 'S', 'S', 'Ремонт компьютеров, предметов личного потребления и хозяйственно-бытового назначения', 'Эта группировка включает:
- ремонт и обслуживание компьютеров и периферийного оборудования компьютеров, такого как настольные компьютеры и ноутбуки, компьютерные терминалы, устройства памяти и принтеры

Эта группировка также включает:
- ремонт коммуникационного оборудования, такого как факсимильные аппараты, аппараты двухсторонней радиосвязи, бытовой электроники, включая радиоприемники и телевизоры;
- ремонт домашней и садовой утвари и оборудования, включая газонокосилки и вентиляторы;
- ремонт обуви и кожаных изделий;
- ремонт мебели и предметов домашней обстановки;
- ремонт одежды и аксессуаров;
- ремонт спортивных товаров;
- ремонт музыкальных инструментов;
- ремонт предметов хобби и других бытовых изделий и предметов личного пользования');
INSERT INTO "public"."okved_2" VALUES ('95.1', '95', 'S', 'Ремонт компьютеров и коммуникационного оборудования', 'Эта группировка включает:
- ремонт и обслуживание компьютеров и периферийного компьютерного и коммуникационного оборудования');
INSERT INTO "public"."okved_2" VALUES ('95.11', '95.1', 'S', 'Ремонт компьютеров и периферийного компьютерного оборудования', 'Эта группировка включает:
- ремонт и обслуживание периферийного оборудования компьютеров, в том числе: настольных компьютеров, ноутбуков, магнитных дисководов, флеш-карт и других устройств памяти, оптических дисководов (записывающих компакт-дисков CD-RW, CD-ROM, ROM DVD, DVD-RW), принтеров, мониторов, клавиатуры, мышек, джойстиков и шариковых указателей, внутренних и внешних компьютерных модемов, выделенных компьютерных терминалов, компьютерных серверов, сканеров, включая сканеры штрихового кода, читающих устройств смарт-карт, шлемов для виртуальных игр, компьютерных проекторов

Эта группировка также включает:
- ремонт и обслуживание: компьютерных терминалов, например банкоматов и торговых автоматов, пунктов продажи (торговых точек) немеханических терминалов, карманных компьютеров (КПК)');
INSERT INTO "public"."okved_2" VALUES ('95.12', '95.1', 'S', 'Ремонт коммуникационного оборудования', 'Эта группировка включает:
- ремонт и обслуживание коммуникационного оборудования, такого как: радиотелефоны, сотовые телефоны, модемы высокочастотного оборудования, факсимильные аппараты, оборудование для отображения и передачи коммуникаций (например, маршрутизаторы, мнемосхемы и системы электрических коммуникаций, модемы), аппараты двухсторонней радиосвязи, профессиональные телевизионные и видеокамеры');
INSERT INTO "public"."okved_2" VALUES ('95.2', '95', 'S', 'Ремонт предметов личного потребления и хозяйственно-бытового назначения', 'Эта группировка включает:
- ремонт и обслуживание бытовых изделий и предметов личного пользования');
INSERT INTO "public"."okved_2" VALUES ('95.21', '95.2', 'S', 'Ремонт электронной бытовой техники', 'Эта группировка включает:
- ремонт и обслуживание бытовой электроники: телевизоров и радиоприемников, видеомагнитофонов, проигрывателей компакт-дисков, любительских видеокамер, многофункциональных бытовых радиоэлектронных аппаратов, и другой аналогичной техники, устройств спутникового телевидения;
- установку, подключение и сопряжение бытовой электроники');
INSERT INTO "public"."okved_2" VALUES ('95.22', '95.2', 'S', 'Ремонт бытовых приборов, домашнего и садового инвентаря', 'Эта группировка включает:
- ремонт, обслуживание, установку и наладку бытовой техники, включая холодильники, печи и духовки, стиральные машины, сушилки для одежды, комнатные кондиционеры; швейные, вязальные, гладильные, посудомоечные, кухонные машиныи комбайны, насосы, воздухоочистители, вентиляторы и других аналогичных изделий;
- ремонт бытовых электронагревательных приборов, водогрейных установок, кухонных приборов, фотооборудования и фотоаппаратов, прочих мелких бытовых приборов (гигиены рта, массажа, бритв, фенов, биноклей, слуховых аппаратов, кинопроекторов, машинок для стрижки волос и других аналогичных изделий);
- ремонт и обслуживание домашнего и садового оборудования, включая газонокосилки, шлифовальные машины, снегоуборочные машины, машинки для обрезки ботвы и т.д.

Эта группировка не включает:
- ремонт ручных электроприборов, см. 33.12;
- ремонт центральных систем кондиционирования воздуха, см. 43.22');
INSERT INTO "public"."okved_2" VALUES ('95.22.1', '95.22', 'S', 'Ремонт бытовой техники', '');
INSERT INTO "public"."okved_2" VALUES ('95.22.2', '95.22', 'S', 'Ремонт домашнего и садового оборудования', '');
INSERT INTO "public"."okved_2" VALUES ('95.23', '95.2', 'S', 'Ремонт обуви и прочих изделий из кожи', 'Эта группировка включает:
- ремонт обуви и кожаных изделий: ботинок, туфель, чемоданов и прочих подобных изделий;
- набойку каблуков;
- окраску обуви');
INSERT INTO "public"."okved_2" VALUES ('95.29', '95.2', 'S', 'Ремонт прочих предметов личного потребления и бытовых товаров', 'Эта группировка включает:
- ремонт товаров личного потребления и бытовых товаров;
- ремонт велосипедов;
- ремонт и перекройку одежды;
- ремонт спортивных товаров (кроме спортивного оружия) и туристического снаряжения;
 - реставрацию книг;
- ремонт музыкальных инструментов (кроме органов и исторических музыкальных инструментов);
- ремонт игрушек и подобных им изделий;
- ремонт металлоизделий бытового и хозяйственного назначения;
- ремонт осветительных приборов;
- ремонт других бытовых изделий и предметов личного пользования;
- настройку пианино

Эта группировка не включает:
- промышленную гравировку по металлу, см. 25.61;
- ремонт спортивного и развлекательного оружия, см. 33.11;
- ремонт ручных электроприборов, см. 33.12;
- ремонт органов иисторических музыкальных инструментов, см. 33.19');
INSERT INTO "public"."okved_2" VALUES ('95.29.1', '95.29', 'S', 'Ремонт одежды и текстильных изделий', '');
INSERT INTO "public"."okved_2" VALUES ('95.29.2', '95.29', 'S', 'Ремонт спортивного и туристского оборудования', '');
INSERT INTO "public"."okved_2" VALUES ('95.29.9', '95.29', 'S', 'Ремонт прочих бытовых изделий и предметов личного пользования, не вошедших в другие группировки', 'Эта группировка включает:
- в т.ч. услуги, такие как изготовление металлической галантереи, ключей, номерных знаков, указателей улиц, пластиковое покрытие удостоверений личности

Эта группировка не включает:
- услуги по ремонту и восстановлению произведений искусства, см. 90.03.11');
INSERT INTO "public"."okved_2" VALUES ('96', 'S', 'S', 'Деятельность по предоставлению прочих персональных услуг', 'Эта группировка включает:
- услуги, не включенные в другие группировки
Особенно это касается таких видов услуг, как стирка и химическая чистка изделий из ткани и меха, услуги парикмахерских и салонов красоты, ритуальные услуги');
INSERT INTO "public"."okved_2" VALUES ('96.0', '96', 'S', 'Деятельность по предоставлению прочих персональных услуг', '');
INSERT INTO "public"."okved_2" VALUES ('96.01', '96.0', 'S', 'Стирка и химическая чистка текстильных и меховых изделий', 'Эта группировка включает:- стирку и химическую чистку, глажение и т.д. всех видов одежды (включая меховую) и текстильных изделий, производимых с помощью механического оборудования, вручную или с использованием автоматов самообслуживания для населения , промышленных и/или коммерческих клиентов;- крашение всех видов одежды, включая меховую, интенсификацию цвета;- различные виды обработки изделий после химической чистки: противомолевая, антистатическая, водо- и грязеотталкивающая, бактерицидная, огн езащитная и т.п.;- восстановление формы изделий после химической чистки;- текущий ремонт изделий после химчистки и крашения;- сбор белья для стирки и его доставку клиентам после стирки;- чистку и мойку ковров, драпировок, занавесок и штор в помещения х клиентов или в других местах;- подготовку белья, рабочей униформы и вещей для стирки;- услуги по аквачистке
Эта группировка не включает:- прокат одежды, даже если чистка таких изделий является составной частью этого вида деятельности, см. 77.29.4;- ремонт и перекройку одежды, см. 95.29');
INSERT INTO "public"."okved_2" VALUES ('96.02', '96.0', 'S', 'Предоставление услуг парикмахерскими и салонами красоты', 'Эта группировка включает:
- мытье волос, подравнивание и стрижку, укладку, окрашивание, мелирование, завивку, выпрямление волос и подобные работы, выполняемые для мужчин и женщин;
- бритье и подравнивание бороды;
- маникюр, педикюр, макияж, массаж лица и т. п.

Эта группировка не включает:
- изготовление париков, см. 32.99');
INSERT INTO "public"."okved_2" VALUES ('96.03', '96.0', 'S', 'Организация похорон и представление связанных с ними услуг', 'Эта группировка включает:
- захоронение и кремацию тел людей и трупов животных и связанную с этим деятельность: подготовку умерших к захоронению или кремации и бальзамирование, услуги гробовщиков;
- предоставление услуг по похоронам или услуг кремации;
- аренду оборудованного места в ритуальном зале;
- сдачу в аренду или продажу мест для захоронения;
- обслуживание могил и мавзолеев;
- изготовление надгробных сооружений из различных материалов и ритуальных принадлежностей

Эта группировка также включает:
- сооружению склепов и мемориальных комплексов;
- изготовление траурных венков, искусственных цветов, гирлянд и т.п.;
- высечку барельефов, выполнение графических портретов на памятниках, скульптурные работы и т.п., выполнение надписей

Эта группировка не включает:
- озеленение кладбищ, см. 81.30;
- предоставление религиозных ритуальных услуг, см. 94.91');
INSERT INTO "public"."okved_2" VALUES ('96.04', '96.0', 'S', 'Деятельность физкультурно- оздоровительная', 'Эта группировка включает:
- деятельность бань и душевых по предоставлению общегигиенических услуг;
- деятельность саун, соляриев, салонов для снижения веса и похудения и т.п.

Эта группировка не включает:
- деятельность массажных салонов, см. 86.90;
-деятельность оздоровительных центров, фитнес- клубов, клубов бодибилдинга и гимнастических залов, см. 93.13');
INSERT INTO "public"."okved_2" VALUES ('32.13.1', '32.13', 'C', 'Производство бижутерии и подобных товаров, кроме изготовленных по индивидуальному заказу', '');
INSERT INTO "public"."okved_2" VALUES ('32.13.2', '32.13', 'C', 'Изготовление бижутерии и подобных товаров по индивидуальному заказу населения', '');
INSERT INTO "public"."okved_2" VALUES ('96.09', '96.0', 'S', 'Предоставление прочих персональных услуг, не включенных в другие группировки', 'Эта группировка включает:
- деятельность астрологов и медиумов;
- социальные услуги, такие как услуги эскорта, бюро знакомств и брачных агентств;
- услуги по уходу за домашними животными, такие как содержание и дрессировка;
- деятельность генеалогических организаций;
- деятельность салонов татуажа и пирсинга;
- услуги чистильщиков обуви, швейцаров, парковщиков автомобилей и т.д.;
- деятельность, связанную с эксплуатацией автоматов личного обслуживания (фотокабинок, аппаратов для взвешивания, измерения кровяного давления, автоматических камер хранения и т.д.);
 - услуги наемных писателей;
 - услуги платных туалетов;
- услуги справочно-информационной службы по оказанию услуг населению по заполнению бланков, написанию заявлений, снятию копий по индивидуальному заказу населения;
- услуги справочно-информационной службы по приему в расклейку объявлений; 
- услуги копировально-множительные по индивидуальному заказу населения;
- услуги посреднические на информацию о финансовых, экономическихи промышленных и иных данных по индивидуальному заказу населения;
- услуги по оборудованию квартир (навеска карнизов, картин, вешалок, зеркал и др. предметов);
- услуги по стирке и глажению белья на дому у заказчика;
- услуги по вспашке огородов, распиловке дров по индивидуальному заказу населения;
- граверные работы по металлу, стеклу, фарфору, дереву, керамике, кроме, ювелирных изделий по индивидуальному заказу населения;
- услуги по ремонту и изготовлению гончарных изделий по индивидуальномузаказу населения;
- нарезка стекла и зеркал, художественная обработка стекла по индивидуальному заказу населения;
- услуги по изготовление с/х инвентаря из материала заказчика по индивидуальному заказу населения

Эта группировка не включает:
- предоставление ветеринарных услуг, см. 75.00;
- эксплуатацию монетных игровых автоматов, действующих при опускании монет (жетонов), см. 92.12;
- эксплуатацию стиральных машин, действующих при опускании монет (жетонов), см. 96.01');
INSERT INTO "public"."okved_2" VALUES ('T', '', 'T', 'ДЕЯТЕЛЬНОСТЬ ДОМАШНИХ ХОЗЯЙСТВ КАК РАБОТОДАТЕЛЕЙ; НЕДИФФЕРЕНЦИРОВАННАЯ ДЕЯТЕЛЬНОСТЬ ЧАСТНЫХ ДОМАШНИХ ХОЗЯЙСТВ ПО ПРОИЗВОДСТВУ ТОВАРОВ И ОКАЗАНИЮ УСЛУГ ДЛЯ СОБСТВЕННОГО ПОТРЕБЛЕНИЯ', '');
INSERT INTO "public"."okved_2" VALUES ('97', 'T', 'T', 'Деятельность домашних хозяйств с наемными работниками', '');
INSERT INTO "public"."okved_2" VALUES ('97.0', '97', 'T', 'Деятельность домашних хозяйств с наемными работниками', '');
INSERT INTO "public"."okved_2" VALUES ('97.00', '97.0', 'T', 'Деятельность домашних хозяйств с наемными работниками', 'Эта группировка включает:
- деятельность домашних хозяйств как работодателей для домашнего персонала, такого как горничные, повара, официанты, слуги, дворецкие, прачки, садовники, привратники, конюхи, шоферы, сторожа, гувернантки, приходящие няни, домашние преподаватели, секретари и т. д. Это позволяет нанятому домашнему персоналу определять деятельность своего работодателя в переписях и исследованиях, даже если работодатель является физическим лицом. Продукция, произведенная такой деятельностью, потребляется домашним хозяйством работодателя

Эта группировка не включает:
- предоставление услуг, таких как приготовление пищи, садоводство и т. д. независимыми поставщиками услуг (компаниями или физическими лицами), см. соответствующий тип услуг');
INSERT INTO "public"."okved_2" VALUES ('98', 'T', 'T', 'Деятельность недифференцированная частных домашних хозяйств по производству товаров и предоставлению услуг для собственного потребления', 'Эта группировка включает:
- недифференцированную деятельность частных домашних хозяйств по производству товаров и предоставлению услуг
Домашние хозяйства следует относить к данной группировке только в случае невозможности идентифицировать первичную деятельность домашних хозяйств
Если домашнее хозяйство участвует в рыночной деятельности, его следует относить к группировке в соответствии с классификацией первичной рыночной деятельности');
INSERT INTO "public"."okved_2" VALUES ('98.1', '98', 'T', 'Деятельность недифференцированная частных домашних хозяйств по производству товаров для собственного потребления', '');
INSERT INTO "public"."okved_2" VALUES ('98.10', '98.1', 'T', 'Деятельность недифференцированная частных домашних хозяйств по производству товаров для собственного потребления', 'Эта группировка включает:
- недифференцированную частную деятельность домашних хозяйств по производству товаров для собственного потребления
Эта деятельность включает:
- ведение хозяйства, охоту и сбор урожая, строительство жилищ, изготовление одеждыи других предметов быта, произведенных домашним хозяйством для собственного потребления
Если домашние хозяйства также заняты производством товаров на продажу, они классифицируются по соответствующему разделу классификатора. Если они преимущественнозаняты производством специализированных товаров для собственного потребления, они классифицируются в разделе по соответствующему товаропроизводящему разделу промышленности классификатора');
INSERT INTO "public"."okved_2" VALUES ('98.2', '98', 'T', 'Деятельность недифференцированная частных домашних хозяйств по предоставлению услуг для собственного потребления', '');
