INSERT INTO "public"."okved_2" VALUES ('98.20', '98.2', 'T', 'Деятельность недифференцированная частных домашних хозяйств по предоставлению услуг для собственного потребления', 'Эта группировка включает:
- недифференцированную деятельность частных домашних хозяйств по производству услуг для собственного потребления
Эти услуги включают приготовление пищи, обучение, уход за членами семьи и другие услуги, производимые домашнимхозяйством для собственных нужд
Если домашние хозяйства также заняты производством разнообразных товаров в собственных целях, они классифицируются как недифференцированная деятельность частных домашних хозяйств по производству товаров для собственного потребления');
