INSERT INTO "public"."okved_2" VALUES ('14.19.5', '14.19', 'C', 'Пошив и вязание прочей одежды и аксессуаров одежды, головных уборов по индивидуальному заказу населения', 'Эта группировка включает:
- пошив мужской, женской и детской спортивной одежды по индивидуальному заказу населения;
- пошив национальной одежды по индивидуальному заказу населения;
