INSERT INTO "public"."okved_2" VALUES ('16.29.3', '16.29', 'C', 'Изготовление изделий из дерева, пробки, соломки и материалов для плетения, корзиночных и плетеных изделий по индивидуальному заказу населения', 'Эта группировка также включает:
- изготовление и ремонт деревянных лодок по индивидуальному заказу населения');
INSERT INTO "public"."okved_2" VALUES ('25.99.3', '25.99', 'C', 'Изготовление готовых металлических изделий хозяйственного назначения по индивидуальному заказу населения', 'Эта группировка включает:
- изготовление металлических предметов хозяйственного назначения, таких как ажурные декоративные решетки, багажные корзинки, чеканные панно и рамки, секции парниковых теплиц, подвески под декоративные тарелки, электроводонагреватели, металлическая посуда, ограждения, ворота, мангалы, емкости, тепловые шкафы, поддоны, трубы, сшивно- кровельные покрытия из железа, детали к бытовым машинам и приборам, механизмы для зашторивания и прочих металлических предметов хозяйственного назначения не включенных в другие группировки');
INSERT INTO "public"."okved_2" VALUES ('31.02.1', '31.02', 'C', 'Производство кухонной мебели, кроме изготовленной по индивидуальному заказу населения', '');
