INSERT INTO "public"."okved_2" VALUES ('31.09.1', '31.09', 'C', 'Производство прочей мебели, кроме изготовленной по индивидуальному заказу населения', '');
INSERT INTO "public"."okved_2" VALUES ('31.09.2', '31.09', 'C', 'Изготовление прочей мебели и отдельных мебельных деталей, не включенных в другие группировки по индивидуальному заказу населения', 'Эта группировка включает:
- изготовление плетеной мебели, корпусной мебели, секционной мебели, мягкой мебели, наборов мебели, встроенной мебели, дачной мебели, мебели для оборудования прихожих по мебели многопланового назначения, трансформируемой мебели;
- изготовление двухсторонних стенок- перегородок;
- изготовление отдельных мебельных деталей (щитов, брусков и др.);
- изготовление щитков, решеток и коробок для маскировки отопительных приборов; 
- изготовление деревянных карнизов, багетных рамок;
- декоративное оформление мебели и отдельных мебельных деталей');
INSERT INTO "public"."okved_2" VALUES ('32.12.6', '32.12', 'C', 'Изготовление ювелирных изделий и аналогичных изделий по индивидуальному заказу населения', 'Эта группировка включает:
- изготовление ювелирных изделий по индивидуальному заказу населения;
- изготовление шкатулок, пудрениц, корпусов для часов по индивидуальному заказу населения;
- изготовление накладных выпильных монограмм к ювелирным изделиям по индивидуальному заказу населения;
- изготовление ювелирных изделий методом литья по выплавляемым моделям по индивидуальному заказу населения;
- изготовление памятных медалей по индивидуальному заказу населения;
- чеканка и гравировка ювелирныхизделий по индивидуальному заказу населения;
- чернение изделий из серебра по индивидуальному заказу населения');
INSERT INTO "public"."okved_2" VALUES ('95.29.11', '95.29.1', 'S', 'Ремонт одежды', 'Эта группировка включает:
- ремонт и обновление женской, мужской, детской верхней одежды из ткани, кожи, меха, замши и т.п., легкой одежды, белья, корсетных изделий, форменной, рабочей и спортивной одежды;
- мужских, женских и детских головных уборовиз различных материалов

Эта группировка не включает:
- ремонт трикотажных изделий');
INSERT INTO "public"."okved_2" VALUES ('95.29.12', '95.29.1', 'S', 'Ремонт текстильных изделий', 'Эта группировка включает:
- ремонт чехлов, тентов, одеял, покрывал, штор и т.п;
- ремонт столового и постельного белья;
- ремонт и реставрация кружевных изделий и изделий художественного ткачества;
- художественную штопку изделий

Эта группировка не включает:
- ремонт трикотажных изделий');
INSERT INTO "public"."okved_2" VALUES ('95.29.13', '95.29.1', 'S', 'Ремонт трикотажных изделий', 'Эта группировка включает:
- ремонт, обновление и художественную штопку верхних мужских, женских и детских трикотажных изделий, бельевых, чулочно- носочных, головных уборов, платочно- шарфовых и т.п. изделий');
INSERT INTO "public"."okved_2" VALUES ('95.29.3', '95.29', 'S', 'Ремонт игрушек и подобных им изделий', 'Эта группировка включает:
- ремонт электротехнических игр, заводных механических игрушек, и т.п.;
- ремонт оборудования для детских игр и аналогичных изделий');
INSERT INTO "public"."okved_2" VALUES ('95.29.4', '95.29', 'S', 'Ремонт металлоизделий бытового и хозяйственного назначения', 'Эта группировка включает: 
- ремонт зонтов, замков, мебели из металла, футляров, сейфов, мангалов, решеток, рамок, самоваров, домашних отопительных котлов и других аналогичных изделий');
INSERT INTO "public"."okved_2" VALUES ('95.29.41', '95.29.4', 'S', 'Ремонт предметов и изделий из металла', '');
INSERT INTO "public"."okved_2" VALUES ('95.29.42', '95.29.4', 'S', 'Ремонт металлической галантереи, ключей, номерных знаков, указателей улиц', '');
INSERT INTO "public"."okved_2" VALUES ('95.29.43', '95.29.4', 'S', 'Заточка пил, чертежных и других инструментов, ножей, ножниц, бритв, коньков и т.п.', '');
INSERT INTO "public"."okved_2" VALUES ('95.29.5', '95.29', 'S', 'Ремонт бытовых осветительных приборов', '');
INSERT INTO "public"."okved_2" VALUES ('95.29.6', '95.29', 'S', 'Ремонт велосипедов', '');
INSERT INTO "public"."okved_2" VALUES ('95.29.7', '95.29', 'S', 'Ремонт и настройка музыкальных инструментов (кроме органов и исторических музыкальных инструментов)', 'Эта группировка не включает:
- ремонт органов и исторических музыкальных инструментов, см. 33.19');
INSERT INTO "public"."okved_2" VALUES ('96.02.1', '96.02', 'S', 'Предоставление парикмахерских услуг', 'Эта группировка включает:
- предоставление парикмахерских услуг для мужчин, женщин и детей;
- пастижерные услуги, чистку, мытье, расчесывание, стрижку, подгонку, окраску и завивку парика, накладки, шиньона и их ремонт');
INSERT INTO "public"."okved_2" VALUES ('96.02.2', '96.02', 'S', 'Предоставление косметических услуг парикмахерскими и салонами красоты', 'Эта группировка включает:
- предоставление услуги по простому и сложному гриму лица, макияжу;
- окраску бровей и ресниц, коррекцию формы бровей, наращивание ресниц, завивке ресниц;
- косметические маски по уходу за кожей лица и шеи с применением косметических средств;
- гигиенический массаж лица и шеи, включая эстетический, стимулирующий, дренажный, аппаратный массаж, СПА-массаж;
- косметический комплексный уход за кожей лица и шеи, включая тестирование кожи, чистку, косметическое очищение, глубокое очищение, тонизирование, гигиенический массаж, маску, защиту, макияж, подбор средств для домашнего ухода;
- маникюрные услуги;
- комплексный уход за кожей кистей рук;
- наращивание ногтей;
- педикюрные услуги;
- комплексный уход за кожей стоп;
-предоставление прочих косметических услуг: услуги СПА-ухода по телу, включая гигиенические, релаксирующие, эстетические методы с использованием косметических средств, природных и преформированных факторов');
INSERT INTO "public"."okved_2" VALUES ('50.20.16', '50.20.1', 'H', 'Транспортирование (перевозка) ядерных материалов, радиоактивных веществ, радиационных источников, частей ядерных установок, радиоактивных отходов морскими судами заграничного плавания', '');
INSERT INTO "public"."okved_2" VALUES ('50.20.26', '50.20.2', 'H', 'Транспортирование (перевозка) ядерных материалов, радиоактивных веществ, радиационных источников, частей ядерных установок, радиоактивных отходов морскими судами каботажного плавания', '');
INSERT INTO "public"."okved_2" VALUES ('52.10.9', '52.10', 'H', 'Хранение и складирование прочих грузов', '');
INSERT INTO "public"."okved_2" VALUES ('71.12.14', '71.12.1', 'M', 'Разработка инженерно-технических проектов и контроль при строительстве и модернизации объектов использования атомной энергии', 'Эта группировка также включает:
- деятельность по размещению объектов использования атомной энергии;
- деятельность по проектированию (включая изыскания) объектов использования атомной энергии;
- государственный строительный надзор при строительствеи реконструкции объектов использования атомной энергии');
INSERT INTO "public"."okved_2" VALUES ('84.25.3', '84.25', 'O', 'Деятельность по обеспечению безопасности в области использования атомной энергии', 'Эта группировка включает:
- деятельность по обеспечению безопасности и контроль за обеспечением безопасности на объектах использования атомной энергии;
- нормативное правовое регулирование и осуществление государственных мер на объектах использованияатомной энергии;
- лицензирование деятельности по обеспечению безопасности в области использования атомной энергии;
- деятельность по организации готовности сил и средств к действиям в случае чрезвычайных ситуаций на объектах использования атомной энергии и государственный контроль за выполнением мероприятий по их предупреждению;
- деятельность по предотвращению и ликвидации последствий аварий при использовании атомной энергии;
- деятельность по охране окружающей среды при использовании атомнойэнергии');
INSERT INTO "public"."okved_2" VALUES ('32.12.7', '32.12', 'C', 'Обработка янтаря и производство изделий из янтаря', 'Эта группировка включает:
- обработку янтаря, гагата (черного янтаря) в виде кусков, листов, пластинок, цилиндров или аналогичных форм следующими операциями: полированием, шлифованием, сверлением, точением и др.;
 - производство изделий из янтаря (природного и агломерированного), гагата');
INSERT INTO "public"."okved_2" VALUES ('71.12.8', '71.12', 'M', 'Деятельность по предоставлению инженерно-технических консультаций в сфере энергосбережения и повышения энергетической эффективности использования энергетических ресурсов', 'Эта группировка включает:
- предоставление технических консультаций по организации и подготовке к реализации мероприятий, направленных на энергосбережение и повышение энергетической эффективности использования энергетических ресурсов;
- энергосервис
 
Эта группировка не включает:
- производство электромонтажных, санитарно-технических и прочих строительно-монтажных работ, см. 43.2;
- энергетическое обследование, см. 71.20.4');
INSERT INTO "public"."okved_2" VALUES ('25.30.21', '25.30.2', 'C', 'Производство ядерных установок, кроме устройств для разделения изотопов', '');
INSERT INTO "public"."okved_2" VALUES ('28.99.41', '28.99.4', 'C', 'Производство оборудования и устройств по разделению изотопов', '');
INSERT INTO "public"."okved_2" VALUES ('25.30.22', '25.30.2', 'C', 'Производство частей ядерных установок, кроме устройств для разделения изотопов', 'Эта группировка включает:
- производство систем ядерных установок;
- производство зон активных ядерных реакторов и элементов активных зон ядерных реакторов;
- производство оборудования теплообменного ядерных установок;
- производство оборудования экс плуатационного для ядерных установок;
- производство оборудования радиационно-защитного для ядерных установок;
- производство оборудования для радиохимического производства и изготовления тепловыделяющих элементов;
- производство прочего оборудования для ядерных установок');
INSERT INTO "public"."okved_2" VALUES ('28.99.49', '28.99.4', 'C', 'Производство оборудования технологического специального прочего для объектов использования атомной энергии, не включенного в другие группировки', '');
INSERT INTO "public"."okved_2" VALUES ('72.19.9', '72.19', 'M', 'Научные исследования и разработки в области естественных и технических наук прочие, не включенные в другие группировки', 'Эта группировка также включает:
- проведение научно-исследовательских работ по сохранению и воссозданию объектов культурного наследия и археологии;
- проведение исследований в области физической географии');
INSERT INTO "public"."okved_2" VALUES ('38.22.1', '38.22', 'E', 'Обработка и утилизация радиоактивных отходов', '');
INSERT INTO "public"."okved_2" VALUES ('27.90.1', '27.90', 'C', 'Производство ускорителей заряженных частиц', 'Эта группировка также включает:
- производство источников частиц, систем обеспечения работы и управления ускорителями;
- производство оборудования для транспортирования и коммутации пучка в ускорителях заряженных частиц;
- производство оборудования д ля ускорителей заряженных частиц для физических исследований');
INSERT INTO "public"."okved_2" VALUES ('38.22.11', '38.22.1', 'E', 'Деятельность по обращению с отработавшим ядерным топливом', 'Эта группировка включает:
- деятельность по подготовке отработавшего ядерного топлива к транспортированию;
- деятельность по приемке отработавшего ядерного топлива;
- деятельность по хранению отработавшего ядерного топлива;
- деятельность по перерабо тке отработавшего ядерного топлива');
INSERT INTO "public"."okved_2" VALUES ('38.22.9', '38.22', 'E', 'Обработка и утилизация опасных отходов прочих, не включенных в другие группировки', '');
INSERT INTO "public"."okved_2" VALUES ('28.99.42', '28.99.4', 'C', 'Производство оборудования и устройств для транспортировки продуктов', '');
INSERT INTO "public"."okved_2" VALUES ('27.90.2', '27.90', 'C', 'Производство радиационных аппаратов и радионуклидных энергетических устройств (РЭУ)', '');
INSERT INTO "public"."okved_2" VALUES ('72.19.12', '72.19.1', 'M', 'Научные исследования и разработки в области ядерной оружейной продукции', 'Эта группировка включает научные исследования и разработку, в том числе проведение фундаментальных, поисковых, научно-исследовательских, опытно-конструкторских и технологических работ:
- оружия на основе ядерных оружейных технологий, его составных ча стей, образцов, макетов, учебно-тренировочных средств;
- ядерных энергетических установок военного назначения и их наземных стендов-прототипов;
- комплексов, установок, стендов, и другого испытательного и производственно-технологического оборудование для разработки, изготовления, эксплуатации и ликвидации оружия на основе ядерных оружейных технологий, ядерных энергетических установок военного назначения и их наземных стендов-прототипов');
INSERT INTO "public"."okved_2" VALUES ('38.22.12', '38.22.1', 'E', 'Деятельность по обращению с особыми радиоактивными отходами', '');
INSERT INTO "public"."okved_2" VALUES ('72.19.11', '72.19.1', 'M', 'Проведение фундаментальных исследований, научно-исследовательских и опытно-конструкторских работ в области использования атомной энергии', '');
INSERT INTO "public"."okved_2" VALUES ('25.99.27', '25.99.2', 'C', 'Производство металлических изделий для области использования атомной энергии', 'Эта группировка включает:
- производство металлоизделий промышленных для области использования атомной энергии;
- производство изделий с радиоактивными изотопами;
- производство изделий со стабильными изотопами;
- производство источников альфа-излуче ния;
- производство источников нейтронного излучения;
- производство источников бета-излучения;
- производство источников гамма- и тормозного излучений;
- производство образцовых источников;
 - производство источников тепла закрытых радионуклидных');
INSERT INTO "public"."okved_2" VALUES ('28.99.4', '28.99', 'C', 'Производство оборудования технологического специального для объектов использования атомной энергии', 'Эта группировка также включает:
- производство оборудования и устройств по разделению изотопов;
- производство оборудования и устройств для транспортировки продуктов;
- производство оборудования, приборов и устройств для автоматизированных систем упр авления технологическим процессом');
INSERT INTO "public"."okved_2" VALUES ('27.90.9', '27.90', 'C', 'Производство электрического оборудования прочего, не включенного в другие группировки', '');
INSERT INTO "public"."okved_2" VALUES ('38.22.13', '38.22.1', 'E', 'Деятельность по обращению с удаляемыми радиоактивными отходами', 'Эта группировка включает:
- деятельность по сбору и сортировке удаляемых радиоактивных отходов;
- деятельность по переработке, кондиционированию и контейнеризации удаляемых радиоактивных отходов;
- деятельность по временному хранению удаляемых радиоа ктивных отходов;
- деятельность по захоронению удаляемых радиоактивных отходов');
INSERT INTO "public"."okved_2" VALUES ('28.99.43', '28.99.4', 'C', 'Производство оборудования для автоматизированных систем управления технологическим процессом атомных электростанций', '');
INSERT INTO "public"."okved_2" VALUES ('10.86.9', '10.86', 'C', 'Производство хлебобулочных и кондитерских изделий для детского питания', '');
INSERT INTO "public"."okved_2" VALUES ('10.86.8', '10.86', 'C', 'Производство рыбной продукции для детского питания', '');
INSERT INTO "public"."okved_2" VALUES ('10.86.7', '10.86', 'C', 'Производство воды питьевой, напитков безалкогольных для детского питания', '');
INSERT INTO "public"."okved_2" VALUES ('22.29.3', '22.29', 'C', 'Производство устройств пломбировочных из пластика', '');
INSERT INTO "public"."okved_2" VALUES ('66.19.7', '66.19', 'K', 'Рейтинговая деятельность', 'Эта группировка включает:
- профессиональную деятельность, осуществляемую на постоянной основе, состоящую в совокупности из подготовки, присвоения, подтверждения, пересмотра, отзыва кредитных рейтингов и прогнозов по кредитным рейтингам на основе ана лиза информации в соответствии с методологией и сопровождающуюся распространением информации о присвоенных кредитных рейтингах и прогнозах по кредитным рейтингам любым способом, обеспечивающим доступ к ней неограниченного круга лиц');
