INSERT INTO "public"."okved_2" VALUES ('72.20.19', '72.20.1', 'M', 'Научные исследования и разработки в области общественных наук прочие', 'Научные исследования и разработки в области общественных наук прочие');
INSERT INTO "public"."okved_2" VALUES ('28.96.9', '28.96', 'C', 'Производство аддитивных установок, использующих прочие виды сырья', 'Производство аддитивных установок, использующих прочие виды сырья');
INSERT INTO "public"."okved_2" VALUES ('28.96.1', '28.96', 'C', 'Производство аддитивных установок, использующих в качестве сырья полимеры, включая пластики', 'Эта группировка включает: - аддитивные установки, использующие процессы фотополимеризации в ванне, процессы экструзии материала');
INSERT INTO "public"."okved_2" VALUES ('84.11.37', '84.11.3', 'O', 'Деятельность органов местного самоуправления внутригородских районов', 'Деятельность органов местного самоуправления внутригородских районов');
