INSERT INTO "public"."okved_2" VALUES ('84.11.36', '84.11.3', 'O', 'Деятельность органов местного самоуправления городских округов с внутригородским делением', 'Деятельность органов местного самоуправления городских округов с внутригородским делением');
INSERT INTO "public"."okved_2" VALUES ('85.41.91', '85.41.9', 'P', 'Деятельность по организации отдыха детей и их оздоровления', 'Эта группировка включает: - деятельность по организации отдыха детей и их оздоровления в организациях сезонного или круглогодичного действия, стационарного и (или) нестационарного типа, с круглосуточным или дневным пребыванием 
Эта группировка не вк лючает: - деятельность туристических агентств и прочих организаций, предоставляющих услуги в сфере туризма, см. 79; - деятельность санаторно-курортных организаций, см. 86.90.4; - деятельность творческую, деятельность в области искусства и организации развлечений, см. 90; - деятельность в области спорта, отдыха и развлечений, см. 93');
INSERT INTO "public"."okved_2" VALUES ('28.30.86', '28.30.8', 'C', 'Производство машин и оборудования для лесного хозяйства', 'Производство машин и оборудования для лесного хозяйства');
INSERT INTO "public"."okved_2" VALUES ('59.11.1', '59.11', 'J', 'Производство анимационных фильмов', 'Действующая редакция Общероссийского классификатора продукции по видам экономической деятельности ОК 034-2014, позиция 59.11.11');
